// ══════════════════════════════════════════════════════════════════════════════
// 테마 시스템
// ══════════════════════════════════════════════════════════════════════════════
const THEMES = [
  { id: 'default', label: '기본 (보라·핑크)', sub: 'LGU+ 브랜드', colors: ['#D70072','#685182'] },
  { id: 'blue',    label: '청색 (Blue)',      sub: '딥블루·스카이', colors: ['#1D4ED8','#0369A1'] },
  { id: 'green',   label: '녹색 (Green)',     sub: '에메랄드·민트', colors: ['#059669','#065F46'] },
  { id: 'amber',   label: '노랑 (Amber)',     sub: '앰버·골드',     colors: ['#D97706','#92400E'] },
  { id: 'gray',    label: '그레이 (Gray)',    sub: '다크·차콜',     colors: ['#374151','#6B7280'] },
];

function applyTheme(themeId) {
  const id = THEMES.find(t => t.id === themeId) ? themeId : 'default';
  if (id === 'default') {
    document.documentElement.removeAttribute('data-theme');
  } else {
    document.documentElement.setAttribute('data-theme', id);
  }
  localStorage.setItem('sn-theme', id);
  // 패널 내 active 갱신
  document.querySelectorAll('.theme-option').forEach(el => {
    el.classList.toggle('active', el.dataset.themeId === id);
    const chk = el.querySelector('.theme-check');
    if (chk) chk.style.display = el.dataset.themeId === id ? '' : 'none';
  });
  // 테마 버튼 아이콘 색 갱신
  const btn = document.getElementById('theme-toggle-btn');
  if (btn) {
    const t = THEMES.find(t => t.id === id);
    btn.style.color = t ? t.colors[0] : 'white';
  }
}

function toggleThemePanel() {
  const panel = document.getElementById('theme-panel');
  if (!panel) { buildThemePanel(); return; }
  panel.classList.toggle('open');
}

function buildThemePanel() {
  let panel = document.getElementById('theme-panel');
  if (!panel) {
    panel = document.createElement('div');
    panel.id = 'theme-panel';
    document.body.appendChild(panel);
    // 패널 바깥 클릭 시 닫기
    document.addEventListener('click', function(e) {
      if (!panel.contains(e.target) && e.target.id !== 'theme-toggle-btn' && !e.target.closest('#theme-toggle-btn')) {
        panel.classList.remove('open');
      }
    });
  }
  const cur = localStorage.getItem('sn-theme') || 'default';
  panel.innerHTML = `
    <div class="theme-title"><i class="fas fa-palette mr-1"></i> 테마 선택</div>
    ${THEMES.map(t => `
      <div class="theme-option ${t.id === cur ? 'active' : ''}" data-theme-id="${t.id}" onclick="applyTheme('${t.id}');document.getElementById('theme-panel').classList.remove('open')">
        <div class="theme-swatch" style="background:linear-gradient(135deg,${t.colors[0]} 0%,${t.colors[1]} 100%)"></div>
        <div style="flex:1;min-width:0">
          <div class="theme-option-label">${t.label}</div>
          <div class="theme-option-sub">${t.sub}</div>
        </div>
        <i class="fas fa-check theme-check" style="display:${t.id === cur ? '' : 'none'}"></i>
      </div>
    `).join('')}
  `;
  panel.classList.add('open');
}

// 페이지 로드 시 저장된 테마 + 사용자 설정 복원
(function() {
  const saved = localStorage.getItem('sn-theme');
  if (saved && saved !== 'default') {
    document.documentElement.setAttribute('data-theme', saved);
  }
  // 글자 크기 즉시 적용 (FOUC 방지)
  const fontKey = localStorage.getItem('sn-font-size');
  if (fontKey) {
    const sizes = { small: '13px', medium: '15px', large: '17px' };
    if (sizes[fontKey]) document.documentElement.style.setProperty('--sn-font-size', sizes[fontKey]);
  }
})();

// ─── 역할 / 직위 공통 헬퍼 ────────────────────────────────────────────────────
// UI 역할 옵션 (value = DB에 저장되는 값)
// DB 실제 저장: worker → 'worker', safety/engineer/site_rep → 'supervisor', ceo → 'admin'
const ROLE_UI_OPTIONS = [
  { value: 'worker',   label: '근로자' },
  { value: 'safety',   label: '안전관리자' },
  { value: 'engineer', label: '공무' },
  { value: 'site_rep', label: '현장대리인' },
  { value: 'ceo',      label: 'CEO' },
  { value: 'lgu_plus', label: 'LGU+' },
  { value: 'sysadmin', label: '시스템관리자' },
];

// UI role → DB role 매핑
function uiRoleToDb(uiRole) {
  if (uiRole === 'worker')                                      return 'worker';
  if (uiRole === 'ceo')                                         return 'admin';
  if (uiRole === 'sysadmin')                                    return 'admin';  // 시스템관리자 → admin DB 역할
  if (uiRole === 'lgu_plus')                                    return 'lgu_plus'; // [FEAT-048] LGU+ 개별 DB 역할
  if (['safety','engineer','site_rep'].includes(uiRole))        return 'supervisor';
  // 이미 DB 값이 들어온 경우 그대로
  return uiRole;
}

// DB role + position → 가장 근접한 UI role 추정
// (편집 모달에서 기존 DB 값으로 select 초기값 세팅 시 사용)
function dbRoleToUi(dbRole, position, subRole) {
  // [FEAT-048] role='lgu_plus' 단일 역할: sub_role 확인 전에 가장 먼저 처리
  if (dbRole === 'lgu_plus') return 'lgu_plus';
  // sub_role이 명시적으로 저장된 경우 가장 우선 사용
  // (safety/engineer/site_rep/worker/lgu_plus/ceo/sysadmin)
  if (subRole) return subRole;
  if (dbRole === 'worker') {
    // worker 하위 세분화: position='LGU+' 이면 lgu_plus (구버전 호환)
    const pos = (position || '');
    if (pos === 'LGU+') return 'lgu_plus';
    return 'worker';
  }
  if (dbRole === 'admin') {
    const pos = (position || '');
    if (pos === '시스템관리자') return 'sysadmin';
    return 'ceo';
  }
  // supervisor 하위 세분화: position 값으로 역추정
  // 각 역할의 첫 번째 옵션이 역할 식별자 (safety→'안전관리자', engineer→'공무', site_rep→'현장대리인')
  if (dbRole === 'supervisor') {
    const pos = (position || '').trim();
    // ① 역할 식별자(첫 번째 옵션)와 정확히 일치하는지 우선 확인
    if (pos === '안전관리자') return 'safety';
    if (pos === '공무')       return 'engineer';
    if (pos === '현장대리인') return 'site_rep';
    // ② OFFICE_POSITION_LIST(사원~대표이사) 값이면 — position만으로는 역할 구분 불가
    //    → DB role이 supervisor 이므로 기본값 'safety' 대신 position 이력이 없는 새 계정으로 간주
    //    단, 이 경우 수정 모달에서 역할 select가 잘못 표시되는 문제를 막기 위해
    //    실제 저장된 position 앞글자로 재탐색 (공무계열 포함 여부로 구분 불가 → 'safety' 유지는 그대로)
    //    ※ 역할을 정확히 보존하려면 updateUser 저장 시 position에 역할 식별자를 포함시켜야 함
    return 'safety';
  }
  return 'worker';
}

// 역할별 직책 옵션
// worker: 기존 근로자 목록 유지
// safety/site_rep/ceo: 단일 고정값 → readonly input으로 표시
// engineer: 선택 가능 2개
// lgu_plus/sysadmin: 공란 고정
const POSITION_OPTIONS = {
  worker:   ['접속','외선','신호수','유도원','굴착기운전원','화물차운전원','작업반장','보통인부'],
  safety:   ['안전관리자'],          // 단일 → 자동 고정 (dbRoleToUi 복원 키 유지)
  engineer: ['관리감독자','정산담당자'], // 2개 선택
  site_rep: ['총괄책임자'],          // 단일 → 자동 고정 (dbRoleToUi 복원 키: '현장대리인'→아래 처리)
  ceo:      ['대표이사'],            // 단일 → 자동 고정
  lgu_plus: [],                      // 공란 고정
  sysadmin: [],                      // '시스템관리자' 고정 (별도 처리)
};

function getPositionList(uiRole) {
  return POSITION_OPTIONS[uiRole] ?? [];
}

// <select> 옵션 HTML 생성 (currentVal 은 선택값)
function buildPositionOptions(uiRole, currentVal) {
  const list = getPositionList(uiRole);
  return `<option value="">선택안함</option>` +
    list.map(p => `<option value="${p}" ${p === currentVal ? 'selected' : ''}>${p}</option>`).join('');
}

// 역할 변경 시 직책 필드를 readonly input 또는 select로 전환
// posFieldId: 직책 필드 id (신규등록='uPosition', 수정='euPosition', 가입='srPosition')
function _applyPositionField(uiRole, posFieldId, currentVal) {
  const el = document.getElementById(posFieldId);
  if (!el) return;

  // 고정값 역할: readonly input
  const fixedMap = {
    safety:   '안전관리자',
    site_rep: '총괄책임자',
    ceo:      '대표이사',
    lgu_plus: '',
    sysadmin: '시스템관리자',
  };

  if (uiRole in fixedMap) {
    const fixedVal = fixedMap[uiRole];
    const placeholder = uiRole === 'lgu_plus' ? '(해당없음)' : '';
    el.outerHTML = `<input id="${posFieldId}" class="form-control" value="${fixedVal}"
      placeholder="${placeholder}" readonly style="background:#F5F0F8;color:#685182">`;
  } else if (uiRole === 'worker' || uiRole === 'engineer') {
    // select 모드
    if (el.tagName !== 'SELECT') {
      el.outerHTML = `<select id="${posFieldId}" class="form-control">${buildPositionOptions(uiRole, currentVal||'')}</select>`;
    } else {
      el.innerHTML = buildPositionOptions(uiRole, currentVal||'');
    }
  } else {
    // 기타: 빈 select
    if (el.tagName !== 'SELECT') {
      el.outerHTML = `<select id="${posFieldId}" class="form-control"><option value="">선택안함</option></select>`;
    } else {
      el.innerHTML = `<option value="">선택안함</option>`;
    }
  }
}

// 역할 select 변경 시 직책 옵션·부서 자동설정
// deptInputId: 부서 input id (신규등록='uDept', 수정='euDept')
// posFieldId: 직책 field id (신규등록='uPosition', 수정='euPosition')
// autoFill: true면 부서 자동입력 (신규등록), false면 기존값 유지 (수정)
function _onUserRoleChange(roleSelectId, deptInputId, posFieldId, autoFill) {
  const uiRole = document.getElementById(roleSelectId)?.value || '';
  const deptEl = document.getElementById(deptInputId);

  // ① 직책 필드 갱신
  _applyPositionField(uiRole, posFieldId, '');

  // ② 부서 자동입력 (autoFill=true 일 때만)
  if (autoFill && deptEl) {
    if (uiRole === 'worker') {
      deptEl.value = '현장';
    } else if (uiRole === 'lgu_plus' || uiRole === 'sysadmin') {
      deptEl.value = '';
    } else {
      deptEl.value = '사무직';
    }
  }
}

// 하위 호환 — 기존 onchange="onRoleChange(...)" 가 남아있을 경우 대비
function onRoleChange(roleSelectId, posSelectId) {
  _applyPositionField(document.getElementById(roleSelectId)?.value || '', posSelectId, '');
}

// 역할 레이블 (DB role 기준) — 카드/리스트 표시용
const ROLE_DISPLAY = {
  admin:      { label: '관리자',    bg: '#FDE8F3', color: '#D70072', icon: 'fas fa-crown' },
  supervisor: { label: '감독자',    bg: '#EDE7F6', color: '#685182', icon: 'fas fa-user-tie' },
  worker:     { label: '근로자',    bg: '#FDE8F3', color: '#A8005A', icon: 'fas fa-hard-hat' },
};
// 세분화된 역할 표시 (UI role → {label, bg, color, icon})
const UI_ROLE_DISPLAY = {
  worker:   { label: '근로자',       bg: '#FDE8F3', color: '#A8005A', icon: 'fas fa-hard-hat' },
  safety:   { label: '안전관리자',   bg: '#EDE7F6', color: '#685182', icon: 'fas fa-shield-halved' },
  engineer: { label: '공무',         bg: '#EDE7F6', color: '#685182', icon: 'fas fa-drafting-compass' },
  site_rep: { label: '현장대리인',   bg: '#EDE7F6', color: '#685182', icon: 'fas fa-user-tie' },
  ceo:      { label: 'CEO',          bg: '#FDE8F3', color: '#D70072', icon: 'fas fa-crown' },
  lgu_plus: { label: 'LGU+',         bg: '#FDE8F3', color: '#D70072', icon: 'fas fa-building' },
  sysadmin: { label: '시스템관리자', bg: '#F5F0F8', color: '#4E3A63', icon: 'fas fa-server' },
};
// DB role + position → UI_ROLE_DISPLAY 반환 (사용자현황 배지 표시용)
function getRoleDisplay(dbRole, position, subRole) {
  const uiRole = dbRoleToUi(dbRole, position, subRole);
  return UI_ROLE_DISPLAY[uiRole] || ROLE_DISPLAY[dbRole] || ROLE_DISPLAY.worker;
}
// 세분화된 역할 레이블 (UI role → label)
const UI_ROLE_LABEL = {
  worker:   '근로자',
  safety:   '안전관리자',
  engineer: '공무',
  site_rep: '현장대리인',
  ceo:      'CEO',
  lgu_plus: 'LGU+',
  // fallback for raw DB values
  admin:      '관리자',
  supervisor: '감독자',
};
