// 권한 체크박스 HTML 생성 (sysadmin 전용)
// allowedPerms: string[] | null  (null이면 전체 허용)
function buildPermissionsSection(allowedPerms, idPrefix='perm') {
  const isAll = allowedPerms === null || allowedPerms === undefined;
  const groups = [...new Set(MENU_DEFINITIONS.map(m => m.group))];
  const checked = (menuId) => isAll || allowedPerms.includes(menuId);

  return `
  <div class="mb-2" id="${idPrefix}-section">
    <div class="text-xs font-black mb-3 flex items-center gap-2" style="color:#685182">
      <i class="fas fa-shield-check"></i> 메뉴 접근 권한
    </div>
    <div class="p-3 rounded-xl mb-2" style="background:#F5F0F8;border:1px solid #EDE7F6">
      <div class="flex items-center justify-between mb-3">
        <span class="text-xs text-slate-500">허용할 메뉴를 선택하세요. 모두 선택 해제 시 전체 허용(기본)으로 처리됩니다.</span>
        <div class="flex gap-2">
          <button type="button" onclick="permSelectAll('${idPrefix}', true)" class="text-xs px-2 py-1 rounded" style="background:#685182;color:white">전체선택</button>
          <button type="button" onclick="permSelectAll('${idPrefix}', false)" class="text-xs px-2 py-1 rounded" style="background:#D8D0DC;color:#4E3A63">전체해제</button>
        </div>
      </div>
      ${groups.map(group => {
        const items = MENU_DEFINITIONS.filter(m => m.group === group);
        return `
        <div class="mb-3">
          <div class="text-xs font-semibold text-slate-500 mb-1.5 flex items-center gap-1">
            <span class="inline-block w-1.5 h-1.5 rounded-full" style="background:#685182"></span>${group}
          </div>
          <div class="grid grid-cols-2 gap-1.5 pl-3">
            ${items.map(m => `
            <label class="flex items-center gap-2 cursor-pointer px-2 py-1.5 rounded-lg hover:bg-sky-50 transition-colors">
              <input type="checkbox" id="${idPrefix}-${m.id}" value="${m.id}"
                     class="w-4 h-4 rounded accent-sky-500 flex-shrink-0"
                     ${checked(m.id) ? 'checked' : ''}>
              <i class="${m.icon} text-xs w-3.5 text-slate-400"></i>
              <span class="text-xs text-slate-700">${m.label}</span>
            </label>`).join('')}
          </div>
        </div>`;
      }).join('')}
    </div>
  </div>`;
}

// 전체선택/해제
function permSelectAll(prefix, selectAll) {
  MENU_DEFINITIONS.forEach(m => {
    const el = document.getElementById(`${prefix}-${m.id}`);
    if (el) el.checked = selectAll;
  });
}

// 체크박스에서 permissions 배열 수집 (빈 배열 → null)
function collectPermissions(prefix='perm') {
  const selected = MENU_DEFINITIONS
    .filter(m => document.getElementById(`${prefix}-${m.id}`)?.checked)
    .map(m => m.id);
  return selected.length === MENU_DEFINITIONS.length ? null : (selected.length === 0 ? null : selected);
}

