const API = axios.create({
  baseURL: '/api',
  // 배열 파라미터를 key=A&key=B (반복키) 형태로 직렬화
  // Hono의 c.req.queries('key') 는 브라켓 없는 반복키를 기대함
  paramsSerializer: params => {
    const parts = [];
    Object.entries(params).forEach(([key, val]) => {
      if (Array.isArray(val)) {
        val.forEach(v => { if (v !== null && v !== undefined && v !== '') parts.push(encodeURIComponent(key) + '=' + encodeURIComponent(v)); });
      } else if (val !== null && val !== undefined && val !== '') {
        parts.push(encodeURIComponent(key) + '=' + encodeURIComponent(val));
      }
    });
    return parts.join('&');
  }
});
API.interceptors.request.use(cfg => {
  const token = localStorage.getItem('token');
  if (token) cfg.headers.Authorization = `Bearer ${token}`;
  return cfg;
});

// 파일 서버 = 같은 서버 (Node.js 단일 서버로 통합)
const FILE_SERVER = '';

let currentUser = null;
let currentPage = 'dashboard';
let _formDirty = false;  // 작성 중인 폼이 있는지 추적
const _legalCache = {};  // 법령안내 캐시 { key: {title, content, law_ref} }

// 폼 작성 시작 시 호출 (modal open)
function markFormDirty() { _formDirty = true; }
// 폼 닫힐 때 / 저장 완료 시 호출
function clearFormDirty() { _formDirty = false; }
// 현재 열린 modal-overlay 가 있고 폼 입력값이 있으면 dirty 판단
function isFormDirty() {
  if (!_formDirty) {
    // 열린 모달 안에 입력값이 있으면 dirty로 간주
    const modal = document.querySelector('.modal-overlay');
    if (!modal) return false;
    const inputs = modal.querySelectorAll('input:not([type=hidden]):not([type=checkbox]):not([type=radio]), textarea');
    for (const el of inputs) {
      if (el.value && el.value.trim() && el.id !== 'logDate' && el.id !== 'logStart') return true;
    }
    return false;
  }
  return _formDirty;
}

