// ─── 공통 파일 업로드 헬퍼 (진행상황 UI 포함) ──────────────────────────────────
/**
 * _uploadWithProgress(url, formData, options)
 * XHR 기반 업로드 + 실시간 진행상황 콜백
 *
 * options:
 *   onProgress(pct, loadedMB, totalMB)  — 진행률 콜백 (0~100)
 *   token                               — Authorization Bearer 토큰 (기본: localStorage)
 *   method                              — HTTP 메서드 (기본: POST)
 *
 * 반환: Promise<{ ok: boolean, status: number, data: any }>
 */
function _uploadWithProgress(url, formData, options = {}) {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    const method = options.method || 'POST';
    xhr.open(method, url);

    const token = options.token || localStorage.getItem('token');
    if (token) xhr.setRequestHeader('Authorization', `Bearer ${token}`);

    xhr.upload.onprogress = (e) => {
      if (!e.lengthComputable || typeof options.onProgress !== 'function') return;
      const pct       = Math.round((e.loaded / e.total) * 100);
      const loadedMB  = (e.loaded / 1024 / 1024).toFixed(1);
      const totalMB   = (e.total  / 1024 / 1024).toFixed(1);
      options.onProgress(pct, loadedMB, totalMB);
    };

    xhr.onload = () => {
      let data;
      try { data = JSON.parse(xhr.responseText); } catch { data = xhr.responseText; }
      resolve({ ok: xhr.status >= 200 && xhr.status < 300, status: xhr.status, data });
    };
    xhr.onerror = () => reject(new Error('네트워크 오류'));
    xhr.ontimeout = () => reject(new Error('업로드 시간 초과'));
    xhr.send(formData);
  });
}

/**
 * _showUploadToast(fileName, pct)
 * 업로드 진행 토스트를 표시하거나 갱신한다.
 * pct >= 100 이면 성공 토스트로 교체.
 */
function _showUploadToast(fileName, pct, total) {
  const id = '__upload_toast__';
  let el = document.getElementById(id);
  if (!el) {
    el = document.createElement('div');
    el.id = id;
    el.style.cssText = `
      position:fixed;bottom:24px;right:24px;z-index:99999;
      background:#1e1e2e;color:#fff;border-radius:12px;
      padding:14px 18px;min-width:260px;max-width:340px;
      box-shadow:0 4px 24px rgba(0,0,0,.35);font-size:13px;
      transition:opacity .3s;
    `;
    document.body.appendChild(el);
  }

  const barColor = pct >= 100 ? '#2DB400' : '#685182';
  const label    = total > 1
    ? `파일 업로드 중... (${Math.min(Math.ceil(pct * total / 100), total)}/${total})`
    : `${fileName} 업로드 중...`;

  el.innerHTML = `
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">
      <i class="fas ${pct>=100?'fa-check-circle':'fa-cloud-upload-alt'}"
         style="color:${barColor};font-size:16px;flex-shrink:0"></i>
      <span style="flex:1;word-break:break-all;line-height:1.4">${label}</span>
    </div>
    <div style="background:#2d2d40;border-radius:4px;height:6px;overflow:hidden">
      <div style="height:6px;width:${pct}%;background:${barColor};transition:width .2s;border-radius:4px"></div>
    </div>
    <div style="margin-top:6px;font-size:11px;color:#aaa;text-align:right">${pct}%</div>
  `;

  if (pct >= 100) {
    setTimeout(() => { el?.remove(); }, 1800);
  }
}

function _hideUploadToast() {
  document.getElementById('__upload_toast__')?.remove();
}

// 대한민국 표준시(KST, UTC+9) 현재 시각 반환
function getKSTNow() {
  const now = new Date();
  // UTC + 9시간
  const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
  return kst;
}

// KST 기준 오늘 날짜 (YYYY-MM-DD)
function getKSTDate() {
  return getKSTNow().toISOString().split('T')[0];
}

// KST 기준 현재 시각 (HH:MM)
function getKSTTime() {
  const kst = getKSTNow();
  const hh = String(kst.getUTCHours()).padStart(2, '0');
  const mm = String(kst.getUTCMinutes()).padStart(2, '0');
  return `${hh}:${mm}`;
}

// UTC 날짜/시각 문자열 → KST 기준 "YYYY-MM-DD HH:MM" 변환 (현장위치 지도용)
// 입력: ISO8601 문자열('2026-06-16T05:30:00Z', '2026-06-16 05:30:00' 등) 또는 날짜만('2026-06-16')
// 출력: "2026-06-16 14:30" (KST) 또는 날짜만 있으면 "2026-06-16"
function _toKSTDateTime(raw) {
  if (!raw) return '';
  try {
    // 날짜만 있는 경우(10자리): 시간 변환 불필요 — 그대로 반환
    if (/^\d{4}-\d{2}-\d{2}$/.test(raw.trim())) return raw.trim().substring(0, 10);
    // 공백 구분자를 T로 교체 후 파싱
    const iso = raw.trim().replace(' ', 'T');
    // 'Z' 없으면 UTC로 가정하여 +00:00 붙이기
    const isoUtc = iso.endsWith('Z') || iso.includes('+') ? iso : iso + '+00:00';
    const d = new Date(isoUtc);
    if (isNaN(d.getTime())) return raw.substring(0, 10); // 파싱 실패 시 날짜만 반환
    // UTC → KST (+9h)
    const kst = new Date(d.getTime() + 9 * 60 * 60 * 1000);
    const yy = kst.getUTCFullYear();
    const mo = String(kst.getUTCMonth() + 1).padStart(2, '0');
    const dd = String(kst.getUTCDate()).padStart(2, '0');
    const hh = String(kst.getUTCHours()).padStart(2, '0');
    const mm = String(kst.getUTCMinutes()).padStart(2, '0');
    return `${yy}-${mo}-${dd} ${hh}:${mm}`;
  } catch (_) {
    return raw.substring(0, 10);
  }
}

// ─── GPS 기반 날씨 자동 입력 ─────────────────────────────────────────────────
// Open-Meteo API (무료, API 키 불필요) → 현재 날씨 데이터 반환
// 반환: { weather: '맑음', temperature: 22, humidity: 55, wind_speed: 3.2 } 또는 { error: '...' }
async function _fetchWeatherByGps() {
  return new Promise((resolve) => {
    if (!navigator.geolocation) {
      resolve({ error: 'GPS 미지원 기기' }); return;
    }
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude: lat, longitude: lon } = pos.coords;
        try {
          const url = `https://api.open-meteo.com/v1/forecast`
            + `?latitude=${lat.toFixed(5)}&longitude=${lon.toFixed(5)}`
            + `&current=temperature_2m,relative_humidity_2m,wind_speed_10m,weather_code`
            + `&wind_speed_unit=ms&timezone=Asia%2FSeoul`;
          const res = await fetch(url);
          if (!res.ok) throw new Error('API 오류 ' + res.status);
          const d = await res.json();
          const c = d.current || {};
          // WMO weather_code → 한국어 날씨 문자열 매핑
          const code = c.weather_code ?? 0;
          let weather = '맑음';
          if (code === 0)                               weather = '맑음';
          else if (code <= 2)                           weather = '맑음';
          else if (code === 3)                          weather = '흐림';
          else if (code >= 45 && code <= 48)            weather = '흐림';   // 안개
          else if (code >= 51 && code <= 57)            weather = '흐림';   // 이슬비
          else if (code >= 61 && code <= 67)            weather = '비';
          else if (code >= 71 && code <= 77)            weather = '눈';
          else if (code >= 80 && code <= 82)            weather = '비';     // 소나기
          else if (code === 85 || code === 86)          weather = '눈';
          else if (code >= 95 && code <= 99)            weather = '비';     // 뇌우
          // 풍속 10m/s 이상이면 강풍 우선 표기
          const wind = c.wind_speed_10m ?? 0;
          if (wind >= 10 && weather === '맑음') weather = '강풍';
          else if (wind >= 14)                  weather = '강풍';
          resolve({
            weather,
            temperature: Math.round(c.temperature_2m ?? 0),
            humidity:    Math.round(c.relative_humidity_2m ?? 0),
            wind_speed:  Math.round(wind * 10) / 10,
          });
        } catch(e) {
          resolve({ error: '날씨 API 오류: ' + e.message });
        }
      },
      (err) => {
        const msg = err.code === 1 ? 'GPS 권한이 거부되었습니다' : 'GPS 위치를 확인할 수 없습니다';
        resolve({ error: msg });
      },
      { timeout: 8000, maximumAge: 300000, enableHighAccuracy: false }
    );
  });
}

// GPS 날씨 자동 입력 공통 처리: weatherSelectId의 select + tempInputId의 input 채우기
// statusId(옵션): 상태 메시지를 표시할 요소 id
async function _autoFillWeather(weatherSelectId, tempInputId, statusId) {
  // 버튼 로딩 표시 (statusId 요소가 있으면 활용)
  const statusEl = statusId ? document.getElementById(statusId) : null;
  const _setStatus = (msg, isError) => {
    if (!statusEl) return;
    statusEl.textContent = msg;
    statusEl.style.color = isError ? '#EF4444' : '#059669';
    statusEl.style.display = msg ? 'block' : 'none';
  };
  _setStatus('날씨 정보를 가져오는 중...', false);

  const result = await _fetchWeatherByGps();

  if (result.error) {
    _setStatus(result.error, true);
    return false;
  }

  // select에 옵션 값 세팅 (맑음/흐림/비/눈/강풍)
  const weatherSel = document.getElementById(weatherSelectId);
  if (weatherSel) {
    const options = Array.from(weatherSel.options).map(o => o.value || o.text);
    const matched = options.find(o => o === result.weather);
    if (matched) weatherSel.value = matched;
    else {
      // 없으면 가장 가까운 옵션 (비/눈 → 첫 번째 포함 판단)
      weatherSel.value = options[0] || '맑음';
    }
  }

  // 기온 input 세팅
  const tempInp = document.getElementById(tempInputId);
  if (tempInp) tempInp.value = result.temperature;

  // 상태 메시지 (습도·풍속 보조 정보 포함)
  _setStatus(
    `${result.weather} ${result.temperature}°C · 습도 ${result.humidity}% · 풍속 ${result.wind_speed}m/s`,
    false
  );
  return true;
}

// 이미 취득된 GPS 좌표로 날씨만 채우기 (loadTbmGPS 성공 후 좌표 재사용)
async function _autoFillWeatherFromCoords(lat, lon, weatherSelectId, tempInputId, statusId) {
  const statusEl = statusId ? document.getElementById(statusId) : null;
  const _setStatus = (msg, isError) => {
    if (!statusEl) return;
    statusEl.textContent = msg;
    statusEl.style.color = isError ? '#EF4444' : '#059669';
    statusEl.style.display = msg ? 'block' : 'none';
  };
  _setStatus('날씨 정보를 가져오는 중...', false);
  try {
    const url = `https://api.open-meteo.com/v1/forecast`
      + `?latitude=${lat.toFixed(5)}&longitude=${lon.toFixed(5)}`
      + `&current=temperature_2m,relative_humidity_2m,wind_speed_10m,weather_code`
      + `&wind_speed_unit=ms&timezone=Asia%2FSeoul`;
    const res = await fetch(url);
    if (!res.ok) throw new Error('API 오류 ' + res.status);
    const d = await res.json();
    const c = d.current || {};
    const code = c.weather_code ?? 0;
    let weather = '맑음';
    if (code === 0 || code <= 2)               weather = '맑음';
    else if (code === 3)                        weather = '흐림';
    else if (code >= 45 && code <= 57)          weather = '흐림';
    else if (code >= 61 && code <= 67)          weather = '비';
    else if (code >= 71 && code <= 77)          weather = '눈';
    else if (code >= 80 && code <= 82)          weather = '비';
    else if (code === 85 || code === 86)        weather = '눈';
    else if (code >= 95 && code <= 99)          weather = '비';
    const wind = c.wind_speed_10m ?? 0;
    if (wind >= 14) weather = '강풍';
    else if (wind >= 10 && weather === '맑음') weather = '강풍';
    const temp = Math.round(c.temperature_2m ?? 0);
    const hum  = Math.round(c.relative_humidity_2m ?? 0);

    const weatherSel = document.getElementById(weatherSelectId);
    if (weatherSel) {
      const options = Array.from(weatherSel.options).map(o => o.value || o.text);
      const matched = options.find(o => o === weather);
      if (matched) weatherSel.value = matched;
    }
    const tempInp = document.getElementById(tempInputId);
    if (tempInp) tempInp.value = temp;

    _setStatus(`${weather} ${temp}°C · 습도 ${hum}% · 풍속 ${Math.round(wind*10)/10}m/s`, false);
  } catch(e) {
    _setStatus('날씨 정보를 가져올 수 없습니다.', true);
  }
}

// GPS → 주소 변환 (Nominatim 역지오코딩) — 내부 원시 함수
async function getGPSAddress() {
  return new Promise((resolve) => {
    if (!navigator.geolocation) {
      resolve({ address: '', error: 'GPS 미지원' });
      return;
    }
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude: lat, longitude: lon } = pos.coords;
        try {
          // 백엔드 역지오코딩 프록시 호출 (카카오 우선 → Nominatim fallback)
          const res = await API.get(`/geocode/reverse?lat=${lat}&lon=${lon}`);
          const data = res.data || {};
          const address = data.address || `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
          resolve({ address, lat, lon, road_address: data.road_address || '', jibun_address: data.jibun_address || '', source: data.source || '' });
        } catch(e) {
          // API 실패 시 Nominatim 직접 호출 fallback
          try {
            const nomRes = await fetch(
              `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json&accept-language=ko`,
              { headers: { 'User-Agent': 'SafetyNoteApp/1.0' } }
            );
            const data = await nomRes.json();
            const a = data.address || {};
            const parts = [
              a.city || a.province || a.state || '',
              a.borough || a.city_district || a.county || '',
              a.suburb || a.quarter || a.neighbourhood || '',
              a.road || '',
              a.house_number || ''
            ].filter(Boolean);
            const address = parts.join(' ') || data.display_name || `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
            resolve({ address, lat, lon });
          } catch(_) {
            resolve({ address: `${lat.toFixed(5)}, ${lon.toFixed(5)}`, lat, lon });
          }
        }
      },
      (err) => {
        const msg = err.code === 1 ? 'GPS 권한 거부됨' : 'GPS 위치 확인 실패';
        resolve({ address: '', error: msg });
      },
      { timeout: 5000, maximumAge: 60000, enableHighAccuracy: false }
    );
  });
}

// GPS 위치 권한 사전 동의 모달 → 사용자 확인 후 getGPSAddress() 실행
// 권한이 이미 granted면 모달 없이 바로 실행
// 권한이 prompt(미결정) 상태면 커스텀 모달로 먼저 안내
async function getGPSAddressWithConsent() {
  // 권한 상태 먼저 확인 (지원하는 브라우저만)
  let permState = 'prompt';
  try {
    const perm = await navigator.permissions.query({ name: 'geolocation' });
    permState = perm.state; // 'granted' | 'denied' | 'prompt'
  } catch(_) { /* permissions API 미지원 브라우저 — 그냥 진행 */ }

  // 이미 허용됨 또는 거부됨(denied)이면 모달 없이 바로 실행
  if (permState !== 'prompt') return getGPSAddress();

  // prompt 상태 — 커스텀 모달로 먼저 안내 후 사용자 선택
  return new Promise((resolve) => {
    // 기존 모달 중복 방지
    const existing = document.getElementById('gpsConsentModal');
    if (existing) existing.remove();

    const m = document.createElement('div');
    m.className = 'modal-overlay modal-sm';
    m.id = 'gpsConsentModal';
    m.style.zIndex = '99999';
    m.innerHTML = `
    <div class="modal" style="max-width:340px;border-radius:20px;overflow:hidden;padding:0">
      <!-- 헤더 -->
      <div style="background:linear-gradient(135deg,#685182,#D70072);padding:22px 20px 18px;text-align:center">
        <div style="width:60px;height:60px;background:rgba(255,255,255,0.2);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 12px">
          <i class="fas fa-location-dot" style="font-size:28px;color:#fff"></i>
        </div>
        <h3 style="color:#fff;font-size:16px;font-weight:800;margin:0">현재 위치를 사용합니다</h3>
        <p style="color:rgba(255,255,255,0.8);font-size:12px;margin:6px 0 0">TBM / 점검 위치 자동 입력에 필요합니다</p>
      </div>
      <!-- 바디 -->
      <div style="padding:18px 20px 10px;background:#fff">
        <p style="font-size:13px;color:#4B5563;line-height:1.7;margin:0 0 12px">
          작업 위치를 자동으로 기록하기 위해<br>
          <strong style="color:#685182">기기의 현재 위치</strong>를 사용합니다.<br>
          다음 화면에서 <b>허용</b>을 선택해 주세요.
        </p>
        <div style="background:#F9F5FF;border:1px solid #E9D5FF;border-radius:10px;padding:10px 12px">
          <div style="font-size:11px;color:#7C3AED;font-weight:700;margin-bottom:5px">
            <i class="fas fa-shield-halved mr-1"></i>개인정보 안내
          </div>
          <div style="font-size:11px;color:#6B7280;line-height:1.6">
            위치 정보는 <b>작업일지 기록</b> 목적으로만 사용되며<br>
            외부로 전송되지 않습니다.
          </div>
        </div>
        <p style="font-size:11px;color:#9CA3AF;margin:10px 0 0;text-align:center">
          위치를 사용하지 않으려면 취소를 누르세요.
        </p>
      </div>
      <!-- 푸터 -->
      <div style="padding:12px 20px 20px;background:#fff;display:flex;gap:8px">
        <button id="gpsConsentCancel"
          style="flex:1;padding:11px;border:1.5px solid #D8D0DC;border-radius:10px;background:#fff;color:#685182;font-size:13px;font-weight:600;cursor:pointer">
          취소
        </button>
        <button id="gpsConsentAllow"
          style="flex:2;padding:11px;border:none;border-radius:10px;background:linear-gradient(135deg,#685182,#D70072);color:#fff;font-size:13px;font-weight:700;cursor:pointer">
          <i class="fas fa-location-arrow mr-1"></i>위치 사용 허용
        </button>
      </div>
    </div>`;

    document.body.appendChild(m);

    document.getElementById('gpsConsentCancel').addEventListener('click', () => {
      m.remove();
      resolve({ address: '', error: 'GPS 권한 거부됨' });
    });
    document.getElementById('gpsConsentAllow').addEventListener('click', () => {
      m.remove();
      resolve(getGPSAddress()); // 브라우저 기본 권한 팝업은 이제 사용자가 맥락을 알고 있음
    });
  });
}

// ─── 공통 GPS 상태 UI 헬퍼 ───────────────────────────────────
