// 가입신청 역할 드롭다운 변경 핸들러
function _selectSrRole(roleValue) {
  const d = SR_ROLE_DISPLAY[roleValue];
  if (!d) return;
  // 역할 안내 메시지 업데이트
  const note = document.getElementById('srRoleNote');
  if (note) {
    note.style.background = d.bg;
    note.style.color = d.color;
    note.innerHTML = `<i class="fas ${d.icon} mr-1"></i> ${d.desc}`;
  }
  // 직책 필드 자동세팅
  _applyPositionField(roleValue, 'srPosition', '');
  // 부서 자동입력 (빈 값일 때만)
  const deptEl = document.getElementById('srDept');
  if (deptEl && !deptEl.value) {
    if (roleValue === 'worker' || roleValue === 'lgu_plus') deptEl.value = '';
    else if (roleValue === 'sysadmin') deptEl.value = '';
    else deptEl.value = '사무직';
  }
}

// 주민번호 미리보기 업데이트
function _updateIdPreview() {
  const front = document.getElementById('srIdFront')?.value || '';
  const gender = document.getElementById('srIdGender')?.value || '';
  const preview = document.getElementById('srIdPreview');
  if (!preview) return;
  if (front.length === 6 && gender.length === 1) {
    const y = parseInt(front.substring(0,2));
    const m = parseInt(front.substring(2,4));
    const d = parseInt(front.substring(4,6));
    const g = parseInt(gender);
    let century = (g === 1 || g === 2) ? 1900 : 2000;
    const fullYear = century + y;
    const now = new Date();
    const age = now.getFullYear() - fullYear - (
      now.getMonth() + 1 < m || (now.getMonth() + 1 === m && now.getDate() < d) ? 1 : 0
    );
    const gLabel = (g === 1 || g === 3) ? '남성' : '여성';
    preview.innerHTML = `<i class="fas fa-check-circle mr-1" style="color:#059669"></i>
      <span style="color:#059669;font-weight:600">${fullYear}년 ${m}월 ${d}일 (${gLabel}) · 만 ${age}세</span>`;
  } else if (front.length > 0 || gender.length > 0) {
    preview.innerHTML = `<span style="color:#9CA3AF">생년월일 6자리와 성별코드 1자리를 입력하세요</span>`;
  } else {
    preview.innerHTML = '';
  }
}

// 가입신청 제출 버튼 활성화 상태 업데이트
function _updateSrSubmitBtn() {
  const privacy  = document.getElementById('srPrivacyCheck')?.checked;
  const security = document.getElementById('srSecurityCheck')?.checked;
  const location = document.getElementById('srLocationCheck')?.checked;
  const btn = document.getElementById('srSubmitBtn');
  const allCheck = document.getElementById('srAllCheck');
  if (!btn) return;
  const allAgreed = privacy && security && location;
  if (allCheck) allCheck.checked = allAgreed;
  if (allAgreed) {
    btn.disabled = false;
    btn.style.background = '#685182';
    btn.style.borderColor = '#685182';
    btn.style.cursor = 'pointer';
  } else {
    btn.disabled = true;
    btn.style.background = '#9CA3AF';
    btn.style.borderColor = '#9CA3AF';
    btn.style.cursor = 'not-allowed';
  }
}

// 전체 동의 토글
function _toggleSrAllCheck(checkbox) {
  const checked = checkbox.checked;
  const privacyCheck  = document.getElementById('srPrivacyCheck');
  const securityCheck = document.getElementById('srSecurityCheck');
  const locationCheck = document.getElementById('srLocationCheck');
  if (privacyCheck)  privacyCheck.checked  = checked;
  if (securityCheck) securityCheck.checked = checked;
  if (locationCheck) locationCheck.checked = checked;
  _updateSrSubmitBtn();
}

async function submitSelfRegister() {
  // 동의 검증
  const privacyOk  = document.getElementById('srPrivacyCheck')?.checked;
  const securityOk = document.getElementById('srSecurityCheck')?.checked;
  const locationOk = document.getElementById('srLocationCheck')?.checked;
  if (!privacyOk || !securityOk || !locationOk) {
    toast('모든 필수 동의 사항(개인정보·보안서약·위치정보)에 동의해야 가입 신청이 가능합니다.', 'error'); return;
  }

  // 주민번호 앞자리 검증
  const idFront  = document.getElementById('srIdFront')?.value.trim() || '';
  const idGender = document.getElementById('srIdGender')?.value.trim() || '';
  if (!idFront || idFront.length !== 6 || !/^\d{6}$/.test(idFront)) {
    toast('생년월일 6자리를 올바르게 입력하세요. (예: 901231)', 'error'); return;
  }
  if (!idGender || !/^[1-4]$/.test(idGender)) {
    toast('성별코드를 입력하세요. (1:1900년대 남, 2:1900년대 여, 3:2000년대 남, 4:2000년대 여)', 'error'); return;
  }

  const srUiRole = document.getElementById('srRole')?.value || 'worker';
  const srDbRole = uiRoleToDb(srUiRole);   // worker→worker, site_rep/safety→supervisor
  // 역할 선택 필수 검증
  if (!srUiRole) {
    toast('역할을 선택하세요.', 'error'); return;
  }
  // 직책: 역할별 고정값 또는 사용자가 선택한 값
  // dbRoleToUi 복원 키 유지: safety→'안전관리자', site_rep→'현장대리인', lgu_plus→'LGU+', sysadmin→'시스템관리자'
  const srPositionEl = document.getElementById('srPosition');
  let srPosition = srPositionEl?.value || '';
  if (srUiRole === 'lgu_plus') {
    srPosition = 'LGU+';
  } else if (srUiRole === 'sysadmin') {
    srPosition = '시스템관리자';
  } else if (srUiRole === 'safety' && !srPosition) {
    srPosition = '안전관리자';
  } else if (srUiRole === 'site_rep') {
    srPosition = '현장대리인';   // dbRoleToUi 복원 키 고정
  } else if (srUiRole === 'ceo') {
    srPosition = '대표이사';
  }
  const data = {
    username:          document.getElementById('srUsername').value.trim(),
    password:          document.getElementById('srPassword').value,
    name:              document.getElementById('srName').value.trim(),
    grade:             document.getElementById('srGrade')?.value.trim() || '',
    role:              srDbRole,
    ui_role:           srUiRole,
    company:           document.getElementById('srCompany').value.trim(),
    department:        document.getElementById('srDept').value.trim(),
    position:          srPosition,
    phone:             document.getElementById('srPhone').value.trim(),
    blood_type:        document.getElementById('srBloodType').value,
    emergency_contact: document.getElementById('srEmergency').value.trim(),
    id_number:         idFront + idGender,
    privacy_agreed:    true,
    security_agreed:   true,
    location_agreed:   true,
  };
  if (!data.username || !data.password || !data.name) {
    toast('아이디, 비밀번호, 이름은 필수입니다.', 'error'); return;
  }
  if (data.password.length < 4) {
    toast('비밀번호는 4자 이상으로 설정하세요.', 'error'); return;
  }
  try {
    const btn = document.getElementById('srSubmitBtn');
    if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin mr-1"></i> 신청 중...'; }
    await API.post('/auth/self-register', data);
    document.querySelector('.modal-overlay')?.remove();
    // 성공 알림 (모달)
    const ok = document.createElement('div');
    ok.className = 'modal-overlay modal-sm';
    ok.innerHTML = `
    <div class="modal" style="max-width:400px;text-align:center">
      <div class="modal-body py-8">
        <i class="fas fa-check-circle text-5xl mb-4 block" style="color:#059669"></i>
        <h3 class="font-black text-lg text-gray-900 mb-2">가입 신청 완료!</h3>
        <p class="text-sm text-gray-500 mb-1">관리자 승인 후 로그인할 수 있습니다.</p>
        <p class="text-xs text-gray-400">승인 여부는 담당자에게 문의하세요.</p>
        <div class="mt-3 p-2 rounded-lg text-xs text-left" style="background:#F0FDF4;color:#166534">
          <i class="fas fa-lock mr-1"></i> 귀하의 개인정보는 개인정보보호법에 따라 안전하게 보호됩니다.
        </div>
      </div>
      <div class="modal-footer">
        <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-primary w-full justify-center">확인</button>
      </div>
    </div>`;
    document.body.appendChild(ok);
  } catch(e) {
    toast(e.response?.data?.error || '가입 신청 실패', 'error');
    const btn = document.getElementById('srSubmitBtn');
    if (btn) {
      btn.disabled = false;
      btn.style.background = '#685182';
      btn.style.borderColor = '#685182';
      btn.innerHTML = '<i class="fas fa-paper-plane mr-1"></i> 가입 신청';
    }
  }
}

async function doLogin() {
  const usernameEl = document.getElementById('loginUsername');
  const passwordEl = document.getElementById('loginPassword');
  const loginBtn   = document.getElementById('loginBtn');
  const btnIcon    = document.getElementById('loginBtnIcon');
  const btnText    = document.getElementById('loginBtnText');

  const username = usernameEl?.value?.trim() || '';
  const password = passwordEl?.value || '';
  if (!username || !password) { toast('아이디와 비밀번호를 입력하세요.', 'error'); return; }

  // 로딩 상태 시작 (중복 클릭 방지)
  if (loginBtn) { loginBtn.disabled = true; loginBtn.style.opacity = '0.8'; }
  if (btnIcon) btnIcon.className = 'fas fa-spinner fa-spin';
  if (btnText) btnText.textContent = ' 로그인 중...';

  try {
    const res = await API.post('/auth/login', { username, password });
    // ✅ 로그인 성공 → 아이디 저장
    localStorage.setItem('sn-last-username', username);
    localStorage.setItem('token', res.data.token);
    currentUser = res.data.user;
    // ── [BUG-009] JS→Java 브릿지: SharedPreferences 에 JWT 저장 ────────────
    // Capacitor WebView 환경에서 MyFirebaseMessagingService 가
    // SharedPreferences("SafetyNotePrefs")["authToken"] 을 읽어 FCM 토큰 등록.
    // localStorage 는 WebView 전용이므로 별도 브릿지 호출 필수.
    if (window.SafetyNoteApp && typeof window.SafetyNoteApp.saveAuthToken === 'function') {
      try { window.SafetyNoteApp.saveAuthToken(res.data.token); } catch(e) { /* ignore */ }
    }
    toast(`${currentUser.name}님 환영합니다!`);
    // [v0.142 LGU+] LGU+ 역할이면 메뉴 설정 사전 로드
    var loginUiRole = dbRoleToUi(currentUser.role, currentUser.position, currentUser.sub_role);
    if (loginUiRole === 'lgu_plus' || currentUser.role === 'lgu_plus' || currentUser.role === 'lgu') { // [FEAT-048]
      await loadLguSettings().catch(function(){});
    }
    renderApp();
  } catch (e) {
    toast(e.response?.data?.error || '로그인 실패', 'error');
    // ❌ 실패 시 버튼 복구 + 비밀번호 필드 흔들기
    if (loginBtn) { loginBtn.disabled = false; loginBtn.style.opacity = ''; }
    if (btnIcon) btnIcon.className = 'fas fa-sign-in-alt';
    if (btnText) btnText.textContent = ' 로그인';
    // 비밀번호 필드 흔들기 애니메이션
    if (passwordEl) {
      passwordEl.style.transition = 'transform 0.1s';
      let shake = 0;
      const shakeInterval = setInterval(() => {
        passwordEl.style.transform = `translateX(${shake % 2 === 0 ? '6px' : '-6px'})`;
        shake++;
        if (shake > 5) {
          clearInterval(shakeInterval);
          passwordEl.style.transform = '';
          passwordEl.focus();
          passwordEl.select();
        }
      }, 60);
    }
  }
}

function doLogout() {
  stopSseClient();
  if (_signCountTimer) { clearInterval(_signCountTimer); _signCountTimer = null; }
  _notifHistory.length = 0;
  _unreadCount = 0;
  _notifPanelOpen = false;
  localStorage.removeItem('token');
  // ── [BUG-009] JS→Java 브릿지: SharedPreferences 에서 JWT 삭제 ──────────
  if (window.SafetyNoteApp && typeof window.SafetyNoteApp.clearAuthToken === 'function') {
    try { window.SafetyNoteApp.clearAuthToken(); } catch(e) { /* ignore */ }
  }
  currentUser = null;
  renderLogin();
}

// ======= [v0.142 LGU+] LGU+ 설정 로드 헬퍼 =======
// 앱 초기화 또는 관리자 설정 변경 후 호출
// window.__lguMenuSettings 에 system_settings lgu_* 값을 캐시
// [BUG-082] /admin/settings 는 admin 전용(403) → LGU+ 역할이 읽을 수 없어 메뉴가 숨겨지는 버그 수정.
//           별도 경량 API /api/lgu-menu-settings 로 전환 (로그인된 모든 역할 허용).
//           관리자는 기존 /admin/settings 도 호출하여 전체 설정을 덮어씀.
async function loadLguSettings() {
  try {
    // ① 모든 역할: lgu_menu_* 전용 경량 API 호출
    var res = await API.get('/lgu-menu-settings');
    var map = (res.data && res.data.settings) || {};
    window.__lguMenuSettings = Object.assign({}, window.__lguMenuSettings || {}, map);
  } catch(e) {
    // 실패 시 기본값 유지 (빈 객체라도 보장)
    if (!window.__lguMenuSettings) window.__lguMenuSettings = {};
  }
  try {
    // ② admin 역할만 추가로 전체 설정 로드 (덮어쓰기)
    if (currentUser && currentUser.role === 'admin') {
      var adminRes = await API.get('/admin/settings');
      var adminSettings = (adminRes.data && adminRes.data.settings) || [];
      var adminMap = {};
      adminSettings.forEach(function(s) { if (s.key && s.key.startsWith('lgu_')) adminMap[s.key] = s.value; });
      window.__lguMenuSettings = Object.assign(window.__lguMenuSettings || {}, adminMap);
    }
  } catch(e) { /* admin 전용 API 실패 무시 */ }
}

// ======= 앱 레이아웃 =======
function renderApp() {
  const myUiRoleForLayout = dbRoleToUi(currentUser.role, currentUser.position, currentUser.sub_role);
  const isWorker   = currentUser.role === 'worker' && myUiRoleForLayout !== 'lgu_plus' && currentUser.role !== 'lgu_plus'; // [FEAT-048]
  const isLguPlus  = myUiRoleForLayout === 'lgu_plus';

  // LGU+ 역할: 기본 허용 메뉴 (system_settings lgu_menu_* 설정에 따라 동적 변경)
  // 기본값: 작업현황(dashboard), 현장점검(inspections), 현장위치지도(site-map)
  var LGU_PLUS_ALLOWED_MENUS = ['dashboard', 'inspections', 'site-map', 'my-profile'];
  if (isLguPlus && window.__lguMenuSettings) {
    // 서버 설정 기반 동적 메뉴 권한 (loadLguSettings()로 로드된 값 사용)
    var lguDyn = [];
    if (window.__lguMenuSettings['lgu_menu_dashboard']     === '1') lguDyn.push('dashboard');
    if (window.__lguMenuSettings['lgu_menu_inspections']   === '1') lguDyn.push('inspections');
    if (window.__lguMenuSettings['lgu_menu_site_map']      === '1') lguDyn.push('site-map');
    if (window.__lguMenuSettings['lgu_menu_constructions'] === '1') lguDyn.push('constructions');
    if (window.__lguMenuSettings['lgu_menu_tasks']         === '1') lguDyn.push('tasks');
    if (window.__lguMenuSettings['lgu_menu_stats']         === '1') lguDyn.push('stats-task', 'stats-inspection', 'stats-worker-safety');
    lguDyn.push('my-profile'); // 내 계정은 항상 허용
    if (lguDyn.length > 1) LGU_PLUS_ALLOWED_MENUS = lguDyn;
  }

  // permissions 기반 메뉴 필터링 함수
  // null이면 전체 허용, 배열이면 해당 id만 허용
  // lgu_plus는 LGU_PLUS_ALLOWED_MENUS를 permissions로 사용
  const userPerms = isLguPlus
    ? LGU_PLUS_ALLOWED_MENUS
    : (currentUser.permissions || null); // null = 전체허용
  const canAccess = (menuId) => !userPerms || userPerms.includes(menuId);

  // 부모 메뉴(children 보유)는 허용된 자식이 하나라도 있으면 표시
  const filterMenu = (items) => items
    .map(item => {
      if (!item.children) return canAccess(item.id) ? item : null;
      const filteredChildren = item.children.filter(c => canAccess(c.id));
      return filteredChildren.length > 0 ? { ...item, children: filteredChildren } : null;
    })
    .filter(Boolean);

  // ── Option C: 아이콘 레일 + 플라이아웃 ─────────────────────────────────────
  // 관리자/감독자 메뉴 그룹 정의 (5개 그룹)
  const isSysAdmin = dbRoleToUi(currentUser.role, currentUser.position, currentUser.sub_role) === 'sysadmin';
  const allManagerGroups = [
    {
      id: 'work', icon: 'fas fa-hard-hat', label: '현장작업', color: '#60a5fa',
      items: [
        { id:'dashboard',     icon:'fas fa-tasks',           label:'작업현황' },
        { id:'tasks',         icon:'fas fa-clipboard-list',  label:'작업관리' },
        { id:'constructions', icon:'fas fa-hard-hat',        label:'공사현황' },
        { id:'site-map',      icon:'fas fa-map-marked-alt',  label:'현장위치 지도' },
      ]
    },
    {
      id: 'safety', icon: 'fas fa-shield-alt', label: '안전점검', color: '#f87171',
      items: [
        { id:'inspections', icon:'fas fa-search',               label:'현장점검' },
        { id:'hazards',     icon:'fas fa-exclamation-triangle', label:'위험신고' },
        { id:'risk', icon:'fas fa-shield-alt', label:'위험성평가', children: [
          { id:'risk-periodic', icon:'fas fa-calendar-check', label:'정기 위험성평가' },
          { id:'risk-adhoc',    icon:'fas fa-bolt',           label:'수시 위험성평가' },
          { id:'risk-items',    icon:'fas fa-list-check',     label:'분류별 항목 관리' },
        ]},
      ]
    },
    {
      id: 'edu', icon: 'fas fa-clipboard-check', label: '안전관리', color: '#a78bfa',
      items: [
        { id:'stats', icon:'fas fa-chart-bar', label:'안전현황', children: [
          { id:'stats-task',          icon:'fas fa-tasks',          label:'작업통계' },
          { id:'stats-inspection',    icon:'fas fa-clipboard-check',label:'현장점검 통계' },
          { id:'stats-worker-safety', icon:'fas fa-user-shield',    label:'근로자 안전준수 현황' },
          { id:'work-stops',          icon:'fas fa-hand-paper',     label:'작업중지현황' },
        ]},
        { id:'edu', icon:'fas fa-graduation-cap', label:'안전교육', children: [
          { id:'edu-periodic',   icon:'fas fa-chalkboard-teacher', label:'정기안전교육' },
          { id:'edu-hire',       icon:'fas fa-user-plus',          label:'채용시안전교육' },
          { id:'edu-job-change', icon:'fas fa-exchange-alt',       label:'작업내용변경시교육' },
          { id:'edu-special',    icon:'fas fa-hard-hat',           label:'특별안전교육' },
          { id:'edu-supervisor', icon:'fas fa-user-tie',           label:'관리감독자교육' },
          { id:'edu-stats',      icon:'fas fa-chart-bar',          label:'교육현황통계' },
        ]},
        { id:'sign-requests', icon:'fas fa-pen-fancy', label:'서명요청' },
      ]
    },
    {
      id: 'volume', icon: 'fas fa-chart-line', label: '현장공량', color: '#34d399',
      items: [
        { id:'volume-stats',  icon:'fas fa-chart-bar',      label:'물량통계' },
        { id:'report-write',  icon:'fas fa-pen-to-square',  label:'작업일보 작성' },
        { id:'field-report',  icon:'fas fa-list-alt',       label:'공량내역' },
        { id:'cable-detail',  icon:'fas fa-cable-car',      label:'광케이블 현황' },
        ...(isSysAdmin ? [{ id:'unit-price', icon:'fas fa-tags', label:'단가 관리' }] : []),
      ]
    },
    {
      id: 'mgmt', icon: 'fas fa-cogs', label: '관리/설정', color: '#fbbf24',
      items: [
        { id:'personnel', icon:'fas fa-users', label:'사용자관리', children: [
          { id:'users',           icon:'fas fa-id-badge',     label:'업무중사용자' },
          { id:'suspended-users', icon:'fas fa-user-slash',   label:'업무중지사용자' },
          { id:'teams',           icon:'fas fa-people-group', label:'현장팀관리' },
          ...(isSysAdmin ? [{ id:'sys-user-mgmt', icon:'fas fa-user-shield', label:'계정관리' }] : []),
        ]},
        { id:'my-profile',     icon:'fas fa-user-cog',      label:'내 계정' },
        ...(currentUser.role === 'admin' || currentUser.role === 'supervisor' ? [
          { id:'admin-settings', icon:'fas fa-cogs',          label:'시스템 설정' },
          { id:'legal-notices',  icon:'fas fa-balance-scale', label:'법령안내 관리' },
        ] : []),
      ]
    },
  ];

  // 근로자 그룹 정의
  const workerGroups = [
    {
      id: 'mytask', icon: 'fas fa-tasks', label: '내 작업', color: '#60a5fa',
      items: [
        { id:'my-tasks',    icon:'fas fa-tasks',          label:'내 작업' },
        { id:'report-write',icon:'fas fa-pen-to-square',  label:'작업일보 작성' },
        { id:'my-stats',    icon:'fas fa-chart-bar',      label:'나의작업현황' },
      ]
    },
    {
      id: 'wsafety', icon: 'fas fa-shield-alt', label: '안전', color: '#f87171',
      items: [
        { id:'hazard-report', icon:'fas fa-exclamation-triangle', label:'위험신고' },
        { id:'sign-requests', icon:'fas fa-pen-fancy',            label:'서명요청' },
      ]
    },
    {
      id: 'wme', icon: 'fas fa-user-cog', label: '내 정보', color: '#fbbf24',
      items: [
        { id:'my-profile', icon:'fas fa-user-cog', label:'내 계정' },
      ]
    },
  ];

  // LGU+ 그룹 정의 (3그룹 구조: 현장작업 / 안전점검 / 통계·정보)
  // 각 그룹은 활성 메뉴가 하나도 없으면 아이콘 레일에서 자동 제거됨
  const lguGroups = (() => {
    var lguSettings = window.__lguMenuSettings || {};
    var isOn = function(key, defaultOn) {
      var val = lguSettings[key];
      return val !== undefined ? val === '1' : (defaultOn === true);
    };

    // ── 그룹①: 현장작업 (작업현황·작업관리·공사현황·현장위치지도) ──────────────
    var workItems = [];
    if (isOn('lgu_menu_dashboard',     true))  workItems.push({ id:'dashboard',     icon:'fas fa-tasks',           label:'작업현황' });
    if (isOn('lgu_menu_tasks',         true))  workItems.push({ id:'tasks',         icon:'fas fa-clipboard-list',  label:'작업관리' });
    if (isOn('lgu_menu_constructions', false)) workItems.push({ id:'constructions', icon:'fas fa-hard-hat',        label:'공사현황' });
    if (isOn('lgu_menu_site_map',      true))  workItems.push({ id:'site-map',      icon:'fas fa-map-marked-alt',  label:'현장위치 지도' });

    // ── 그룹②: 안전점검 (현장점검) ──────────────────────────────────────────────
    var safetyItems = [];
    if (isOn('lgu_menu_inspections', true)) safetyItems.push({ id:'inspections', icon:'fas fa-search', label:'현장점검' });

    // ── 그룹③: 통계·정보 (안전현황 통계 서브메뉴 + 내 계정) ──────────────────────
    var infoItems = [];
    if (isOn('lgu_menu_stats', true)) {
      infoItems.push({ id:'stats', icon:'fas fa-chart-bar', label:'안전현황', children: [
        { id:'stats-task',          icon:'fas fa-tasks',           label:'작업통계' },
        { id:'stats-inspection',    icon:'fas fa-clipboard-check', label:'현장점검 통계' },
        { id:'stats-worker-safety', icon:'fas fa-user-shield',     label:'근로자 안전준수 현황' },
      ]});
    }
    infoItems.push({ id:'my-profile', icon:'fas fa-user-cog', label:'내 계정' }); // 항상 표시

    // 활성 메뉴가 있는 그룹만 레일에 노출
    var groups = [];
    if (workItems.length > 0)   groups.push({ id:'lgu-work',   icon:'fas fa-hard-hat',    label:'현장작업', color:'#60a5fa', items: workItems   });
    if (safetyItems.length > 0) groups.push({ id:'lgu-safety', icon:'fas fa-shield-alt',  label:'안전점검', color:'#f87171', items: safetyItems });
    groups.push(                             { id:'lgu-info',  icon:'fas fa-chart-bar',   label:'통계·정보', color:'#fbbf24', items: infoItems   });
    return groups;
  })();

  const groups = isLguPlus ? lguGroups : isWorker ? workerGroups : allManagerGroups;

  // 현재 페이지가 속한 그룹 ID 찾기
  const findActiveGroup = (gs, page) => {
    for (const g of gs) {
      for (const item of g.items) {
        if (item.id === page) return g.id;
        if (item.children && item.children.some(c => c.id === page)) return g.id;
      }
    }
    return gs[0]?.id || '';
  };
  const activeGroupId = findActiveGroup(groups, currentPage);

  // ── HTML 빌더 헬퍼 ─────────────────────────────────────
  const buildRailGroups = (gs) => gs.map(g => {
    const isActive = g.id === activeGroupId;
    // 서명요청 배지: 안전관리(edu), 안전(wsafety), LGU+ 안전점검(lgu-safety) 그룹에 표시
    const showBadge = g.id === 'edu' || g.id === 'wsafety' || g.id === 'lgu-safety';
    return `<div class="rail-group-btn${isActive ? ' active' : ''}" 
                 onclick="openFlyout('${g.id}')" 
                 title="${g.label}" id="rail-btn-${g.id}" data-color="${g.color}">
      <i class="${g.icon}" style="color:${isActive ? g.color : ''}"></i>
      <span>${g.label}</span>
      ${showBadge ? `<span class="rail-badge hidden" id="rail-badge-${g.id}">0</span>` : ''}
    </div>`;
  }).join('');

  const buildFlyoutItems = (items, grpColor) => items.map(item => {
    if (item.children) {
      // 서브메뉴 있는 항목
      const hasActive = item.children.some(c => c.id === currentPage);
      const subHtml = item.children.map(c => `
        <div class="flyout-sub-item${c.id === currentPage ? ' active' : ''}"
             onclick="safeNavigateTo('${c.id}')" id="fitem-${c.id}">
          <i class="${c.icon}" style="color:${grpColor}99"></i>
          <span>${c.label}</span>
        </div>`).join('');
      return `
        <div class="flyout-nav-parent${hasActive ? ' open' : ''}" 
             onclick="toggleFlyoutSub('fsub-${item.id}', this)">
          <i class="${item.icon} p-icon" style="color:${grpColor}CC"></i>
          <span style="flex:1">${item.label}</span>
          <i class="fas fa-chevron-down p-arrow"></i>
        </div>
        <div class="flyout-sub${hasActive ? ' open' : ''}" id="fsub-${item.id}">
          ${subHtml}
        </div>`;
    }
    return `<div class="flyout-nav-item${item.id === currentPage ? ' active' : ''}"
                 onclick="safeNavigateTo('${item.id}')" id="fitem-${item.id}">
      <i class="${item.icon}" style="color:${grpColor}CC"></i>
      <span>${item.label}</span>
    </div>`;
  }).join('');

  const buildFlyoutPanels = (gs) => gs.map(g => `
    <div class="flyout-group-panel" id="fpanel-${g.id}" style="display:none;height:100%;flex-direction:column">
      <div class="flyout-header">
        <i class="${g.icon}" style="color:${g.color}"></i>
        <span>${g.label}</span>
      </div>
      <div class="flyout-nav">
        ${buildFlyoutItems(g.items, g.color)}
      </div>
    </div>`).join('');

  // ── 모바일 하단 탭 빌더 ────────────────────────────────
  const buildBottomNav = (gs) => {
    if (gs.length === 1) {
      // LGU+: 단일 그룹 — 주요 페이지 직접 노출
      const g = gs[0];
      const flat = g.items.filter(i => !i.children).slice(0, 4);
      return flat.map(item => `
        <div class="bottom-nav-item${currentPage === item.id ? ' active' : ''}" onclick="safeNavigateTo('${item.id}')">
          <i class="${item.icon}"></i>
          <span>${item.label}</span>
        </div>`).join('');
    }
    // 그룹 탭 (최대 5개)
    return gs.map(g => {
      const isActive = g.id === activeGroupId;
      const showBadge = g.id === 'edu' || g.id === 'wsafety';
      return `<div class="bottom-nav-group${isActive ? ' active' : ''}" 
                   onclick="openFlyout('${g.id}')" id="bnav-${g.id}">
        <i class="${g.icon}" style="${isActive ? `color:var(--t-primary)` : ''}"></i>
        <span>${g.label}</span>
        ${showBadge ? `<span class="bnav-badge" id="bnav-badge-${g.id}">0</span>` : ''}
      </div>`;
    }).join('');
  };

  document.getElementById('app').innerHTML = `
  <!-- Option C: 아이콘 레일 -->
  <div id="icon-rail">
    <div class="rail-brand">
      <img src="/static/app-icon.png" alt="SN">
    </div>
    <div class="rail-groups">
      ${buildRailGroups(groups)}
    </div>
    <div class="rail-footer">
      <div class="rail-footer-btn" onclick="safeNavigateTo('my-profile')" title="내 계정">
        <i class="fas fa-user-circle"></i>
        <span>내계정</span>
      </div>
      <div class="rail-footer-btn rail-logout-btn" onclick="doLogout()" title="로그아웃">
        <i class="fas fa-sign-out-alt"></i>
        <span>로그아웃</span>
      </div>
    </div>
    <!-- FEAT-059: LinkMak 크레딧 — 아이콘 레일 최하단 -->
    <div class="rail-credit" title="Powered by LinkMak Co.">
      <span class="rail-credit-name">LinkMak</span>
      <span class="rail-credit-sub">Co.,Ltd</span>
    </div>
  </div>

  <!-- 플라이아웃 패널 -->
  <div id="flyout-panel">
    ${buildFlyoutPanels(groups)}
  </div>

  <!-- 플라이아웃 오버레이 (바깥 클릭 시 닫기) -->
  <div id="flyout-overlay" onclick="closeFlyout()"></div>

  <!-- 기존 사이드바 (호환성 유지, 숨김) -->
  <div id="sidebar" class="sidebar" style="display:none"></div>
  <div id="sidebar-overlay" class="sidebar-overlay"></div>


  <!-- 메인 콘텐츠 -->
  <div class="main-content">
    <!-- 헤더 -->
    <div class="top-header">
      <div class="flex items-center gap-3">
        <button onclick="toggleSidebar()" class="md:hidden text-white text-xl p-1"><i class="fas fa-bars"></i></button>
        <h2 id="pageTitle" class="font-bold text-base tracking-tight">${getPageTitle(currentPage)}</h2>
      </div>
      <div class="flex items-center gap-3">
        <span class="text-pink-100 text-xs hide-mobile font-medium">${currentUser.name}</span>
        <!-- 테마 선택 버튼 -->
        <button id="theme-toggle-btn" onclick="buildThemePanel()" title="테마 변경"
          class="relative text-white text-base p-1 hover:opacity-80" style="line-height:1">
          <i class="fas fa-palette"></i>
        </button>
        <!-- 알림 벨 버튼 (SSE 실시간 알림) -->
        <button id="notif-bell-btn" onclick="toggleNotifPanel()" title="알림 센터"
          class="relative text-white text-base p-1 hover:opacity-80" style="line-height:1">
          <i class="fas fa-bell"></i>
          <span id="notif-bell-badge" class="hidden absolute -top-1 -right-1 min-w-[16px] h-4 px-0.5 text-center rounded-full text-white font-bold leading-4"
            style="font-size:10px;background:var(--t-badge-bg,#D70072);border:1.5px solid rgba(255,255,255,0.9)">0</span>
        </button>
        <!-- 서명요청 배지 버튼 -->
        <button id="sign-req-badge-btn" onclick="safeNavigateTo('sign-requests')" title="서명요청"
          class="relative text-white text-base p-1 hover:opacity-80" style="line-height:1">
          <i class="fas fa-pen-fancy"></i>
          <span id="sign-req-count" class="hidden absolute -top-1 -right-1 min-w-[16px] h-4 px-0.5 text-center rounded-full text-white font-bold leading-4"
            style="font-size:10px;background:var(--t-badge-bg,#D70072);border:1.5px solid rgba(255,255,255,0.9)">0</span>
        </button>
        <div class="w-7 h-7 rounded-full bg-white bg-opacity-20 flex items-center justify-center text-white text-xs hide-mobile">
          <i class="fas fa-user"></i>
        </div>
        <button onclick="doLogout()" class="text-pink-100 hover:text-white text-sm ml-1" title="로그아웃">
          <i class="fas fa-sign-out-alt"></i>
        </button>
      </div>
    </div>

    <!-- 페이지 콘텐츠 -->
    <div id="page-content" class="p-4"></div>
  </div>

  <!-- FEAT-059: LinkMak 크레딧 바 — 메인 콘텐츠 하단 고정 (데스크톱) -->
  <div id="app-credit-bar">
    <span class="acb-text">Powered by</span>
    <div class="acb-sep"></div>
    <span class="acb-brand">LinkMak Co., Ltd.</span>
  </div>

  <!-- 하단 네비게이션 (모바일) — 그룹 탭 -->
  <div class="bottom-nav md:hidden">
    ${buildBottomNav(groups)}
  </div>`;

  // buildLayout에서 생성한 그룹 데이터를 전역에 등록 (syncFlyoutActive에서 사용)
  window._flyoutGroups = groups;

  navigateTo(currentPage);
  // 로그인 후 서명 요청 카운트 폴링 시작
  startSignCountPoller();
  // SSE 실시간 알림 클라이언트 시작
  startSseClient();
  // DB에 저장된 미읽음 알림 로드 (오프라인 수신분 포함)
  _loadUnreadNotificationsFromDB();
  // 저장된 테마 적용 (버튼 아이콘 색 포함)
  applyTheme(localStorage.getItem('sn-theme') || 'default');
  // 저장된 사용자 설정 적용 (글자 크기 등)
  applyUserPrefs();
}

// 금일예정작업 바로가기 — dashboard로 이동 후 금일 예정 작업 카드로 스크롤
// ─────────────────────────────────────────────────────────────────────────────
// ─── SSE 실시간 알림 시스템 ───────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────────────────────
let _sseSource = null;
let _sseRetryDelay = 2000;
let _sseRetryTimer = null;
const _notifHistory = [];   // 최근 알림 목록 (최대 20건)
let _unreadCount = 0;
let _notifPanelOpen = false;

/**
 * 로그인 직후 DB에 저장된 미읽음 알림을 가져와 히스토리/배지에 반영.
 * SSE가 끊긴 동안 발생한 알림(정산요청 등)을 놓치지 않도록 한다.
 */
async function _loadUnreadNotificationsFromDB() {
  try {
    const res = await API.get('/notifications');
    const rows = res.data || [];
    // 기존 히스토리 중복 방지 (SSE로 이미 수신된 항목은 _id가 없으므로 ref 기준으로 dedup)
    const existingIds = new Set(_notifHistory.filter(n => n._dbId).map(n => n._dbId));
    let added = 0;
    for (const row of rows) {
      if (existingIds.has(row.id)) continue;
      const notif = {
        _dbId:   row.id,
        _id:     row.id + '_db',
        type:    row.type,
        title:   row.title,
        message: row.message,
        conId:   row.ref_type === 'construction' ? row.ref_id : undefined,
        taskId:  row.ref_type === 'task' ? row.ref_id : undefined,
        ref_id:  row.ref_id,
        ref_type: row.ref_type,
        ts:      new Date(row.created_at).getTime(),
        read:    row.is_read === 1,
      };
      _notifHistory.push(notif);
      if (!notif.read) { _unreadCount++; added++; }
    }
    // 최신순 정렬 (SSE 수신분 + DB 로드분 혼재)
    _notifHistory.sort((a, b) => (b.ts || 0) - (a.ts || 0));
    if (_notifHistory.length > 50) _notifHistory.splice(50);
    if (added > 0) updateNotifBadge();
  } catch (_) {
    // 알림 로드 실패는 조용히 무시
  }
}

/** SSE 연결 시작 — 로그인 후 renderApp() 에서 호출 */
function startSseClient() {
  if (_sseSource) { _sseSource.close(); _sseSource = null; }
  if (_sseRetryTimer) { clearTimeout(_sseRetryTimer); _sseRetryTimer = null; }
  const token = localStorage.getItem('token');
  if (!token) return;

  // EventSource 는 커스텀 헤더 불가 → 쿼리스트링으로 토큰 전달
  _sseSource = new EventSource(`/api/events?token=${encodeURIComponent(token)}`);

  _sseSource.onopen = () => {
    _sseRetryDelay = 2000;   // 연결 성공 시 지수 백오프 초기화
  };

  _sseSource.onmessage = (e) => {
    try {
      const data = JSON.parse(e.data);
      if (data.type === 'connected') return; // welcome 이벤트 무시
      handleSseNotification(data);
    } catch (_) {}
  };

  _sseSource.onerror = () => {
    if (_sseSource) { _sseSource.close(); _sseSource = null; }
    // 지수 백오프 재연결 (최대 30초)
    _sseRetryTimer = setTimeout(() => {
      _sseRetryDelay = Math.min(_sseRetryDelay * 2, 30000);
      startSseClient();
    }, _sseRetryDelay);
  };
}

/** SSE 연결 종료 — 로그아웃 시 호출 */
function stopSseClient() {
  if (_sseSource) { _sseSource.close(); _sseSource = null; }
  if (_sseRetryTimer) { clearTimeout(_sseRetryTimer); _sseRetryTimer = null; }
}

/** 수신한 SSE 이벤트 처리 */
function handleSseNotification(data) {
  // 1. 히스토리에 추가 (최대 20건)
  const notif = { ...data, read: false, _id: Date.now() + Math.random() };
  _notifHistory.unshift(notif);
  if (_notifHistory.length > 20) _notifHistory.pop();
  _unreadCount++;

  // 2. 헤더 알림 배지 업데이트
  updateNotifBadge();

  // 3. 토스트 표시
  showNotifToast(data);

  // 4. 서명 요청이면 카운트 즉시 갱신
  if (data.type === 'sign_request') refreshSignRequestCount();

  // 5. 패널이 열려 있으면 패널 내용 갱신
  if (_notifPanelOpen) renderNotifPanel();
}

/** 알림 타입별 메타 정보 */
function _notifMeta(type) {
  const map = {
    sign_request:        { icon: 'fa-pen-fancy',           color: '#D70072', label: '서명 요청' },
    sign_done:           { icon: 'fa-check-circle',         color: '#22c55e', label: '서명 완료' },
    sign_rejected:       { icon: 'fa-times-circle',         color: '#ef4444', label: '서명 거부' },
    tbm_sign:            { icon: 'fa-clipboard-check',      color: '#685182', label: 'TBM 서명' },
    tbm_risk_sign:       { icon: 'fa-shield-alt',           color: '#685182', label: '위험성평가 서명' },
    edu_sign:            { icon: 'fa-graduation-cap',       color: '#685182', label: '교육 서명' },
    task_created:        { icon: 'fa-plus-circle',          color: '#3b82f6', label: '작업 등록' },
    task_assigned:       { icon: 'fa-user-check',           color: '#3b82f6', label: '작업 배정' },
    task_status:         { icon: 'fa-exchange-alt',         color: '#f59e0b', label: '작업 상태 변경' },
    task_status_manager: { icon: 'fa-bell-concierge',       color: '#7c3aed', label: '작업 상태 변경' },
    task_status_change:  { icon: 'fa-bell-concierge',       color: '#7c3aed', label: '작업 상태 변경' },
    hazard_report:       { icon: 'fa-exclamation-triangle', color: '#ef4444', label: '위험 신고' },
    settlement_request:  { icon: 'fa-receipt',              color: '#4338CA', label: '정산요청' },
  };
  return map[type] || { icon: 'fa-bell', color: '#685182', label: '알림' };
}

/** 우상단 슬라이드-인 토스트 (알림 전용, 기존 toast()와 별개) */
function showNotifToast(data) {
  const meta = _notifMeta(data.type);
  const msg = data.message || `${meta.label} 알림이 도착했습니다.`;

  const el = document.createElement('div');
  el.style.cssText = `
    position:fixed; top:64px; right:12px; z-index:99999;
    max-width:320px; min-width:220px;
    background:#fff; border-radius:12px;
    box-shadow: 0 4px 20px rgba(0,0,0,0.18);
    border-left: 4px solid ${meta.color};
    display:flex; align-items:flex-start; gap:10px;
    padding:12px 14px; cursor:pointer;
    transform: translateX(120%); transition: transform 0.32s cubic-bezier(.22,.68,0,1.2);
    font-family: inherit;
  `;
  el.innerHTML = `
    <i class="fas ${meta.icon}" style="color:${meta.color};font-size:16px;margin-top:2px;flex-shrink:0"></i>
    <div style="flex:1;overflow:hidden">
      <div style="font-size:11px;font-weight:700;color:${meta.color};margin-bottom:2px">${meta.label}</div>
      <div style="font-size:12px;color:#333;line-height:1.4;word-break:break-all">${msg}</div>
    </div>
    <button onclick="this.closest('[data-notif-toast]').remove()" style="flex-shrink:0;background:none;border:none;cursor:pointer;color:#aaa;font-size:14px;padding:0;margin-left:4px;line-height:1">&times;</button>
  `;
  el.setAttribute('data-notif-toast', '1');
  el.onclick = (ev) => {
    if (ev.target.tagName === 'BUTTON') return;
    el.remove();
    _navigateByNotif(data);
  };

  document.body.appendChild(el);
  // 슬라이드-인
  requestAnimationFrame(() => {
    requestAnimationFrame(() => { el.style.transform = 'translateX(0)'; });
  });
  // 5초 후 자동 제거 (슬라이드-아웃)
  const autoRemove = setTimeout(() => {
    el.style.transform = 'translateX(120%)';
    setTimeout(() => el.remove(), 350);
  }, 5000);
  el.addEventListener('mouseenter', () => clearTimeout(autoRemove));
}

/** 헤더 알림 배지 숫자 갱신 */
function updateNotifBadge() {
  const badge = document.getElementById('notif-bell-badge');
  if (!badge) return;
  if (_unreadCount > 0) {
    badge.textContent = _unreadCount > 99 ? '99+' : _unreadCount;
    badge.classList.remove('hidden');
  } else {
    badge.classList.add('hidden');
  }
}

/** 알림 패널 아이템 클릭 핸들러 — 타입별 페이지 이동 */
function _onNotifPanelItemClick(idx) {
  const n = _notifHistory[idx];
  if (!n) return;
  toggleNotifPanel(); // 패널 닫기
  _navigateByNotif(n);
}

/** 알림 타입별 페이지/상세 이동 공통 함수 */
function _navigateByNotif(n) {
  const type = n.type;

  // ── 작업 관련 알림: 작업 상세 화면으로 직접 진입
  if (
    type === 'task_status' ||
    type === 'task_status_manager' ||
    type === 'task_status_change' ||
    type === 'task_created' ||
    type === 'task_assigned'
  ) {
    const taskId = n.taskId || (n.ref_type === 'task' ? n.ref_id : null);
    if (taskId) {
      // tasks 페이지가 아닌 경우 먼저 이동 후 상세 오픈
      if (currentPage !== 'tasks') {
        safeNavigateTo('tasks');
        setTimeout(() => showTaskDetail(taskId), 450);
      } else {
        showTaskDetail(taskId);
      }
    } else {
      safeNavigateTo('tasks');
    }
    return;
  }

  // ── 서명 요청
  if (type === 'sign_request') { safeNavigateTo('sign-requests'); return; }

  // ── 위험 신고
  if (type === 'hazard_report') { safeNavigateTo('hazards'); return; }

  // ── 정산 요청: 공사 상세 모달로 바로 이동
  if (type === 'settlement_request') {
    safeNavigateTo('constructions');
    const conId = n.conId || (n.ref_type === 'construction' ? n.ref_id : null);
    if (conId) setTimeout(() => showConstructionDetail(conId), 400);
    return;
  }
}

/** 알림 센터 패널 열기/닫기 토글 */
function toggleNotifPanel() {
  _notifPanelOpen = !_notifPanelOpen;
  if (_notifPanelOpen) {
    renderNotifPanel();
    // 패널 열면 미읽음 초기화 (메모리 + DB)
    _notifHistory.forEach(n => { n.read = true; });
    _unreadCount = 0;
    updateNotifBadge();
    // DB 미읽음 전체 읽음 처리 (비동기, 실패해도 UX 영향 없음)
    API.patch('/notifications/read-all').catch(() => {});
  } else {
    const panel = document.getElementById('notif-panel');
    if (panel) panel.remove();
  }
}

/** 알림 센터 패널 렌더링 */
function renderNotifPanel() {
  let panel = document.getElementById('notif-panel');
  if (!panel) {
    panel = document.createElement('div');
    panel.id = 'notif-panel';
    document.body.appendChild(panel);
    // 패널 바깥 클릭 시 닫기
    setTimeout(() => {
      document.addEventListener('click', _closeNotifPanelOutside, { once: false });
    }, 10);
  }

  panel.style.cssText = `
    position:fixed; top:52px; right:8px; z-index:9999;
    width:320px; max-height:480px;
    background:#fff; border-radius:14px;
    box-shadow:0 8px 32px rgba(0,0,0,0.18);
    display:flex; flex-direction:column;
    overflow:hidden; font-family:inherit;
    border:1px solid #f0e6f6;
  `;

  const isEmpty = _notifHistory.length === 0;
  const items = _notifHistory.map((n, idx) => {
    const meta = _notifMeta(n.type);
    const timeStr = n.ts ? _relativeTime(n.ts) : '';
    return `
      <div style="display:flex;align-items:flex-start;gap:10px;padding:11px 14px;border-bottom:1px solid #f5f5f5;
        background:${n.read ? '#fff' : '#fdf5fa'};cursor:pointer;transition:background 0.15s"
        onmouseenter="this.style.background='#f9f0f7'" onmouseleave="this.style.background='${n.read ? '#fff' : '#fdf5fa'}'"
        onclick="_onNotifPanelItemClick(${idx})">
        <div style="width:32px;height:32px;border-radius:50%;background:${meta.color}22;display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:1px">
          <i class="fas ${meta.icon}" style="color:${meta.color};font-size:13px"></i>
        </div>
        <div style="flex:1;overflow:hidden">
          <div style="font-size:11px;font-weight:700;color:${meta.color};margin-bottom:2px">${meta.label}</div>
          <div style="font-size:12px;color:#333;line-height:1.4;word-break:break-all">${n.message || meta.label + ' 알림'}</div>
          ${timeStr ? `<div style="font-size:10px;color:#aaa;margin-top:3px">${timeStr}</div>` : ''}
        </div>
        ${!n.read ? '<div style="width:7px;height:7px;border-radius:50%;background:#D70072;flex-shrink:0;margin-top:5px"></div>' : ''}
      </div>
    `;
  }).join('');

  panel.innerHTML = `
    <div style="display:flex;align-items:center;justify-content:space-between;padding:12px 14px 10px;border-bottom:1px solid #f0e6f6">
      <span style="font-size:14px;font-weight:700;color:#685182">
        <i class="fas fa-bell mr-1.5" style="color:#D70072"></i>알림 센터
      </span>
      <div style="display:flex;align-items:center;gap:8px">
        ${_notifHistory.length > 0 ? `<button onclick="clearNotifHistory()" style="font-size:11px;color:#aaa;background:none;border:none;cursor:pointer;padding:2px 4px">전체 삭제</button>` : ''}
        <button onclick="toggleNotifPanel()" style="background:none;border:none;cursor:pointer;color:#aaa;font-size:16px;padding:0 2px">&times;</button>
      </div>
    </div>
    <div style="overflow-y:auto;flex:1">
      ${isEmpty
        ? `<div style="text-align:center;padding:40px 20px;color:#bbb;font-size:13px"><i class="fas fa-bell-slash" style="font-size:28px;display:block;margin-bottom:8px;color:#e0e0e0"></i>알림이 없습니다</div>`
        : items
      }
    </div>
  `;
}

function _closeNotifPanelOutside(e) {
  if (!_notifPanelOpen) {
    document.removeEventListener('click', _closeNotifPanelOutside);
    return;
  }
  const panel = document.getElementById('notif-panel');
  const btn = document.getElementById('notif-bell-btn');
  if (panel && !panel.contains(e.target) && btn && !btn.contains(e.target)) {
    _notifPanelOpen = false;
    panel.remove();
    document.removeEventListener('click', _closeNotifPanelOutside);
  }
}

/** 알림 히스토리 전체 삭제 */
// [BUG-023] 기존: 메모리(_notifHistory)만 삭제 → 재로그인 시 복원
// 수정: 서버 DB DELETE 먼저 호출 → 성공 시 메모리/UI 갱신
async function clearNotifHistory() {
  try {
    await API.delete('/notifications/clear-all')
  } catch (e) {
    console.warn('[알림] 전체삭제 API 실패:', e)
    toast('알림 삭제 중 오류가 발생했습니다.', 'error')
    return
  }
  _notifHistory.length = 0
  _unreadCount = 0
  updateNotifBadge()
  renderNotifPanel()
}

/** 상대 시간 표시 (n초 전, n분 전, n시간 전) */
function _relativeTime(ts) {
  const diff = Math.floor((Date.now() - ts) / 1000);
  if (diff < 60) return '방금 전';
  if (diff < 3600) return `${Math.floor(diff / 60)}분 전`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}시간 전`;
  return `${Math.floor(diff / 86400)}일 전`;
}

// ─── 서명 요청 카운트 폴링 (로그인 후 주기적 갱신) ─────────────────────────────
let _signCountTimer = null;
async function refreshSignRequestCount() {
  try {
    const res = await API.get('/signature-requests/count');
    const cnt = res.data?.count || 0;
    // 헤더 배지
    const hBadge = document.getElementById('sign-req-count');
    if (hBadge) {
      hBadge.textContent = cnt > 99 ? '99+' : cnt;
      hBadge.classList.toggle('hidden', cnt === 0);
    }
    // 하단 네비 배지 (구형 4탭 — 호환성 유지)
    const bBadge = document.getElementById('bottom-sign-count');
    if (bBadge) {
      bBadge.textContent = cnt > 99 ? '99+' : cnt;
      bBadge.classList.toggle('hidden', cnt === 0);
    }
    // Option C: 레일 배지 (안전관리 그룹 = edu, 근로자 wsafety, LGU+ 안전점검 lgu-safety)
    ['edu', 'wsafety', 'lgu-safety'].forEach(gid => {
      const rBadge = document.getElementById('rail-badge-' + gid);
      if (rBadge) {
        rBadge.textContent = cnt > 99 ? '99+' : cnt;
        rBadge.classList.toggle('hidden', cnt === 0);
      }
      const nBadge = document.getElementById('bnav-badge-' + gid);
      if (nBadge) {
        nBadge.textContent = cnt > 99 ? '99+' : cnt;
        nBadge.classList.toggle('hidden', cnt === 0);
      }
    });
  } catch(_) {}
}
function startSignCountPoller() {
  refreshSignRequestCount();
  if (_signCountTimer) clearInterval(_signCountTimer);
  _signCountTimer = setInterval(refreshSignRequestCount, 30000); // 30초마다
}

function navigateTodayTasks() {
  navigateTo('dashboard');
  // dashboard 렌더 완료 후 금일 예정 작업 카드로 스크롤
  setTimeout(() => {
    const target = document.querySelector('[data-section="today-tasks"]') ||
                   [...document.querySelectorAll('h3,h4,.text-sm')].find(el => el.textContent.includes('금일 예정 작업'));
    if (target) {
      target.scrollIntoView({ behavior: 'smooth', block: 'start' });
      // 하이라이트 효과
      const card = target.closest('.card') || target.parentElement;
      if (card) {
        card.style.transition = 'box-shadow 0.3s';
        card.style.boxShadow = '0 0 0 3px #D70072aa';
        setTimeout(() => { card.style.boxShadow = ''; }, 1500);
      }
    }
  }, 500);
}

