function deleteMedia(photoId, caption, closeModal) {
  const m = document.createElement('div');
  m.className = 'modal-overlay modal-sm';
  m.style.zIndex = '10000';
  m.innerHTML = `
  <div class="modal" style="max-width:340px">
    <div class="modal-header" style="background:linear-gradient(135deg,#A8005A,#D70072);color:white">
      <div class="flex items-center gap-2">
        <i class="fas fa-image text-lg"></i>
        <h3 class="font-bold">사진/동영상 삭제</h3>
      </div>
      <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer;opacity:0.8">×</button>
    </div>
    <div class="modal-body">
      <div style="background:#FDE8F3;border:1.5px solid #FDE8F3;border-radius:12px;padding:14px 16px;color:#A8005A;font-size:14px;line-height:1.6">
        <i class="fas fa-exclamation-triangle mr-2 text-red-400"></i>
        <strong>"${caption}"</strong>을(를) 삭제하시겠습니까?<br>
        <span style="font-size:12px;opacity:0.8">삭제된 파일은 복구할 수 없습니다.</span>
      </div>
    </div>
    <div class="modal-footer" style="display:flex;gap:8px;justify-content:flex-end">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button id="doDeleteMediaBtn" class="btn btn-danger font-bold"><i class="fas fa-trash mr-1"></i>삭제</button>
    </div>
  </div>`;
  document.body.appendChild(m);
  m.querySelector('#doDeleteMediaBtn').onclick = async () => {
    m.remove();
  try {
    // ① 삭제 전에 taskId 먼저 저장 (모달이 아직 DOM에 있을 때)
    const taskModalEl = document.querySelector('.modal[data-task-id]');
    const taskId = taskModalEl ? parseInt(taskModalEl.dataset.taskId) : null;

    const token = localStorage.getItem('token');
    const res = await fetch(`/api/photos/${photoId}`, {
      method: 'DELETE',
      headers: token ? { 'Authorization': `Bearer ${token}` } : {}
    });
    const data = await res.json();
    if (res.ok && data.success) {
      toast('삭제되었습니다.');

      // ② 사진/동영상 뷰어 모달만 닫기 (있을 경우)
      if (closeModal) closeModal.remove();

      // ③ 사진 탭만 부분 갱신 (전체 모달 재로드 없이 즉시 반영)
      if (taskId && document.getElementById('dtab-photo')) {
        await _refreshPhotoTab(taskId);
        // 사진 탭 활성화 유지
        const photoTabBtn = document.querySelector('[onclick*="switchDetailTab"][onclick*="photo"]');
        if (photoTabBtn) photoTabBtn.click();
        else {
          document.querySelectorAll('.detail-tab').forEach(t => t.classList.add('hidden'));
          const tab = document.getElementById('dtab-photo');
          if (tab) tab.classList.remove('hidden');
        }
      } else {
        // 작업 상세 모달이 없으면 전체 재로드
        if (taskId) {
          document.querySelectorAll('.modal-overlay').forEach(m => m.remove());
          await showTaskDetail(taskId);
          setTimeout(() => {
            const photoTabBtn = document.querySelector('[onclick*="switchDetailTab"][onclick*="photo"]');
            if (photoTabBtn) photoTabBtn.click();
          }, 200);
        } else {
          document.querySelectorAll('.modal-overlay').forEach(m => m.remove());
        }
      }
    } else {
      throw new Error(data.error || '삭제 실패');
    }
  } catch(e) {
    toast(`삭제 실패: ${e.message}`, 'error');
  }
  };
}

// ======= 위험성 평가 양식 (엑셀 표준 데이터 기반) =======
async function showRiskAssessmentForm(taskId) {
  const taskRes = await API.get(`/tasks/${taskId}`);
  const task = taskRes.data;

  // 작업유형이 있으면 표준 위험성평가 항목 자동 로드 (다중 유형 지원)
  let stdItems = [];
  let stdGrouped = {};
  const workTypes = task.work_types && task.work_types.length > 0
    ? task.work_types
    : task.work_type_id ? [{ id: task.work_type_id, name: task.work_type_name }] : [];

  for (const wt of workTypes) {
    try {
      const res = await API.get('/risk/items/standard-form', { params: { work_type_id: wt.id } });
      const items = res.data.items || [];
      const grouped = res.data.grouped || {};
      // 유형명 태그 추가
      items.forEach(item => { item._work_type_name = wt.name; });
      stdItems = stdItems.concat(items);
      // grouped 병합 (카테고리별)
      Object.entries(grouped).forEach(([cat, catItems]) => {
        if (!stdGrouped[cat]) stdGrouped[cat] = [];
        catItems.forEach(ci => { ci._work_type_name = wt.name; });
        stdGrouped[cat] = stdGrouped[cat].concat(catItems);
      });
    } catch(e) {}
  }

  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.setAttribute('data-task-id', taskId);
  modal.innerHTML = `
  <div class="modal" style="max-width:1000px">
    <div class="modal-header">
      <div>
        <h3 class="font-bold text-lg"><i class="fas fa-clipboard-check mr-2 text-yellow-500"></i>위험성 평가</h3>
        <p class="text-sm text-gray-500">${task.title} · ${task.location || ''}</p>
        ${workTypes.length > 0 ? `<p class="text-xs text-blue-600 mt-0.5"><i class="fas fa-tag mr-1"></i>작업유형: ${workTypes.map(wt=>`<span class="bg-blue-100 px-1.5 py-0.5 rounded mr-1">${wt.name}</span>`).join('')}</p>` : ''}
      </div>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body" style="max-height:80vh;overflow-y:auto">
      <div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4">
        <div class="form-group">
          <label class="form-label">평가일시</label>
          <input id="raDate" class="form-control" type="datetime-local" value="${kstDateTimeLocal()}">
        </div>
        <div class="form-group" style="grid-column:span 2">
          <label class="form-label" style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px">
            <span>날씨 / 기온(°C)</span>
            <button type="button"
              onclick="_autoFillWeather('raWeather','raTemp','raWeatherStatus')"
              style="display:inline-flex;align-items:center;gap:4px;padding:3px 9px;background:linear-gradient(135deg,#0369a1,#0284c7);color:#fff;border:none;border-radius:8px;font-size:11px;font-weight:600;cursor:pointer;white-space:nowrap">
              <i class="fas fa-cloud-sun" style="font-size:10px"></i>GPS 날씨 자동입력
            </button>
          </label>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
            <select id="raWeather" class="form-control">
              <option>맑음</option><option>흐림</option><option>비</option><option>눈</option><option>강풍</option>
            </select>
            <input id="raTemp" class="form-control" placeholder="예: 22 (°C)">
          </div>
          <div id="raWeatherStatus" style="font-size:11px;color:#059669;margin-top:4px;display:none"></div>
        </div>
        <div class="form-group">
          <label class="form-label">투입 인원</label>
          <input id="raWorkers" class="form-control" type="number" value="${(task.assigned_workers||[]).length||1}">
        </div>
      </div>
      <div class="mb-4">
        <div class="flex justify-between items-center mb-3 flex-wrap gap-2">
          <div>
            <h4 class="font-bold text-gray-700">위험성 평가 항목</h4>
            ${stdItems.length > 0 ? `<p class="text-xs text-green-600 mt-0.5"><i class="fas fa-check-circle mr-1"></i>표준 양식 ${stdItems.length}개 항목 자동 로드됨</p>` : ''}
          </div>
          <div class="flex gap-2 flex-wrap">
            ${workTypes.length > 0 ? `
              <button onclick="loadStandardRiskItems(${JSON.stringify(workTypes.map(wt=>wt.id))})" class="btn btn-outline text-xs py-1 px-3">
                <i class="fas fa-sync-alt mr-1"></i>표준항목 다시 불러오기
              </button>` : `
              <button onclick="showWorkTypeSelector()" class="btn btn-outline text-xs py-1 px-3">
                <i class="fas fa-list mr-1"></i>작업유형별 항목 선택
              </button>`}
            <button onclick="addRiskRow()" class="btn btn-outline text-xs py-1 px-3">
              <i class="fas fa-plus mr-1"></i>항목 추가
            </button>
            <button onclick="toggleAllRiskRows()" id="toggleRiskBtn" class="btn btn-outline text-xs py-1 px-3">
              <i class="fas fa-compress-alt mr-1"></i>접기
            </button>
          </div>
        </div>
        <div class="flex gap-2 mb-3 flex-wrap text-xs">
          <span class="px-2 py-1 rounded bg-green-100 text-green-700">● 낮음 (1-2)</span>
          <span class="px-2 py-1 rounded bg-yellow-100 text-yellow-700">● 보통 (3-4)</span>
          <span class="px-2 py-1 rounded bg-orange-100 text-orange-700">● 높음 (5-6)</span>
          <span class="px-2 py-1 rounded bg-red-100 text-red-700">● 매우높음 (8-25)</span>
        </div>
        <div id="riskRows" class="space-y-2"></div>
      </div>
      <div class="form-group">
        <label class="form-label">특이사항 / 추가 안전조치</label>
        <textarea id="raNotes" class="form-control" rows="2" placeholder="특이사항 입력"></textarea>
      </div>
    </div>
    <div class="modal-footer">
      <div class="text-sm text-gray-500" id="riskItemCount">0개 항목</div>
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button onclick="submitRiskAssessment(${taskId})" class="btn btn-warning">
        <i class="fas fa-save"></i> 위험성 평가 완료
      </button>
    </div>
  </div>`;
  document.body.appendChild(modal);

  // 표준 항목 자동 로드
  const container = document.getElementById('riskRows');
  if (stdItems.length > 0) {
    Object.entries(stdGrouped).forEach(([cat, items]) => {
      const header = document.createElement('div');
      header.className = 'risk-category-header bg-blue-50 border border-blue-200 rounded-lg px-3 py-2 mt-3 mb-1 flex justify-between items-center cursor-pointer';
      header.innerHTML = `<span class="font-bold text-blue-800 text-sm"><i class="fas fa-layer-group mr-2"></i>${cat} <span class="text-blue-500 font-normal">(${items.length}건)</span></span><i class="fas fa-chevron-down text-blue-400 text-xs toggle-cat-icon"></i>`;
      header.onclick = function() {
        const next = this.nextElementSibling;
        if (next) {
          next.classList.toggle('hidden');
          this.querySelector('.toggle-cat-icon').className = next.classList.contains('hidden')
            ? 'fas fa-chevron-right text-blue-400 text-xs toggle-cat-icon'
            : 'fas fa-chevron-down text-blue-400 text-xs toggle-cat-icon';
        }
      };
      container.appendChild(header);
      const catDiv = document.createElement('div');
      catDiv.className = 'cat-items space-y-2';
      items.forEach(item => catDiv.appendChild(createRiskRow(item)));
      container.appendChild(catDiv);
    });
  } else {
    container.appendChild(createRiskRow());
  }
  updateRiskItemCount();
}

function updateRiskItemCount() {
  const count = document.querySelectorAll('.risk-row').length;
  const el = document.getElementById('riskItemCount');
  if (el) el.textContent = count + '개 항목';
}

let riskRowsCollapsed = false;
function toggleAllRiskRows() {
  const catItems = document.querySelectorAll('.cat-items');
  riskRowsCollapsed = !riskRowsCollapsed;
  catItems.forEach(el => el.classList.toggle('hidden', riskRowsCollapsed));
  const btn = document.getElementById('toggleRiskBtn');
  if (btn) btn.innerHTML = riskRowsCollapsed
    ? '<i class="fas fa-expand-alt mr-1"></i>펼치기'
    : '<i class="fas fa-compress-alt mr-1"></i>접기';
}

async function loadStandardRiskItems(workTypeIdOrIds) {
  // 단일 ID 또는 배열 ID 모두 지원
  const typeIds = Array.isArray(workTypeIdOrIds) ? workTypeIdOrIds : [workTypeIdOrIds];
  try {
    let allItems = [];
    const mergedGrouped = {};
    for (const wtId of typeIds) {
      const res = await API.get('/risk/items/standard-form', { params: { work_type_id: wtId } });
      const items = res.data.items || [];
      const grouped = res.data.grouped || {};
      allItems = allItems.concat(items);
      Object.entries(grouped).forEach(([cat, catItems]) => {
        if (!mergedGrouped[cat]) mergedGrouped[cat] = [];
        mergedGrouped[cat] = mergedGrouped[cat].concat(catItems);
      });
    }
    const container = document.getElementById('riskRows');
    container.innerHTML = '';
    Object.entries(mergedGrouped).forEach(([cat, catItems]) => {
      const header = document.createElement('div');
      header.className = 'risk-category-header bg-blue-50 border border-blue-200 rounded-lg px-3 py-2 mt-3 mb-1 flex justify-between items-center cursor-pointer';
      header.innerHTML = `<span class="font-bold text-blue-800 text-sm"><i class="fas fa-layer-group mr-2"></i>${cat} <span class="text-blue-500 font-normal">(${catItems.length}건)</span></span><i class="fas fa-chevron-down text-blue-400 text-xs toggle-cat-icon"></i>`;
      header.onclick = function() {
        const next = this.nextElementSibling;
        if (next) next.classList.toggle('hidden');
      };
      container.appendChild(header);
      const catDiv = document.createElement('div');
      catDiv.className = 'cat-items space-y-2';
      catItems.forEach(item => catDiv.appendChild(createRiskRow(item)));
      container.appendChild(catDiv);
    });
    toast(allItems.length + '개 표준 항목이 로드되었습니다.');
    updateRiskItemCount();
  } catch(e) {
    toast('항목 로드 실패', 'error');
  }
}

async function showWorkTypeSelector() {
  try {
    const res = await API.get('/risk/items/summary');
    const summary = res.data;
    const grouped = {};
    summary.forEach(item => {
      if (!grouped[item.category_name]) grouped[item.category_name] = [];
      grouped[item.category_name].push(item);
    });
    const container = document.getElementById('riskRows');
    let html = '<div class="bg-blue-50 border border-blue-200 rounded-xl p-4"><p class="font-bold text-blue-800 mb-3"><i class="fas fa-list-ul mr-2"></i>작업유형 선택 (표준 위험성평가 항목 자동 로드)</p><div class="grid md:grid-cols-2 lg:grid-cols-3 gap-2 max-h-72 overflow-y-auto">';
    Object.entries(grouped).forEach(([cat, types]) => {
      html += `<div><p class="text-xs font-bold text-gray-600 mb-1">${cat}</p>`;
      types.forEach(t => {
        html += `<button onclick="selectWorkTypeForRisk(${t.work_type_id}, '${t.work_type_name}')" class="block w-full text-left px-3 py-2 text-sm hover:bg-blue-100 rounded-lg mb-1 border border-gray-200 bg-white"><span class="font-medium">${t.work_type_name}</span><span class="text-xs text-gray-400 ml-2">${t.item_count}개 항목${t.high_risk_count > 0 ? ' <span class=\'text-red-500\'>(고위험 ' + t.high_risk_count + '건)</span>' : ''}</span></button>`;
      });
      html += '</div>';
    });
    html += '</div></div>';
    container.innerHTML = html;
  } catch(e) {
    toast('작업유형 목록 로드 실패', 'error');
  }
}

async function selectWorkTypeForRisk(workTypeId, workTypeName) {
  try {
    const res = await API.get('/risk/items/standard-form', { params: { work_type_id: workTypeId } });
    const items = res.data.items || [];
    const grouped = res.data.grouped || {};
    const container = document.getElementById('riskRows');
    container.innerHTML = '';
    const infoDiv = document.createElement('div');
    infoDiv.className = 'bg-green-50 border border-green-200 rounded-lg px-3 py-2 mb-2 text-sm text-green-800';
    infoDiv.innerHTML = '<i class="fas fa-check-circle mr-2"></i><strong>' + workTypeName + '</strong> 표준 위험성평가 항목 ' + items.length + '개 로드됨';
    container.appendChild(infoDiv);
    Object.entries(grouped).forEach(([cat, catItems]) => {
      const header = document.createElement('div');
      header.className = 'risk-category-header bg-blue-50 border border-blue-200 rounded-lg px-3 py-2 mt-2 mb-1 flex justify-between items-center cursor-pointer';
      header.innerHTML = `<span class="font-bold text-blue-800 text-sm"><i class="fas fa-layer-group mr-2"></i>${cat} <span class="text-blue-500 font-normal">(${catItems.length}건)</span></span><i class="fas fa-chevron-down text-blue-400 text-xs toggle-cat-icon"></i>`;
      header.onclick = function() {
        const next = this.nextElementSibling;
        if (next) next.classList.toggle('hidden');
      };
      container.appendChild(header);
      const catDiv = document.createElement('div');
      catDiv.className = 'cat-items space-y-2';
      catItems.forEach(item => catDiv.appendChild(createRiskRow(item)));
      container.appendChild(catDiv);
    });
    toast(items.length + '개 항목 로드됨');
    updateRiskItemCount();
  } catch(e) {
    toast('항목 로드 실패', 'error');
  }
}

async function loadRiskItems(workTypeId) {
  return loadStandardRiskItems(workTypeId);
}

function createRiskRow(item = {}) {
  const div = document.createElement('div');
  div.className = 'risk-row border border-gray-200 rounded-xl p-3 bg-gray-50';
  const bFreq = item.before_frequency || 2;
  const bSev = item.before_severity || 2;
  const aFreq = item.after_frequency || 1;
  const aSev = item.after_severity || 2;
  const bScore = bFreq * bSev;
  const aScore = aFreq * aSev;
  const riskLevelB = calcRiskLevel(bFreq, bSev);
  const riskLevelA = calcRiskLevel(aFreq, aSev);

  // 위험수준 표시용 배지
  const hazardText = item.hazard || '';
  const factorText = item.risk_factor || '';
  const controlText = item.control_measures || '';

  div.innerHTML = `
    <div class="flex justify-between items-start mb-2">
      <div class="flex-1 grid md:grid-cols-2 gap-2">
        <div class="form-group mb-0">
          <label class="form-label text-xs">유해·위험요인 (원인)</label>
          <input class="form-control text-xs riskHazard" value="${hazardText.substring(0,100)}">
        </div>
        <div class="form-group mb-0">
          <label class="form-label text-xs">위험성 내용</label>
          <input class="form-control text-xs riskFactor" value="${factorText.substring(0,200)}">
        </div>
      </div>
      <button onclick="this.closest('.risk-row').remove(); updateRiskItemCount();" class="text-red-400 hover:text-red-600 text-xs ml-2 mt-4 flex-shrink-0">
        <i class="fas fa-trash"></i>
      </button>
    </div>
    <input type="hidden" class="riskCategory" value="${(item.category||'').replace(/"/g,'&quot;')}">
    <div class="grid grid-cols-2 gap-2 mb-2">
      <div class="bg-red-50 p-2 rounded-lg">
        <div class="text-xs font-bold text-red-700 mb-1">개선 전</div>
        <div class="flex gap-1 items-end">
          <div class="flex-1">
            <label class="form-label text-xs">빈도</label>
            <select class="form-control text-xs riskBeforeFreq" onchange="updateRiskScore(this)">
              ${[1,2,3,4,5].map(v=>`<option value="${v}" ${bFreq==v?'selected':''}>${v}</option>`).join('')}
            </select>
          </div>
          <div class="flex-1">
            <label class="form-label text-xs">강도</label>
            <select class="form-control text-xs riskBeforeSev" onchange="updateRiskScore(this)">
              ${[1,2,3,4,5].map(v=>`<option value="${v}" ${bSev==v?'selected':''}>${v}</option>`).join('')}
            </select>
          </div>
          <div class="text-center">
            <label class="form-label text-xs">위험도</label>
            <div class="risk-score before-score ${getRiskColor(riskLevelB)}">${bScore}</div>
          </div>
        </div>
      </div>
      <div class="bg-green-50 p-2 rounded-lg">
        <div class="text-xs font-bold text-green-700 mb-1">개선 후</div>
        <div class="flex gap-1 items-end">
          <div class="flex-1">
            <label class="form-label text-xs">빈도</label>
            <select class="form-control text-xs riskAfterFreq" onchange="updateRiskScore(this)">
              ${[1,2,3,4,5].map(v=>`<option value="${v}" ${aFreq==v?'selected':''}>${v}</option>`).join('')}
            </select>
          </div>
          <div class="flex-1">
            <label class="form-label text-xs">강도</label>
            <select class="form-control text-xs riskAfterSev" onchange="updateRiskScore(this)">
              ${[1,2,3,4,5].map(v=>`<option value="${v}" ${aSev==v?'selected':''}>${v}</option>`).join('')}
            </select>
          </div>
          <div class="text-center">
            <label class="form-label text-xs">위험도</label>
            <div class="risk-score after-score ${getRiskColor(riskLevelA)}">${aScore}</div>
          </div>
        </div>
      </div>
    </div>
    <div class="form-group mb-0">
      <label class="form-label text-xs">안전조치 / 감소대책</label>
      <textarea class="form-control text-xs riskControl" rows="2">${controlText}</textarea>
    </div>
    <input type="hidden" class="riskItemId" value="${item.id||''}">`;
  return div;
}

function addRiskRow() {
  const container = document.getElementById('riskRows');
  const newRow = createRiskRow();
  container.appendChild(newRow);
  updateRiskItemCount();
}

function updateRiskScore(el) {
  const row = el.closest('.risk-row');
  if (!row) return;
  const bFreq = parseInt(row.querySelector('.riskBeforeFreq').value) || 1;
  const bSev = parseInt(row.querySelector('.riskBeforeSev').value) || 1;
  const aFreq = parseInt(row.querySelector('.riskAfterFreq').value) || 1;
  const aSev = parseInt(row.querySelector('.riskAfterSev').value) || 1;
  const bScore = bFreq * bSev;
  const aScore = aFreq * aSev;
  const bEl = row.querySelector('.before-score');
  const aEl = row.querySelector('.after-score');
  bEl.textContent = bScore;
  bEl.className = `risk-score before-score ${getRiskColor(calcRiskLevel(bFreq,bSev))}`;
  aEl.textContent = aScore;
  aEl.className = `risk-score after-score ${getRiskColor(calcRiskLevel(aFreq,aSev))}`;
}

async function submitRiskAssessment(taskId) {
  const rows = document.querySelectorAll('.risk-row');
  const details = [];
  rows.forEach(row => {
    const cat = row.querySelector('.riskCategory')?.value;
    const hazard = row.querySelector('.riskHazard')?.value;
    const factor = row.querySelector('.riskFactor')?.value;
    const bFreq = parseInt(row.querySelector('.riskBeforeFreq')?.value) || 2;
    const bSev = parseInt(row.querySelector('.riskBeforeSev')?.value) || 2;
    const aFreq = parseInt(row.querySelector('.riskAfterFreq')?.value) || 1;
    const aSev = parseInt(row.querySelector('.riskAfterSev')?.value) || 2;
    const control = row.querySelector('.riskControl')?.value;
    const itemId = row.querySelector('.riskItemId')?.value;
    if (hazard || factor) {
      details.push({
        item_id: itemId || null,
        category: cat || '', hazard: hazard || '', risk_factor: factor || '',
        before_frequency: bFreq, before_severity: bSev, before_risk_level: calcRiskLevel(bFreq, bSev),
        after_frequency: aFreq, after_severity: aSev, after_risk_level: calcRiskLevel(aFreq, aSev),
        control_measures: control || '', is_confirmed: true
      });
    }
  });

  if (details.length === 0) { toast('위험성 평가 항목을 1개 이상 입력하세요.', 'error'); return; }

  try {
    await API.post('/risk', {
      task_id: taskId,
      weather: document.getElementById('raWeather').value,
      temperature: document.getElementById('raTemp').value,
      workers_count: parseInt(document.getElementById('raWorkers').value) || 1,
      notes: document.getElementById('raNotes').value,
      details
    });
    toast(`위험성 평가 완료 (${details.length}개 항목 저장)`);
    document.querySelector('.modal-overlay')?.remove();
    showTaskDetail(taskId);
  } catch(e) {
    toast(e.response?.data?.error || '저장 실패', 'error');
  }
}

