// ─── 작업일지 첨부파일 드래그&드롭 핸들러 ────────────────────────────────────
function handleLogAttachDrop(event) {
  const input = document.getElementById('logAttachInput');
  if (!input || !event.dataTransfer?.files?.length) return;
  // DataTransfer 파일을 input에 합산
  const dt = new DataTransfer();
  // 기존 파일 유지
  if (input.files) {
    for (const f of input.files) dt.items.add(f);
  }
  for (const f of event.dataTransfer.files) dt.items.add(f);
  input.files = dt.files;
  renderLogAttachPreview(input.files);
}

// 첨부파일 미리보기 렌더링
function renderLogAttachPreview(files) {
  const preview = document.getElementById('logAttachPreview');
  if (!preview) return;
  if (!files || files.length === 0) {
    preview.innerHTML = '';
    return;
  }
  const iconFor = (mime) => {
    if (!mime) return 'fas fa-file text-gray-400';
    if (mime.startsWith('image/'))      return 'fas fa-file-image text-purple-500';
    if (mime === 'application/pdf')     return 'fas fa-file-pdf text-red-500';
    if (mime.includes('word'))          return 'fas fa-file-word text-blue-600';
    if (mime.includes('excel') || mime.includes('spreadsheet')) return 'fas fa-file-excel text-green-600';
    if (mime.includes('powerpoint') || mime.includes('presentation')) return 'fas fa-file-powerpoint text-orange-500';
    if (mime.startsWith('video/'))      return 'fas fa-file-video text-blue-400';
    return 'fas fa-file text-gray-400';
  };
  const fmtSize = b => b < 1024*1024 ? (b/1024).toFixed(1)+'KB' : (b/1024/1024).toFixed(1)+'MB';
  preview.innerHTML = [...files].map((f, i) => `
    <div class="flex items-center gap-2 p-2 bg-gray-50 rounded-lg border border-gray-200 text-xs">
      <i class="${iconFor(f.type)} w-4 text-center flex-shrink-0"></i>
      <span class="flex-1 truncate text-gray-700">${f.name}</span>
      <span class="text-gray-400 flex-shrink-0">${fmtSize(f.size)}</span>
      <button type="button" onclick="removeLogAttachFile(${i})"
        class="text-gray-300 hover:text-red-500 flex-shrink-0 ml-1">
        <i class="fas fa-times"></i>
      </button>
    </div>
  `).join('');
}

// 첨부파일 목록에서 특정 파일 제거
function removeLogAttachFile(index) {
  const input = document.getElementById('logAttachInput');
  if (!input || !input.files) return;
  const dt = new DataTransfer();
  [...input.files].forEach((f, i) => { if (i !== index) dt.items.add(f); });
  input.files = dt.files;
  renderLogAttachPreview(input.files);
}

async function submitWorkLog(taskId) {
  try {
    const status = document.getElementById('logStatus').value;

    // ── GPS 좌표 자동 수집 (백그라운드, 실패해도 저장 진행) ──
    let gps_lat = null, gps_lon = null;
    try {
      if (navigator.geolocation) {
        const pos = await new Promise((resolve, reject) =>
          navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000, maximumAge: 60000 })
        );
        gps_lat = parseFloat(pos.coords.latitude.toFixed(6));
        gps_lon = parseFloat(pos.coords.longitude.toFixed(6));
      }
    } catch(_) { /* GPS 실패 시 null 유지 — 저장은 계속 진행 */ }

    const logRes = await API.post('/worklogs', {
      task_id: taskId,
      log_date: document.getElementById('logDate').value,
      start_time: document.getElementById('logStart').value,
      end_time: document.getElementById('logEnd').value || null,
      work_location: document.getElementById('logLocation').value,
      actual_quantity: parseFloat(document.getElementById('logQty')?.value) || 0,
      work_description: document.getElementById('logDesc').value,
      issues: document.getElementById('logIssues').value,
      tomorrow_plan: document.getElementById('logTomorrow').value,
      status,
      gps_lat,
      gps_lon
    });
    // 저장된 worklog id (description에 넣어서 첨부파일과 연결)
    const worklogId = logRes.data?.id || logRes.data?.worklog_id || '';

    // 첨부파일 업로드 (있을 경우)
    const attachInput = document.getElementById('logAttachInput');
    const hasFiles = attachInput?.files?.length > 0;
    if (hasFiles) {
      // 진행바 표시
      const progressWrap = document.getElementById('logAttachProgress');
      const progressBar  = document.getElementById('logAttachProgressBar');
      const progressPct  = document.getElementById('logAttachProgressPct');
      if (progressWrap) progressWrap.classList.remove('hidden');

      // 저장 버튼 비활성화
      const saveBtn = document.querySelector('.modal [onclick*="submitWorkLog"]');
      if (saveBtn) { saveBtn.disabled = true; saveBtn.innerHTML = '<i class="fas fa-spinner fa-spin mr-1"></i> 업로드 중...'; }

      try {
        await uploadTaskAttachmentsWithDesc(taskId, attachInput.files, String(worklogId), (pct) => {
          if (progressBar) progressBar.style.width = pct + '%';
          if (progressPct) progressPct.textContent = pct + '%';
        }, 'work_log');
      } catch (_) {
        // 업로드 오류는 내부에서 toast 처리됨 — 일지는 이미 저장됨
      }
    }

    toast('작업 일지가 저장되었습니다.');
    // 모달 전체 닫기 후 작업 상세 재오픈 (창 상태 유지)
    document.querySelectorAll('.modal-overlay').forEach(m => m.remove());
    setTimeout(() => showTaskDetail(taskId), 200);
    // 배경 목록도 조용히 갱신 (필터 유지)
    const content = document.getElementById('page-content');
    if (content) {
      if (currentUser?.role === 'worker') renderMyTasksPage(content);
      else renderTasksPage(content);
    }
  } catch(e) {
    toast(e.response?.data?.error || '저장 실패', 'error');
  }
}

