// compressImage: 이미지 파일을 Canvas로 리사이즈·압축 후 File 객체로 반환
// - maxWidth/maxHeight: 최대 해상도 (초과 시 비율 유지하며 축소)
// - quality: JPEG 품질 (0.0~1.0)
// - 동영상/비지원 포맷은 원본 그대로 반환
function compressImage(file, maxWidth = 1920, maxHeight = 1920, quality = 0.82) {
  return new Promise((resolve) => {
    // 동영상은 압축 불가 → 원본 반환
    if (file.type.startsWith('video/') || /\.(mp4|mov|avi|webm|mkv)$/i.test(file.name)) {
      return resolve(file);
    }
    // HEIC 등 Canvas 미지원 포맷은 원본 반환
    if (!/^image\/(jpeg|jpg|png|gif|webp|bmp)$/i.test(file.type) && !/\.(jpe?g|png|gif|webp|bmp)$/i.test(file.name)) {
      return resolve(file);
    }
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        let { width, height } = img;
        // 이미 충분히 작으면 압축 생략 (1MB 미만)
        if (file.size < 1024 * 1024 && width <= maxWidth && height <= maxHeight) {
          return resolve(file);
        }
        if (width > maxWidth || height > maxHeight) {
          const ratio = Math.min(maxWidth / width, maxHeight / height);
          width  = Math.round(width  * ratio);
          height = Math.round(height * ratio);
        }
        const canvas = document.createElement('canvas');
        canvas.width  = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);
        canvas.toBlob((blob) => {
          if (!blob) return resolve(file); // 변환 실패 시 원본
          // 압축 결과가 원본보다 크면 원본 사용
          if (blob.size >= file.size) return resolve(file);
          const compressed = new File([blob], file.name.replace(/\.[^.]+$/, '.jpg'), { type: 'image/jpeg' });
          resolve(compressed);
        }, 'image/jpeg', quality);
      };
      img.onerror = () => resolve(file);
      img.src = e.target.result;
    };
    reader.onerror = () => resolve(file);
    reader.readAsDataURL(file);
  });
}

function previewPhotos(input) {
  const preview = document.getElementById('photoPreview');
  preview.innerHTML = '';
  Array.from(input.files).forEach(file => {
    const div = document.createElement('div');
    div.className = 'photo-thumb';
    const isVideo = file.type.startsWith('video/') || /\.(mp4|mov|avi|webm|mkv)$/i.test(file.name);
    const sizeMB = (file.size / 1024 / 1024).toFixed(1);
    if (isVideo) {
      const url = URL.createObjectURL(file);
      div.innerHTML = `
        <video src="${url}" class="w-full h-full object-cover" muted preload="metadata"></video>
        <div class="overlay"><i class="fas fa-play"></i></div>
        <div class="absolute top-1 left-1 bg-blue-600 text-white text-xs px-1 rounded"><i class="fas fa-video"></i></div>
        <div class="absolute bottom-0 left-0 right-0 bg-black bg-opacity-60 text-white text-xs p-0.5 text-center truncate">${file.name} (${sizeMB}MB)</div>`;
      preview.appendChild(div);
    } else if (file.type.startsWith('image/') || /\.heic$/i.test(file.name)) {
      const reader = new FileReader();
      reader.onload = (e) => {
        div.innerHTML = `<img src="${e.target.result}" alt="${file.name}">
          <div class="overlay"><i class="fas fa-check"></i></div>
          <div class="absolute bottom-0 left-0 right-0 bg-black bg-opacity-50 text-white text-xs p-0.5 text-center truncate">${file.name} (${sizeMB}MB)</div>`;
        preview.appendChild(div);
      };
      reader.readAsDataURL(file);
    }
  });
}

async function submitPhotos(taskId) {
  const input = document.getElementById('photoInput');
  const files = input.files;
  if (files.length === 0) { toast('사진을 선택하세요.', 'error'); return; }

  const btn        = document.getElementById('uploadBtn');
  const cancelBtn  = document.getElementById('uploadCancelBtn');
  const progWrap   = document.getElementById('uploadProgressWrap');
  const progBar    = document.getElementById('uploadProgressBar');
  const progLabel  = document.getElementById('uploadProgressLabel');
  const progPct    = document.getElementById('uploadProgressPct');
  const progSub    = document.getElementById('uploadProgressSub');

  const setProgress = (pct, label, sub='') => {
    if (!progBar) return;
    progBar.style.width = pct + '%';
    if (progLabel) progLabel.textContent = label;
    if (progPct)   progPct.textContent   = Math.round(pct) + '%';
    if (progSub)   progSub.textContent   = sub;
  };

  btn.disabled = true;
  btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> 처리 중...';
  if (cancelBtn) cancelBtn.disabled = true;
  if (progWrap)  progWrap.classList.remove('hidden');
  setProgress(0, '파일 확인 중...');

  const photoType = document.getElementById('photoType').value;
  const caption   = document.getElementById('photoCaption').value;

  // ① 파일 필터링
  const validFiles = [];
  for (const file of files) {
    const isImage = file.type.startsWith('image/') || /\.heic$/i.test(file.name);
    const isVideo = file.type.startsWith('video/') || /\.(mp4|mov|avi|webm|mkv)$/i.test(file.name);
    if (!isImage && !isVideo) {
      toast(`${file.name}: 이미지 또는 동영상 파일만 업로드 가능합니다.`, 'warning');
      continue;
    }
    const maxSize = isVideo ? 500 * 1024 * 1024 : 50 * 1024 * 1024;
    if (file.size > maxSize) {
      toast(`${file.name}: ${isVideo ? '500MB' : '50MB'} 초과 파일은 지원하지 않습니다.`, 'warning');
      continue;
    }
    validFiles.push({ file, isImage, isVideo });
  }

  if (validFiles.length === 0) {
    btn.disabled = false;
    btn.innerHTML = '<i class="fas fa-upload"></i> 업로드';
    if (cancelBtn) cancelBtn.disabled = false;
    if (progWrap)  progWrap.classList.add('hidden');
    return;
  }

  // ② 이미지 압축 (동영상 제외)
  const formData = new FormData();
  formData.append('task_id', taskId);
  formData.append('photo_type', photoType);
  formData.append('caption', caption);

  const imgCount   = validFiles.filter(v => v.isImage).length;
  let compressedN  = 0;
  let totalOrigMB  = 0;
  let totalCompMB  = 0;

  for (let i = 0; i < validFiles.length; i++) {
    const { file, isImage } = validFiles[i];
    const pct = (i / validFiles.length) * 40; // 0~40%: 압축 단계
    if (isImage) {
      setProgress(pct, `이미지 압축 중... (${i+1}/${validFiles.length})`, file.name);
      const origMB = file.size / 1024 / 1024;
      const compressed = await compressImage(file);
      const compMB = compressed.size / 1024 / 1024;
      totalOrigMB += origMB;
      totalCompMB += compMB;
      compressedN++;
      formData.append('photos', compressed);
    } else {
      setProgress(pct, `파일 준비 중... (${i+1}/${validFiles.length})`, file.name);
      formData.append('photos', file);
    }
  }

  // 압축 결과 요약
  const savedMB   = Math.max(0, totalOrigMB - totalCompMB).toFixed(1);
  const savedPct  = totalOrigMB > 0 ? Math.round((1 - totalCompMB/totalOrigMB)*100) : 0;
  const compSummary = imgCount > 0 && savedPct > 5
    ? `이미지 압축 완료 (${totalOrigMB.toFixed(1)}MB → ${totalCompMB.toFixed(1)}MB, ${savedPct}% 절약)`
    : '';

  // ③ XHR 업로드 (진행률 추적)
  setProgress(40, '서버에 업로드 중...', compSummary);

  try {
    const result = await new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest();
      xhr.open('POST', '/api/photos');
      const token = localStorage.getItem('token');
      if (token) xhr.setRequestHeader('Authorization', `Bearer ${token}`);

      xhr.upload.onprogress = (e) => {
        if (!e.lengthComputable) return;
        // 40~95%: 업로드 진행
        const uploadPct = 40 + (e.loaded / e.total) * 55;
        const uploadedMB = (e.loaded / 1024 / 1024).toFixed(1);
        const totalMB    = (e.total  / 1024 / 1024).toFixed(1);
        setProgress(uploadPct, `업로드 중... ${uploadedMB}MB / ${totalMB}MB`, compSummary);
        _showUploadToast('작업 사진', Math.round(uploadPct), validFiles.length);
      };

      xhr.onload = () => {
        try { resolve({ status: xhr.status, data: JSON.parse(xhr.responseText) }); }
        catch(e) { reject(new Error('응답 파싱 오류')); }
      };
      xhr.onerror = () => reject(new Error('네트워크 오류'));
      xhr.send(formData);
    });

    setProgress(100, '완료!');
    _hideUploadToast();
    if (result.status >= 200 && result.status < 300 && result.data.success) {
      const uploadedIds  = result.data.ids || [];
      const countMsg = result.data.count > 0 ? `${result.data.count}개 파일 업로드 완료` : '업로드 완료';
      const compMsg  = imgCount > 0 && savedPct > 5 ? ` (${savedPct}% 압축)` : '';
      toast(countMsg + compMsg);

      // ── 업로드 완료 사진 즉시 표시 (모달 내) ─────────────────────────────
      const listWrap   = document.getElementById('uploadedPhotoList');
      const grid       = document.getElementById('uploadedPhotoGrid');
      const countEl    = document.getElementById('uploadedPhotoCount');
      const divider    = document.getElementById('uploadedDivider');
      const subtitle   = document.getElementById('photoUploadSubtitle');
      if (listWrap && grid && uploadedIds.length > 0) {
        const prevCount = parseInt(countEl?.textContent || '0');
        const newCount  = prevCount + uploadedIds.length;
        if (countEl) countEl.textContent = String(newCount);

        for (const photoId of uploadedIds) {
          const isVideo = false; // photos API는 사진 id 반환
          const thumb = document.createElement('div');
          thumb.className = 'relative rounded-lg overflow-hidden border border-green-200 bg-green-50';
          thumb.style.cssText = 'aspect-ratio:1;cursor:pointer';
          thumb.innerHTML = `
            <img src="${photoImgSrc(photoId)}"
                 class="w-full h-full object-cover"
                 onerror="this.parentElement.innerHTML='<div class=\'w-full h-full flex items-center justify-center text-gray-300\'><i class=\'fas fa-film text-2xl\'></i></div>'">
            <div class="absolute top-1 right-1 bg-green-500 text-white rounded-full" style="width:16px;height:16px;display:flex;align-items:center;justify-content:center;font-size:8px">
              <i class="fas fa-check"></i>
            </div>`;
          grid.appendChild(thumb);
        }
        listWrap.classList.remove('hidden');
        if (divider)  divider.classList.remove('hidden');
        if (subtitle) subtitle.textContent = `${newCount}개 등록 완료 — 추가 등록 가능`;
      }

      // ── 입력 폼 초기화 (추가 등록 가능 상태) ────────────────────────────
      const previewEl = document.getElementById('photoPreview');
      const inputEl   = document.getElementById('photoInput');
      const captionEl = document.getElementById('photoCaption');
      if (previewEl) previewEl.innerHTML = '';
      if (inputEl)   inputEl.value = '';
      if (captionEl) captionEl.value = '';
      if (progWrap)  progWrap.classList.add('hidden');

      btn.disabled = false;
      btn.innerHTML = '<i class="fas fa-upload"></i> 추가 업로드';
      if (cancelBtn) {
        cancelBtn.disabled = false;
        cancelBtn.innerHTML = '<i class="fas fa-check mr-1"></i>완료 (닫기)';
        cancelBtn.className = 'btn btn-primary';
      }

      // ── 사진 탭 즉시 갱신 (업로드 모달 열려있는 상태에서도 탭 갱신) ───────
      // dtab-photo가 DOM에 있으면 바로 갱신 (작업 상세 모달이 열려있는 경우)
      if (document.getElementById('dtab-photo')) {
        _refreshPhotoTab(taskId).catch(() => {});
      }
    } else {
      throw new Error(result.data?.error || `업로드 실패 (${result.status})`);
    }
  } catch(e) {
    console.error('업로드 오류:', e);
    toast(`업로드 실패: ${e.message}`, 'error');
    btn.disabled = false;
    btn.innerHTML = '<i class="fas fa-upload"></i> 업로드';
    if (cancelBtn) cancelBtn.disabled = false;
    setProgress(0, '오류 발생');
    if (progWrap)  progWrap.classList.add('hidden');
  }
}

// ======= 위험성 평가 상세 보기 (작업 탭 전용) =======
async function showTaskRiskDetail(riskId, taskId) {
  try {
    const res = await API.get(`/risk/${riskId}`);
    const ra = res.data;
    const modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.innerHTML = `
    <div class="modal" style="max-width:900px">
      <div class="modal-header">
        <div>
          <h3 class="font-bold text-lg">위험성 평가 상세</h3>
          <p class="text-sm text-gray-500">${ra.task_title} · ${ra.assessor_name} · ${formatDateTime(ra.assessment_date)}</p>
        </div>
        <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 text-xl"><i class="fas fa-times"></i></button>
      </div>
      <div class="modal-body">
        <div class="grid grid-cols-4 gap-3 mb-4 text-sm">
          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">날씨</span><br><b>${ra.weather||'-'}</b></div>
          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">기온</span><br><b>${ra.temperature||'-'}</b></div>
          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">투입인원</span><br><b>${ra.workers_count||0}명</b></div>
          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">상태</span><br>${riskLevelBadge(ra.status)}</div>
        </div>
        ${ra.details?.length > 0 ? `
        <div class="overflow-x-auto">
          <table class="table risk-table text-xs">
            <thead>
              <tr>
                <th>분류</th>
                <th>유해·위험요인</th>
                <th>위험성 내용</th>
                <th colspan="3">개선 전</th>
                <th colspan="3">개선 후</th>
                <th>감소대책</th>
              </tr>
              <tr class="bg-gray-50 text-xs">
                <th></th><th></th><th></th>
                <th>빈도</th><th>강도</th><th>위험도</th>
                <th>빈도</th><th>강도</th><th>위험도</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              ${ra.details.map(d => `
                <tr>
                  <td>${d.category}</td>
                  <td>${d.hazard}</td>
                  <td>${d.risk_factor}</td>
                  <td class="text-center">${d.before_frequency}</td>
                  <td class="text-center">${d.before_severity}</td>
                  <td class="text-center"><span class="risk-score ${getRiskColor(d.before_risk_level)}">${d.before_frequency*d.before_severity}</span></td>
                  <td class="text-center">${d.after_frequency}</td>
                  <td class="text-center">${d.after_severity}</td>
                  <td class="text-center"><span class="risk-score ${getRiskColor(d.after_risk_level)}">${d.after_frequency*d.after_severity}</span></td>
                  <td class="text-xs">${d.control_measures||'-'}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>
        </div>` : '<p class="text-gray-400 text-center py-4">평가 항목이 없습니다.</p>'}
      </div>
      <div class="modal-footer">
        <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">닫기</button>
      </div>
    </div>`;
    document.body.appendChild(modal);
  } catch(e) {
    toast('로드 실패', 'error');
  }
}

// ======= TBM 상세 보기 =======
async function showTbmDetail(tbmId) {
  const overlayEl = document.createElement('div');
  overlayEl.className = 'modal-overlay';
  overlayEl.setAttribute('data-tbm-id', tbmId);
  overlayEl.innerHTML = `<div class="modal" style="max-width:640px"><div class="flex justify-center py-10"><div class="spinner"></div></div></div>`;
  document.body.appendChild(overlayEl);

  async function _reload() {
    // 스크롤 위치 저장
    const modalBody = overlayEl.querySelector('.modal-body');
    const savedScroll = modalBody ? modalBody.scrollTop : 0;
    // 기존 내용 위에 로딩 오버레이만 표시 (깜빡임 최소화)
    const loadingMask = document.createElement('div');
    loadingMask.style.cssText = 'position:absolute;inset:0;background:rgba(255,255,255,0.6);display:flex;align-items:center;justify-content:center;z-index:9;border-radius:12px';
    loadingMask.innerHTML = '<div class="spinner"></div>';
    const modalEl = overlayEl.querySelector('.modal');
    if (modalEl) { modalEl.style.position = 'relative'; modalEl.appendChild(loadingMask); }
    try {
      const [res, sigsRes, approvalRes] = await Promise.all([
        API.get(`/tbm/${tbmId}`),
        API.get(`/tbm/${tbmId}/signatures`).catch(() => ({ data: [] })),
        API.get(`/tbm/${tbmId}/approval-status`).catch(() => ({ data: {} }))
      ]);
      const tbm = res.data;
      const signatures = Array.isArray(sigsRes.data) ? sigsRes.data : [];
      const approval = approvalRes.data || {};
      // BUG-058: TBM 안전조치 사진 (체크리스트 tbm_sections)
      let _tbmDetailSections = [];
      if (tbm.task_id) {
        try {
          const clRes = await API.get('/checklist/task/' + tbm.task_id);
          _tbmDetailSections = clRes.data?.tbm_sections || [];
        } catch(_) {}
      }
      const mySig = signatures.find(s => s.user_id === currentUser.id);
      // tbm_done 카드 배지도 함께 갱신 (task_id 기준)
      if (tbm.task_id) {
        const attendees = Array.isArray(tbm.attendees) ? tbm.attendees : [];
        // BUG-088: 결재 서명(approval_*) 제외 — 근로자(attendee/conductor) 서명만 카운트
        const workerSigsForBadge = signatures.filter(s => s.role === 'attendee' || s.role === 'conductor');
        const signedNames = new Set(workerSigsForBadge.map(s => s.user_name || '').filter(Boolean));
        const signedCount = attendees.length > 0 ? attendees.filter(n => signedNames.has(n)).length : workerSigsForBadge.length;
        const total = attendees.length || workerSigsForBadge.length;
        const badge = document.getElementById(`tbm-sig-badge-${tbm.task_id}`);
        if (badge) {
          const allSigned = total > 0 && signedCount >= total;
          badge.textContent = allSigned ? `✅ 전원 서명완료 (${total}명)` : total === 0 ? '서명 없음' : `✍️ ${signedCount}/${total}명 서명`;
          badge.style.color = allSigned ? '#059669' : total === 0 ? '#9CA3AF' : '#B45309';
        }
      }

      // 내 역할: tbm 실시자이면 conductor, 아니면 attendee
      const myRole = (tbm.conductor_id === currentUser.id || tbm.conducted_by === currentUser.id) ? 'conductor' : 'attendee';
      // showTbmDetail 스코프 전용 변수
      const _tbmTaskId   = tbm.task_id || '';
      const _tbmIsWorker = currentUser.role === 'worker';

      // ── 참가자 명단 기준 서명 현황 계산 ────────────────────────────────────
      // BUG-088: 결재 서명(approval_*)은 카운트에서 제외 — 근로자 서명만 집계
      const attendees = Array.isArray(tbm.attendees) ? tbm.attendees : [];
      // 이름→서명 매핑 (동명이인 시 첫 번째 서명 사용) — attendee/conductor만
      const workerSigs = signatures.filter(s => s.role === 'attendee' || s.role === 'conductor');
      const sigByName  = {};
      for (const s of workerSigs) { if (s.user_name && !sigByName[s.user_name]) sigByName[s.user_name] = s; }
      // 참가자 명단이 있으면 명단 기준, 없으면 근로자 서명자 목록만 표시
      const signedCount   = workerSigs.length;
      const totalCount    = attendees.length || signedCount;
      const unsignedNames = attendees.filter(n => !sigByName[n]);
      const allSigned     = attendees.length > 0 ? unsignedNames.length === 0 : signedCount > 0;

      // ── 참가자별 서명 행 렌더링 ─────────────────────────────────────────────
      // 명단 있으면 명단 기준, 없으면 서명자 목록만
      const attendeeRows = attendees.length > 0
        ? attendees.map((name, idx) => {
            const sig     = sigByName[name];
            const isMine  = sig && sig.user_id === currentUser.id;
            const dateStr = sig ? (sig.signed_at||'').slice(0,16).replace('T',' ') : '';
            const sigImg  = sig?.sign_data
              ? `<img src="${sig.sign_data}" style="height:28px;max-width:64px;object-fit:contain;border:1px solid #e5e7eb;border-radius:4px;background:#fff" title="서명">`
              : '';
            if (sig) {
              // 서명 완료
              return `<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:#F0FDF4;border:1px solid #BBF7D0;border-radius:8px;font-size:12px">
                <span style="width:20px;height:20px;border-radius:50%;background:#10B981;display:flex;align-items:center;justify-content:center;flex-shrink:0">
                  <i class="fas fa-check" style="color:white;font-size:9px"></i>
                </span>
                <span style="font-weight:700;color:#065F46;flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${name}</span>
                ${sigImg}
                <span style="font-size:10px;color:#6B7280;white-space:nowrap">${dateStr}</span>
                ${isMine ? `<button onclick="_tbmUnsign(${tbmId},${sig.id})" style="background:none;border:none;color:#EF4444;cursor:pointer;padding:2px;font-size:10px;flex-shrink:0" title="서명 취소"><i class="fas fa-undo"></i></button>` : ''}
              </div>`;
            } else {
              // 미서명 — 클릭 가능한 서명 버튼
              return `<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:#FEF2F2;border:1.5px solid #FECACA;border-radius:8px;font-size:12px;cursor:pointer"
                onclick="_tbmSignFor(${tbmId},'${name.replace(/'/g,"\\'")}','attendee')">
                <span style="width:20px;height:20px;border-radius:50%;background:#FCA5A5;display:flex;align-items:center;justify-content:center;flex-shrink:0">
                  <i class="fas fa-pen-nib" style="color:white;font-size:9px"></i>
                </span>
                <span style="font-weight:700;color:#991B1B;flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${name}</span>
                <span style="font-size:11px;color:#EF4444;font-weight:600;white-space:nowrap">미서명</span>
                <i class="fas fa-chevron-right" style="color:#EF4444;font-size:10px"></i>
              </div>`;
            }
          })
        : signatures.map(s => {
            const isMine  = s.user_id === currentUser.id;
            const roleLabel = s.role === 'conductor' ? '실시자' : '참석자';
            const dateStr = (s.signed_at||'').slice(0,16).replace('T',' ');
            const sigImg  = s.sign_data
              ? `<img src="${s.sign_data}" style="height:28px;max-width:64px;object-fit:contain;border:1px solid #e5e7eb;border-radius:4px;background:#fff">`
              : '<i class="fas fa-check" style="color:#10B981;font-size:10px"></i>';
            return `<div style="display:flex;align-items:center;gap:8px;padding:7px 10px;background:white;border:1px solid #FDE68A;border-radius:8px;margin-bottom:4px;font-size:12px">
              <i class="fas fa-check-circle" style="color:#10B981;font-size:14px;flex-shrink:0"></i>
              <span style="display:inline-block;padding:1px 7px;border-radius:9999px;font-size:10px;font-weight:700;background:#FDE8F3;color:#A8005A;flex-shrink:0">${roleLabel}</span>
              <span style="font-weight:700;color:#1F2937;flex:1">${s.user_name||'-'}</span>
              ${sigImg}
              <span style="font-size:10px;color:#9CA3AF;white-space:nowrap">${dateStr}</span>
              ${isMine ? `<button onclick="_tbmUnsign(${tbmId},${s.id})" style="background:none;border:none;color:#EF4444;cursor:pointer;padding:0;font-size:10px" title="서명 취소"><i class="fas fa-undo"></i></button>` : ''}
            </div>`;
          });

      // ── 서명 현황 헤더 배지 ──────────────────────────────────────────────────
      const progressPct = totalCount > 0 ? Math.round(signedCount / totalCount * 100) : 0;
      const progressColor = allSigned ? '#10B981' : signedCount > 0 ? '#F59E0B' : '#EF4444';

      overlayEl.querySelector('.modal').innerHTML = `
      <div class="modal-header" style="background:linear-gradient(135deg,#1D4ED8,#3B82F6);color:white;border-radius:12px 12px 0 0;padding:14px 18px;display:flex;align-items:flex-start;justify-content:space-between">
        <div>
          <div style="font-size:10px;color:rgba(255,255,255,0.7);margin-bottom:2px">TBM (Tool Box Meeting)</div>
          <h3 style="font-weight:700;font-size:15px;margin:0"><i class="fas fa-hard-hat" style="margin-right:6px"></i>TBM 상세</h3>
          <p style="font-size:11px;color:rgba(255,255,255,0.65);margin:2px 0 0">${tbm.task_title} · ${formatDateTime(tbm.tbm_date)}</p>
        </div>
        <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:rgba(255,255,255,0.8);font-size:20px;cursor:pointer;padding:0"><i class="fas fa-times"></i></button>
      </div>
      <div class="modal-body" style="max-height:72vh;overflow-y:auto">
        <!-- 기본정보 -->
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:12px;font-size:12px">
          <div style="background:#F0F9FF;border-radius:8px;padding:8px 10px"><span style="color:#9CA3AF">실시자</span><br><b>${tbm.conductor_name}</b></div>
          <div style="background:#F0F9FF;border-radius:8px;padding:8px 10px"><span style="color:#9CA3AF">위치</span><br><b>${tbm.location||'-'}</b></div>
          <div style="background:#F0F9FF;border-radius:8px;padding:8px 10px"><span style="color:#9CA3AF">날씨/기온</span><br><b>${tbm.weather||'-'} / ${tbm.temperature||'-'}°C</b></div>
          <div style="background:#F0F9FF;border-radius:8px;padding:8px 10px"><span style="color:#9CA3AF">참석인원</span><br>
            <b>${totalCount}명</b>
            <span style="font-size:10px;font-weight:600;margin-left:6px;padding:1px 7px;border-radius:9999px;background:${allSigned?'#D1FAE5':'#FEF3C7'};color:${allSigned?'#065F46':'#92400E'}">
              서명 ${signedCount}/${totalCount}
            </span>
          </div>
        </div>

        <!-- 서명 진행률 바 -->
        <div style="margin-bottom:14px">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
            <span style="font-size:11px;font-weight:700;color:#374151">
              <i class="fas fa-signature" style="margin-right:4px;color:#D97706"></i>서명 진행 현황
            </span>
            <span style="font-size:11px;font-weight:700;color:${progressColor}">${signedCount}/${totalCount}명 완료</span>
          </div>
          <div style="height:8px;background:#F3F4F6;border-radius:9999px;overflow:hidden">
            <div style="height:100%;width:${progressPct}%;background:${progressColor};border-radius:9999px;transition:width .4s"></div>
          </div>
          ${allSigned
            ? `<div style="font-size:11px;color:#059669;font-weight:600;margin-top:4px;text-align:center"><i class="fas fa-check-circle mr-1"></i>전원 서명 완료 — 작업 개시 가능합니다</div>`
            : unsignedNames.length > 0
              ? `<div style="font-size:11px;color:#DC2626;margin-top:4px"><i class="fas fa-exclamation-circle mr-1"></i>미서명: ${unsignedNames.join(', ')}</div>`
              : `<div style="font-size:11px;color:#9CA3AF;margin-top:4px">아직 서명이 없습니다</div>`}
        </div>

        <div style="margin-bottom:12px">
          <div style="font-size:12px;font-weight:700;color:#374151;margin-bottom:6px"><i class="fas fa-book" style="margin-right:4px;color:#3B82F6"></i>작업 내용 및 안전교육 사항</div>
          <div style="background:#F9FAFB;padding:10px 12px;border-radius:8px;font-size:12px;white-space:pre-wrap">${tbm.safety_topics||'-'}</div>
        </div>
        <div style="margin-bottom:12px">
          <div style="font-size:12px;font-weight:700;color:#374151;margin-bottom:6px"><i class="fas fa-exclamation-triangle" style="margin-right:4px;color:#F59E0B"></i>주의사항</div>
          <div style="background:#FFFBEB;padding:10px 12px;border-radius:8px;font-size:12px;white-space:pre-wrap">${tbm.precautions||'-'}</div>
        </div>
        ${tbm.special_notes ? `
        <div style="margin-bottom:12px">
          <div style="font-size:12px;font-weight:700;color:#374151;margin-bottom:6px"><i class="fas fa-sticky-note" style="margin-right:4px;color:#8B5CF6"></i>특이사항</div>
          <div style="background:#F5F3FF;padding:10px 12px;border-radius:8px;font-size:12px">${tbm.special_notes}</div>
        </div>` : ''}

        <!-- 서명 패널 -->
        <div style="background:${allSigned?'#F0FDF4':'#FFF8E7'};border:1.5px solid ${allSigned?'#86EFAC':'#FDE68A'};border-radius:12px;padding:12px 14px;margin-bottom:8px">
          <div style="font-size:12px;font-weight:700;color:${allSigned?'#065F46':'#92400E'};margin-bottom:10px;display:flex;align-items:center;justify-content:space-between">
            <span><i class="fas fa-pen-nib" style="margin-right:5px;color:${allSigned?'#10B981':'#D97706'}"></i>참가자 서명
              <span style="font-size:10px;padding:1px 7px;border-radius:9999px;margin-left:5px;font-weight:600;background:${allSigned?'#D1FAE5':'#FEF3C7'};color:${allSigned?'#065F46':'#92400E'}">${signedCount}/${totalCount}</span>
            </span>
            <div style="display:flex;align-items:center;gap:5px">
              <span style="font-size:9px;font-weight:400;color:#B45309">산업안전보건법 제29조</span>
              <button onclick="_tbmEditAttendees(${tbmId},${JSON.stringify(attendees).replace(/"/g,'&quot;')})"
                style="padding:2px 8px;background:#685182;color:white;border:none;border-radius:6px;font-size:10px;font-weight:600;cursor:pointer;white-space:nowrap">
                <i class="fas fa-user-edit" style="margin-right:2px"></i>참가자 편집
              </button>
            </div>
          </div>

          <!-- 참가자별 서명 현황 (BUG-058: 2열 grid) -->
          <div style="margin-bottom:10px">
            ${attendeeRows.length > 0
              ? `<div style="display:grid;grid-template-columns:1fr 1fr;gap:5px">${attendeeRows.join('')}</div>`
              : '<div style="font-size:11px;color:#9CA3AF;text-align:center;padding:8px"><i class="fas fa-pen-nib" style="margin-right:4px"></i>서명 없음</div>'}
          </div>

          <!-- 내 서명 버튼 (미서명 시) -->
          ${!mySig ? `
          <button onclick="_tbmSign(${tbmId},'${myRole}')"
            style="width:100%;padding:10px;background:linear-gradient(135deg,#D97706,#F59E0B);color:white;border:none;border-radius:10px;font-size:13px;font-weight:700;cursor:pointer;margin-bottom:8px;display:flex;align-items:center;justify-content:center;gap:6px">
            <i class="fas fa-pen-nib"></i> 내 서명 추가
            <span style="font-size:11px;opacity:0.85">(${myRole==='conductor'?'실시자':'참석자'})</span>
          </button>` : ''}

          <!-- 현장 순차 서명 수집 버튼 (비근로자 or 미서명자 있을 때) -->
          ${unsignedNames.length > 0 ? `
          <button onclick="_tbmCollectSign(${tbmId}, ${JSON.stringify(unsignedNames).replace(/"/g,'&quot;')})"
            style="width:100%;padding:10px;background:linear-gradient(135deg,#D70072,#FF349E);color:white;border:none;border-radius:10px;font-size:13px;font-weight:700;cursor:pointer;margin-bottom:8px;display:flex;align-items:center;justify-content:center;gap:6px">
            <i class="fas fa-users"></i> 현장 순차 서명 받기
            <span style="font-size:11px;opacity:0.85">(미서명 ${unsignedNames.length}명)</span>
          </button>` : ''}

          <!-- 서명 요청 보내기 (전체 공개) -->
          ${true ? `
          <button onclick="_tbmSendSignRequest(${tbmId},${_tbmTaskId})"
            style="width:100%;padding:8px;background:linear-gradient(135deg,#685182,#8E72A8);color:white;border:none;border-radius:10px;font-size:12px;font-weight:600;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:5px">
            <i class="fas fa-paper-plane"></i> 앱 서명 요청 보내기
          </button>` : ''}
        </div>

        <!-- ── 결재 서명 섹션 ──────────────────────────────────────────── -->
        ${(() => {
          const pos  = currentUser?.position || '';
          const role = currentUser?.role || '';
          const isAdmin = role === 'admin';

          const hasSig   = r => !!(r && (r.sign_data || r.user_name));
          const sSig = approval.approval_safety;
          const gSig = approval.approval_general;
          // BUG-089: 대표이사(approval_ceo) 제거 — 안전관리자 → 총괄책임 2단계로 변경
          // const cSig = approval.approval_ceo;

          // 서명 순서: 안전관리자 → 총괄책임
          const canSafety  = !hasSig(sSig) && (pos === '안전관리자' || isAdmin);
          const canGeneral = !hasSig(gSig) && hasSig(sSig) && (pos === '현장대리인' || isAdmin);
          // canCeo 제거됨

          function approvalCard(sig, approvalRole, label, canSign, locked) {
            const bg    = hasSig(sig) ? '#F0FDF4' : canSign ? '#EDE9FE' : '#F9FAFB';
            const border= hasSig(sig) ? '#86EFAC'  : canSign ? '#A78BFA' : '#E5E7EB';
            const sigImg = sig?.sign_data
              ? `<img src="${sig.sign_data}" style="height:36px;max-width:80px;object-fit:contain;border:1px solid #d1d5db;border-radius:4px;background:#fff;display:block;margin:4px auto 2px">`
              : '';
            const sigName = sig?.user_name ? `<div style="font-size:10px;color:#374151;font-weight:700;margin-top:2px">${sig.user_name}</div>` : '';
            const sigDate = sig?.signed_at ? `<div style="font-size:9px;color:#9CA3AF">${sig.signed_at.slice(0,10)}</div>` : '';
            const checkBadge = hasSig(sig)
              ? `<div style="font-size:10px;color:#059669;font-weight:700;margin-bottom:2px"><i class="fas fa-check-circle mr-1"></i>서명완료</div>`
              : locked ? `<div style="font-size:10px;color:#9CA3AF;margin-bottom:2px"><i class="fas fa-lock mr-1"></i>대기중</div>`
              : `<div style="font-size:10px;color:#7C3AED;font-weight:700;margin-bottom:2px"><i class="fas fa-pen-nib mr-1"></i>서명필요</div>`;

            return `
              <div style="flex:1;background:${bg};border:1.5px solid ${border};border-radius:10px;padding:10px 8px;text-align:center;min-width:0">
                <div style="font-size:11px;font-weight:700;color:#374151;margin-bottom:4px">${label}</div>
                ${checkBadge}
                ${sigImg}${sigName}${sigDate}
                ${canSign ? `
                <button onclick="_tbmApprovalSignInApp(${tbmId},'${approvalRole}')"
                  style="margin-top:6px;width:100%;padding:5px 4px;background:#4E3A63;color:white;border:none;border-radius:7px;font-size:11px;font-weight:700;cursor:pointer">
                  ✍ 서명하기
                </button>` : ''}
              </div>`;
          }

          return `
          <div style="background:#F5F3FF;border:1.5px solid #DDD6FE;border-radius:12px;padding:12px 14px;margin-bottom:8px">
            <div style="font-size:12px;font-weight:700;color:#4E3A63;margin-bottom:10px;display:flex;align-items:center;gap:6px">
              <i class="fas fa-stamp" style="color:#7C3AED"></i>결재 서명
              <span style="font-size:10px;font-weight:400;color:#9CA3AF">안전관리자 → 총괄책임 순</span>
            </div>
            <div style="display:flex;gap:8px">
              ${approvalCard(sSig, 'approval_safety',  '안전관리자', canSafety, false)}
              ${approvalCard(gSig, 'approval_general', '총괄책임',   canGeneral, !hasSig(sSig))}
            </div>
            ${!canSafety && !canGeneral && (!hasSig(sSig) || !hasSig(gSig)) ? `
            <div style="font-size:10px;color:#9CA3AF;margin-top:8px;text-align:center">
              <i class="fas fa-info-circle mr-1"></i>
              ${!hasSig(sSig) ? '안전관리자가 먼저 서명해야 합니다.' :
                '안전관리자 서명 완료. 총괄책임 서명 대기 중입니다.'}
            </div>` : ''}
          </div>`;
        })()}

        <!-- BUG-058: TBM 안전조치 촬영사진 미리보기 섹션 -->
        ${(() => {
          const secs = (_tbmDetailSections || []);
          const allPhotos = secs.flatMap(sec => {
            let ps = [];
            try { ps = typeof sec.photos === 'string' ? JSON.parse(sec.photos) : (sec.photos || []); } catch(_) {}
            return ps.filter(p => p.file_path).map(p => ({ ...p, section_name: sec.section_name || '' }));
          });
          if (!allPhotos.length) return '';
          const photoItems = allPhotos.map(p => {
            const imgSrc = tbmPhotoImgSrc(p.id);
            const safeLabel = (p.label||'').replace(/'/g,"\\'").replace(/"/g,'&quot;');
            const dispLabel = (p.label||'').replace(/</g,'&lt;');
            const dispSection = (p.section_name||'').replace(/</g,'&lt;');
            return `<div style="border:1px solid #E5E7EB;border-radius:8px;overflow:hidden;cursor:pointer"
              onclick="showTbmPhotoPreview('${imgSrc}','${safeLabel}')">
              <img src="${imgSrc}" style="width:100%;aspect-ratio:4/3;object-fit:cover" onerror="this.style.opacity='.3'">
              <div style="padding:3px 5px;font-size:10px;color:#374151;background:#F9FAFB;border-top:1px solid #E5E7EB;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">
                [${dispSection}] ${dispLabel}
              </div>
            </div>`;
          }).join('');
          return `
          <div style="background:#F0F9FF;border:1.5px solid #BAE6FD;border-radius:12px;padding:12px 14px;margin-bottom:8px">
            <div style="font-size:12px;font-weight:700;color:#0369A1;margin-bottom:8px">
              <i class="fas fa-camera" style="margin-right:4px"></i>TBM 안전조치 촬영사진
              <span style="font-size:10px;font-weight:400;color:#0284C7;margin-left:5px">${allPhotos.length}장</span>
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
              ${photoItems}
            </div>
          </div>`;
        })()}
      </div>
      <div class="modal-footer" style="display:flex;gap:8px;padding:10px 16px;border-top:1px solid #E5E7EB;background:white;border-radius:0 0 12px 12px">
        <button onclick="_tbmPrint(${tbmId})"
          style="padding:6px 14px;background:#4E3A63;color:white;border:none;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;display:flex;align-items:center;gap:4px">
          <i class="fas fa-print"></i> 인쇄
        </button>
        ${_tbmTaskId ? `
        <button onclick="this.closest('.modal-overlay').remove();_openTbmPhotoModal(null,${_tbmTaskId})"
          style="padding:6px 14px;background:#0891B2;color:white;border:none;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;display:flex;align-items:center;gap:4px">
          <i class="fas fa-camera"></i> 사진 등록
        </button>` : ''}
        ${allSigned ? `
        <button onclick="_tbmShare(${tbmId}, this)"
          style="padding:6px 14px;background:#0EA5E9;color:white;border:none;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;display:flex;align-items:center;gap:4px">
          <i class="fas fa-share-alt"></i> 공유
        </button>` : ''}
        ${(currentUser?.role === 'admin' || tbm.conductor_id === currentUser?.id) ? `
        <button onclick="_deleteTbm(${tbmId},${_tbmTaskId||'null'})"
          style="padding:6px 14px;background:#FEF2F2;color:#DC2626;border:1px solid #FECACA;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;display:flex;align-items:center;gap:4px">
          <i class="fas fa-trash-alt"></i> TBM 삭제
        </button>` : ''}
        <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline" style="margin-left:auto">닫기</button>
      </div>`;

      // 스크롤 위치 복원
      const newModalBody = overlayEl.querySelector('.modal-body');
      if (newModalBody && savedScroll) newModalBody.scrollTop = savedScroll;

    } catch(e) {
      overlayEl.remove();
      toast('로드 실패', 'error');
    }
  }

  overlayEl._reload = _reload;
  await _reload();
}

// ── TBM 결재 서명 (앱 내 서명 패드) ──────────────────────────────────────────
async function _tbmApprovalSignInApp(tbmId, approvalRole) {
  const LABELS = {
    approval_safety:  '안전관리자 서명',
    approval_general: '총괄책임 결재 서명',
    // BUG-089: approval_ceo 제거됨
  };
  const DESCS = {
    approval_safety:  '안전관리자로서 TBM 회의록을 확인하고 서명합니다.',
    approval_general: '총괄책임으로서 TBM 회의록을 결재합니다.',
    // BUG-089: approval_ceo 제거됨
  };
  const signData = await showSignaturePad({
    title:    LABELS[approvalRole] || '결재 서명',
    subtitle: DESCS[approvalRole]  || '',
    penColor: '#1a1a1a'
  });
  if (signData === null) return;  // 취소
  try {
    await API.post(`/tbm/${tbmId}/approval-sign`, {
      approval_role: approvalRole,
      sign_data: signData
    });
    toast(LABELS[approvalRole] + ' 완료', 'success');
    // 모달 즉시 갱신
    const overlay = document.querySelector(`.modal-overlay[data-tbm-id="${tbmId}"]`);
    if (overlay && overlay._reload) await overlay._reload();
  } catch(e) {
    toast(e.response?.data?.error || '결재 서명 처리 실패', 'error');
  }
}

// ── 교육일지 결재 서명 [FEAT-060] ────────────────────────────────────────────
async function _eduApprovalSignInApp(sessionId, approvalRole, eduType) {
  const LABELS = {
    approval_safety:  '안전관리자 서명',
    approval_general: '현장대리인 결재 서명',
    approval_ceo:     '대표이사 최종 결재',
  };
  const DESCS = {
    approval_safety:  '안전관리자로서 교육일지를 확인하고 서명합니다.',
    approval_general: '현장대리인으로서 교육일지를 결재합니다.',
    approval_ceo:     '대표이사로서 교육일지를 최종 결재합니다.',
  };
  const signData = await showSignaturePad({
    title:    LABELS[approvalRole] || '결재 서명',
    subtitle: DESCS[approvalRole]  || '',
    penColor: '#1a1a1a'
  });
  if (signData === null) return;  // 취소
  try {
    await API.post(`/education/sessions/${sessionId}/approval-sign`, {
      approval_role: approvalRole,
      sign_data: signData
    });
    toast(LABELS[approvalRole] + ' 완료', 'success');
    // 모달 갱신 (기존 모달 닫고 재오픈)
    document.querySelectorAll('.modal-overlay').forEach(el => el.remove());
    showEduDetailModal(sessionId, eduType);
  } catch(e) {
    toast(e.response?.data?.error || '결재 서명 처리 실패', 'error');
  }
}

// ── 출력 미리보기 공통 오버레이 헬퍼 (BUG-094: Android WebView window.close() 차단 대응) ─────
// window.open() + window.close() 대신 현재 페이지 위에 전체화면 오버레이 iframe을 띄웁니다.
// HTML 내부의 닫기 버튼은 window.parent.postMessage('closePrintOverlay','*') 를 호출합니다.
//
// ★ 인쇄 방식: Blob URL → iframe.src (sandbox 없음)
//   - srcdoc + sandbox 방식: Chrome에서 window.print() 호출 시 부모 창을 인쇄하는 버그 존재
//   - Blob URL + src 방식: iframe이 독립 origin으로 처리되어 window.print()가 iframe 자체를 인쇄
//   - sandbox 속성 제거: allow-modals 없이도 print 다이얼로그 열림 (blob: URL은 별도 origin)
function _openPrintOverlay(htmlContent) {
  // 기존 오버레이 제거
  const existing = document.getElementById('__print-overlay__');
  if (existing) existing.remove();

  // 기존 blob URL 정리
  if (window.__printBlobUrl__) {
    URL.revokeObjectURL(window.__printBlobUrl__);
    window.__printBlobUrl__ = null;
  }

  const overlay = document.createElement('div');
  overlay.id = '__print-overlay__';
  overlay.style.cssText = [
    'position:fixed', 'inset:0', 'z-index:99999',
    'background:#1f2937', 'display:flex', 'flex-direction:column',
  ].join(';');

  // ── 로딩 스피너 ──
  const spinner = document.createElement('div');
  spinner.style.cssText = [
    'position:absolute','inset:0','z-index:1',
    'display:flex','flex-direction:column','align-items:center','justify-content:center',
    'background:#1f2937','color:#fff','gap:14px'
  ].join(';');
  spinner.innerHTML = '<div style="width:40px;height:40px;border:4px solid #374151;border-top-color:#D70072;border-radius:50%;animation:ps 0.8s linear infinite"></div>' +
    '<div style="font-size:13px;color:#9ca3af">불러오는 중...</div>' +
    '<style>@keyframes ps{to{transform:rotate(360deg)}}</style>';
  overlay.appendChild(spinner);

  const iframe = document.createElement('iframe');
  // sandbox 속성 없음 — blob: URL iframe은 별도 origin이므로 window.print()가 자신을 인쇄
  iframe.style.cssText = 'flex:1;width:100%;border:none;opacity:0;transition:opacity 0.2s';

  iframe.addEventListener('load', function() {
    spinner.style.display = 'none';
    iframe.style.opacity = '1';
  });

  overlay.appendChild(iframe);
  document.body.appendChild(overlay);

  // ★ Blob URL 방식으로 src 설정 (srcdoc 대신)
  // blob: URL은 별도 origin → window.print() = iframe 자신을 인쇄 (부모창 인쇄 버그 없음)
  const blob = new Blob([htmlContent], { type: 'text/html;charset=utf-8' });
  const blobUrl = URL.createObjectURL(blob);
  window.__printBlobUrl__ = blobUrl;
  iframe.src = blobUrl;

  // ── 메시지 수신: 닫기 / TBM 결재 서명 후 재출력 ──
  function _onCloseMsg(e) {
    const msg = e.data;
    if (msg === 'closePrintOverlay') {
      overlay.remove();
      if (window.__printBlobUrl__) {
        URL.revokeObjectURL(window.__printBlobUrl__);
        window.__printBlobUrl__ = null;
      }
      window.removeEventListener('message', _onCloseMsg);
    } else if (msg && msg.type === 'reloadTbmPrint' && msg.tbmId) {
      // blob URL은 reload() 불가 → 오버레이 닫고 _tbmPrint() 재호출
      overlay.remove();
      if (window.__printBlobUrl__) {
        URL.revokeObjectURL(window.__printBlobUrl__);
        window.__printBlobUrl__ = null;
      }
      window.removeEventListener('message', _onCloseMsg);
      setTimeout(() => _tbmPrint(msg.tbmId), 150);
    }
  }
  window.addEventListener('message', _onCloseMsg);
}

// ── TBM 서명 / 인쇄 전역 함수 ────────────────────────────────────────────────

// 특정 참가자 이름으로 서명 받기 (참가자 행 클릭 시 호출)
async function _tbmSignFor(tbmId, personName, role) {
  const signData = await showSignaturePad({
    title: `TBM 서명 — ${personName}`,
    subtitle: `${personName} 님이 직접 서명해 주세요`,
    penColor: '#1a1a1a'
  });
  if (signData === null) return;
  try {
    await API.post('/tbm/' + tbmId + '/signatures', {
      role,
      sign_data: signData,
      signer_name: personName   // 서버에서 user_name 매핑에 사용
    });
    toast(`${personName} 서명 등록 완료`, 'success');
    const overlay = document.querySelector('.modal-overlay[data-tbm-id="' + tbmId + '"]');
    if (overlay && overlay._reload) await overlay._reload();
  } catch(e) {
    toast(e.response?.data?.error || '서명 등록 실패', 'error');
  }
}

// 현장 순차 서명 수집 — 미서명자 목록을 순서대로 서명 패드 호출
async function _tbmCollectSign(tbmId, unsignedNames) {
  // unsignedNames 는 HTML attribute 에서 &quot; 복원 필요
  const names = Array.isArray(unsignedNames) ? unsignedNames : [];
  if (names.length === 0) { toast('모든 참가자가 서명 완료했습니다.', 'success'); return; }

  // 진행 상태 모달
  const prog = document.createElement('div');
  prog.className = 'modal-overlay modal-sm';
  prog.style.zIndex = '10010';
  prog.innerHTML = `
  <div class="modal" style="max-width:380px;text-align:center">
    <div class="modal-header" style="background:linear-gradient(135deg,#D70072,#FF349E);color:white">
      <div><i class="fas fa-users mr-2"></i><b>현장 순차 서명 수집</b></div>
      <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer">×</button>
    </div>
    <div class="modal-body" style="padding:20px 24px">
      <div id="_collectProgBar" style="height:6px;background:#F3F4F6;border-radius:9999px;overflow:hidden;margin-bottom:12px">
        <div id="_collectProgFill" style="height:100%;width:0%;background:#D70072;border-radius:9999px;transition:width .3s"></div>
      </div>
      <div id="_collectStatus" style="font-size:14px;font-weight:700;color:#1F2937;margin-bottom:6px">서명 준비 중...</div>
      <div id="_collectSub" style="font-size:12px;color:#6B7280"></div>
    </div>
  </div>`;
  document.body.appendChild(prog);

  let completed = 0;
  const total = names.length;

  for (let i = 0; i < names.length; i++) {
    const name = names[i];

    // 진행 바 업데이트
    const fill = prog.querySelector('#_collectProgFill');
    const stat = prog.querySelector('#_collectStatus');
    const sub  = prog.querySelector('#_collectSub');
    if (fill) fill.style.width = Math.round(i / total * 100) + '%';
    if (stat) stat.textContent = `${name} 님 서명 대기`;
    if (sub)  sub.textContent  = `${i + 1} / ${total} 명`;

    const signData = await showSignaturePad({
      title: `TBM 서명 — ${name}`,
      subtitle: `${name} 님이 직접 서명해 주세요 (${i+1}/${total})`,
      penColor: '#1a1a1a'
    });

    if (signData === null) {
      // 취소 — 이 사람 건너뛰기 여부 확인
      const skip = await showInfoConfirm(
        `${name} 님 서명을 건너뛸까요?`,
        '나머지 미서명자 서명을 계속 진행합니다.',
        '건너뛰기'
      );
      if (!skip) break; // 전체 중단
      continue;         // 이 사람만 건너뜀
    }

    try {
      await API.post('/tbm/' + tbmId + '/signatures', {
        role: 'attendee',
        sign_data: signData,
        signer_name: name
      });
      completed++;
    } catch(e) {
      toast(`${name} 서명 저장 실패`, 'error');
    }
  }

  // 완료 처리
  prog.remove();
  if (completed > 0) {
    toast(`${completed}명 서명 완료!`, 'success');
    const overlay = document.querySelector('.modal-overlay[data-tbm-id="' + tbmId + '"]');
    if (overlay && overlay._reload) await overlay._reload();
    // 배지도 즉시 갱신
    _refreshTbmSigBadge(tbmId);
  }
}

// ── TBM 참가자 명단 편집 모달 ────────────────────────────────────────────────
// attendees: string[] — 현재 참가자 목록
async function _tbmEditAttendees(tbmId, attendees) {
  const current = Array.isArray(attendees) ? [...attendees] : [];

  // 편집 모달 생성
  const modal = document.createElement('div');
  modal.className = 'modal-overlay modal-sm';
  modal.style.zIndex = '10010';
  modal.innerHTML = `
  <div class="modal" style="max-width:420px">
    <div class="modal-header" style="background:linear-gradient(135deg,#685182,#8E72A8);color:white">
      <div><i class="fas fa-user-edit mr-2"></i><b>TBM 참가자 편집</b></div>
      <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer;padding:0">×</button>
    </div>
    <div class="modal-body" style="padding:16px 18px">
      <div style="font-size:12px;color:#6B7280;margin-bottom:10px">
        <i class="fas fa-info-circle" style="margin-right:4px;color:#685182"></i>
        참가자를 추가하거나 삭제할 수 있습니다. 서명된 참가자의 서명 기록은 유지됩니다.
      </div>

      <!-- 현재 참가자 목록 -->
      <div style="margin-bottom:12px">
        <div style="font-size:12px;font-weight:700;color:#374151;margin-bottom:6px">현재 참가자</div>
        <div id="_attendee-list" style="min-height:40px;border:1.5px solid #E5E7EB;border-radius:8px;padding:8px;background:#F9FAFB">
          ${current.length === 0
            ? '<div style="font-size:12px;color:#9CA3AF;text-align:center;padding:6px">참가자 없음</div>'
            : current.map((name, i) => `
              <div id="_att-row-${i}" style="display:flex;align-items:center;gap:6px;padding:5px 6px;margin-bottom:4px;background:white;border:1px solid #E5E7EB;border-radius:6px">
                <i class="fas fa-user" style="color:#685182;font-size:11px;flex-shrink:0"></i>
                <span style="flex:1;font-size:12px;font-weight:600;color:#1F2937">${name}</span>
                <button onclick="_attRemove(this,'${name.replace(/'/g,"\\'")}',${i})"
                  style="background:none;border:none;color:#EF4444;cursor:pointer;padding:2px 4px;font-size:11px" title="삭제">
                  <i class="fas fa-times"></i>
                </button>
              </div>`).join('')}
        </div>
      </div>

      <!-- 참가자 추가 입력 -->
      <div style="margin-bottom:6px">
        <div style="font-size:12px;font-weight:700;color:#374151;margin-bottom:6px">참가자 추가</div>
        <div style="display:flex;gap:6px">
          <input id="_att-input" type="text" placeholder="이름 입력 후 추가"
            style="flex:1;padding:8px 10px;border:1.5px solid #D1D5DB;border-radius:8px;font-size:13px;outline:none"
            onkeydown="if(event.key==='Enter'){event.preventDefault();_attAdd()}"
            onfocus="this.style.borderColor='#685182'" onblur="this.style.borderColor='#D1D5DB'">
          <button onclick="_attAdd()"
            style="padding:8px 14px;background:#685182;color:white;border:none;border-radius:8px;font-size:13px;font-weight:600;cursor:pointer;white-space:nowrap">
            <i class="fas fa-plus mr-1"></i>추가
          </button>
        </div>
        <div id="_att-err" style="font-size:11px;color:#EF4444;margin-top:4px;display:none"></div>
      </div>
    </div>
    <div class="modal-footer" style="display:flex;gap:8px;padding:10px 16px;border-top:1px solid #E5E7EB;background:white;border-radius:0 0 12px 12px">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline" style="flex:1">취소</button>
      <button id="_att-save-btn" onclick="_attSave(${tbmId})"
        style="flex:1;padding:9px;background:linear-gradient(135deg,#D70072,#FF349E);color:white;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer">
        <i class="fas fa-save mr-1"></i>저장
      </button>
    </div>
  </div>`;
  document.body.appendChild(modal);

  // 현재 참가자 목록 (편집 중 상태 관리)
  let _editList = [...current];

  window._attRemove = function(btn, name, idx) {
    _editList = _editList.filter(n => n !== name);
    const row = document.getElementById(`_att-row-${idx}`);
    if (row) row.remove();
    _attRefreshList();
  };
  window._attAdd = function() {
    const input = document.getElementById('_att-input');
    const errEl = document.getElementById('_att-err');
    const name = input.value.trim();
    if (!name) { errEl.textContent = '이름을 입력해 주세요.'; errEl.style.display = 'block'; return; }
    if (_editList.includes(name)) { errEl.textContent = `'${name}'은(는) 이미 참가자 목록에 있습니다.`; errEl.style.display = 'block'; return; }
    errEl.style.display = 'none';
    _editList.push(name);
    input.value = '';
    _attRefreshList();
    input.focus();
  };
  function _attRefreshList() {
    const listEl = document.getElementById('_attendee-list');
    if (!listEl) return;
    if (_editList.length === 0) {
      listEl.innerHTML = '<div style="font-size:12px;color:#9CA3AF;text-align:center;padding:6px">참가자 없음</div>';
    } else {
      listEl.innerHTML = _editList.map((name, i) => `
        <div id="_att-row-${i}" style="display:flex;align-items:center;gap:6px;padding:5px 6px;margin-bottom:4px;background:white;border:1px solid #E5E7EB;border-radius:6px">
          <i class="fas fa-user" style="color:#685182;font-size:11px;flex-shrink:0"></i>
          <span style="flex:1;font-size:12px;font-weight:600;color:#1F2937">${name}</span>
          <button onclick="_attRemove(this,'${name.replace(/'/g,"\\'")}',${i})"
            style="background:none;border:none;color:#EF4444;cursor:pointer;padding:2px 4px;font-size:11px">
            <i class="fas fa-times"></i>
          </button>
        </div>`).join('');
    }
  }
  window._attSave = async function(tbmId) {
    const btn = document.getElementById('_att-save-btn');
    if (btn) { btn.disabled = true; btn.textContent = '저장 중...'; }
    try {
      await API.patch(`/tbm/${tbmId}/attendees`, { attendees: _editList });
      toast('참가자 목록이 저장되었습니다.', 'success');
      modal.remove();
      // TBM 상세 모달 즉시 갱신
      const overlay = document.querySelector(`.modal-overlay[data-tbm-id="${tbmId}"]`);
      if (overlay && overlay._reload) await overlay._reload();
    } catch(e) {
      toast(e.response?.data?.error || '저장 실패', 'error');
      if (btn) { btn.disabled = false; btn.textContent = '저장'; }
    }
  };
}

// ── tbm_done 카드 → TBM 서명 패널 열기 (task_id → tbm_id 조회 후 showTbmDetail 호출)
async function _openTbmSignPanel(taskId) {
  try {
    const res = await API.get(`/tasks/${taskId}/tbm-info`);
    const tbmInfo = res.data?.tbm;
    if (!tbmInfo || !tbmInfo.id) {
      toast('TBM 기록이 없습니다.', 'error');
      return;
    }
    showTbmDetail(tbmInfo.id);
  } catch(e) {
    toast('TBM 조회 실패', 'error');
  }
}

// ── tbm_done 카드 배지 단건 갱신 (tbm_id 기준)
async function _refreshTbmSigBadge(tbmId) {
  try {
    const [tbmRes, sigRes] = await Promise.all([
      API.get(`/tbm/${tbmId}`),
      API.get(`/tbm/${tbmId}/signatures`)
    ]);
    const tbm = tbmRes.data || {};
    const sigs = Array.isArray(sigRes.data) ? sigRes.data : [];
    const attendees = Array.isArray(tbm.attendees) ? tbm.attendees : [];
    // 서명된 이름 집합 (이름 기반 + 계정 기반 모두 포함)
    const signedNames = new Set(sigs.map(s => s.user_name || '').filter(Boolean));
    const signedCount = attendees.length > 0
      ? attendees.filter(n => signedNames.has(n)).length
      : sigs.length;
    const total = attendees.length || sigs.length;
    // task_id를 알아야 배지를 업데이트할 수 있으므로, tbm.task_id 사용
    const taskId = tbm.task_id;
    if (!taskId) return;
    const badge = document.getElementById(`tbm-sig-badge-${taskId}`);
    if (!badge) return;
    const allSigned = total > 0 && signedCount >= total;
    badge.textContent = allSigned
      ? `✅ 전원 서명완료 (${total}명)`
      : `✍️ ${signedCount}/${total}명 서명`;
    badge.style.color = allSigned ? '#059669' : '#B45309';
  } catch(e) {
    // 조용히 실패 (배지 업데이트 실패는 무시)
  }
}

// ── tbm_done 카드 배지 task_id 기준 갱신 (task_id → tbm_id 조회 후 _refreshTbmSigBadge)
async function _loadTbmSigBadge(taskId) {
  try {
    const res = await API.get(`/tasks/${taskId}/tbm-info`);
    const tbmInfo = res.data?.tbm;
    if (!tbmInfo?.id) {
      const badge = document.getElementById(`tbm-sig-badge-${taskId}`);
      if (badge) { badge.textContent = '미등록'; badge.style.color = '#9CA3AF'; }
      return;
    }
    // tbm_id 기준 서명 현황 로드
    const [tbmRes, sigRes] = await Promise.all([
      API.get(`/tbm/${tbmInfo.id}`),
      API.get(`/tbm/${tbmInfo.id}/signatures`)
    ]);
    const tbm = tbmRes.data || {};
    const sigs = Array.isArray(sigRes.data) ? sigRes.data : [];
    const attendees = Array.isArray(tbm.attendees) ? tbm.attendees : [];
    const signedNames = new Set(sigs.map(s => s.user_name || '').filter(Boolean));
    const signedCount = attendees.length > 0
      ? attendees.filter(n => signedNames.has(n)).length
      : sigs.length;
    const total = attendees.length || sigs.length;
    const badge = document.getElementById(`tbm-sig-badge-${taskId}`);
    if (!badge) return;
    const allSigned = total > 0 && signedCount >= total;
    badge.textContent = allSigned
      ? `✅ 전원 서명완료 (${total}명)`
      : total === 0
        ? '서명 없음'
        : `✍️ ${signedCount}/${total}명 서명`;
    badge.style.color = allSigned ? '#059669' : total === 0 ? '#9CA3AF' : '#B45309';

    // 전원 서명 완료 시: 공유 버튼 표시 + 서명받기 버튼 숨김
    const shareBtn     = document.getElementById(`tbm-share-btn-${taskId}`);   // 근로자 카드 버튼
    const taskShareBtn = document.getElementById(`task-share-btn-${taskId}`);  // 관리자 상세 버튼
    const signBtn      = document.getElementById(`tbm-sign-btn-${taskId}`);
    if (allSigned) {
      if (shareBtn)     { shareBtn.style.display     = 'inline-flex'; }
      if (taskShareBtn) { taskShareBtn.style.display = 'inline-flex'; }
      if (signBtn)      { signBtn.style.display      = 'none'; }
    }
  } catch(e) {
    const badge = document.getElementById(`tbm-sig-badge-${taskId}`);
    if (badge) { badge.textContent = '조회 실패'; badge.style.color = '#EF4444'; }
  }
}

// ── 관리자 작업 상세화면 공유 버튼 비동기 토글 ─────────────────────────────
// showTaskDetail 렌더 후 tbm_done 상태에서 호출 → 전원 서명완료 시 task-share-btn 표시
async function _loadTaskShareBtn(taskId) {
  try {
    const res = await API.get(`/tasks/${taskId}/tbm-info`);
    const tbmInfo = res.data?.tbm;
    if (!tbmInfo?.id) return;

    const [tbmRes, sigRes] = await Promise.all([
      API.get(`/tbm/${tbmInfo.id}`),
      API.get(`/tbm/${tbmInfo.id}/signatures`)
    ]);
    const tbm = tbmRes.data || {};
    const sigs = Array.isArray(sigRes.data) ? sigRes.data : [];
    const attendees = Array.isArray(tbm.attendees) ? tbm.attendees : [];
    const signedNames = new Set(sigs.map(s => s.user_name || '').filter(Boolean));
    const signedCount = attendees.length > 0
      ? attendees.filter(n => signedNames.has(n)).length
      : sigs.length;
    const total = attendees.length || sigs.length;
    const allSigned = total > 0 && signedCount >= total;

    if (allSigned) {
      const shareBtn = document.getElementById(`task-share-btn-${taskId}`);
      if (shareBtn) { shareBtn.style.display = 'inline-flex'; }
    }
  } catch(e) {
    // 조회 실패 시 버튼 미표시 (silent fail)
  }
}

async function _tbmSign(tbmId, role) {
  const roleLabel = role === 'conductor' ? '진행자' : '참석자';
  const signData = await showSignaturePad({
    title: `TBM ${roleLabel} 서명`,
    subtitle: '서명 후 [서명 완료] 버튼을 눌러주세요',
    penColor: '#1a1a1a'
  });
  if (signData === null) return; // 취소
  try {
    await API.post('/tbm/' + tbmId + '/signatures', { role, sign_data: signData });
    toast('TBM 서명이 등록되었습니다.', 'success');
    const overlay = document.querySelector('.modal-overlay[data-tbm-id="' + tbmId + '"]');
    if (overlay && overlay._reload) await overlay._reload();
  } catch(e) {
    toast(e.message || 'TBM 서명 등록 실패', 'error');
  }
}

async function _tbmUnsign(tbmId, sigId) {
  const ok = await showWarningConfirm(
    'TBM 서명을 취소하시겠습니까?',
    '취소된 서명은 복구할 수 없습니다.',
    '서명 취소'
  );
  if (!ok) return;
  try {
    await API.delete('/tbm/' + tbmId + '/signatures/' + sigId);
    toast('서명이 취소되었습니다.', 'success');
    const overlay = document.querySelector('.modal-overlay[data-tbm-id="' + tbmId + '"]');
    if (overlay && overlay._reload) await overlay._reload();
  } catch(e) {
    toast(e.message || '서명 취소 실패', 'error');
  }
}

// TBM 서명 요청 보내기 (참석자 명단 기반 자동 선택 + 서명 현황 표시)
async function _tbmSendSignRequest(tbmId, taskId) {
  try {
    // TBM 정보 + 기존 서명자 + 전체 사용자 + 기존 서명 요청 동시 조회
    const [tbmRes, sigsRes, usersRes, existingReqsRes] = await Promise.all([
      API.get('/tbm/' + tbmId),
      API.get('/tbm/' + tbmId + '/signatures').catch(() => ({ data: [] })),
      API.get('/users').catch(() => ({ data: [] })),
      API.get('/signature-requests', { params: { status: 'pending' } }).catch(() => ({ data: [] }))
    ]);
    const tbm = tbmRes.data;
    const existingSigs = Array.isArray(sigsRes.data) ? sigsRes.data : [];
    const allUsers = Array.isArray(usersRes.data) ? usersRes.data.filter(u => u.is_active && !u.is_pending) : [];

    // 이미 서명한 user_id 목록
    const signedUserIds = new Set(existingSigs.map(s => s.user_id).filter(Boolean));
    // 이미 서명 요청 발송된 user_id 목록 (pending)
    const pendingReqUserIds = new Set(
      (Array.isArray(existingReqsRes.data) ? existingReqsRes.data : [])
        .filter(r => r.ref_type === 'tbm' && Number(r.ref_id) === Number(tbmId))
        .map(r => r.target_user_id)
    );

    // TBM 참석자 이름 목록에서 매칭되는 사용자 자동 선택
    const attendeeNames = new Set((tbm.attendees || []).map(n => n.trim()));
    const matchedByName = new Set(
      allUsers.filter(u => attendeeNames.has(u.name)).map(u => u.id)
    );

    const bm = document.createElement('div');
    bm.className = 'modal-overlay';

    const userListHtml = allUsers.map(u => {
      const isSigned    = signedUserIds.has(u.id);
      const isPending   = pendingReqUserIds.has(u.id);
      const isMatched   = matchedByName.has(u.id);
      const isChecked   = isMatched && !isSigned;   // 참석자 매칭 & 미서명이면 기본 선택
      const isDisabled  = isSigned;                 // 이미 서명한 사람은 선택 불가

      let badge = '';
      if (isSigned)   badge = `<span style="font-size:10px;padding:1px 6px;border-radius:8px;background:#D1FAE5;color:#065F46;font-weight:700">✅ 서명완료</span>`;
      else if (isPending) badge = `<span style="font-size:10px;padding:1px 6px;border-radius:8px;background:#FEF3C7;color:#92400E;font-weight:700">⏳ 요청중</span>`;
      else if (isMatched) badge = `<span style="font-size:10px;padding:1px 6px;border-radius:8px;background:#EDE9FE;color:#5B21B6;font-weight:700">참석자</span>`;

      return `
      <label style="display:flex;align-items:center;gap:8px;padding:7px 10px;border-radius:8px;cursor:${isDisabled?'default':'pointer'};
        background:${isSigned?'#F0FDF4':isMatched?'#F5F3FF':'#FAFAFA'};
        border:1px solid ${isSigned?'#BBF7D0':isMatched?'#DDD6FE':'#E5E7EB'};margin-bottom:5px;opacity:${isDisabled?'0.7':'1'}">
        <input type="checkbox" value="${u.id}" ${isChecked?'checked':''} ${isDisabled?'disabled':''} style="width:15px;height:15px;accent-color:#685182">
        <span style="font-size:13px;font-weight:600;flex:1">${u.name}</span>
        <span style="font-size:11px;color:#9CA3AF">${u.position||u.role||''}</span>
        ${badge}
      </label>`;
    }).join('');

    const taskTitle = tbm.task_title || `작업 #${taskId}`;
    const tbmDateStr = (tbm.tbm_date || '').slice(0, 10);
    bm.innerHTML = `
    <div class="modal" style="max-width:440px">
      <div class="modal-header" style="background:linear-gradient(135deg,#685182,#8E72A8);color:white">
        <div>
          <div class="flex items-center gap-2"><i class="fas fa-paper-plane"></i><h3 class="font-bold">TBM 서명 요청 보내기</h3></div>
          <div style="font-size:11px;opacity:.75;margin-top:2px">${taskTitle} · ${tbmDateStr}</div>
        </div>
        <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer">×</button>
      </div>
      <div class="modal-body">
        <!-- 현황 요약 -->
        <div style="display:flex;gap:8px;margin-bottom:10px">
          <div style="flex:1;background:#F0FDF4;border:1px solid #BBF7D0;border-radius:8px;padding:8px;text-align:center">
            <div style="font-size:18px;font-weight:700;color:#059669">${existingSigs.length}</div>
            <div style="font-size:11px;color:#6B7280">서명 완료</div>
          </div>
          <div style="flex:1;background:#FEF3C7;border:1px solid #FDE68A;border-radius:8px;padding:8px;text-align:center">
            <div style="font-size:18px;font-weight:700;color:#D97706">${pendingReqUserIds.size}</div>
            <div style="font-size:11px;color:#6B7280">요청 중</div>
          </div>
          <div style="flex:1;background:#F5F3FF;border:1px solid #DDD6FE;border-radius:8px;padding:8px;text-align:center">
            <div style="font-size:18px;font-weight:700;color:#7C3AED">${attendeeNames.size}</div>
            <div style="font-size:11px;color:#6B7280">참석자 수</div>
          </div>
        </div>
        <div style="font-size:11px;color:#6B7280;margin-bottom:8px">
          <i class="fas fa-info-circle mr-1" style="color:#8E72A8"></i>
          TBM 참석자로 등록된 사용자는 자동 선택됩니다. 서명 완료자는 선택 불가합니다.
        </div>
        <div style="display:flex;gap:6px;margin-bottom:8px">
          <button onclick="this.closest('.modal-body').querySelectorAll('input[type=checkbox]:not(:disabled)').forEach(cb=>cb.checked=true)"
            style="font-size:11px;padding:3px 10px;border:1px solid #685182;color:#685182;background:white;border-radius:6px;cursor:pointer">전체선택</button>
          <button onclick="this.closest('.modal-body').querySelectorAll('input[type=checkbox]:not(:disabled)').forEach(cb=>cb.checked=false)"
            style="font-size:11px;padding:3px 10px;border:1px solid #9CA3AF;color:#6B7280;background:white;border-radius:6px;cursor:pointer">전체해제</button>
        </div>
        <div style="max-height:300px;overflow-y:auto;padding-right:2px">
          ${userListHtml || '<div style="color:#9CA3AF;font-size:13px;text-align:center;padding:16px">활성 사용자가 없습니다</div>'}
        </div>
      </div>
      <div class="modal-footer flex gap-2 justify-end">
        <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
        <button id="do-send-sign-req" class="btn font-bold" style="background:linear-gradient(135deg,#685182,#8E72A8);color:white;border:none">
          <i class="fas fa-paper-plane mr-1"></i>서명 요청 보내기
        </button>
      </div>
    </div>`;
    document.body.appendChild(bm);

    bm.querySelector('#do-send-sign-req').onclick = async () => {
      const checked = [...bm.querySelectorAll('input[type=checkbox]:checked:not(:disabled)')].map(cb => Number(cb.value));
      if (checked.length === 0) { toast('대상자를 선택해주세요.', 'error'); return; }

      // 버튼 로딩 상태
      const sendBtn = bm.querySelector('#do-send-sign-req');
      sendBtn.disabled = true;
      sendBtn.innerHTML = '<i class="fas fa-spinner fa-spin mr-1"></i>전송 중...';

      try {
        const res = await API.post('/signature-requests/bulk', {
          ref_type: 'tbm',
          ref_id: Number(tbmId),
          ref_sub_type: `task_${taskId}`,
          title: `TBM 서명 요청 — ${taskTitle}`,
          description: `TBM 일자: ${tbmDateStr} / 실시자: ${tbm.conductor_name || ''}`,
          target_user_ids: checked,
        });
        const cnt = res.data.created || checked.length;
        bm.remove();

        // ── 서명 요청 후 즉시 서명화면으로 이동 ──────────────
        toast(`${cnt}명에게 서명 요청을 보냈습니다. 서명화면으로 이동합니다.`, 'success');
        refreshSignRequestCount();

        // 열려있는 모든 모달 닫기
        document.querySelectorAll('.modal-overlay').forEach(el => el.remove());

        // 서명요청 페이지로 이동
        setTimeout(() => safeNavigateTo('sign-requests'), 400);

      } catch(e) {
        sendBtn.disabled = false;
        sendBtn.innerHTML = '<i class="fas fa-paper-plane mr-1"></i>서명 요청 보내기';
        toast(e.response?.data?.error || '서명 요청 실패', 'error');
      }
    };
  } catch(e) { toast('로드 실패: ' + e.message, 'error'); }
}

// ── TBM 삭제 (중복 등록 정리용) ──────────────────────────────────────────────
async function _deleteTbm(tbmId, taskId) {
  const ok = await showDeleteConfirm(
    'TBM 기록을 삭제하시겠습니까?',
    '서명 기록을 포함한 모든 데이터가 삭제됩니다. 이 작업은 되돌릴 수 없습니다.'
  );
  if (!ok) return;
  try {
    const res = await API.delete(`/tbm/${tbmId}`);
    toast('TBM이 삭제되었습니다.', 'success');

    // ① 상세 모달 닫기
    const overlay = document.querySelector(`.modal-overlay[data-tbm-id="${tbmId}"]`);
    if (overlay) overlay.remove();

    // ② 작업 상세 TBM 탭 갱신 — 있으면 전체 재로드
    if (taskId) {
      // 열려 있는 작업 상세 모달 찾기
      const taskModals = document.querySelectorAll('.modal-overlay');
      let taskModalFound = false;
      for (const m of taskModals) {
        // showTaskDetail 호출 시 data-task-id 속성이 없을 수 있으므로 탭 버튼으로 판별
        const tbmTabContent = m.querySelector('#dtab-tbm');
        if (tbmTabContent) {
          taskModalFound = true;
          // TBM 탭이 현재 활성이면 showTaskDetail 전체 재로드
          showTaskDetail(taskId);
          break;
        }
      }
    }

    // ③ TBM이 0건이 되면 task.status가 in_progress로 롤백됐으므로 배지 업데이트
    if (res.data?.remaining_tbm === 0) {
      // tbm_done 배지 제거
      const badge = document.getElementById(`tbm-sig-badge-${taskId}`);
      if (badge) badge.remove();
      // 내 작업 목록 새로고침 (tbm_done → in_progress 상태 변경 반영)
      const mainContent = document.getElementById('main-content');
      if (mainContent && mainContent.dataset.page === 'my-tasks') {
        renderMyTasksPage(mainContent);
      }
    }
  } catch(e) {
    toast(e.response?.data?.error || 'TBM 삭제에 실패했습니다.', 'error');
  }
}

async function _tbmPrint(tbmId) {
  try {
    const [res, sigsRes, approvalRes] = await Promise.all([
      API.get('/tbm/' + tbmId),
      API.get('/tbm/' + tbmId + '/signatures').catch(() => ({ data: [] })),
      API.get('/tbm/' + tbmId + '/approval-status').catch(() => ({ data: {} }))
    ]);
    const tbm = res.data;
    const signatures = Array.isArray(sigsRes.data) ? sigsRes.data : [];
    const approval = approvalRes.data || {};

    // BUG-057: 체크리스트(TBM 사진) 조회 — task_id 기반
    let tbmChecklistSections = [];
    if (tbm.task_id) {
      try {
        const clRes = await API.get('/checklist/task/' + tbm.task_id);
        tbmChecklistSections = clRes.data?.tbm_sections || [];
      } catch(_) {}
    }

    // blob: URL origin에서 상대경로(/api/...)는 서버에 도달하지 않음
    // → window.location.origin을 prefix로 붙여 절대 URL로 만들어야 함
    const _origin = window.location.origin;
    const _photoToken = localStorage.getItem('token') || '';

    const today = new Date().toLocaleDateString('ko-KR', { year: 'numeric', month: 'long', day: 'numeric', ..._KST });
    const printDt = new Date().toLocaleString('ko-KR', _KST);

    // ── 서명자: 실시자 먼저, 이후 참석자 순 ─────────────────────────────────
    const conductorSigs = signatures.filter(s => s.role === 'conductor');
    const attendeeSigs  = signatures.filter(s => s.role === 'attendee');
    const orderedSigs   = [...conductorSigs, ...attendeeSigs];

    // ── 서명란 행 생성 (서명된 사람 + 미서명 빈 슬롯) ───────────────────────
    const minBlankRows = 2;  // 서명 후에도 최소 2줄 빈칸 유지
    const allAttendees = Array.isArray(tbm.attendees) ? tbm.attendees : [];
    // 서명된 사람 이름 Set
    const signedNames = new Set(orderedSigs.map(s => s.user_name || ''));
    // 미서명 참석자 (이름 목록에 있지만 서명 없는 사람)
    const unsignedAttendees = allAttendees.filter(name => !signedNames.has(name));

    // ── BUG-057: 서명란 2열 구성 (인원별 2명씩 좌우 배치) ───────────────────
    // 전체 서명 슬롯 = 서명완료 + 미서명참석자 + 빈슬롯(최소 2)
    function _makeSigCell(roleLabel, name, sigImg, dateStr, isBold, position) {
      return `
        <td style="border:1pt solid #888;text-align:center;font-weight:${isBold?'700':'400'};width:44px;padding:3px 2px">${roleLabel}</td>
        <td style="border:1pt solid #888;width:60px;padding:3px 4px">${name}</td>
        <td style="border:1pt solid #888;width:52px;text-align:center;padding:3px 2px">${position||'-'}</td>
        <td style="border:1pt solid #888;width:60px;text-align:center;font-size:7.5pt;padding:2px">${dateStr}</td>
        <td style="border:1pt solid #888;text-align:center;height:46px;vertical-align:middle;min-width:60px">${sigImg}</td>`;
    }
    function _makeBlankCell() {
      return `
        <td style="border:1pt solid #888;width:44px;padding:3px 2px"></td>
        <td style="border:1pt solid #888;width:60px;padding:3px 4px"></td>
        <td style="border:1pt solid #888;width:52px"></td>
        <td style="border:1pt solid #888;width:60px"></td>
        <td style="border:1pt solid #888;height:46px;min-width:60px"></td>`;
    }
    // 모든 슬롯 배열 생성
    const allSigSlots = [
      ...orderedSigs.map(s => {
        const roleLabel = s.role === 'conductor' ? '실시자' : '참석자';
        const sigImg = s.sign_data
          ? `<img src="${s.sign_data}" style="max-height:36px;max-width:100%;object-fit:contain;display:block;margin:0 auto">`
          : '<span style="color:#ccc;font-size:7.5pt">미서명</span>';
        return { type:'sig', roleLabel, name: s.user_name||'-', sigImg, dateStr:(s.signed_at||'').slice(0,10), position: s.position||'' };
      }),
      ...unsignedAttendees.map(name => ({
        type:'unsigned', roleLabel:'참석자', name, sigImg:'<span style="color:#ccc;font-size:7.5pt">미서명</span>', dateStr:'', position:''
      }))
    ];
    // 최소 빈 슬롯 추가 (짝수 맞추기 + 최소 2개)
    const totalSlots = allSigSlots.length;
    const blanksNeeded = Math.max(minBlankRows, totalSlots % 2 === 0 ? minBlankRows : 1);
    for (let i = 0; i < blanksNeeded; i++) allSigSlots.push({ type:'blank' });
    // 2열 행 생성
    const sigRowsHtml = (() => {
      let rows = '';
      for (let i = 0; i < allSigSlots.length; i += 2) {
        const L = allSigSlots[i];
        const R = allSigSlots[i+1] || { type:'blank' };
        const leftCell  = L.type==='blank' ? _makeBlankCell() : _makeSigCell(L.roleLabel, L.name, L.sigImg, L.dateStr, L.type==='sig', L.position);
        const rightCell = R.type==='blank' ? _makeBlankCell() : _makeSigCell(R.roleLabel, R.name, R.sigImg, R.dateStr, R.type==='sig', R.position);
        rows += `<tr style="border-right:2pt solid #aaa">${leftCell}<td style="width:6px;background:#f5f5f5;border-top:1pt solid #bbb;border-bottom:1pt solid #bbb"></td>${rightCell}</tr>`;
      }
      return rows;
    })();
    // 구버전 변수 호환 (사용하지 않지만 참조 오류 방지)
    const unsignedRows = '';
    const blankRows = '';

    // ── 누락 필수항목 경고 체크 ──────────────────────────────────────────────
    const warns = [];
    if (!tbm.conductor_name) warns.push('실시자(TBM 진행자)');
    if (!tbm.location)       warns.push('실시 장소');
    if (!tbm.safety_topics)  warns.push('작업내용/안전교육 사항');
    if (!tbm.precautions)    warns.push('주의사항');
    if (signatures.length === 0) warns.push('서명(최소 1명 이상)');
    if (!allAttendees.length) warns.push('참석자 명단');

    const warnBanner = warns.length > 0
      ? `<div style="background:#FEF3C7;border:1.5px solid #FDE68A;border-radius:6px;padding:7px 12px;font-size:8.5pt;color:#92400E;margin-bottom:10px">
           <b>⚠ 법적 필수 기재사항 누락:</b> ${warns.join(' · ')}
         </div>`
      : '';

    // ── 참석자 명단 태그 형식 ────────────────────────────────────────────────
    const attendeeTagsHtml = allAttendees.map(a => {
      const isSigned = signedNames.has(a);
      return `<span style="display:inline-block;border:1px solid ${isSigned?'#6EE7B7':'#ccc'};
        background:${isSigned?'#F0FDF4':'#fff'};color:${isSigned?'#065F46':'#333'};
        padding:2px 8px;border-radius:3px;font-size:8.5pt;margin:2px;font-weight:${isSigned?'700':'400'}">
        ${a}${isSigned ? ' ✓' : ''}
      </span>`;
    }).join('');

    // ── 결재란 (서명 현황 반영) ──────────────────────────────────────────────
    // 서명 순서: 총괄책임(현장대리인) → 대표이사 → 안전관리자
    function _approvalCell(sig, role, label, canSign) {
      if (sig && sig.sign_data) {
        // 서명 이미지 표시
        return `<td style="border:1px solid #888;width:80px;padding:3px;text-align:center;vertical-align:middle;position:relative">
          <img src="${sig.sign_data}" style="max-height:42px;max-width:72px;object-fit:contain;display:block;margin:0 auto">
          <div style="font-size:6.5pt;color:#555;margin-top:2px">${sig.user_name||''}</div>
          <div style="font-size:6pt;color:#aaa">${(sig.signed_at||'').slice(0,10)}</div>
        </td>`;
      } else if (sig) {
        // 계정 서명 (sign_data 없음)
        return `<td style="border:1px solid #888;width:80px;padding:3px;text-align:center;vertical-align:middle">
          <div style="font-size:7.5pt;font-weight:700;color:#333">${sig.user_name||''}</div>
          <div style="font-size:6.5pt;color:#666;margin-top:1px">✓ 서명완료</div>
          <div style="font-size:6pt;color:#aaa">${(sig.signed_at||'').slice(0,10)}</div>
        </td>`;
      } else if (canSign) {
        // 서명 가능 상태: 버튼 표시
        return `<td style="border:1px solid #888;width:80px;padding:4px;text-align:center;vertical-align:middle" class="no-print">
          <button onclick="window._tbmApprovalSign('${role}')"
            style="background:#4E3A63;color:white;border:none;border-radius:6px;padding:5px 8px;font-size:8pt;cursor:pointer;width:100%">
            ✍ 서명하기
          </button>
        </td>
        <td style="border:1px solid #888;width:80px;padding:4px;text-align:center;vertical-align:middle;color:#ccc;font-size:7.5pt" class="print-only">
          (서명대기)
        </td>`;
      } else {
        // 잠금 상태 (이전 단계 미완료)
        return `<td style="border:1px solid #888;width:80px;padding:4px;text-align:center;vertical-align:middle;color:#ccc;font-size:7.5pt">
          (대기중)
        </td>`;
      }
    }

    const hasSafetySign  = !!approval.approval_safety;
    const hasGeneralSign = !!approval.approval_general;
    // BUG-089: hasCeoSign 제거됨

    // 현재 로그인 사용자 직책 기반 서명 가능 여부
    const curPosition = (currentUser || {}).position || '';
    const curRole     = (currentUser || {}).role || '';
    const isAdmin     = curRole === 'admin';

    // BUG-089: 서명 순서: 안전관리자 → 총괄책임 (대표이사 제거)
    // 안전관리자: 안전관리자 직책 또는 관리자 (첫 번째)
    const canSignSafety  = !hasSafetySign  && (curPosition === '안전관리자' || isAdmin);
    // 총괄책임: 현장대리인 직책 또는 관리자, + 안전관리자 서명 완료 후
    const canSignGeneral = !hasGeneralSign && hasSafetySign  && (curPosition === '현장대리인' || isAdmin);
    // canSignCeo 제거됨

    const approvalHtml = `
      <table style="border-collapse:collapse;font-size:8pt;float:right;margin-bottom:6px">
        <colgroup>
          <col style="width:32px">
          <col style="width:80px">
          <col style="width:80px">
          <!-- BUG-089: 대표이사 col 제거됨 -->
        </colgroup>
        <tr>
          <th rowspan="2" style="border:1px solid #888;padding:4px 6px;background:#f0eeef;text-align:center;vertical-align:middle;font-size:8pt;writing-mode:vertical-rl;letter-spacing:2px">결&nbsp;재</th>
          <th style="border:1px solid #888;padding:3px 0;background:#f0eeef;text-align:center">안전관리자</th>
          <th style="border:1px solid #888;padding:3px 0;background:#f0eeef;text-align:center">총괄책임</th>
          <!-- BUG-089: 대표이사 열 제거됨 -->
        </tr>
        <tr style="height:60px">
          ${_approvalCell(approval.approval_safety, 'approval_safety', '안전관리자', canSignSafety)}
          ${_approvalCell(approval.approval_general,'approval_general','총괄책임',   canSignGeneral)}
          <!-- BUG-089: approval_ceo 셀 제거됨 -->
        </tr>
        ${(!hasSafetySign || !hasGeneralSign) ? `
        <tr class="no-print">
          <td colspan="3" style="border:none;padding:3px 0;font-size:7pt;color:#9CA3AF;text-align:right">
            서명 순서: 안전관리자 → 총괄책임
          </td>
        </tr>` : ''}
      </table>
      <div style="clear:both"></div>`;

    // ── 미리보기 오버레이 열기 (BUG-094: Android WebView 호환) ─────────────────
    const _tbmPrintHtml = `<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <title>TBM 회의록 - ${(tbm.task_title||'').replace(/</g,'&lt;')}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    @font-face { font-family:'LG Smart KR'; src:url('${_origin}/static/fonts/LGSmartKR-regular.woff2') format('woff2'); font-weight:400; font-display:swap; }
    @font-face { font-family:'LG Smart KR'; src:url('${_origin}/static/fonts/LGSmartKR-semibold.woff2') format('woff2'); font-weight:600; font-display:swap; }
    @font-face { font-family:'LG Smart KR'; src:url('${_origin}/static/fonts/LGSmartKR-bold.woff2') format('woff2'); font-weight:700; font-display:swap; }
    body { font-family:'LG Smart KR','Malgun Gothic','맑은 고딕','Apple SD Gothic Neo',sans-serif; font-size:10pt; color:#000; margin:0; padding:0; }

    /* ── 툴바 (화면 전용) ── */
    .print-toolbar {
      display: none;
    }
    @media screen {
      body { background:#e5e7eb; padding:0; padding-top:52px; overflow-x:hidden; }
      .print-toolbar {
        display: flex;
        position:fixed; top:0; left:0; right:0; z-index:999;
        background:#1f2937; color:#fff;
        align-items:center; padding:8px 16px; gap:10px;
        box-shadow:0 2px 8px rgba(0,0,0,0.3);
      }
      .print-toolbar .toolbar-title { font-size:12px; font-weight:bold; flex:1; }
      .btn-print { background:#D70072; color:#fff; padding:6px 18px; border-radius:7px; border:none; font-size:12px; font-weight:bold; cursor:pointer; }
      .btn-close  { background:#374151; color:#ccc;  padding:6px 14px; border-radius:7px; border:none; font-size:12px; cursor:pointer; }
      /* 화면에 꽉 차게: .page-sheet-wrap이 JS로 scale 적용 */
      .page-sheet-wrap {
        display: flex;
        flex-direction: column;
        align-items: center;
        transform-origin: top center;
      }
    }
    @media print {
      .print-toolbar { display:none !important; }
      .no-print { display:none !important; }
      .print-only { display:table-cell !important; }
      #approval-sign-modal { display:none !important; }
      img { page-break-inside:avoid; break-inside:avoid; }
      tr  { page-break-inside:avoid; break-inside:avoid; }
      /* ★ 인쇄 시 page-sheet-wrap JS transform 무효화 */
      .page-sheet-wrap {
        transform: none !important;
        width: 210mm !important;
        margin: 0 auto !important;
      }
      /* ★ 인쇄 시 page-sheet: 고정 height/overflow 해제 → 내용이 인쇄에 반영되도록 */
      .page-sheet {
        height: auto !important;
        overflow: visible !important;
        position: static !important;
      }
      /* ★ 인쇄 시 page-inner: absolute 해제 → 일반 흐름으로 복원 */
      .page-inner {
        position: static !important;
        transform: none !important;
        width: 100% !important;
      }
    }

    /* ── A4 페이지 시트 ── */
    .page-sheet {
      position: relative;
      background: #fff;
      width:  210mm;
      height: 297mm;
      overflow: hidden;
      flex-shrink: 0;
    }
    @media screen {
      .page-sheet {
        margin: 0 auto 24px;
        box-shadow: 0 4px 24px rgba(0,0,0,0.18);
      }
    }
    @media print {
      .page-sheet {
        page-break-after: always;
        break-after: page;
      }
      .page-sheet:last-child {
        page-break-after: avoid;
        break-after: avoid;
      }
    }
    /* 실제 내용 컨테이너 — JS가 transform-origin:top left 기준으로 scale */
    .page-inner {
      position: absolute;
      top: 0; left: 0;
      width: 210mm;        /* 항상 A4 폭 고정 */
      transform-origin: top left;
      padding: 13mm 13mm 14mm 15mm;
    }

    /* ── 화면 미리보기 페이지 구분 레이블 ── */
    @media screen {
      .page-label {
        text-align:center; font-size:9px; color:#aaa;
        letter-spacing:1px; padding:6px 0 4px;
      }
    }
    @media print { .page-label { display:none; } }

    /* ── 공통 요소 ── */
    .law-header {
      display:flex; justify-content:space-between;
      font-size:7pt; color:#888; font-weight:bold;
      margin-bottom:5px; padding-bottom:3px;
      border-bottom:0.5pt solid #ddd;
    }
    .doc-title {
      text-align:center; font-size:15pt; font-weight:800;
      letter-spacing:3px; margin:3px 0 2px;
      border-bottom:2.5pt double #333; padding-bottom:5px;
    }
    .doc-subtitle { text-align:center; font-size:8.5pt; color:#555; margin:0 0 8px; }
    .law-notice {
      background:#EFF6FF; border:1pt solid #BFDBFE;
      padding:4px 8px; font-size:7.5pt; color:#1D4ED8;
      margin-bottom:7px; border-radius:2px; line-height:1.4;
    }
    .info-table { width:100%; border-collapse:collapse; margin-bottom:7px; font-size:8.5pt; table-layout:fixed; }
    .info-table th { border:1pt solid #888; padding:3px 5px; background:#f0eeef; font-weight:700; white-space:nowrap; width:58px; text-align:center; }
    .info-table td { border:1pt solid #888; padding:3px 5px; }
    .section-hdr {
      font-size:9pt; font-weight:800; margin:6px 0 3px;
      border-left:3pt solid #685182; padding-left:6px; color:#4E3A63; letter-spacing:0.3px;
    }
    .content-box {
      border:1pt solid #aaa; padding:5px 9px;
      font-size:8.5pt; border-radius:2px; white-space:pre-wrap; line-height:1.5;
    }
    .attendee-box {
      border:1pt solid #aaa; padding:5px 9px;
      font-size:8.5pt; margin-bottom:6px; border-radius:2px;
    }
    .foot-note {
      font-size:7pt; color:#777; text-align:right;
      margin-top:6px; border-top:0.5pt solid #ddd; padding-top:3px;
    }
    /* 결재 서명 패드 모달 */
    #approval-sign-modal {
      display:none; position:fixed; inset:0; background:rgba(0,0,0,0.5);
      z-index:9999; align-items:center; justify-content:center;
    }
    #approval-sign-modal.open { display:flex; }
    #approval-sign-box {
      background:#fff; border-radius:14px; padding:24px; width:340px;
      box-shadow:0 8px 32px rgba(0,0,0,0.25); font-family:inherit;
    }
    #approval-sign-canvas {
      border:1.5px solid #ccc; border-radius:8px; cursor:crosshair;
      touch-action:none; display:block; width:100%; height:160px;
    }
    .print-only { display:none; }
  </style>
</head>
<body>

  <!-- 화면 미리보기 툴바 -->
  <div class="print-toolbar no-print">
    <span class="toolbar-title">
      <span style="font-size:10px;opacity:0.7;margin-right:6px">📋 TBM 회의록 미리보기</span>
      ${(tbm.task_title || '').replace(/</g,'&lt;')}
    </span>
    <button class="btn-print" onclick="window.print()">🖨️ 인쇄 / PDF 저장</button>
    <button class="btn-close" onclick="window.parent.postMessage('closePrintOverlay','*')">✕ 닫기</button>
  </div>
  <!-- 페이지 래퍼: JS가 화면 크기에 맞게 scale 적용 -->
  <!-- ★ no-print 제거: blob URL 인쇄 시 page-sheet-wrap이 숨겨져 빈 페이지가 되는 버그 수정 -->
  <div class="page-sheet-wrap" id="pageWrap">

  <!-- ══════════════════════════════════════════════════
       PAGE 1 : 본문 (기본정보 ~ 위험요인)
       ══════════════════════════════════════════════════ -->
  <div class="page-label">─── 1페이지 ───</div>
  <div class="page-sheet" id="sheet1">
    <div class="page-inner" id="inner1">

      <div class="law-header">
        <span>산업안전보건법 제29조 / 시행규칙 제26조 · 별표 5 — TBM(Tool Box Meeting) 회의록</span>
        <span>출력일: ${today}</span>
      </div>

      <!-- 결재란 -->
      ${approvalHtml}

      <div class="doc-title">TBM 회의록</div>
      <div class="doc-subtitle">Tool Box Meeting — 산업안전보건법 제29조 작업 전 안전보건교육 실시 기록</div>

      <div class="law-notice">
        ※ 본 기록은 산업안전보건법 제29조(근로자에 대한 안전보건교육) 및 시행규칙 제26조·별표 5에 의거
           작업 전 안전교육 실시 기록으로 보관합니다. (산업안전보건법 시행규칙 제167조 — 3년 보관 의무)
      </div>

      ${warnBanner}

      <table class="info-table">
        <tr>
          <th>작업명</th>
          <td colspan="3">${(tbm.task_title || '-').replace(/</g,'&lt;')}</td>
          <th>담당자</th>
          <td>${(tbm.contractor_name || '-').replace(/</g,'&lt;')}</td>
        </tr>
        <tr>
          <th>실시일시</th>
          <td>${_toKSTDateTime(tbm.tbm_date)}</td>
          <th>TBM진행자</th>
          <td>${(tbm.conductor_name || '-').replace(/</g,'&lt;')}</td>
          <th>작업번호</th>
          <td>${(() => {
            // 요청번호의 작업번호(work_number) + 작업등록의 서브작업번호(sub_task_number)
            const workNum = (tbm.work_number || '').toString().trim();
            const subNum  = (tbm.sub_task_number || '').toString().trim();
            if (workNum && subNum) return workNum + '-' + subNum;
            if (workNum) return workNum;
            // work_number 없을 때 fallback: task_number 기반
            const taskNum = (tbm.task_number || '').toString().trim();
            if (taskNum && subNum) return taskNum + '-' + subNum;
            if (taskNum) return taskNum;
            return '-';
          })()}</td>
        </tr>
        <tr>
          <th>실시장소</th>
          <td>${(tbm.location || '-').replace(/</g,'&lt;')}</td>
          <th>날씨/기온</th>
          <td>${(tbm.weather || '-').replace(/</g,'&lt;')} / ${tbm.temperature || '-'}°C</td>
          <th>참석인원</th>
          <td>${tbm.workers_count || allAttendees.length || 0}명</td>
        </tr>
      </table>

      <div class="section-hdr">① 참석자 명단</div>
      <div class="attendee-box">
        ${attendeeTagsHtml || '<span style="color:#aaa;font-size:8pt">미입력</span>'}
      </div>

      <div class="section-hdr">② 작업내용 및 안전교육 사항 <span style="font-size:7.5pt;font-weight:400;color:#999">(산업안전보건법 시행규칙 별표 5 교육내용)</span></div>
      <div class="content-box">${(tbm.safety_topics || '미입력').replace(/</g,'&lt;').replace(/\n/g,'<br>')}</div>

      <div class="section-hdr">③ 위험요인 및 주의사항</div>
      <div class="content-box">${(tbm.precautions || '미입력').replace(/</g,'&lt;').replace(/\n/g,'<br>')}</div>

      ${tbm.special_notes ? `
      <div class="section-hdr">④ 특이사항 / 현장 전달사항</div>
      <div class="content-box">${(tbm.special_notes).replace(/</g,'&lt;').replace(/\n/g,'<br>')}</div>` : ''}

      <div class="foot-note">출력일시: ${printDt} &nbsp;·&nbsp; TBM ID: ${tbmId} &nbsp;·&nbsp; 산업안전보건법 시행규칙 제167조에 따라 3년간 보관</div>
    </div>
  </div>

  <!-- ══════════════════════════════════════════════════
       PAGE 2 : 서명란 + 사진 (한 페이지, _autoScale로 자동 축소)
       ══════════════════════════════════════════════════ -->
  <div class="page-label">─── 2페이지 (서명란 + 사진) ───</div>
  <div class="page-sheet" id="sheet2">
    <div class="page-inner" id="inner2">

      <div class="law-header">
        <span>산업안전보건법 제29조 / 시행규칙 제26조 · 별표 5 — TBM(Tool Box Meeting) 회의록</span>
        <span>출력일: ${today}</span>
      </div>

      <div class="section-hdr" style="margin-top:0">⑤ 서명란 <span style="font-size:7.5pt;font-weight:400;color:#999">(실시자 및 전체 참석 근로자 서명)</span></div>
      <table style="width:100%;border-collapse:collapse;font-size:8.5pt">
        <thead>
          <tr style="background:#f0eeef">
            <th style="border:1pt solid #888;width:44px;padding:3px 2px;text-align:center">구분</th>
            <th style="border:1pt solid #888;width:60px;padding:3px 4px;text-align:center">성명</th>
            <th style="border:1pt solid #888;width:52px;padding:3px 2px;text-align:center">직책</th>
            <th style="border:1pt solid #888;width:60px;padding:3px 2px;text-align:center">서명일시</th>
            <th style="border:1pt solid #888;padding:3px 2px;text-align:center">서명</th>
            <th style="border:none;width:6px;background:#f5f5f5"></th>
            <th style="border:1pt solid #888;width:44px;padding:3px 2px;text-align:center">구분</th>
            <th style="border:1pt solid #888;width:60px;padding:3px 4px;text-align:center">성명</th>
            <th style="border:1pt solid #888;width:52px;padding:3px 2px;text-align:center">직책</th>
            <th style="border:1pt solid #888;width:60px;padding:3px 2px;text-align:center">서명일시</th>
            <th style="border:1pt solid #888;padding:3px 2px;text-align:center">서명</th>
          </tr>
        </thead>
        <tbody>${sigRowsHtml}</tbody>
      </table>

      <div style="font-size:7pt;color:#888;margin-top:4px;line-height:1.4">
        ※ 교육 실시자는 반드시 서명란에 서명하여야 하며, 참석 근로자 전원이 서명함으로써 본 교육 참여를 확인합니다.
      </div>

      ${(() => {
        const secs = (tbmChecklistSections || []);
        const secsWithPhotos = secs.map(sec => {
          let ps = []; try { ps = typeof sec.photos==='string' ? JSON.parse(sec.photos) : (sec.photos||[]); } catch(_){}
          return { ...sec, parsedPhotos: ps.filter(p => p.file_path) };
        }).filter(sec => sec.parsedPhotos.length > 0);
        if (!secsWithPhotos.length) return '';
        let photoContent = '<div class="section-hdr" style="margin-top:8px">⑥ TBM 안전조치 사진</div>';
        secsWithPhotos.forEach(sec => {
          photoContent += '<div style="margin-bottom:8px">';
          photoContent += '<div style="background:#1D4ED8;color:white;padding:3px 10px;border-radius:5px 5px 0 0;font-size:8pt;font-weight:700;display:flex;align-items:center;gap:5px">'
                       + '<span>&#9632;</span> ' + (sec.section_name||'').replace(/</g,'&lt;')
                       + '<span style="margin-left:auto;font-size:7pt;opacity:0.85;font-weight:400">' + sec.parsedPhotos.length + '장</span>'
                       + '</div>';
          photoContent += '<div style="background:#EFF6FF;border:1.5px solid #BFDBFE;border-top:none;border-radius:0 0 5px 5px;padding:5px">';
          photoContent += '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:5px">';
          sec.parsedPhotos.forEach(p => {
            photoContent += '<div style="border:1px solid #BFDBFE;border-radius:4px;overflow:hidden;background:white">';
            photoContent += '<div style="width:100%;aspect-ratio:4/3;overflow:hidden;background:#f0f0f0">';
            photoContent += '<img src="' + _origin + '/api/tbm-photos/' + p.id + '/img?token=' + encodeURIComponent(_photoToken) + '"'
                         + ' style="width:100%;height:100%;object-fit:cover;display:block">';
            photoContent += '</div>';
            if (p.label) {
              photoContent += '<div style="padding:2px 5px;font-size:6.5pt;color:#1E40AF;background:#EFF6FF;border-top:1px solid #BFDBFE">' + (p.label||'').replace(/</g,'&lt;') + '</div>';
            }
            photoContent += '</div>';
          });
          photoContent += '</div></div></div>';
        });
        return photoContent;
      })()}

      <div class="foot-note">출력일시: ${printDt} &nbsp;·&nbsp; TBM ID: ${tbmId} &nbsp;·&nbsp; 산업안전보건법 시행규칙 제167조에 따라 3년간 보관</div>
    </div>
  </div>

  </div><!-- /page-sheet-wrap -->

  <!-- 결재 서명 패드 모달 -->
  <div id="approval-sign-modal">
    <div id="approval-sign-box">
      <div style="font-size:15px;font-weight:700;color:#4E3A63;margin-bottom:4px" id="approval-sign-title">결재 서명</div>
      <div style="font-size:12px;color:#888;margin-bottom:12px" id="approval-sign-desc"></div>
      <canvas id="approval-sign-canvas" width="292" height="160"></canvas>
      <div style="display:flex;gap:8px;margin-top:12px">
        <button id="approval-sign-clear"
          style="flex:1;padding:8px;border:1px solid #ddd;border-radius:8px;background:#f9f9f9;cursor:pointer;font-size:13px">
          지우기
        </button>
        <button id="approval-sign-submit"
          style="flex:2;padding:8px;border:none;border-radius:8px;background:#4E3A63;color:white;cursor:pointer;font-size:13px;font-weight:700">
          ✍ 서명 완료
        </button>
        <button id="approval-sign-cancel"
          style="flex:1;padding:8px;border:1px solid #ddd;border-radius:8px;background:#f9f9f9;cursor:pointer;font-size:13px">
          취소
        </button>
      </div>
    </div>
  </div>

  <script>
  // ── 각 페이지 자동 축소: 내용이 A4 높이를 초과하면 scale down ──────────────
  // A4 인쇄 가용 높이 = 297mm - 상하 패딩(13+14mm) = 270mm → px 환산
  // 1mm ≈ 3.7795px (96dpi 기준)
  // ── 화면 크기에 맞게 page-sheet-wrap 확대/축소 (미리보기 최대 크기) ────────
  function _fitToScreen() {
    const wrap = document.getElementById('pageWrap');
    if (!wrap) return;
    const TOOLBAR_H = 52;
    const PADDING   = 16;
    const availW = window.innerWidth  - PADDING * 2;
    const availH = window.innerHeight - TOOLBAR_H - PADDING;
    // 210mm = 793.7px (96dpi 기준)
    const sheetW = 210 * 3.7795;
    const scaleW = availW / sheetW;
    // 세로는 넘쳐도 스크롤 허용 — 가로 기준으로만 맞춤
    const scale  = Math.min(scaleW, 1.5); // 최대 1.5배까지만 확대
    wrap.style.transform = \`scale(\${scale})\`;
    wrap.style.transformOrigin = 'top center';
    // wrap이 scale 후 차지하는 실제 높이 보정
    const sheets = wrap.querySelectorAll('.page-sheet');
    let totalH = 0;
    sheets.forEach(s => { totalH += s.offsetHeight + 24; });
    wrap.style.marginBottom = (totalH * scale - totalH) + 'px';
  }
  _fitToScreen();
  window.addEventListener('resize', _fitToScreen);

  // ── 사진 lazy load 완료 후 _autoScale 재실행 (사진 높이 반영) ────────────
  function _autoScale() {
    const MM_TO_PX = 3.7795;
    const A4_H_MM  = 297;
    const PAD_TOP_MM  = 13;
    const PAD_BOT_MM  = 14;
    const AVAIL_H_PX  = (A4_H_MM - PAD_TOP_MM - PAD_BOT_MM) * MM_TO_PX; // ~1020px

    ['inner1','inner2'].forEach(id => {
      const inner = document.getElementById(id);
      if (!inner) return;
      inner.style.transform = '';
      const naturalH = inner.scrollHeight;
      if (naturalH <= AVAIL_H_PX) return;
      const scale = AVAIL_H_PX / naturalH;
      inner.style.transform = \`scale(\${scale})\`;
    });
  }

  // 초기 실행 (서명 이미지 등 즉시 로드 항목 반영)
  _autoScale();

  // 사진 로드 완료 후 재실행 (base64 embed 혹은 fallback URL 이미지 높이 반영)
  (function _watchPhotoLoad() {
    const imgs = document.querySelectorAll('#inner2 img');
    if (!imgs.length) return;
    let loaded = 0;
    imgs.forEach(img => {
      if (img.complete) {
        loaded++;
        if (loaded === imgs.length) _autoScale();
      } else {
        img.addEventListener('load',  () => { loaded++; if (loaded === imgs.length) _autoScale(); });
        img.addEventListener('error', () => { loaded++; if (loaded === imgs.length) _autoScale(); });
      }
    });
  })();

  // ── 결재 서명 패드 로직 ────────────────────────────────────────────────────
  (function() {
    const TOKEN   = '${localStorage.getItem('token') || ''}';
    const TBM_ID  = ${tbmId};
    const BASE_URL = '${window.location.origin}';

    let _currentApprovalRole = null;
    const modal    = document.getElementById('approval-sign-modal');
    const canvas   = document.getElementById('approval-sign-canvas');
    const ctx      = canvas.getContext('2d');
    let drawing    = false;
    let hasStroke  = false;

    // 캔버스 실제 픽셀 크기 보정
    function resizeCanvas() {
      const rect = canvas.getBoundingClientRect();
      const scaleX = rect.width  / canvas.clientWidth  || 1;
      const scaleY = rect.height / canvas.clientHeight || 1;
      if (canvas.width !== rect.width || canvas.height !== rect.height) {
        canvas.width  = Math.round(rect.width);
        canvas.height = Math.round(rect.height);
      }
    }

    function getPos(e) {
      const rect = canvas.getBoundingClientRect();
      const src = e.touches ? e.touches[0] : e;
      return { x: src.clientX - rect.left, y: src.clientY - rect.top };
    }

    canvas.addEventListener('mousedown',  e => { resizeCanvas(); drawing=true; hasStroke=true; const p=getPos(e); ctx.beginPath(); ctx.moveTo(p.x,p.y); });
    canvas.addEventListener('mousemove',  e => { if(!drawing) return; const p=getPos(e); ctx.lineWidth=2; ctx.lineCap='round'; ctx.strokeStyle='#1a1a1a'; ctx.lineTo(p.x,p.y); ctx.stroke(); });
    canvas.addEventListener('mouseup',    () => drawing=false);
    canvas.addEventListener('mouseleave', () => drawing=false);
    canvas.addEventListener('touchstart', e => { e.preventDefault(); resizeCanvas(); drawing=true; hasStroke=true; const p=getPos(e); ctx.beginPath(); ctx.moveTo(p.x,p.y); }, {passive:false});
    canvas.addEventListener('touchmove',  e => { e.preventDefault(); if(!drawing) return; const p=getPos(e); ctx.lineWidth=2; ctx.lineCap='round'; ctx.strokeStyle='#1a1a1a'; ctx.lineTo(p.x,p.y); ctx.stroke(); }, {passive:false});
    canvas.addEventListener('touchend',   () => drawing=false);

    document.getElementById('approval-sign-clear').onclick = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      hasStroke = false;
    };
    document.getElementById('approval-sign-cancel').onclick = () => {
      modal.classList.remove('open');
      _currentApprovalRole = null;
    };

    document.getElementById('approval-sign-submit').onclick = async () => {
      if (!hasStroke) { alert('서명을 입력해 주세요.'); return; }
      const signData = canvas.toDataURL('image/png');
      try {
        const res = await fetch(BASE_URL + '/api/tbm/' + TBM_ID + '/approval-sign', {
          method: 'POST',
          headers: { 'Content-Type':'application/json', 'Authorization':'Bearer ' + TOKEN },
          body: JSON.stringify({ approval_role: _currentApprovalRole, sign_data: signData })
        });
        const json = await res.json();
        if (!res.ok) { alert(json.error || '서명 처리 실패'); return; }
        modal.classList.remove('open');
        // blob URL iframe은 window.location.reload() 불가 → 부모에 재출력 요청
        window.parent.postMessage({ type: 'reloadTbmPrint', tbmId: TBM_ID }, '*');
      } catch(e) {
        alert('서명 처리 중 오류가 발생했습니다.');
      }
    };

    // 전역 함수: 결재란 서명 버튼 onclick에서 호출
    // 서명 순서: 안전관리자 → 총괄책임(현장대리인) → 대표이사
    const ROLE_LABELS = {
      approval_safety:  '안전관리자 서명',
      approval_general: '총괄책임 결재 서명',
      // BUG-089: approval_ceo 제거됨
    };
    const ROLE_DESCS = {
      approval_safety:  '안전관리자로서 TBM 회의록을 확인하고 서명합니다.',
      approval_general: '총괄책임으로서 TBM 회의록을 결재합니다.',
      // BUG-089: approval_ceo 제거됨
    };

    window._tbmApprovalSign = function(role) {
      _currentApprovalRole = role;
      document.getElementById('approval-sign-title').textContent = ROLE_LABELS[role] || '결재 서명';
      document.getElementById('approval-sign-desc').textContent  = ROLE_DESCS[role]  || '';
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      hasStroke = false;
      modal.classList.add('open');
      setTimeout(resizeCanvas, 50);
    };
  })();
  </script>

</body>
</html>`;
    _openPrintOverlay(_tbmPrintHtml);
  } catch(e) {
    toast(e.message || 'TBM 인쇄 데이터 로딩 실패', 'error');
  }
}

// FEAT-037: TBM 완료 결과 공유 — 클립보드 복사 (공개 URL, 7일 유효)
async function _tbmShare(tbmId, btnEl) {
  if (btnEl) { btnEl.disabled = true; btnEl.innerHTML = '<i class="fas fa-spinner fa-spin"></i> 처리 중...'; }
  try {
    const res = await API.post(`/tbm/${tbmId}/share-token`);
    const d = res.data;
    const fullUrl = window.location.origin + d.url;
    if (btnEl) { btnEl.disabled = false; btnEl.innerHTML = '<i class="fas fa-share-alt"></i> 공유'; }

    // ── 복사 텍스트 구성 ──────────────────────────────────────────
    const workerList = (d.attendees && d.attendees.length > 0 ? d.attendees : d.assigned_workers) || [];
    const lines = [];
    if (d.work_number)      lines.push(`작업번호   : ${d.work_number}`);
    if (d.task_title)       lines.push(`작업명     : ${d.task_title}`);
    if (d.contractor_name)  lines.push(`담당자     : ${d.contractor_name}`);
    if (d.lgu_supervisor)   lines.push(`공사감독자 : ${d.lgu_supervisor}`);
    if (workerList.length)  lines.push(`작업자     : ${workerList.join(', ')}`);
    if (d.gps_address)      lines.push(`TBM실시 주소 : ${d.gps_address}`);
    lines.push(`TBM사진은 아래 URL 클릭`);
    lines.push(fullUrl);
    const shareText = lines.join('\n');

    // ── 클립보드 복사 시도 ────────────────────────────────────────
    try {
      await navigator.clipboard.writeText(shareText);
      toast('TBM 공유 내용이 클립보드에 복사되었습니다. (링크 7일 유효)', 'success');
    } catch(_) {
      // clipboard API 불가 시 모달로 내용 표시
      const m = document.createElement('div');
      m.className = 'modal-overlay modal-sm';
      m.innerHTML = `
        <div class="bg-white rounded-2xl overflow-hidden max-w-sm w-full mx-4">
          <div class="flex justify-between items-center px-4 py-3 border-b">
            <span class="font-semibold text-sm"><i class="fas fa-share-alt mr-2 text-sky-500"></i>TBM 결과 공유</span>
            <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 hover:text-gray-600 text-xl">&times;</button>
          </div>
          <div class="p-4">
            <p class="text-xs text-gray-500 mb-2">아래 내용을 복사하여 공유하세요 <span style="color:#0EA5E9">(링크 7일 유효)</span></p>
            <textarea id="_tbmShareText" readonly
              style="width:100%;height:160px;background:#F9FAFB;border:1px solid #E5E7EB;border-radius:8px;padding:10px;font-size:12px;line-height:1.6;color:#1F2937;resize:none;font-family:inherit"></textarea>
            <button onclick="const t=document.getElementById('_tbmShareText');t.select();navigator.clipboard.writeText(t.value).catch(()=>{document.execCommand('copy');}).then(()=>{ toast('복사됨','success'); this.closest('.modal-overlay').remove(); })"
              style="margin-top:10px;width:100%;padding:8px;background:#0EA5E9;color:white;border:none;border-radius:8px;font-size:13px;font-weight:600;cursor:pointer">
              <i class="fas fa-copy mr-1"></i> 복사
            </button>
          </div>
        </div>`;
      m.querySelector('#_tbmShareText').value = shareText;
      m.addEventListener('click', e => { if (e.target === m) m.remove(); });
      document.body.appendChild(m);
    }
  } catch(e) {
    if (btnEl) { btnEl.disabled = false; btnEl.innerHTML = '<i class="fas fa-share-alt"></i> 공유'; }
    toast(e.response?.data?.error || 'TBM 공유 링크 생성에 실패했습니다.', 'error');
  }
}

// task_id 기준으로 tbm_id를 조회한 후 _tbmShare 호출 (근로자 카드 공유 버튼)
async function _tbmShareByTaskId(taskId, btnEl) {
  if (btnEl) { btnEl.disabled = true; btnEl.innerHTML = '<i class="fas fa-spinner fa-spin"></i>'; }
  try {
    const res = await API.get(`/tasks/${taskId}/tbm-info`);
    const tbmId = res.data?.tbm?.id;
    if (!tbmId) { toast('TBM 정보를 찾을 수 없습니다.', 'error'); return; }
    if (btnEl) { btnEl.disabled = false; btnEl.innerHTML = '<i class="fas fa-share-alt"></i> 공유'; }
    await _tbmShare(tbmId, null);
  } catch(e) {
    if (btnEl) { btnEl.disabled = false; btnEl.innerHTML = '<i class="fas fa-share-alt"></i> 공유'; }
    toast('TBM 공유 링크 생성에 실패했습니다.', 'error');
  }
}

// ======= 근로자 - 내 작업 목록 =======
// 나의작업현황 카드 클릭 → 내 작업 페이지로 필터 이동
let _myTasksFilter = null;  // 'all' | 'working' | 'completed' | 'logs' | 'quantity'
function navigateMyTasksWithFilter(filterType) {
  _myTasksFilter = filterType;
  navigateTo('my-tasks');
}
// 내 작업 페이지 내부에서 즉시 필터 재렌더링 (페이지 이동 없이 카드 클릭)
function applyMyTasksFilter(filterType) {
  _myTasksFilter = filterType;
  // 실제 컨테이너 ID는 'page-content' (main-content 아님)
  const content = document.getElementById('page-content') || document.getElementById('main-content');
  if (content) renderMyTasksPage(content);
}

async function renderMyTasksPage(container) {
  // 나의작업현황에서 넘어온 필터 소비
  const activeFilter = _myTasksFilter;
  _myTasksFilter = null;

  try {
    // 내 작업 + 미배정 작업(직접 선택 가능) 모두 로드
    const [myRes, unassignedRes] = await Promise.all([
      API.get('/tasks'),
      API.get('/tasks/unassigned-list')
    ]);
    const myTasks  = Array.isArray(myRes.data) ? myRes.data : (myRes.data?.tasks || []);
    const unassigned = (Array.isArray(unassignedRes.data) ? unassignedRes.data : (unassignedRes.data?.tasks || [])).filter(t => !myTasks.find(m => m.id === t.id));

    // ── 필터별 표시 작업 선택 ──────────────────────────────
    // logs/quantity 필터는 통계 API에서 task_id 목록이 필요하므로 추가 로드
    let logTaskIds = null;
    if (activeFilter === 'logs' || activeFilter === 'quantity') {
      try {
        const statsRes = await API.get('/stats/worker/me');
        const logs = statsRes.data?.recentLogs || [];
        logTaskIds = new Set(logs.map(l => l.task_id).filter(Boolean));
      } catch(e) { logTaskIds = new Set(); }
    }

    // 필터 정의
    const FILTER_META = {
      all:       { label:'전체 배정 작업',    icon:'fas fa-list',           color:'#3B82F6' },
      working:   { label:'진행 중 작업',      icon:'fas fa-spinner',        color:'#10B981' },
      completed: { label:'완료 작업',         icon:'fas fa-check-circle',   color:'#F59E0B' },
      logs:      { label:'작업 일지 작성 작업', icon:'fas fa-book-open',      color:'#F59E0B' },
      quantity:  { label:'시공 실적 작업',     icon:'fas fa-ruler-combined', color:'#8B5CF6' },
    };

    let filteredTasks = myTasks;
    if (activeFilter === 'working') {
      filteredTasks = myTasks.filter(t => t.status === 'working');
    } else if (activeFilter === 'completed') {
      filteredTasks = myTasks.filter(t => t.status === 'completed');
    } else if (activeFilter === 'logs' && logTaskIds) {
      filteredTasks = myTasks.filter(t => logTaskIds.has(t.id));
    } else if (activeFilter === 'quantity' && logTaskIds) {
      filteredTasks = myTasks.filter(t => logTaskIds.has(t.id));
    }

    // 필터 없을 때만 미배정 포함
    const tasks = activeFilter
      ? filteredTasks
      : [...myTasks, ...unassigned.map(t => ({...t, _unassigned: true}))];

    const fm = activeFilter ? FILTER_META[activeFilter] : null;

    container.innerHTML = `
    <div class="page-container">
      ${fm ? `
      <!-- 필터 배너 -->
      <div class="flex items-center justify-between mb-4 px-3 py-2 rounded-xl"
           style="background:${fm.color}18;border:1.5px solid ${fm.color}44">
        <div class="flex items-center gap-2">
          <i class="${fm.icon}" style="color:${fm.color}"></i>
          <span class="text-sm font-bold" style="color:${fm.color}">${fm.label}</span>
          <span class="text-xs px-2 py-0.5 rounded-full font-semibold text-white" style="background:${fm.color}">${tasks.length}건</span>
        </div>
        <button onclick="applyMyTasksFilter(null)" class="text-xs text-gray-400 hover:text-gray-600">
          <i class="fas fa-times mr-1"></i>필터 해제
        </button>
      </div>` : ''}

      <div class="mb-4 grid grid-cols-3 gap-3">
        <div class="stat-card blue shadow-sm text-center cursor-pointer hover:shadow-md transition-shadow active:scale-95"
             onclick="applyMyTasksFilter('all')" title="전체 작업 목록">
          <div class="text-2xl font-bold text-blue-600">${myTasks.length}</div>
          <div class="text-xs text-gray-500">내 작업</div>
          <div class="text-xs mt-1" style="color:#3B82F6;opacity:0.7"><i class="fas fa-arrow-right text-xs"></i></div>
        </div>
        <div class="stat-card green shadow-sm text-center cursor-pointer hover:shadow-md transition-shadow active:scale-95"
             onclick="applyMyTasksFilter('working')" title="진행 중 작업 목록">
          <div class="text-2xl font-bold text-green-600">${myTasks.filter(t=>t.status==='working').length}</div>
          <div class="text-xs text-gray-500">진행중</div>
          <div class="text-xs mt-1" style="color:#10B981;opacity:0.7"><i class="fas fa-arrow-right text-xs"></i></div>
        </div>
        <div class="stat-card yellow shadow-sm text-center cursor-pointer hover:shadow-md transition-shadow active:scale-95"
             onclick="applyMyTasksFilter('completed')" title="완료 작업 목록">
          <div class="text-2xl font-bold text-yellow-600">${myTasks.filter(t=>t.status==='completed').length}</div>
          <div class="text-xs text-gray-500">완료</div>
          <div class="text-xs mt-1" style="color:#F59E0B;opacity:0.7"><i class="fas fa-arrow-right text-xs"></i></div>
        </div>
      </div>
      ${!activeFilter && unassigned.length > 0 ? `
      <div class="mb-4 p-3 bg-blue-50 border border-blue-200 rounded-xl">
        <div class="text-sm font-bold text-blue-700 mb-1"><i class="fas fa-info-circle mr-1"></i>배정 가능한 미배정 작업 ${unassigned.length}건이 있습니다.</div>
        <div class="text-xs text-blue-500">아래 목록에서 "내 작업 가져오기"를 눌러 작업을 배정받을 수 있습니다.</div>
      </div>` : ''}

      <div class="space-y-3">
        ${tasks.length === 0 ? `
          <div class="text-center py-12 text-gray-400">
            <i class="fas fa-clipboard-list text-5xl mb-3"></i>
            <p>배정된 작업이 없습니다.</p>
          </div>` :
          tasks.map(t => `
            <div class="card cursor-pointer hover:shadow-md transition-shadow" onclick="showTaskDetail(${t.id})">
              <div class="flex justify-between items-start mb-2">
                <div class="flex-1 min-w-0">
                  <h3 class="font-bold text-gray-800 truncate">${t.title}</h3>
                  <p class="text-xs text-gray-400 mt-1">${t.category_name||''} ${t.work_type_name?'· '+t.work_type_name:''}</p>
                </div>
                ${statusBadge(t.status)}
              </div>
              <div class="flex gap-4 text-xs text-gray-500 mb-3">
                <span><i class="fas fa-map-marker-alt mr-1"></i>${t.location||'-'}</span>
                <span><i class="fas fa-calendar mr-1"></i>${formatDate(t.planned_date)}</span>
                ${priorityBadge(t.priority)}
              </div>

              <!-- 작업 플로우: 작업자배정→위험성체크리스트→TBM→작업개시→작업완료→일지완료 -->
              <div class="flex gap-1 overflow-x-auto pb-1">
                ${['assigned','in_progress','tbm_done','working','work_completed','completed'].map(s => {
                  const statusOrder = ['unassigned','assigned','in_progress','tbm_done','working','work_completed','completed'];
                  const labels = {assigned:'배정',in_progress:'체크리스트',tbm_done:'TBM',working:'작업개시',work_completed:'작업완료',completed:'일지완료'};
                  const curIdx = statusOrder.indexOf(t.status);
                  const stepIdx = statusOrder.indexOf(s);
                  const done = curIdx > stepIdx;
                  const active = curIdx === stepIdx;
                  const isLast = s === 'completed';
                  const purpleFrom = statusOrder.indexOf('work_completed');
                  // work_completed 이후 단계는 보라색
                  const dotStyle = done
                    ? (stepIdx >= purpleFrom ? 'background:#685182;color:#fff' : 'background:#D70072;color:#fff')
                    : active
                      ? (stepIdx >= purpleFrom ? 'background:#685182;color:#fff;opacity:0.85' : 'background:#D70072;color:#fff;opacity:0.85')
                      : 'background:#D8D0DC;color:#C6C6C6';
                  return `<div class="flex items-center gap-0.5">
                    <div class="w-5 h-5 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0" style="${dotStyle}">
                      ${done?'✓':''}
                    </div>
                    <span class="text-gray-400 whitespace-nowrap" style="font-size:10px">${labels[s]}</span>
                    ${!isLast?'<div class="w-2 h-0.5 bg-gray-200 flex-shrink-0"></div>':''}
                  </div>`;
                }).join('')}
              </div>

              <!-- tbm_done 상태: 서명 현황 배너 -->
              ${t.status === 'tbm_done' ? `
              <div style="margin-top:8px;padding:8px 10px;border-radius:10px;background:#FFF8E7;border:1.5px solid #FDE68A;cursor:pointer"
                onclick="event.stopPropagation();_openTbmSignPanel(${t.id})">
                <div style="display:flex;align-items:center;justify-content:space-between">
                  <span style="font-size:12px;font-weight:700;color:#92400E">
                    <i class="fas fa-pen-nib" style="margin-right:5px;color:#D97706"></i>TBM 서명 현황
                  </span>
                  <span style="font-size:11px;color:#B45309;font-weight:600" id="tbm-sig-badge-${t.id}">
                    <i class="fas fa-spinner fa-spin" style="font-size:10px"></i> 확인 중...
                  </span>
                </div>
                <div style="font-size:11px;color:#92400E;margin-top:4px">
                  <i class="fas fa-hand-pointer" style="margin-right:3px"></i>탭하여 서명 현황 확인 및 서명 받기
                </div>
              </div>` : ''}

              <!-- 빠른 액션 (워크플로우 반영) -->
              <div class="flex flex-wrap gap-2 mt-3" onclick="event.stopPropagation()">
                ${t.status === 'unassigned' ? `<button onclick="selfAssignTask(${t.id})" class="btn btn-primary text-xs py-1 flex-1"><i class="fas fa-hand-pointer mr-1"></i>내 작업 가져오기</button>` : ''}
                ${t.status === 'assigned' ? `<button onclick="showChecklistAssessment(${t.id},this.dataset.title,this.dataset.cls)" data-title="${(t.title||'').replace(/"/g,'&quot;')}" data-cls="${t.work_class||'cable_install'}" class="btn btn-purple text-xs py-1 flex-1"><i class="fas fa-clipboard-list mr-1"></i>위험성(체크리스트)평가</button>` : ''}
                ${t.status === 'in_progress' ? `<button onclick="showTbmForm(${t.id})" class="btn btn-warning text-xs py-1 flex-1"><i class="fas fa-users mr-1"></i>TBM 실시</button>` : ''}
                ${t.status === 'tbm_done' ? `
                  <button id="tbm-sign-btn-${t.id}" onclick="_openTbmSignPanel(${t.id})" class="btn text-xs py-1 flex-1 font-bold" style="background:linear-gradient(135deg,#D70072,#FF349E);color:white;border:none">
                    <i class="fas fa-pen-nib mr-1"></i>서명 받기
                  </button>
                  <button id="tbm-share-btn-${t.id}" onclick="_tbmShareByTaskId(${t.id}, this)" style="display:none;padding:5px 10px;background:#0EA5E9;color:white;border:none;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer;align-items:center;gap:3px">
                    <i class="fas fa-share-alt"></i> 공유
                  </button>
                  <button onclick="changeTaskStatus(${t.id},'working')" class="btn btn-success text-xs py-1 flex-1"><i class="fas fa-play mr-1"></i>작업 개시</button>
                ` : ''}
                ${t.status === 'working' ? `<button onclick="confirmWorkComplete(${t.id})" class="btn btn-warning text-xs py-1 flex-1"><i class="fas fa-flag-checkered mr-1"></i>작업 완료</button>` : ''}
                ${t.status === 'work_completed' ? `
                  <div class="w-full">
                    <div class="flex items-center gap-1 mb-1.5 px-2 py-1 rounded-lg" style="background:#EDE7F6;border:1px solid #8E72A8">
                      <i class="fas fa-clipboard-check text-xs" style="color:#685182"></i>
                      <span class="text-xs font-medium" style="color:#4E3A63">작업 완료 — 일지 작성이 필요합니다</span>
                    </div>
                    <button onclick="showWorkLogForm(${t.id})" class="btn text-xs py-1 w-full text-white font-bold" style="background:#685182;border-color:#685182"><i class="fas fa-pen mr-1"></i>작업 일지 작성</button>
                  </div>` : ''}
                ${t.status === 'completed' ? `<button onclick="showWorkLogForm(${t.id})" class="btn btn-outline text-xs py-1 flex-1"><i class="fas fa-book-open mr-1"></i>일지 추가 작성</button>` : ''}
                ${t.status !== 'unassigned' && t.status !== 'work_completed' ? `<button onclick="showPhotoUpload(${t.id})" class="btn btn-outline text-xs py-1 px-3"><i class="fas fa-camera"></i></button>` : ''}
              </div>
            </div>
          `).join('')}
      </div>
    </div>`;

    // ── tbm_done 카드 서명 현황 배지 비동기 업데이트 ──────────────────────────
    // 렌더링 완료 후 tbm_done 상태 작업들의 서명 현황을 병렬로 조회해 배지 갱신
    const tbmDoneTasks = tasks.filter(t => t.status === 'tbm_done');
    if (tbmDoneTasks.length > 0) {
      // 약간의 딜레이 후 병렬 조회 (DOM 업데이트 완료 보장)
      setTimeout(() => {
        tbmDoneTasks.forEach(t => _loadTbmSigBadge(t.id));
      }, 100);
    }

  } catch(e) {
    container.innerHTML = `<p class="text-red-500 p-4">로드 실패: ${e.message}</p>`;
  }
}

// ======= 현장 점검 =======
async function renderInspectionsPage(container) {
  try {
    // ── 전역 필터 상태 초기화 ──────────────────────────────────
    const _today = getKSTDate(); // KST 기준 오늘 날짜
    // 첫 진입 기본값: 당일 점검(KST), 작업탭 = 현장진행중
    if (window._insDateFrom     === undefined) window._insDateFrom     = _today;
    if (window._insDateTo       === undefined) window._insDateTo       = _today;
    if (window._insStatusFilter === undefined) window._insStatusFilter = '';   // 점검 처리상태 (open/in_progress/closed/'' 전체)
    if (window._insTaskTab      === undefined) window._insTaskTab      = 'active'; // 작업상태 탭

    const _df  = window._insDateFrom;
    const _dt  = window._insDateTo;
    const _sf  = window._insStatusFilter;
    const _tab = window._insTaskTab;

    // ── 작업상태 탭 정의 ──────────────────────────────────────
    // active  : TBM완료 + 작업중 (현장 진행중) ← 기본
    // progress: 배정완료 ~ 작업완료 전 (작업진행 전체)
    // done    : 작업완료 + 일지완료 (종료된 작업)
    // all     : 취소 제외 전체
    const ACTIVE_STATUSES    = ['tbm_done', 'working'];
    const PROGRESS_STATUSES  = ['assigned', 'in_progress', 'tbm_done', 'working', 'work_completed'];
    const DONE_STATUSES      = ['work_completed', 'completed'];

    // ── API 쿼리 파라미터 ─────────────────────────────────────
    const insParams = new URLSearchParams();
    if (_df) insParams.set('date_from', _df);
    if (_dt) insParams.set('date_to',   _dt);
    if (_sf) insParams.set('status',    _sf);

    // ── 데이터 로드 ───────────────────────────────────────────
    const [tasksRes, insRes] = await Promise.all([
      API.get('/tasks'),
      API.get(`/inspections?${insParams.toString()}`),
    ]);
    const _rawAllTasks = tasksRes.data.tasks || tasksRes.data || [];
    const inspections = insRes.data || [];

    // ── [BUG-079] LGU+ 클라이언트 필터: is_auto_request_no=0 건만 표시 ──────
    // 서버에서 이미 필터되지만, sub_role 누락 등 방어를 위해 클라이언트도 적용
    var _insMyUiRole = dbRoleToUi(currentUser.role, currentUser.position, currentUser.sub_role);
    var _insIsLgu = (_insMyUiRole === 'lgu_plus' || currentUser.role === 'lgu_plus' || currentUser.role === 'lgu'); // [FEAT-048]
    const allTasks = _insIsLgu
      ? _rawAllTasks.filter(function(t) { return t.is_auto_request_no === 0; })
      : _rawAllTasks;

    // ── 작업상태 탭 기준 필터링 ───────────────────────────────
    const filterByTab = (t) => {
      if (_tab === 'active')   return ACTIVE_STATUSES.includes(t.status);
      if (_tab === 'progress') return PROGRESS_STATUSES.includes(t.status);
      if (_tab === 'done')     return DONE_STATUSES.includes(t.status);
      return t.status !== 'cancelled'; // all
    };
    const tasks = allTasks.filter(filterByTab);

    // ── 모달용 작업자 맵 ──────────────────────────────────────
    _insTaskWorkersMap = {};
    for (const t of allTasks) {
      if (Array.isArray(t.assigned_workers) && t.assigned_workers.length > 0) {
        _insTaskWorkersMap[t.id] = t.assigned_workers.map(w => ({ id: w.id, name: w.name, position: w.position || '' }));
      }
    }
    window._insTasksCache = allTasks;

    // ── task_id → 점검 목록 맵핑 (날짜 필터 적용된 점검) ─────
    const insMap = {};
    inspections.forEach(i => {
      const tid = i.task_id || '__none__';
      if (!insMap[tid]) insMap[tid] = [];
      insMap[tid].push(i);
    });

    // ── 상태 표시 헬퍼 ───────────────────────────────────────
    const TASK_STATUS = {
      unassigned:     { label:'미배정',       cls:'bg-gray-100 text-gray-500',    dot:'#9CA3AF' },
      assigned:       { label:'배정완료',     cls:'bg-blue-100 text-blue-600',    dot:'#3B82F6' },
      in_progress:    { label:'체크리스트완료', cls:'bg-yellow-100 text-yellow-700', dot:'#F59E0B' },
      tbm_done:       { label:'TBM완료',      cls:'bg-purple-100 text-purple-700', dot:'#7C3AED' },
      working:        { label:'작업진행중',    cls:'bg-green-100 text-green-700',   dot:'#10B981' },
      work_completed: { label:'작업완료',     cls:'bg-teal-100 text-teal-700',    dot:'#0D9488' },
      completed:      { label:'일지완료',     cls:'bg-gray-200 text-gray-600',    dot:'#6B7280' },
      cancelled:      { label:'취소',         cls:'bg-red-100 text-red-400',      dot:'#F87171' },
    };
    const INS_STATUS = {
      open:        { label:'미처리', cls:'bg-yellow-100 text-yellow-700', icon:'fas fa-exclamation-circle' },
      in_progress: { label:'처리중', cls:'bg-blue-100 text-blue-700',    icon:'fas fa-spinner' },
      closed:      { label:'완료',   cls:'bg-green-100 text-green-700',   icon:'fas fa-check-circle' },
    };
    const HAZARD_CLS = {
      critical:'bg-red-100 text-red-700', high:'bg-orange-100 text-orange-700',
      medium:'bg-yellow-100 text-yellow-700', low:'bg-gray-100 text-gray-500'
    };
    const HAZARD_LBL = { critical:'긴급', high:'높음', medium:'보통', low:'낮음' };
    const INS_TYPE_LBL = { routine:'정기점검', joint:'합동점검', frequent:'수시점검' };

    // ── 탭별 카운트 ───────────────────────────────────────────
    const cnt = (statuses) => allTasks.filter(t => statuses.includes(t.status)).length;
    const cntAll = allTasks.filter(t => t.status !== 'cancelled').length;

    // ── 점검 필터 (점검있음/없음) ─────────────────────────────
    window._insSubFilter = window._insSubFilter || 'all';

    // ── 날짜 범위 표시 ────────────────────────────────────────
    const dateRangeLabel = (_df === _dt && _df)
      ? _df
      : (_df || _dt) ? `${_df || '처음'} ~ ${_dt || '오늘'}` : '전체 기간';

    const TAB_DEFS = [
      { key:'active',   label:'🟢 현장진행중', desc:'TBM완료·작업중',       statuses: ACTIVE_STATUSES },
      { key:'progress', label:'📋 작업진행',   desc:'배정완료~작업완료',     statuses: PROGRESS_STATUSES },
      { key:'done',     label:'✅ 완료',        desc:'작업완료·일지완료',     statuses: DONE_STATUSES },
      { key:'all',      label:'전체',          desc:'취소 제외 전체',        statuses: null },
    ];

    container.innerHTML = `
    <div class="page-container">
      <!-- 헤더 -->
      <div class="flex items-center justify-between mb-3 flex-wrap gap-2">
        <div>
          <h2 class="text-xl font-black text-gray-900" style="border-left:4px solid #685182;padding-left:10px">현장점검</h2>
          <p class="text-xs text-gray-400 mt-0.5 pl-3">${dateRangeLabel} · 점검 ${inspections.length}건</p>
        </div>
        <button onclick="showCreateInspectionModal()" class="btn btn-primary">
          <i class="fas fa-plus mr-1"></i>점검 등록
        </button>
      </div>

      <!-- ① 작업상태 탭 (주 필터) -->
      <div class="flex gap-1 mb-3 flex-wrap">
        ${TAB_DEFS.map(tab => {
          const tabCnt = tab.statuses ? cnt(tab.statuses) : cntAll;
          const isActive = _tab === tab.key;
          return `<button
            onclick="window._insTaskTab='${tab.key}';window._insSubFilter='all';renderInspectionsPage(document.getElementById('page-content'))"
            style="padding:6px 14px;border-radius:999px;font-size:12px;font-weight:700;border:2px solid ${isActive?'#685182':'#D8D0DC'};
                   background:${isActive?'#685182':'white'};color:${isActive?'white':'#685182'};cursor:pointer;transition:all .15s;white-space:nowrap">
            ${tab.label}
            <span style="background:${isActive?'rgba(255,255,255,0.25)':'#F5F0F8'};border-radius:999px;padding:0 6px;font-size:11px;margin-left:3px;color:${isActive?'white':'#685182'}">${tabCnt}</span>
          </button>`;
        }).join('')}
      </div>

      <!-- ② 점검일 + 처리상태 필터 바 -->
      <div class="card p-3 mb-3" style="background:#F5F0F8;border:1px solid #D8D0DC">
        <div class="flex flex-wrap items-center gap-2">
          <!-- 점검 처리상태 -->
          <div class="flex items-center gap-1">
            <label class="text-xs font-bold text-gray-600 whitespace-nowrap">점검상태</label>
            <select id="insStatusFilter" class="form-control text-sm" style="width:auto;min-width:85px">
              <option value=""            ${_sf===''           ?'selected':''}>전체</option>
              <option value="open"        ${_sf==='open'       ?'selected':''}>미처리</option>
              <option value="in_progress" ${_sf==='in_progress'?'selected':''}>처리중</option>
              <option value="closed"      ${_sf==='closed'     ?'selected':''}>완료</option>
            </select>
          </div>
          <!-- 날짜 범위 -->
          <div class="flex items-center gap-1">
            <label class="text-xs font-bold text-gray-600 whitespace-nowrap">점검일</label>
            <input type="date" id="insDateFrom" value="${_df}" class="form-control text-sm" style="width:135px">
            <span class="text-gray-400 text-sm">~</span>
            <input type="date" id="insDateTo"   value="${_dt}" class="form-control text-sm" style="width:135px">
          </div>
          <!-- 빠른 날짜 선택 -->
          <div class="flex gap-1">
            <button onclick="_setInsDateRange('today')"  class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">오늘</button>
            <button onclick="_setInsDateRange('week')"   class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">7일</button>
            <button onclick="_setInsDateRange('month')"  class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">30일</button>
            <button onclick="_setInsDateRange('all')"    class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">전체</button>
          </div>
          <button onclick="_applyInsFilters()" class="btn btn-sm ml-auto" style="background:#685182;color:white;border:none">
            <i class="fas fa-search mr-1"></i>조회
          </button>
        </div>
      </div>

      <!-- ③ 점검있음/없음 서브탭 -->
      <div class="tab-bar mb-3" id="insFilterBar">
        ${[
          ['all',     '전체',   tasks.length],
          ['has_ins', '점검있음', tasks.filter(t => insMap[t.id]?.length).length],
          ['no_ins',  '미점검',  tasks.filter(t => !insMap[t.id]?.length).length],
        ].map(([key, lbl, c]) =>
          `<div class="tab-item ${window._insSubFilter===key?'active':''}"
               onclick="window._insSubFilter='${key}';renderInspectionsPage(document.getElementById('page-content'))">
             ${lbl} <span style="background:rgba(0,0,0,0.08);border-radius:999px;padding:0 6px;font-size:11px;margin-left:3px">${c}</span>
           </div>`
        ).join('')}
      </div>

      <!-- ④ 작업 리스트 -->
      <div class="card p-0 overflow-hidden">
        <div style="display:grid;grid-template-columns:2fr 90px 90px 1fr 80px;background:#F5F0F8;border-bottom:1px solid #D8D0DC;padding:8px 14px;font-size:11px;font-weight:700;color:#9CA3AF;text-transform:uppercase;letter-spacing:.5px">
          <div>작업명</div><div>작업상태</div><div>점검</div><div>최근점검내용</div><div style="text-align:right">액션</div>
        </div>
        <div id="insTaskList">
          ${(() => {
            const filtered = tasks.filter(t => {
              const ins = insMap[t.id] || [];
              if (window._insSubFilter === 'has_ins') return ins.length > 0;
              if (window._insSubFilter === 'no_ins')  return ins.length === 0;
              return true;
            });

            if (filtered.length === 0) return `
              <div style="padding:48px;text-align:center;color:#C6C6C6">
                <i class="fas fa-hard-hat" style="font-size:2.5rem;margin-bottom:12px;display:block;opacity:.2"></i>
                <div style="font-size:13px;font-weight:600;color:#9CA3AF;margin-bottom:4px">해당하는 작업이 없습니다</div>
                <div style="font-size:11px;color:#C6C6C6">${_tab==='active'?'현장 진행중(TBM완료·작업중) 작업이 없습니다':''}</div>
              </div>`;

            return filtered.map(t => {
              const ins    = (insMap[t.id] || []).sort((a,b) => b.id - a.id);
              const latest = ins[0];
              const ts     = TASK_STATUS[t.status] || TASK_STATUS.unassigned;
              // 점검 등록 가능 여부: 취소·일지완료는 불가, 작업완료는 열람만
              const canRegister = !['cancelled', 'completed'].includes(t.status);
              const isReadOnly  = t.status === 'work_completed';

              return `
              <div style="border-bottom:1px solid #F0ECF5">
                <div style="display:grid;grid-template-columns:2fr 90px 90px 1fr 80px;padding:10px 14px;align-items:center;gap:6px;background:${isReadOnly?'#FAFAFA':'white'}"
                     class="hover:bg-purple-50 transition-colors">
                  <!-- 작업명 -->
                  <div>
                    <div style="font-weight:700;font-size:13px;color:#685182;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;cursor:pointer"
                         onclick="event.stopPropagation();showTaskDetail(${t.id})"
                         title="작업 상세 보기">${t.title}</div>
                    <div style="font-size:11px;color:#9CA3AF;margin-top:2px;display:flex;align-items:center;gap:4px">
                      ${t.task_number ? `<span>${t.task_number}</span><span style="color:#D8D0DC">·</span>` : ''}
                      <span>${t.planned_date || t.work_date || '-'}</span>
                      ${t.location ? `<span style="color:#D8D0DC">·</span><i class="fas fa-map-marker-alt" style="color:#C6C6C6"></i><span>${t.location}</span>` : ''}
                    </div>
                  </div>
                  <!-- 작업상태 -->
                  <div>
                    <span style="display:inline-flex;align-items:center;gap:4px;font-size:11px;padding:2px 8px;border-radius:999px;font-weight:600" class="${ts.cls}">
                      <span style="width:6px;height:6px;border-radius:50%;background:${ts.dot};flex-shrink:0"></span>
                      ${ts.label}
                    </span>
                  </div>
                  <!-- 점검 현황 -->
                  <div>
                    ${ins.length === 0
                      ? `<span style="font-size:11px;color:#C6C6C6"><i class="fas fa-minus-circle mr-1"></i>없음</span>`
                      : `<span style="font-size:11px;padding:2px 8px;border-radius:999px;background:#EDE9F6;color:#685182;font-weight:700;cursor:pointer"
                              onclick="showTaskInspectionList(${t.id},'${t.title.replace(/'/g,'&#39;')}')">
                           <i class="fas fa-clipboard-check mr-1"></i>${ins.length}건
                         </span>`
                    }
                  </div>
                  <!-- 최근 점검 내용 -->
                  <div style="font-size:11px;color:#9CA3AF;overflow:hidden;white-space:nowrap;text-overflow:ellipsis">
                    ${latest ? (() => {
                      const _lm2 = { 'excellent':'우수','good':'양호','pass':'적정','fail':'불량','우수':'우수','양호':'양호','적정':'적정','불량':'불량' };
                      const _cm2 = { '불량':'#D70072','적정':'#D70072','양호':'#685182','우수':'#685182' };
                      const _bm2 = { '불량':'#FDE8F3','적정':'#FDE8F3','양호':'#F5F0F8','우수':'#F5F0F8' };
                      const krR    = latest.inspection_result && latest.inspection_result !== 'none' ? (_lm2[latest.inspection_result] || latest.inspection_result) : null;
                      const rBadge = krR ? `<span style="padding:1px 5px;border-radius:999px;font-size:10px;font-weight:700;margin-right:4px;color:${_cm2[krR]||'#9CA3AF'};background:${_bm2[krR]||'#F5F0F8'};border:1px solid ${_cm2[krR]||'#C6C6C6'}55">${krR}</span>` : '';
                      return `${rBadge}<span style="padding:1px 5px;border-radius:4px;font-size:10px;font-weight:600;margin-right:4px" class="${INS_STATUS[latest.status]?.cls||''}">${INS_STATUS[latest.status]?.label||''}</span>${latest.findings ? latest.findings.substring(0,30)+(latest.findings.length>30?'…':'') : latest.location || '-'}`;
                    })() : '<span style="color:#D1D5DB">-</span>'}
                  </div>
                  <!-- 액션 버튼 -->
                  <div style="display:flex;gap:4px;justify-content:flex-end">
                    ${ins.length > 0
                      ? `<button onclick="showTaskInspectionList(${t.id},'${t.title.replace(/'/g,'&#39;')}')"
                           style="font-size:11px;padding:3px 8px;border-radius:6px;border:1px solid #D8D0DC;background:white;cursor:pointer;color:#685182;font-weight:600"
                           onmouseover="this.style.background='#F5F0F8'" onmouseout="this.style.background='white'">
                           <i class="fas fa-list mr-1"></i>내역
                         </button>`
                      : ''}
                    ${canRegister
                      ? `<button onclick="showCreateInspectionModal(${t.id})"
                           style="font-size:11px;padding:3px 8px;border-radius:6px;border:none;background:#685182;cursor:pointer;color:white;font-weight:600"
                           title="점검 등록">
                           <i class="fas fa-plus"></i>
                         </button>`
                      : `<span style="font-size:10px;color:#C6C6C6;padding:3px 6px" title="일지완료 작업">-</span>`
                    }
                  </div>
                </div>
                <!-- 점검 내역 인라인 (토글) -->
                <div id="ins-detail-${t.id}" style="display:none;background:#F5F0F8;border-top:1px solid #EDE7F6;padding:0 14px 10px">
                  ${ins.map(i => {
                    // inspection_result 영문→한국어 변환
                    const _lm = { 'excellent':'우수','good':'양호','pass':'적정','fail':'불량','우수':'우수','양호':'양호','적정':'적정','불량':'불량' };
                    const _cm = { '불량':'#D70072','적정':'#D70072','양호':'#685182','우수':'#685182' };
                    const _bm = { '불량':'#FDE8F3','적정':'#FDE8F3','양호':'#F5F0F8','우수':'#F5F0F8' };
                    const krRes = i.inspection_result && i.inspection_result !== 'none' ? (_lm[i.inspection_result] || i.inspection_result) : null;
                    const resBadge = krRes
                      ? `<span style="font-size:10px;padding:1px 6px;border-radius:999px;font-weight:700;flex-shrink:0;color:${_cm[krRes]||'#C6C6C6'};background:${_bm[krRes]||'#F5F0F8'};border:1px solid ${_cm[krRes]||'#C6C6C6'}44">${krRes}</span>`
                      : '';
                    return `
                  <div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid #F5F0F8;cursor:pointer"
                       onclick="showInspectionDetail(${i.id})">
                    <i class="${INS_STATUS[i.status]?.icon||'fas fa-circle'}" style="color:${i.status==='closed'?'#685182':i.status==='in_progress'?'#685182':'#D70072'};font-size:12px;width:14px;text-align:center"></i>
                    <span style="font-size:11px;font-weight:700;color:#C6C6C6;width:80px;flex-shrink:0">${i.inspection_date_only||i.inspection_date?.split('T')[0]||'-'}</span>
                    <span style="font-size:11px;padding:1px 5px;border-radius:4px;font-weight:600;flex-shrink:0" class="${HAZARD_CLS[i.hazard_level]||''}">${HAZARD_LBL[i.hazard_level]||'-'}</span>
                    <span style="font-size:11px;color:#685182;white-space:nowrap;padding:1px 5px;border-radius:4px;background:#F5F0F8;flex-shrink:0">${INS_TYPE_LBL[i.inspection_type]||i.inspection_type||'-'}</span>
                    <span style="font-size:11px;color:#C6C6C6;overflow:hidden;white-space:nowrap;text-overflow:ellipsis;flex:1">${i.findings||i.location||'-'}</span>
                    ${resBadge}
                    <span style="font-size:11px;color:#C6C6C6;flex-shrink:0">${i.inspector_name||'-'}</span>
                    <span style="font-size:11px;padding:1px 6px;border-radius:999px;font-weight:600;flex-shrink:0" class="${INS_STATUS[i.status]?.cls||''}">${INS_STATUS[i.status]?.label||''}</span>
                  </div>`;
                  }).join('')}
                </div>
              </div>`;
            }).join('');
          })()}
        </div>
      </div>
    </div>`;
  } catch(e) {
    container.innerHTML = `<p class="text-red-500 p-4">로드 실패: ${e.message}</p>`;
  }
}

// 특정 작업의 점검 내역 인라인 토글
function showTaskInspectionList(taskId, taskTitle) {
  const el = document.getElementById(`ins-detail-${taskId}`);
  if (!el) return;
  const isOpen = el.style.display !== 'none';
  el.style.display = isOpen ? 'none' : 'block';
}

// 현장점검 필터 적용 (조회 버튼 클릭)
function _applyInsFilters() {
  // DOM → 전역 저장 후 재렌더링
  window._insDateFrom     = document.getElementById('insDateFrom')?.value     ?? window._insDateFrom ?? '';
  window._insDateTo       = document.getElementById('insDateTo')?.value       ?? window._insDateTo   ?? '';
  window._insStatusFilter = document.getElementById('insStatusFilter')?.value ?? window._insStatusFilter ?? '';
  renderInspectionsPage(document.getElementById('page-content'));
}

// 현장점검 빠른 날짜 선택 — 전역 직접 수정 후 재렌더링
function _setInsDateRange(range) {
  const today = getKSTDate(); // KST 기준 오늘
  if (range === 'today') {
    window._insDateFrom = today; window._insDateTo = today;
  } else if (range === 'week') {
    const d = getKSTNow(); d.setUTCDate(d.getUTCDate() - 7);
    window._insDateFrom = d.toISOString().split('T')[0];
    window._insDateTo   = today;
  } else if (range === 'month') {
    const d = getKSTNow(); d.setUTCDate(d.getUTCDate() - 30);
    window._insDateFrom = d.toISOString().split('T')[0];
    window._insDateTo   = today;
  } else if (range === 'all') {
    window._insDateFrom = ''; window._insDateTo = '';
  }
  renderInspectionsPage(document.getElementById('page-content'));
}

// 모달용 전역 변수 — 작업별 배정 작업자 맵
let _insTaskWorkersMap = {};

async function showCreateInspectionModal(presetTaskId) {
  // 작업 목록: 페이지 렌더 시 캐시된 데이터 재사용 → API 재호출 방지
  let allTasks = window._insTasksCache || [];
  if (allTasks.length === 0) {
    try {
      const tRes = await API.get('/tasks');
      allTasks = tRes.data.tasks || tRes.data || [];
      window._insTasksCache = allTasks;
      _insTaskWorkersMap = {};
      for (const t of allTasks) {
        if (Array.isArray(t.assigned_workers) && t.assigned_workers.length > 0) {
          _insTaskWorkersMap[t.id] = t.assigned_workers.map(w => ({ id: w.id, name: w.name, position: w.position || '' }));
        }
      }
    } catch(e) {}
  }

  const taskSelectHtml = allTasks.length > 0
    ? `<select id="insTaskId" class="form-control" onchange="onInsTaskSelect(this)">
        <option value="">— 작업 선택 안 함 —</option>
        ${allTasks.map(t => {
          // 옵션 우측 주소 표시: 최종주소 → 작업지시주소 → location 순
          const dispAddr = t.confirmed_address || t.work_order_address || t.location || '';
          const addrLabel = dispAddr
            ? (t.confirmed_address ? ` · 📍 ${dispAddr}` : ` · ${dispAddr}`)
            : '';
          return `<option value="${t.id}"
            data-location="${t.location||''}"
            data-confirmed="${t.confirmed_address||''}"
            data-work-order="${t.work_order_address||''}"
            ${presetTaskId==t.id?'selected':''}>${t.task_number ? '['+t.task_number+'] ' : ''}${t.title}${addrLabel}</option>`;
        }).join('')}
       </select>`
    : `<div class="text-sm text-gray-400 bg-gray-50 rounded-lg px-3 py-2 border border-gray-200">
         <i class="fas fa-info-circle mr-1 text-blue-400"></i>등록된 작업이 없습니다.
       </div>`;

  const todayStr = getKSTDate(); // KST 기준 오늘

  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
  <div class="modal" style="max-width:600px;">
    <div class="modal-header">
      <h3 class="font-bold text-lg"><i class="fas fa-search text-blue-500 mr-2"></i>현장 점검 등록</h3>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">
          <i class="fas fa-hard-hat text-blue-400 mr-1"></i>진행중 작업 연결
          <span class="text-xs font-normal text-gray-400 ml-1">(선택 시 위치 자동 연동)</span>
        </label>
        ${taskSelectHtml}
      </div>
      <div class="grid grid-cols-2 gap-4">
        <div class="form-group">
          <label class="form-label">점검일 <span class="text-red-500">*</span></label>
          <input id="insDateOnly" class="form-control" type="date" value="${todayStr}">
        </div>
        <div class="form-group"><label class="form-label">점검 유형</label>
          <select id="insType" class="form-control">
            <option value="routine">정기점검</option>
            <option value="joint">합동점검</option>
            <option value="frequent" selected>수시점검</option>
          </select>
        </div>
      </div>
      <div class="form-group">
        <label class="form-label">점검 위치 <span class="text-red-500">*</span>
          <span class="text-xs font-normal text-gray-400 ml-1">(직접 입력 또는 GPS 버튼으로 자동 입력)</span>
        </label>
        <div class="flex gap-2">
          <input id="insLocation" class="form-control" placeholder="점검 위치를 입력하세요">
          <button type="button" id="insGpsBtn" onclick="refreshGPSInspection()"
            style="padding:6px 12px;background:#685182;color:white;border:none;border-radius:8px;font-size:11px;font-weight:600;cursor:pointer;white-space:nowrap;flex-shrink:0;min-width:72px">
            <i class="fas fa-location-arrow mr-1"></i>현재위치
          </button>
          <button type="button"
            onclick="showMapModal(document.getElementById('insLocation').value)"
            title="지도로 찾아가기"
            style="padding:6px 10px;background:#2DB400;color:white;border:none;border-radius:8px;font-size:11px;font-weight:600;cursor:pointer;white-space:nowrap;flex-shrink:0">
            <i class="fas fa-map-marker-alt"></i><span style="margin-left:3px">지도</span>
          </button>
        </div>
        <div id="insLocationStatus" class="hidden mt-2 rounded-lg px-3 py-2 text-xs flex items-center gap-2"></div>
      </div>
      <div class="form-group"><label class="form-label">위험도</label>
        <select id="insHazard" class="form-control">
          <option value="low">낮음</option>
          <option value="medium">보통</option>
          <option value="high">높음</option>
          <option value="critical">긴급</option>
        </select>
      </div>
      <div class="form-group"><label class="form-label">점검 내용</label><textarea id="insFindings" class="form-control" rows="3" placeholder="점검 내용 및 발견된 문제점"></textarea></div>
      <div class="form-group"><label class="form-label">조치 사항</label><textarea id="insCorrectiveActions" class="form-control" rows="2" placeholder="필요한 시정/조치 사항"></textarea></div>

      <!-- 점검 결과 선택 -->
      <div class="form-group">
        <label class="form-label"><i class="fas fa-clipboard-check text-green-500 mr-1"></i>점검 결과</label>
        <div class="flex gap-2 flex-wrap" id="insResultBtns">
          ${['불량','적정','양호','우수'].map((v,i) => {
            const colors = ['red','yellow','blue','green'];
            return `<button type="button" onclick="selectInsResult('${v}')"
              id="insResult_${v}"
              class="px-4 py-2 rounded-lg border-2 text-sm font-semibold transition-all border-gray-200 text-gray-500 hover:border-${colors[i]}-400"
              data-result="${v}">${v}</button>`;
          }).join('')}
        </div>
        <input type="hidden" id="insResult" value="">
      </div>
      <!-- 사유 입력 (결과 선택 시 표시) -->
      <div class="form-group hidden" id="insReasonGroup">
        <label class="form-label" id="insReasonLabel">사유 / 비고</label>
        <textarea id="insReason" class="form-control" rows="2" placeholder="선택 사유 또는 세부 내용을 입력해 주세요"></textarea>
      </div>
      <!-- 작업자 선택 (불량/우수 선택 시 표시) -->
      <div class="form-group hidden" id="insWorkerGroup">
        <label class="form-label">
          <i class="fas fa-users mr-1" id="insWorkerIcon"></i>
          <span id="insWorkerLabel">해당 작업자 선택</span>
          <span class="text-xs font-normal text-gray-400 ml-1">(다중 선택 가능)</span>
        </label>
        <div id="insWorkerList" class="border border-gray-200 rounded-lg p-3 bg-gray-50 max-h-48 overflow-y-auto">
          <p class="text-sm text-gray-400 text-center py-2"><i class="fas fa-info-circle mr-1"></i>작업을 먼저 선택해 주세요</p>
        </div>
      </div>

      <div class="form-group"><label class="form-label">사진/동영상 (선택)</label>
        <div class="upload-zone" onclick="document.getElementById('insPhotoInput').click()">
          <i class="fas fa-photo-video text-3xl text-gray-300 mb-1"></i>
          <p class="text-xs text-gray-400">사진 및 동영상 첨부 (선택) · 동영상 최대 500MB</p>
        </div>
        <input type="file" id="insPhotoInput" accept="image/*,video/*,.heic,.mov,.avi,.mp4,.webm,.mkv" class="hidden" multiple onchange="previewInsPhotos(this)">
        <div id="insPhotoPreview" class="photo-grid mt-2"></div>
      </div>
    </div>
    <div class="modal-footer">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button onclick="submitInspection()" class="btn btn-primary"><i class="fas fa-save"></i> 저장</button>
    </div>
  </div>`;
  document.body.appendChild(modal);
  markFormDirty();
  // presetTaskId 가 있으면 작업 선택 후 confirmed_address/work_order_address 를 insLocation에 자동 설정
  if (presetTaskId) {
    const sel = document.getElementById('insTaskId');
    if (sel) {
      sel.value = String(presetTaskId);
      onInsTaskSelect(sel);
    }
  }
  // GPS 자동 요청 제거 — GPS 버튼 클릭 시에만 위치 권한 요청 (사용자 명시적 동의)
}

// 현장점검 GPS 상태 표시 헬퍼
function _setInsGpsStatus(type, message) {
  setGpsStatus('insLocationStatus', 'insGpsBtn', type, message);
}

// 현장점검 GPS 실행 공통 함수
async function _runGPSForInspection() {
  const input = document.getElementById('insLocation');
  if (!input) return;
  _setInsGpsStatus('loading', 'GPS 위치를 가져오는 중입니다...');
  const result = await getGPSAddressWithConsent();
  if (!document.getElementById('insLocationStatus')) return;
  if (result.error) {
    if (result.error === 'GPS 권한 거부됨') {
      _setInsGpsStatus('warning', 'GPS 권한이 거부되었습니다. 브라우저 설정에서 위치 권한을 허용하거나 위치를 직접 입력해 주세요.');
    } else {
      _setInsGpsStatus('error', `${result.error} — 위치를 직접 입력해 주세요.`);
    }
  } else {
    if (result.address) input.value = result.address;
    _setInsGpsStatus('success', 'GPS 위치가 자동으로 입력되었습니다. 필요 시 직접 수정할 수 있습니다.');
  }
}

// 점검 결과 버튼 선택
function selectInsResult(val) {
  document.getElementById('insResult').value = val;
  const colorMap = { '불량':'red', '적정':'yellow', '양호':'blue', '우수':'green' };
  ['불량','적정','양호','우수'].forEach(v => {
    const btn = document.getElementById(`insResult_${v}`);
    if (!btn) return;
    if (v === val) {
      const c = colorMap[v];
      btn.className = `px-4 py-2 rounded-lg border-2 text-sm font-semibold transition-all border-${c}-500 bg-${c}-50 text-${c}-700`;
    } else {
      btn.className = `px-4 py-2 rounded-lg border-2 text-sm font-semibold transition-all border-gray-200 text-gray-500`;
    }
  });
  // 사유 입력 표시
  const reasonGroup = document.getElementById('insReasonGroup');
  const reasonLabel = document.getElementById('insReasonLabel');
  if (reasonGroup) {
    reasonGroup.classList.remove('hidden');
    const labelMap = { '불량':'불량 사유 (필수)', '적정':'적정 판단 근거', '양호':'양호 판단 근거', '우수':'우수 판단 근거' };
    if (reasonLabel) reasonLabel.textContent = labelMap[val] || '사유 / 비고';
  }
  // 불량/우수: 작업자 선택 UI 표시
  const workerGroup = document.getElementById('insWorkerGroup');
  const workerLabel = document.getElementById('insWorkerLabel');
  const workerIcon  = document.getElementById('insWorkerIcon');
  if (workerGroup) {
    if (val === '불량' || val === '우수') {
      workerGroup.classList.remove('hidden');
      if (val === '불량') {
        workerLabel.textContent = '불량 해당 작업자 선택';
        workerIcon.style.color  = '#D70072'; // red-600
      } else {
        workerLabel.textContent = '우수 해당 작업자 선택';
        workerIcon.style.color  = '#685182'; // green-600
      }
      // 현재 선택된 작업의 배정 작업자 목록 렌더링
      renderInsWorkerList(val);
    } else {
      workerGroup.classList.add('hidden');
    }
  }
}

// 작업자 선택 UI 렌더링 (불량/우수 시)
async function renderInsWorkerList(resultType) {
  const list = document.getElementById('insWorkerList');
  if (!list) return;
  const accentColor = resultType === '불량' ? '#D70072' : '#685182';
  const badgeBg     = resultType === '불량' ? '#FDE8F3' : '#F5F0F8';

  const taskSel = document.getElementById('insTaskId');
  const taskId  = taskSel ? parseInt(taskSel.value) : 0;

  // 체크된 값 기억 (작업 전환 시 유지)
  const prevChecked = new Set(
    Array.from(list.querySelectorAll('.ins-worker-check:checked')).map(c => parseInt(c.value))
  );

  let workers = [];

  if (taskId && _insTaskWorkersMap[taskId] && _insTaskWorkersMap[taskId].length > 0) {
    // 작업에 배정된 작업자가 있으면 그 목록 사용
    workers = _insTaskWorkersMap[taskId];
  } else {
    // 작업 미선택이거나 배정 작업자 없으면 → 전체 근로자 목록 로드
    list.innerHTML = `<p class="text-xs text-gray-400 text-center py-2"><i class="fas fa-spinner fa-spin mr-1"></i>근로자 목록 불러오는 중...</p>`;
    try {
      const uRes = await API.get('/users', { params: { role: 'worker' } });
      const allWorkers = uRes.data || [];
      workers = allWorkers.map(u => ({ id: u.id, name: u.name, position: u.position || '', team_name: u.team_name || '' }));
    } catch(e) {
      list.innerHTML = `<p class="text-sm text-red-400 text-center py-2"><i class="fas fa-exclamation-circle mr-1"></i>근로자 목록 로드 실패</p>`;
      return;
    }
  }

  if (workers.length === 0) {
    list.innerHTML = `<p class="text-sm text-gray-400 text-center py-2"><i class="fas fa-users mr-1"></i>등록된 근로자가 없습니다.</p>`;
    return;
  }

  const taskLabel = taskId
    ? `<p class="text-xs text-gray-400 mb-2 px-1"><i class="fas fa-filter mr-1 text-blue-400"></i>이 작업에 배정된 근로자 ${workers.length}명</p>`
    : `<p class="text-xs text-gray-400 mb-2 px-1"><i class="fas fa-users mr-1 text-gray-400"></i>전체 근로자 ${workers.length}명 (작업 미선택 — 직접 선택)</p>`;

  list.innerHTML = taskLabel + workers.map(w => `
    <label class="flex items-center gap-2.5 px-2 py-1.5 rounded-lg cursor-pointer hover:bg-white transition-colors" style="border:1px solid transparent" onmouseover="this.style.borderColor='${accentColor}33'" onmouseout="this.style.borderColor='transparent'">
      <input type="checkbox" class="ins-worker-check w-4 h-4 cursor-pointer rounded" style="accent-color:${accentColor}" value="${w.id}" ${prevChecked.has(w.id) ? 'checked' : ''}>
      <span class="inline-flex items-center justify-center w-7 h-7 rounded-full text-xs font-bold text-white flex-shrink-0" style="background:${accentColor}">${w.name.charAt(0)}</span>
      <span class="text-sm font-medium text-gray-800">${w.name}</span>
      ${w.position ? `<span class="text-xs px-1.5 py-0.5 rounded" style="background:${badgeBg};color:${accentColor}">${w.position}</span>` : ''}
      ${w.team_name ? `<span class="text-xs text-gray-400 ml-auto">${w.team_name}</span>` : ''}
    </label>
  `).join('');
}

// 작업 선택 시 위치 자동 연동
function onInsTaskSelect(sel) {
  const opt = sel.options[sel.selectedIndex];
  const locInput = document.getElementById('insLocation');
  if (!locInput) return;

  // 최종주소 우선: confirmed_address → work_order_address → location 순
  const confirmed = opt.dataset.confirmed || '';
  const workOrder = opt.dataset.workOrder || '';
  const loc       = opt.dataset.location || '';
  const bestAddr  = confirmed || workOrder || loc;

  if (bestAddr) {
    locInput.value = bestAddr;
    const srcLabel = confirmed ? '최종주소' : workOrder ? '작업지시 주소' : '작업 위치';
    _setInsGpsStatus('success', `${srcLabel}에서 자동으로 불러왔습니다. 직접 수정 가능합니다.`);
  }
  // 작업자 선택 UI도 갱신 (불량/우수 선택 중이면)
  const currentResult = document.getElementById('insResult')?.value;
  if (currentResult === '불량' || currentResult === '우수') {
    renderInsWorkerList(currentResult);
  }
}



async function refreshGPSInspection() {
  await _runGPSForInspection();
}

function previewInsPhotos(input) {
  const preview = document.getElementById('insPhotoPreview');
  preview.innerHTML = '';
  const files = Array.from(input.files);
  if (files.length === 0) return;

  // 파일 수 / 용량 요약 헤더
  const totalMB = (files.reduce((s, f) => s + f.size, 0) / 1024 / 1024).toFixed(1);
  const header = document.createElement('p');
  header.className = 'col-span-full text-xs text-gray-500 mb-1';
  header.textContent = `${files.length}개 선택 · 전체 ${totalMB}MB`;
  preview.appendChild(header);

  files.forEach(file => {
    const div = document.createElement('div');
    div.className = 'photo-thumb';
    const sizeMB = (file.size / 1024 / 1024).toFixed(1);
    const isVideo = file.type.startsWith('video/') || /\.(mp4|mov|avi|webm|mkv)$/i.test(file.name);

    if (isVideo) {
      const url = URL.createObjectURL(file);
      div.innerHTML = `
        <video src="${url}" class="w-full h-full object-cover" muted preload="metadata"></video>
        <div class="overlay"><i class="fas fa-play"></i></div>
        <div class="absolute top-1 left-1 bg-blue-600 text-white text-xs px-1 rounded"><i class="fas fa-video"></i></div>
        <div class="absolute bottom-0 left-0 right-0 bg-black bg-opacity-60 text-white text-xs p-0.5 text-center truncate">${file.name} (${sizeMB}MB)</div>`;
      preview.appendChild(div);
    } else if (file.type.startsWith('image/') || /\.heic$/i.test(file.name)) {
      const reader = new FileReader();
      reader.onload = (e) => {
        div.innerHTML = `
          <img src="${e.target.result}" alt="${file.name}" class="w-full h-full object-cover">
          <div class="overlay"><i class="fas fa-check"></i></div>
          <div class="absolute bottom-0 left-0 right-0 bg-black bg-opacity-50 text-white text-xs p-0.5 text-center truncate">${file.name} (${sizeMB}MB)</div>`;
        preview.appendChild(div);
      };
      reader.readAsDataURL(file);
    }
  });
}

async function submitInspection() {
  const location = document.getElementById('insLocation').value;
  if (!location) { toast('점검 위치를 입력하세요.', 'error'); return; }

  const taskIdEl = document.getElementById('insTaskId');
  const taskId = taskIdEl ? (taskIdEl.value ? parseInt(taskIdEl.value) : null) : null;
  const insResult = document.getElementById('insResult')?.value || '';
  const insReason = document.getElementById('insReason')?.value || '';
  const insDateOnly = document.getElementById('insDateOnly')?.value || getKSTDate();

  // 1단계: 점검 데이터를 JSON으로 wrangler API에 저장 (사진 제외)
  const input = document.getElementById('insPhotoInput');
  const photoFiles = Array.from(input.files).filter(f => {
    const isVideo = f.type.startsWith('video/') || /\.(mp4|mov|avi|webm|mkv)$/i.test(f.name);
    return f.size <= (isVideo ? 500 : 50) * 1024 * 1024;
  });

  // 불량/우수 선택된 작업자 수집
  const selectedWorkerIds = [];
  if (insResult === '불량' || insResult === '우수') {
    document.querySelectorAll('.ins-worker-check:checked').forEach(cb => {
      const wid = parseInt(cb.value);
      if (wid) selectedWorkerIds.push(wid);
    });
  }

  // 디버그 로그 — 실제로 전송되는 값 확인
  console.log('[submitInspection] 전송 데이터:', {
    insResult, selectedWorkerIds,
    insResultHidden: document.getElementById('insResult')?.value,
  });

  try {
    const res = await API.post('/inspections', {
      location,
      task_id: taskId,
      inspection_type: document.getElementById('insType').value,
      hazard_level: document.getElementById('insHazard').value,
      findings: document.getElementById('insFindings').value,
      corrective_actions: document.getElementById('insCorrectiveActions').value,
      inspection_date_only: insDateOnly,
      inspection_result: insResult,
      result_reason: insReason,
      worker_ids: selectedWorkerIds,
      photos: [],
    });
    const inspectionId = res.data.id;
    const workersSaved = res.data.workers_saved ?? null;

    // 디버그: 서버 응답 확인
    console.log('[submitInspection] 서버 응답:', res.data);

    // 2단계: 사진이 있으면 파일 서버에 별도 업로드
    if (photoFiles.length > 0) {
      const formData = new FormData();
      formData.append('inspection_id', inspectionId);
      for (const file of photoFiles) formData.append('photos', file);
      const token = localStorage.getItem('token');
      const uploadResult = await _uploadWithProgress('/api/inspection-photos', formData, {
        onProgress: (pct, loadedMB, totalMB) => {
          _showUploadToast('점검 사진', pct, photoFiles.length);
        }
      });
      _hideUploadToast();
      if (!uploadResult.ok) console.warn('사진 업로드 경고:', uploadResult.data?.error);
    }

    // workers_saved가 응답에 있으면 → 새 서버 코드 실행 중
    let workerMsg = '';
    if (workersSaved !== null) {
      if ((insResult === '불량' || insResult === '우수') && selectedWorkerIds.length > 0) {
        workerMsg = workersSaved > 0
          ? ` · 작업자 ${workersSaved}명 기록됨`
          : ` · ⚠️ 작업자 저장 실패 (서버 로그 확인 필요)`;
      }
    }
    toast('현장 점검이 등록되었습니다.' + (photoFiles.length > 0 ? ` (사진 ${photoFiles.length}개)` : '') + workerMsg);
    document.querySelector('.modal-overlay')?.remove();
    renderInspectionsPage(document.getElementById('page-content'));
  } catch(e) {
    console.error('[submitInspection] 오류:', e.response?.data, e.message);
    toast(e.response?.data?.error || e.message || '저장 실패', 'error');
  }
}

async function showInspectionDetail(id) {
  try {
    const res = await API.get(`/inspections/${id}`);
    const ins = res.data;
    const modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.innerHTML = `
    <div class="modal">
      <div class="modal-header">
        <h3 class="font-bold text-lg">현장 점검 상세</h3>
        <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 text-xl"><i class="fas fa-times"></i></button>
      </div>
      <div class="modal-body">
        <div class="grid grid-cols-2 gap-3 mb-4 text-sm">
          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">점검자</span><br><b>${ins.inspector_name}</b></div>
          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">점검일시</span><br><b>${formatDateTime(ins.inspection_date)}</b></div>

          ${/* ── 최종주소 (연결 작업의 confirmed_address — 점검 위치 바로 위) ── */
          ins.task_id ? (() => {
            const ca = ins.task_confirmed_address || '';
            const srcMap = { risk:'위험성평가', tbm:'TBM', working:'작업개시' };
            const srcLabel = srcMap[ins.task_confirmed_address_source] || '';
            const srcColor = ins.task_confirmed_address_source === 'working' ? '#2DB400'
              : ins.task_confirmed_address_source === 'tbm' ? '#685182' : '#D70072';
            return `<div class="col-span-2 rounded-lg p-3 border" style="background:#FFF7F0;border-color:#FFD6A5">
              <div class="flex items-center gap-1.5 mb-1.5 flex-wrap">
                <i class="fas fa-map-pin text-xs" style="color:${ca ? '#D70072' : '#C6C6C6'}"></i>
                <span class="text-xs font-bold" style="color:#64748B">최종주소</span>
                <span class="text-xs" style="color:#888">(연결 작업 기준)</span>
                ${ca && srcLabel ? `<span class="text-xs px-1.5 py-0.5 rounded-full font-bold"
                  style="background:${srcColor}22;color:${srcColor};font-size:9px">${srcLabel}</span>` : ''}
              </div>
              ${ca ? `
              <div class="flex items-center gap-2 flex-wrap">
                <span class="font-bold" style="font-size:12px;color:#D70072">${ca}</span>
                <button type="button"
                  onclick="showMapModal('${ca.replace(/\\/g,'\\\\').replace(/'/g,"\\'")}')"
                  title="지도로 찾아가기"
                  style="padding:2px 8px;background:#2DB400;color:white;border:none;border-radius:5px;font-size:9px;font-weight:700;cursor:pointer;white-space:nowrap;flex-shrink:0">
                  <i class="fas fa-map-marker-alt"></i> 지도
                </button>
              </div>
              ${ins.task_confirmed_address_at ? `<div class="text-xs mt-1" style="color:#C6C6C6">${(ins.task_confirmed_address_at||'').substring(0,16)} 갱신</div>` : ''}
              ` : `<div class="text-xs italic" style="color:#C6C6C6">미갱신 — 위험성평가·TBM·작업개시 후 갱신됩니다</div>`}
            </div>`;
          })() : ''}

          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">점검 위치</span><br>
            <div class="flex items-center gap-2 flex-wrap mt-0.5">
              <b>${ins.location}</b>
              ${ins.location ? `<button type="button"
                onclick="showMapModal('${(ins.location||'').replace(/\\/g,'\\\\').replace(/'/g,"\\'")}')"
                title="지도로 찾아가기"
                style="padding:3px 8px;background:#2DB400;color:white;border:none;border-radius:6px;font-size:10px;font-weight:600;cursor:pointer;white-space:nowrap;flex-shrink:0">
                <i class="fas fa-map-marker-alt"></i><span style="margin-left:2px">지도</span>
              </button>` : ''}
            </div>
          </div>
          <div class="bg-gray-50 p-3 rounded-lg"><span class="text-gray-500">위험도</span><br>
            <span class="badge ${ins.hazard_level==='critical'?'risk-critical':ins.hazard_level==='high'?'risk-high':ins.hazard_level==='medium'?'risk-medium':'risk-low'}">
              ${ins.hazard_level==='critical'?'긴급':ins.hazard_level==='high'?'높음':ins.hazard_level==='medium'?'보통':'낮음'}
            </span>
          </div>
        </div>
        <div class="mb-3"><div class="text-sm font-bold mb-1">점검 내용</div><div class="bg-gray-50 p-3 rounded-lg text-sm">${ins.findings||'-'}</div></div>
        <div class="mb-3"><div class="text-sm font-bold mb-1">조치 사항</div><div class="bg-blue-50 p-3 rounded-lg text-sm">${ins.corrective_actions||'-'}</div></div>
        ${ins.due_date ? `<div class="mb-3"><div class="text-sm font-bold mb-1">조치 기한</div><div class="text-sm">${formatDate(ins.due_date)}</div></div>` : ''}
        ${ins.inspection_result && ins.inspection_result !== 'none' ? (() => {
          // DB 영문값 → 한국어 레이블 변환
          const labelMap = { 'excellent':'우수', 'good':'양호', 'pass':'적정', 'fail':'불량',
                             '우수':'우수', '양호':'양호', '적정':'적정', '불량':'불량' };
          const krResult = labelMap[ins.inspection_result] || ins.inspection_result;
          const colorMap = { '불량':'#D70072', '적정':'#D70072', '양호':'#685182', '우수':'#685182' };
          const bgMap    = { '불량':'#FDE8F3', '적정':'#FDE8F3', '양호':'#F5F0F8', '우수':'#F5F0F8' };
          const iconMap  = { '불량':'fa-exclamation-triangle', '적정':'fa-check', '양호':'fa-thumbs-up', '우수':'fa-star' };
          const col = colorMap[krResult] || '#C6C6C6';
          const bg  = bgMap[krResult]    || '#F5F0F8';
          const ico = iconMap[krResult]  || 'fa-clipboard-check';
          let html = `<div class="mb-3 p-3 rounded-xl" style="background:${bg};border:1px solid ${col}33">
            <div class="flex items-center gap-2 mb-1">
              <span class="text-xs font-black px-2 py-0.5 rounded-full text-white" style="background:${col}">
                <i class="fas ${ico} mr-1"></i>${krResult}
              </span>
              <span class="text-xs font-bold text-gray-600">점검 결과</span>
            </div>
            ${ins.result_reason ? `<div class="text-xs text-gray-600 mt-1">${ins.result_reason}</div>` : ''}`;
          // 연결 작업자 표시
          if (Array.isArray(ins.workers) && ins.workers.length > 0) {
            html += `<div class="mt-2">
              <div class="text-xs font-bold mb-1" style="color:${col}">
                <i class="fas fa-users mr-1"></i>기록 대상 작업자 (${ins.workers.length}명)
              </div>
              <div class="flex flex-wrap gap-1">
                ${ins.workers.map(w => `<span class="text-xs px-2 py-0.5 rounded-full font-medium" style="background:${col}22;color:${col};border:1px solid ${col}44">${w.worker_name}${w.position?' · '+w.position:''}</span>`).join('')}
              </div>
            </div>`;
          }
          html += `</div>`;
          return html;
        })() : ''}
        ${ins.photos?.length > 0 ? `
          <div class="mb-3">
            <div class="text-sm font-bold mb-2">첨부 사진/동영상 (${ins.photos.length}개)</div>
            <div class="photo-grid">
              ${ins.photos.map(p => {
                const isVideo = /\.(mp4|mov|avi|webm|mkv)$/i.test(p.file_name || '') || (p.mime_type||'').startsWith('video/');
                const canDelete = currentUser && currentUser.role !== 'worker';
                const delBtn = canDelete ? `<button onclick="event.stopPropagation();deleteInsMedia(${p.id},${ins.id})" class="absolute top-1 right-1 bg-red-600 bg-opacity-80 text-white rounded-full w-6 h-6 flex items-center justify-center text-xs hover:bg-red-700 z-10" title="삭제"><i class="fas fa-trash"></i></button>` : '';
                if (isVideo) {
                  return `<div class="photo-thumb relative cursor-pointer" onclick="showInsVideoData(${p.id})">
                    <video src="/api/inspections/photo/${p.id}/img" class="w-full h-full object-cover" muted preload="metadata"></video>
                    <div class="overlay"><i class="fas fa-play text-2xl"></i></div>
                    <div class="absolute top-1 left-1 bg-blue-600 text-white text-xs px-1 rounded"><i class="fas fa-video"></i></div>
                    ${delBtn}
                  </div>`;
                } else {
                  const cap2 = (p.caption || '점검사진').replace(/\\/g,'\\\\').replace(/'/g,"\\'");
                  return `<div class="photo-thumb cursor-pointer relative" onclick="showInsPhotoData(${p.id},'${cap2}')">
                    <img src="/api/inspections/photo/${p.id}/img" alt="${p.caption||'점검사진'}" onerror="this.style.opacity='0.3'">
                    <div class="overlay"><i class="fas fa-expand"></i></div>
                    ${delBtn}
                  </div>`;
                }
              }).join('')}
            </div>
          </div>` : ''}
      </div>
      <div class="modal-footer" style="flex-wrap:wrap;gap:8px">
        ${currentUser && currentUser.role !== 'worker' ? `
          <!-- 처리상태 드롭다운 -->
          <div style="display:flex;align-items:center;gap:6px;margin-right:auto">
            <label style="font-size:12px;font-weight:600;color:#64748B;white-space:nowrap">처리상태</label>
            <select id="insStatusSel_${ins.id}" onchange="changeInspectionStatus(${ins.id},this.value)"
              style="font-size:12px;font-weight:600;padding:5px 10px;border-radius:8px;border:2px solid;cursor:pointer;outline:none;
                     ${ins.status==='closed'?'border-color:#10B981;background:#ECFDF5;color:#065F46':ins.status==='in_progress'?'border-color:#3B82F6;background:#EFF6FF;color:#1E40AF':'border-color:#F59E0B;background:#FFFBEB;color:#92400E'}">
              <option value="open"        ${(ins.status||'open')==='open'        ?'selected':''}>⚠ 미처리</option>
              <option value="in_progress" ${ins.status==='in_progress'?'selected':''}>🔄 처리중</option>
              <option value="closed"      ${ins.status==='closed'     ?'selected':''}>✅ 완료</option>
            </select>
          </div>
          <button onclick="addInsPhoto(${ins.id})" class="btn btn-secondary">
            <i class="fas fa-camera"></i> 사진 추가
          </button>
          <button onclick="editInspection(${ins.id})" class="btn" style="background:#685182;color:white;border:none">
            <i class="fas fa-edit"></i> 수정
          </button>
          <button onclick="deleteInspection(${ins.id})" class="btn btn-danger">
            <i class="fas fa-trash"></i> 삭제
          </button>` : ''}
        <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">닫기</button>
      </div>
    </div>`;
    document.body.appendChild(modal);
  } catch(e) { toast('로드 실패', 'error'); }
}

