// 점검 사진/동영상 삭제
function deleteInsMedia(photoId, inspectionId) {
  const m = document.createElement('div');
  m.className = 'modal-overlay modal-sm';
  m.style.zIndex = '10000';
  m.innerHTML = `
  <div class="modal" style="max-width:340px">
    <div class="modal-header" style="background:linear-gradient(135deg,#A8005A,#D70072);color:white">
      <div class="flex items-center gap-2">
        <i class="fas fa-image text-lg"></i>
        <h3 class="font-bold">사진/동영상 삭제</h3>
      </div>
      <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer;opacity:0.8">×</button>
    </div>
    <div class="modal-body">
      <div style="background:#FDE8F3;border:1.5px solid #FDE8F3;border-radius:12px;padding:14px 16px;color:#A8005A;font-size:14px;line-height:1.6">
        <i class="fas fa-exclamation-triangle mr-2 text-red-400"></i>
        이 사진/동영상을 삭제하시겠습니까?<br>
        <span style="font-size:12px;opacity:0.8">삭제된 파일은 복구할 수 없습니다.</span>
      </div>
    </div>
    <div class="modal-footer" style="display:flex;gap:8px;justify-content:flex-end">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button id="doDeleteInsMediaBtn" class="btn btn-danger font-bold"><i class="fas fa-trash mr-1"></i>삭제</button>
    </div>
  </div>`;
  document.body.appendChild(m);
  m.querySelector('#doDeleteInsMediaBtn').onclick = async () => {
    m.remove();
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`/api/inspection-photos/${photoId}`, {
        method: 'DELETE',
        headers: token ? { 'Authorization': `Bearer ${token}` } : {}
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || '삭제 실패');
      toast('삭제되었습니다.');
      // 현재 모달 닫고 상세 화면 다시 열기
      document.querySelectorAll('.modal-overlay').forEach(mo => mo.remove());
      showInspectionDetail(inspectionId);
    } catch(e) {
      toast(e.message || '삭제 실패', 'error');
    }
  };
}

// ─── 현장 점검 수정 모달 ───────────────────────────────────────────────────────
async function editInspection(id) {
  let ins;
  try {
    const res = await API.get(`/inspections/${id}`);
    ins = res.data;
  } catch(e) { toast('데이터 로드 실패', 'error'); return; }

  // 작업 목록 캐시 활용
  let allTasks = window._insTasksCache || [];
  if (allTasks.length === 0) {
    try {
      const tRes = await API.get('/tasks');
      allTasks = tRes.data.tasks || tRes.data || [];
      window._insTasksCache = allTasks;
      _insTaskWorkersMap = {};
      for (const t of allTasks) {
        if (Array.isArray(t.assigned_workers) && t.assigned_workers.length > 0) {
          _insTaskWorkersMap[t.id] = t.assigned_workers.map(w => ({ id: w.id, name: w.name, position: w.position || '' }));
        }
      }
    } catch(e) {}
  }

  const taskSelectHtml = allTasks.length > 0
    ? `<select id="insEditTaskId" class="form-control" onchange="onInsEditTaskSelect(this)">
        <option value="">— 작업 선택 안 함 —</option>
        ${allTasks.map(t => `<option value="${t.id}" ${ins.task_id==t.id?'selected':''}>${t.task_number?'['+t.task_number+'] ':''}${t.title}</option>`).join('')}
       </select>`
    : `<div class="text-sm text-gray-400 bg-gray-50 rounded-lg px-3 py-2 border border-gray-200"><i class="fas fa-info-circle mr-1 text-blue-400"></i>등록된 작업이 없습니다.</div>`;

  const insTypeLabelMap = { routine:'정기점검', joint:'합동점검', frequent:'수시점검' };
  const currentResult = ins.inspection_result || '';
  const colorMap = { '불량':'red', '적정':'yellow', '양호':'blue', '우수':'green' };

  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
  <div class="modal" style="max-width:600px;">
    <div class="modal-header" style="background:linear-gradient(135deg,#4F3B78,#685182);color:white">
      <div class="flex items-center gap-2">
        <i class="fas fa-edit text-lg"></i>
        <h3 class="font-bold text-lg">현장 점검 수정</h3>
      </div>
      <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer;opacity:0.8">×</button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label"><i class="fas fa-hard-hat text-blue-400 mr-1"></i>진행중 작업 연결</label>
        ${taskSelectHtml}
      </div>
      <div class="grid grid-cols-2 gap-4">
        <div class="form-group">
          <label class="form-label">점검일 <span class="text-red-500">*</span></label>
          <input id="insEditDateOnly" class="form-control" type="date" value="${ins.inspection_date_only||''}">
        </div>
        <div class="form-group"><label class="form-label">점검 유형</label>
          <select id="insEditType" class="form-control">
            <option value="routine" ${ins.inspection_type==='routine'?'selected':''}>정기점검</option>
            <option value="joint"   ${ins.inspection_type==='joint'?'selected':''}>합동점검</option>
            <option value="frequent"${ins.inspection_type==='frequent'?'selected':''}>수시점검</option>
          </select>
        </div>
      </div>
      <div class="form-group">
        <label class="form-label">점검 위치 <span class="text-red-500">*</span></label>
        <input id="insEditLocation" class="form-control" value="${(ins.location||'').replace(/"/g,'&quot;')}" placeholder="점검 위치를 입력하세요">
      </div>
      <div class="form-group"><label class="form-label">위험도</label>
        <select id="insEditHazard" class="form-control">
          <option value="low"      ${ins.hazard_level==='low'?'selected':''}>낮음</option>
          <option value="medium"   ${ins.hazard_level==='medium'?'selected':''}>보통</option>
          <option value="high"     ${ins.hazard_level==='high'?'selected':''}>높음</option>
          <option value="critical" ${ins.hazard_level==='critical'?'selected':''}>긴급</option>
        </select>
      </div>
      <div class="form-group"><label class="form-label">점검 내용</label>
        <textarea id="insEditFindings" class="form-control" rows="3" placeholder="점검 내용 및 발견된 문제점">${ins.findings||''}</textarea>
      </div>
      <div class="form-group"><label class="form-label">조치 사항</label>
        <textarea id="insEditCorrectiveActions" class="form-control" rows="2" placeholder="필요한 시정/조치 사항">${ins.corrective_actions||''}</textarea>
      </div>
      <!-- 점검 결과 선택 -->
      <div class="form-group">
        <label class="form-label"><i class="fas fa-clipboard-check text-green-500 mr-1"></i>점검 결과</label>
        <div class="flex gap-2 flex-wrap" id="insEditResultBtns">
          ${['불량','적정','양호','우수'].map((v,i) => {
            const colors = ['red','yellow','blue','green'];
            const isSelected = currentResult === v;
            const c = colors[i];
            const cls = isSelected
              ? `px-4 py-2 rounded-lg border-2 text-sm font-semibold transition-all border-${c}-500 bg-${c}-50 text-${c}-700`
              : `px-4 py-2 rounded-lg border-2 text-sm font-semibold transition-all border-gray-200 text-gray-500 hover:border-${c}-400`;
            return `<button type="button" onclick="selectInsEditResult('${v}')" id="insEditResult_${v}" class="${cls}" data-result="${v}">${v}</button>`;
          }).join('')}
        </div>
        <input type="hidden" id="insEditResult" value="${currentResult}">
      </div>
      <!-- 사유 입력 -->
      <div class="form-group ${currentResult && currentResult!=='none' ? '' : 'hidden'}" id="insEditReasonGroup">
        <label class="form-label">사유 / 비고</label>
        <textarea id="insEditReason" class="form-control" rows="2" placeholder="선택 사유 또는 세부 내용">${ins.result_reason||''}</textarea>
      </div>
      <!-- 작업자 선택 (불량/우수) -->
      <div class="form-group ${['불량','우수'].includes(currentResult) ? '' : 'hidden'}" id="insEditWorkerGroup">
        <label class="form-label"><i class="fas fa-users mr-1"></i>해당 작업자 선택 <span class="text-xs font-normal text-gray-400 ml-1">(다중 선택 가능)</span></label>
        <div id="insEditWorkerList" class="border border-gray-200 rounded-lg p-3 bg-gray-50 max-h-48 overflow-y-auto">
          <p class="text-sm text-gray-400 text-center py-2"><i class="fas fa-info-circle mr-1"></i>작업을 먼저 선택해 주세요</p>
        </div>
      </div>
    </div>
    <div class="modal-footer">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button onclick="submitEditInspection(${id})" class="btn btn-primary" style="background:#685182"><i class="fas fa-save mr-1"></i>저장</button>
    </div>
  </div>`;
  document.body.appendChild(modal);

  // 기존 연결 작업자 체크 상태 초기화
  window._insEditPrevWorkerIds = (ins.workers || []).map(w => w.worker_id);
  // 작업 선택 시 작업자 목록 갱신
  if (ins.task_id) {
    const sel = document.getElementById('insEditTaskId');
    if (sel) onInsEditTaskSelect(sel);
  }
}

// 수정 모달: 결과 버튼 선택
function selectInsEditResult(val) {
  document.getElementById('insEditResult').value = val;
  const colorMap = { '불량':'red', '적정':'yellow', '양호':'blue', '우수':'green' };
  ['불량','적정','양호','우수'].forEach(v => {
    const btn = document.getElementById(`insEditResult_${v}`);
    if (!btn) return;
    if (v === val) {
      const c = colorMap[v];
      btn.className = `px-4 py-2 rounded-lg border-2 text-sm font-semibold transition-all border-${c}-500 bg-${c}-50 text-${c}-700`;
    } else {
      btn.className = `px-4 py-2 rounded-lg border-2 text-sm font-semibold transition-all border-gray-200 text-gray-500 hover:border-${colorMap[v]}-400`;
    }
  });
  // 사유 입력창 표시
  const rg = document.getElementById('insEditReasonGroup');
  if (rg) rg.classList.toggle('hidden', !val);
  // 작업자 선택창 표시 (불량/우수만)
  const wg = document.getElementById('insEditWorkerGroup');
  if (wg) wg.classList.toggle('hidden', !['불량','우수'].includes(val));
}

// 수정 모달: 작업 선택 시 작업자 목록 갱신
function onInsEditTaskSelect(sel) {
  const taskId = parseInt(sel.value) || 0;
  const prevChecked = new Set(window._insEditPrevWorkerIds || []);
  const wg = document.getElementById('insEditWorkerGroup');
  const list = document.getElementById('insEditWorkerList');
  if (!list) return;
  let workers = [];
  if (taskId && _insTaskWorkersMap[taskId] && _insTaskWorkersMap[taskId].length > 0) {
    workers = _insTaskWorkersMap[taskId];
  }
  if (workers.length === 0) {
    list.innerHTML = '<p class="text-sm text-gray-400 text-center py-2"><i class="fas fa-info-circle mr-1"></i>연결된 작업자가 없습니다</p>';
    return;
  }
  const currentResult = document.getElementById('insEditResult')?.value || '';
  const accentColor = currentResult === '우수' ? '#2DB400' : '#D70072';
  list.innerHTML = workers.map(w =>
    `<label class="flex items-center gap-2 py-1.5 cursor-pointer hover:bg-gray-100 rounded px-1">
       <input type="checkbox" class="ins-edit-worker-check w-4 h-4 cursor-pointer rounded" style="accent-color:${accentColor}" value="${w.id}" ${prevChecked.has(w.id)?'checked':''}>
       <span class="text-sm font-medium">${w.name}</span>
       ${w.position ? `<span class="text-xs text-gray-400">${w.position}</span>` : ''}
     </label>`
  ).join('');
}

// 수정 저장
async function submitEditInspection(id) {
  const location = document.getElementById('insEditLocation')?.value?.trim() || '';
  if (!location) { toast('점검 위치를 입력하세요.', 'error'); return; }

  const inspection_result = document.getElementById('insEditResult')?.value || '';
  const worker_ids = [];
  if (['불량','우수'].includes(inspection_result)) {
    document.querySelectorAll('.ins-edit-worker-check:checked').forEach(cb => {
      const wid = parseInt(cb.value);
      if (wid) worker_ids.push(wid);
    });
  }

  const body = {
    location,
    inspection_type:    document.getElementById('insEditType')?.value || 'routine',
    hazard_level:       document.getElementById('insEditHazard')?.value || 'low',
    findings:           document.getElementById('insEditFindings')?.value || '',
    corrective_actions: document.getElementById('insEditCorrectiveActions')?.value || '',
    inspection_date_only: document.getElementById('insEditDateOnly')?.value || '',
    inspection_result,
    result_reason:      document.getElementById('insEditReason')?.value || '',
    worker_ids,
  };

  // 디버그 로그
  console.log('[submitEditInspection] 전송 데이터:', { id, inspection_result, worker_ids });

  try {
    const res = await API.put(`/inspections/${id}`, body);
    const workersSaved = res.data?.workers_saved ?? null;
    console.log('[submitEditInspection] 서버 응답:', res.data);

    let workerMsg = '';
    if (workersSaved !== null) {
      if (['불량','우수'].includes(inspection_result) && worker_ids.length > 0) {
        workerMsg = workersSaved > 0
          ? ` · 작업자 ${workersSaved}명 기록됨`
          : ` · ⚠️ 작업자 저장 실패`;
      }
    }
    toast('점검이 수정되었습니다.' + workerMsg);
    document.querySelectorAll('.modal-overlay').forEach(m => m.remove());
    // 상세 모달 다시 열기
    showInspectionDetail(id);
    // 목록 페이지 갱신
    const content = document.getElementById('page-content');
    if (content && currentPage === 'inspections') renderInspectionsPage(content);
  } catch(e) {
    console.error('[submitEditInspection] 오류:', e.response?.data, e.message);
    toast(e.response?.data?.error || e.message || '수정 실패', 'error');
  }
}

// ─── 현장 점검 삭제 확인 모달 ─────────────────────────────────────────────────
function deleteInspection(id) {
  const m = document.createElement('div');
  m.className = 'modal-overlay modal-sm';
  m.style.zIndex = '10000';
  m.innerHTML = `
  <div class="modal" style="max-width:360px">
    <div class="modal-header" style="background:linear-gradient(135deg,#A8005A,#D70072);color:white">
      <div class="flex items-center gap-2">
        <i class="fas fa-trash text-lg"></i>
        <h3 class="font-bold">현장 점검 삭제</h3>
      </div>
      <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer;opacity:0.8">×</button>
    </div>
    <div class="modal-body">
      <div style="background:#FDE8F3;border:1.5px solid #FFC3DD;border-radius:12px;padding:14px 16px;color:#A8005A;font-size:14px;line-height:1.7">
        <i class="fas fa-exclamation-triangle mr-2 text-red-400"></i>
        이 현장 점검을 <b>삭제</b>하시겠습니까?<br>
        <span style="font-size:12px;opacity:0.8">첨부된 사진/동영상도 함께 삭제되며,<br>삭제된 데이터는 복구할 수 없습니다.</span>
      </div>
    </div>
    <div class="modal-footer" style="display:flex;gap:8px;justify-content:flex-end">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button id="doDeleteInsBtn" class="btn btn-danger font-bold"><i class="fas fa-trash mr-1"></i>삭제</button>
    </div>
  </div>`;
  document.body.appendChild(m);
  m.querySelector('#doDeleteInsBtn').onclick = async () => {
    m.remove();
    try {
      await API.delete(`/inspections/${id}`);
      toast('점검이 삭제되었습니다.');
      document.querySelectorAll('.modal-overlay').forEach(mo => mo.remove());
      const content = document.getElementById('page-content');
      if (content) renderInspectionsPage(content);
    } catch(e) {
      toast(e.response?.data?.error || e.message || '삭제 실패', 'error');
    }
  };
}

// 점검 상세에서 사진 추가
async function addInsPhoto(inspectionId) {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = 'image/*,video/*,.heic,.mov,.avi,.mp4,.webm,.mkv';
  input.multiple = true;
  input.onchange = async () => {
    const files = Array.from(input.files);
    if (!files.length) return;
    const formData = new FormData();
    formData.append('inspection_id', String(inspectionId));
    let skipped = 0;
    for (const f of files) {
      if (f.size > 500 * 1024 * 1024) {
        toast(`${f.name}: 파일이 너무 큽니다 (최대 500MB)`, 'error');
        skipped++;
        continue;
      }
      formData.append('photos', f);
    }
    if (files.length === skipped) return;
    const totalFiles = files.length - skipped;
    try {
      const result = await _uploadWithProgress('/api/inspection-photos', formData, {
        onProgress: (pct, loadedMB, totalMB) => {
          _showUploadToast('점검 사진', pct, totalFiles);
        }
      });
      _hideUploadToast();
      if (!result.ok) throw new Error(result.data?.error || '업로드 실패');
      toast(`사진 ${result.data.count}개 추가되었습니다.`);
      document.querySelectorAll('.modal-overlay').forEach(m => m.remove());
      showInspectionDetail(inspectionId);
    } catch(e) {
      _hideUploadToast();
      toast(e.message || '업로드 실패', 'error');
    }
  };
  input.click();
}

async function updateInspectionStatus(id, status) {
  try {
    await API.patch(`/inspections/${id}/status`, { status });
    toast('상태가 업데이트되었습니다.');
    renderInspectionsPage(document.getElementById('page-content'));
  } catch(e) { toast('실패', 'error'); }
}

// 상세 모달 드롭다운 상태 변경
async function changeInspectionStatus(id, status) {
  const statusLabelMap = { open:'미처리', in_progress:'처리중', closed:'완료' };
  const statusLabel = statusLabelMap[status] || status;
  const sel = document.getElementById(`insStatusSel_${id}`);

  // 완료(closed) 전환 시 확인 모달
  if (status === 'closed') {
    const confirmed = await new Promise(resolve => {
      const m = document.createElement('div');
      m.className = 'modal-overlay modal-sm';
      m.style.zIndex = '10001';
      m.innerHTML = `
        <div class="modal" style="max-width:360px">
          <div class="modal-header" style="background:linear-gradient(135deg,#059669,#10B981);color:white">
            <h3 class="font-bold text-lg"><i class="fas fa-check-circle mr-2"></i>점검 완료 처리</h3>
            <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer">×</button>
          </div>
          <div class="modal-body">
            <p class="text-sm text-gray-700 mb-2">이 점검을 <b style="color:#059669">완료</b> 처리하시겠습니까?</p>
            <p class="text-xs text-gray-500"><i class="fas fa-bell mr-1 text-yellow-500"></i>완료 처리 시 안전관리자·현장대리인·대표이사에게 알림이 발송됩니다.</p>
          </div>
          <div class="modal-footer">
            <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
            <button id="_insCloseConfirmBtn" class="btn btn-primary" style="background:#059669;border-color:#059669">
              <i class="fas fa-check mr-1"></i>완료 처리
            </button>
          </div>
        </div>`;
      document.body.appendChild(m);
      m.querySelector('#_insCloseConfirmBtn').onclick = () => { m.remove(); resolve(true); };
      m.querySelector('.modal-header button').onclick  = () => { m.remove(); resolve(false); };
    });
    if (!confirmed) {
      // 선택 취소 시 이전 값으로 복원
      if (sel) {
        const res = await API.get(`/inspections/${id}`).catch(() => null);
        const prev = res?.data?.status || 'open';
        sel.value = prev;
        _applyInsStatusSelStyle(sel, prev);
      }
      return;
    }
  }

  try {
    await API.patch(`/inspections/${id}/status`, { status });
    // 드롭다운 스타일 즉시 갱신
    if (sel) _applyInsStatusSelStyle(sel, status);
    toast(`점검이 [${statusLabel}] 처리되었습니다.${status === 'closed' ? ' 관련자에게 알림이 발송됩니다.' : ''}`);
    // 목록 갱신
    const content = document.getElementById('page-content');
    if (content && currentPage === 'inspections') renderInspectionsPage(content);
  } catch(e) {
    toast(e.response?.data?.error || '상태 변경 실패', 'error');
    // 실패 시 이전 값으로 복원
    if (sel) {
      const res = await API.get(`/inspections/${id}`).catch(() => null);
      const prev = res?.data?.status || 'open';
      sel.value = prev;
      _applyInsStatusSelStyle(sel, prev);
    }
  }
}

function _applyInsStatusSelStyle(sel, status) {
  if (!sel) return;
  if (status === 'closed') {
    sel.style.borderColor = '#10B981'; sel.style.background = '#ECFDF5'; sel.style.color = '#065F46';
  } else if (status === 'in_progress') {
    sel.style.borderColor = '#3B82F6'; sel.style.background = '#EFF6FF'; sel.style.color = '#1E40AF';
  } else {
    sel.style.borderColor = '#F59E0B'; sel.style.background = '#FFFBEB'; sel.style.color = '#92400E';
  }
}

// ======= 위험(아차사고)신고 =======
let _hazardTab = 'danger'; // 'danger' | 'nearmiss'
async function renderHazardsPage(container) {
  try {
    const res = await API.get('/hazards');
    const all = res.data || [];

    // 신고 유형 분류: report_type 컬럼 없으면 hazard_type으로 구분
    const dangerList  = all.filter(h => !h.report_type || h.report_type === 'danger');
    const nearmissList = all.filter(h => h.report_type === 'nearmiss');

    const tab = _hazardTab;
    const list = tab === 'nearmiss' ? nearmissList : dangerList;

    container.innerHTML = `
    <div class="page-container">

      <!-- 상단 안내 배너 -->
      <div class="rounded-2xl p-4 mb-4 flex items-start gap-3"
           style="background:linear-gradient(135deg,#FDE8F3 0%,#EDE7F6 100%);border:1.5px solid #FF349E">
        <div class="flex-shrink-0 w-10 h-10 rounded-xl flex items-center justify-center" style="background:#D70072">
          <i class="fas fa-shield-alt text-white text-lg"></i>
        </div>
        <div>
          <p class="font-bold text-sm" style="color:#A8005A">위험신고 · 아차사고(Near Miss) 신고</p>
          <p class="text-xs mt-0.5" style="color:#685182">
            <strong>위험신고</strong>는 즉각적인 위험상황 발견 시, <strong>아차사고 신고</strong>는 사고가 날 뻔한 상황(인적·물적 피해 없음)을 신고합니다.<br>
            <span style="color:#D70072">하인리히 법칙: 중대재해 1건 전에 아차사고 300건이 선행됩니다.</span>
          </p>
        </div>
      </div>

      <!-- 탭 + 신고 버튼 -->
      <div class="flex items-center justify-between mb-3">
        <div class="flex gap-1 p-1 rounded-xl" style="background:#F5F0F8">
          <button onclick="_switchHazardTab('danger')" id="tabDanger"
            class="px-4 py-2 rounded-lg text-sm font-bold transition-all ${tab==='danger'?'text-white shadow':'text-gray-500'}"
            style="${tab==='danger'?'background:#D70072':''}">
            <i class="fas fa-exclamation-triangle mr-1"></i>위험신고
            <span class="ml-1 text-xs px-1.5 py-0.5 rounded-full ${tab==='danger'?'bg-white':'bg-gray-200'}"
                  style="${tab==='danger'?'color:#D70072':'color:#888'}">${dangerList.length}</span>
          </button>
          <button onclick="_switchHazardTab('nearmiss')" id="tabNearmiss"
            class="px-4 py-2 rounded-lg text-sm font-bold transition-all ${tab==='nearmiss'?'text-white shadow':'text-gray-500'}"
            style="${tab==='nearmiss'?'background:#685182':''}">
            <i class="fas fa-bell mr-1"></i>아차사고
            <span class="ml-1 text-xs px-1.5 py-0.5 rounded-full ${tab==='nearmiss'?'bg-white':'bg-gray-200'}"
                  style="${tab==='nearmiss'?'color:#685182':'color:#888'}">${nearmissList.length}</span>
          </button>
        </div>
        <button onclick="showHazardReportForm('${tab}')" class="btn btn-danger text-sm py-2">
          <i class="fas fa-plus mr-1"></i> 신고 등록
        </button>
      </div>

      <!-- 탭별 설명 -->
      ${tab === 'danger' ? `
      <div class="rounded-xl p-3 mb-3 text-xs flex items-center gap-2" style="background:#FDE8F3;border:1px solid #FF349E;color:#A8005A">
        <i class="fas fa-exclamation-circle flex-shrink-0"></i>
        <span><strong>위험신고</strong>: 추락·감전·화재 등 즉각 대응이 필요한 위험상황 신고. 산안법 제52조에 따라 근로자는 급박한 위험 시 작업을 중지하고 대피할 권리가 있습니다.</span>
      </div>` : `
      <div class="rounded-xl p-3 mb-3 text-xs flex items-center gap-2" style="background:#EDE7F6;border:1px solid #8E72A8;color:#4E3A63">
        <i class="fas fa-bell flex-shrink-0"></i>
        <span><strong>아차사고(Near Miss)</strong>: 사고가 날 뻔했으나 인적·물적 피해 없이 종료된 상황. 발굴·신고하면 위험성평가에 반영되어 중대재해를 예방합니다.</span>
      </div>`}

      <!-- 목록 -->
      <div class="space-y-3">
        ${list.length === 0 ? `
          <div class="card text-center py-12 text-gray-400">
            <i class="fas fa-shield-alt text-5xl mb-3 ${tab==='nearmiss'?'text-purple-200':'text-green-300'}"></i>
            <p class="${tab==='nearmiss'?'text-purple-500':'text-green-600'} font-medium">
              ${tab==='nearmiss'?'신고된 아차사고가 없습니다.':'등록된 위험신고가 없습니다.'}
            </p>
            <p class="text-xs text-gray-400 mt-1">위험을 발견하면 즉시 신고해 주세요.</p>
          </div>` :
          list.map(h => {
            const riskBorder = h.risk_level==='critical'?'border-l-4':'border-l-4';
            const borderColor = h.report_type==='nearmiss'
              ? (h.risk_level==='critical'?'#685182':h.risk_level==='high'?'#8E72A8':h.risk_level==='medium'?'#9C82AF':'#C6C6C6')
              : (h.risk_level==='critical'?'#D70072':h.risk_level==='high'?'#FF349E':h.risk_level==='medium'?'#685182':'#C6C6C6');
            const statusLabel = h.status==='resolved'?'조치완료':h.status==='reviewing'?'검토중':'미처리';
            const statusStyle = h.status==='resolved'?'background:#EDE7F6;color:#685182'
              :h.status==='reviewing'?'background:#FDE8F3;color:#D70072':'background:#D70072;color:#fff';
            const riskLabel = h.risk_level==='critical'?'긴급':h.risk_level==='high'?'높음':h.risk_level==='medium'?'보통':'낮음';
            const riskClass = h.risk_level==='critical'?'risk-critical':h.risk_level==='high'?'risk-high':h.risk_level==='medium'?'risk-medium':'risk-low';
            return `
            <div class="card" style="border-left:4px solid ${borderColor};cursor:pointer" onclick="showHazardDetail(${h.id})">
              <div class="flex justify-between items-start mb-2">
                <div class="flex-1">
                  <div class="flex items-center gap-2 mb-1 flex-wrap">
                    ${h.report_type==='nearmiss'?`<span class="text-xs px-2 py-0.5 rounded-full font-bold" style="background:#EDE7F6;color:#685182"><i class="fas fa-bell mr-1"></i>아차사고</span>`:''}
                    <span class="font-bold text-sm" style="color:#4E3A63">${h.hazard_type}</span>
                    <span class="badge ${riskClass}">${riskLabel}</span>
                  </div>
                  <p class="text-xs" style="color:#C6C6C6">${h.reporter_name||'-'} · ${h.location||'-'} · ${formatDateTime(h.report_date)}</p>
                </div>
                <span class="badge flex-shrink-0" style="${statusStyle}">${statusLabel}</span>
              </div>
              <p class="text-sm mb-2" style="color:#4E3A63">${h.hazard_description||''}</p>
              ${h.near_miss_cause ? `<p class="text-xs mb-1 px-2 py-1 rounded-lg" style="background:#EDE7F6;color:#4E3A63"><i class="fas fa-search mr-1" style="color:#685182"></i><strong>발생 원인:</strong> ${h.near_miss_cause}</p>` : ''}
              ${h.recurrence_prevention ? `<p class="text-xs mb-1 px-2 py-1 rounded-lg" style="background:#F5F0F8;color:#685182"><i class="fas fa-shield-alt mr-1"></i><strong>재발방지:</strong> ${h.recurrence_prevention}</p>` : ''}
              ${h.immediate_action ? `<p class="text-xs mb-2" style="color:#685182"><i class="fas fa-bolt mr-1"></i>즉각조치: ${h.immediate_action}</p>` : ''}
              ${h.resolution_notes ? `<p class="text-xs px-3 py-2 rounded-lg mb-2" style="background:#EDE7F6;color:#685182"><i class="fas fa-clipboard-check mr-1"></i>처리내용: ${h.resolution_notes}</p>` : ''}
              <div class="flex gap-2 mt-2" onclick="event.stopPropagation()">
                ${h.status !== 'resolved' && currentUser.role !== 'worker' ? `
                <button onclick="resolveHazard(${h.id})" class="btn btn-primary text-xs py-1">
                  <i class="fas fa-check-circle mr-1"></i> 처리 완료
                </button>` : ''}
                <button onclick="showHazardDetail(${h.id})" class="btn btn-outline text-xs py-1">
                  <i class="fas fa-eye mr-1"></i> 상세보기
                </button>
              </div>
            </div>`;
          }).join('')}
      </div>
    </div>`;
  } catch(e) {
    container.innerHTML = `<p class="text-red-500 p-4">로드 실패</p>`;
  }
}
function _switchHazardTab(tab) {
  _hazardTab = tab;
  const content = document.getElementById('page-content') || document.getElementById('main-content');
  if (content) renderHazardsPage(content);
}

