  // 새 모달 열 때마다 이전 assessment ID 초기화 (오염 방지)
  window._checklistAssessmentId = null;
  window._checklistTaskId = taskId;

  const curWc = taskWorkClass || 'cable_install';

  // 작업 분류 목록 (4종)
  const wcList = [
    { value:'cable_install',   label:'광케이블 시설',    icon:'fas fa-ethernet'      },
    { value:'cable_splice',    label:'광케이블 접속',    icon:'fas fa-plug'           },
    { value:'equipment_other', label:'장비 시설및 기타', icon:'fas fa-tools'          },
    { value:'conduit',         label:'관로시설',         icon:'fas fa-circle-nodes'   }
  ];

  // 조건부 항목 체크박스 목록 (5종)
