// ======= 인원 관리 (사용자 + 현장팀 통합) =======
let _userListData = [];  // 정렬/엑셀용 캐시

async function renderUsersPage(container) {
  try {
    const [usersRes, teamsRes, pendingRes] = await Promise.all([
      API.get('/users'),
      API.get('/teams').catch(()=>({data:[]})),
      API.get('/auth/pending-users').catch(()=>({data:[]}))
    ]);
    const users = usersRes.data;
    const teams = teamsRes.data;
    const pendingUsers = Array.isArray(pendingRes.data) ? pendingRes.data : [];
    _userListData = users;

    // 팀 매핑 (user_id → {team_name, team_id, is_leader})
    const userTeamMap = {};
    for (const team of teams) {
      for (const m of (team.members || [])) {
        userTeamMap[m.id] = { team_name: team.name, team_id: team.id, is_leader: m.is_leader };
      }
    }

    // 탭 필터링
    const allTeamMemberIds = new Set(Object.keys(userTeamMap).map(Number));
    const noTeamUsers = users.filter(u => !allTeamMemberIds.has(u.id));

    // 행 렌더
    function renderUserRow(u) {
      const info     = getRoleDisplay(u.role, u.position, u.sub_role);
      const teamInfo = userTeamMap[u.id];
      const teamLabel = teamInfo
        ? `<span class="text-xs font-bold" style="color:#685182"><i class="fas fa-people-group mr-0.5"></i>${teamInfo.team_name}</span>${teamInfo.is_leader ? `<span class="badge ml-1" style="background:#FDE8F3;color:#D70072;font-size:9px"><i class="fas fa-star mr-0.5"></i>팀장</span>` : ''}`
        : `<span class="text-xs text-gray-300">미배정</span>`;
      return `
      <tr style="border-bottom:1px solid #F5F0F8"
          onmouseover="this.style.background='#F5F0F8'" onmouseout="this.style.background=''">
        <td class="px-3 py-2 text-center" style="width:72px">
          <div class="flex items-center justify-center gap-1">
            <input type="checkbox" class="user-qr-check w-3.5 h-3.5 accent-pink-600 cursor-pointer"
              value="${u.id}"
              data-name="${u.name.replace(/"/g,'&quot;')}"
              data-team="${(teamInfo?.team_name||'').replace(/"/g,'&quot;')}"
              data-position="${(u.position||'').replace(/"/g,'&quot;')}"
              onchange="updateQrBulkCount()">
            <button onclick="printQrCard(${u.id},this.dataset.name,this.dataset.team,this.dataset.pos)"
                    data-name="${u.name.replace(/"/g,'&quot;')}"
                    data-team="${(teamInfo?.team_name||'').replace(/"/g,'&quot;')}"
                    data-pos="${(u.position||'').replace(/"/g,'&quot;')}"
                    class="w-7 h-7 rounded-lg flex items-center justify-center text-white text-xs font-black flex-shrink-0"
                    style="background:${teamInfo?.is_leader?'linear-gradient(135deg,#D70072,#685182)':'linear-gradient(135deg,#685182,#8E72A8)'}"
                    title="QR 카드 인쇄">
              <i class="fas fa-print text-xs"></i>
            </button>
            <button onclick="showUserQrModal(${u.id},this.dataset.name,this.dataset.team,this.dataset.pos)"
                    data-name="${u.name.replace(/"/g,'&quot;')}"
                    data-team="${(teamInfo?.team_name||'').replace(/"/g,'&quot;')}"
                    data-pos="${(u.position||'').replace(/"/g,'&quot;')}"
                    class="w-6 h-6 rounded-md flex items-center justify-center text-xs flex-shrink-0"
                    style="background:#F5F0F8;color:#685182;border:1px solid #D8D0DC"
                    title="QR 미리보기">
              <i class="fas fa-qrcode" style="font-size:10px"></i>
            </button>
          </div>
        </td>
        <td class="px-3 py-2">
          <div class="font-bold text-sm text-gray-900">${u.name}</div>
          <div class="text-xs text-gray-400">@${u.username}</div>
        </td>
        <td class="px-3 py-2 text-sm text-gray-600">
          ${u.phone||`<span class="text-gray-300">-</span>`}
        </td>
        <td class="px-3 py-2">
          <span class="badge" style="background:${info.bg};color:${info.color};font-size:10px">
            <i class="${info.icon} mr-0.5"></i>${info.label}
          </span>
        </td>
        <td class="px-3 py-2 text-sm text-gray-600">${u.department||`<span class="text-gray-300">-</span>`}</td>
        <td class="px-3 py-2">
          ${u.position?`<span class="text-xs px-1.5 py-0.5 rounded font-medium" style="background:#F5F0F8;color:#685182">${u.position}</span>`:`<span class="text-gray-300 text-xs">-</span>`}
        </td>
        <td class="px-3 py-2">${teamLabel}</td>
        <td class="px-3 py-2 text-right">
          <div class="flex gap-1 justify-end">
            <button class="btn py-1 px-2 text-xs" id="insHistBtn_${u.id}"
              onclick="showUserInspectionHistory(${u.id},this.dataset.name)"
              data-name="${u.name.replace(/"/g,'&quot;')}"
              title="점검 이력" style="background:#F5F0F8;color:#685182;border:1px solid #D8D0DC">
              <i class="fas fa-clipboard-check"></i>
            </button>
          </div>
        </td>
      </tr>`;
    }

    // 정렬 트리거는 buildSortableTable 후 마지막에 등록 (하단 참조)

    function buildSortableTable(id, userList, emptyMsg) {
      if (!userList.length) return `<p class="text-sm text-gray-400 p-6 text-center">${emptyMsg}</p>`;
      return `
      <div style="overflow-x:auto">
        <table id="${id}" style="width:100%;border-collapse:collapse">
          <thead>
            <tr style="background:#F5F0F8;border-bottom:2px solid #D8D0DC">
              <th class="px-3 py-2.5 text-center text-xs font-black text-gray-500" style="width:72px">
                <input type="checkbox" class="user-qr-check-all w-3.5 h-3.5 accent-pink-600 cursor-pointer"
                  title="전체 선택" onchange="toggleAllQrChecks(this,'${id}')">
                <span class="ml-0.5">QR</span>
              </th>
              ${sortTh('이름','name',id)}
              ${sortTh('연락처','phone',id)}
              ${sortTh('역할','role',id)}
              ${sortTh('부서','department',id)}
              ${sortTh('직책','position',id)}
              ${sortTh('팀구분','team_name',id)}
              <th class="px-3 py-2.5 text-right text-xs font-black text-gray-500" style="width:60px">이력</th>
            </tr>
          </thead>
          <tbody>${userList.map(u=>renderUserRow(u)).join('')}</tbody>
        </table>
      </div>`;
    }

    // 팀 카드 렌더링 (팀별 탭)
    function buildTeamSection(team) {
      const teamMembers = (team.members||[]).map(m => users.find(u => u.id === m.id)).filter(Boolean);
      const isAdmin = currentUser.role === 'admin';
      return `
      <div id="userTab-team-${team.id}" class="hidden pt-3">
        <!-- 팀 헤더 + 관리 버튼 -->
        <div class="mb-3 p-3 rounded-xl flex items-center gap-3 flex-wrap" style="background:linear-gradient(135deg,#FDE8F3,#EDE7F6)">
          <div class="w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center text-white font-bold"
               style="background:linear-gradient(135deg,#D70072,#685182)">${team.name.charAt(0)}</div>
          <div class="flex-1 min-w-0">
            <div class="font-black text-sm" style="color:#D70072">${team.name}</div>
            ${team.leader
              ? `<div class="font-bold text-gray-900"><i class="fas fa-star mr-1 text-xs" style="color:#D70072"></i>팀장: ${team.leader.name}${team.leader.position?' ('+team.leader.position+')':''}</div>`
              : `<div class="text-xs text-yellow-700"><i class="fas fa-exclamation-triangle mr-1"></i>팀장 미지정</div>`}
            <div class="text-xs text-gray-500 mt-0.5">총 ${team.member_count}명</div>
          </div>
          <div class="flex gap-2 flex-shrink-0">
            <button onclick="showTeamMembersModal(${team.id})" class="btn btn-outline btn-sm text-xs">
              <i class="fas fa-users-cog mr-1"></i>팀원 수정
            </button>
            ${isAdmin ? `
            <button onclick="showEditTeamModal(${team.id},'${team.name.replace(/'/g,"\\'")}','${(team.description||'').replace(/'/g,"\\'")}') " class="btn btn-outline btn-sm text-xs">
              <i class="fas fa-edit mr-1"></i>팀 수정
            </button>
            <button onclick="deleteTeam(${team.id},'${team.name.replace(/'/g,"\\'")}') " class="btn btn-danger btn-sm text-xs">
              <i class="fas fa-trash"></i>
            </button>` : ''}
          </div>
        </div>
        <div class="card" style="padding:0;overflow:hidden">
          ${buildSortableTable('userTeamTable-'+team.id, teamMembers, '배정된 팀원이 없습니다.')}
        </div>
      </div>`;
    }

    container.innerHTML = `
    <div class="page-container">
      <!-- 헤더 -->
      <div class="flex items-center justify-between mb-4 flex-wrap gap-2">
        <div>
          <h2 class="text-xl font-black text-gray-900" style="border-left:4px solid #D70072;padding-left:10px">
            <i class="fas fa-id-badge mr-2" style="color:#D70072"></i>업무중사용자
            ${pendingUsers.length > 0 ? `<span class="ml-2 badge" style="background:#FEF3C7;color:#D97706;font-size:11px;vertical-align:middle"><i class="fas fa-clock mr-1"></i>승인대기 ${pendingUsers.length}명</span>` : ''}
          </h2>
          <p class="text-sm text-gray-400 mt-1 pl-4">활성 ${users.length}명 · 팀 ${teams.length}개 구성</p>
        </div>
        <div class="flex gap-2 flex-wrap">
          ${pendingUsers.length > 0 ? `
          <button onclick="showPendingUsersModal()" class="btn" style="background:#FEF3C7;color:#D97706;border:1.5px solid #FCD34D;font-weight:700">
            <i class="fas fa-user-check mr-1"></i>승인대기 ${pendingUsers.length}명
          </button>` : ''}
          ${currentUser.role==='admin'?`
          <button onclick="showCreateTeamModal()" class="btn btn-success">
            <i class="fas fa-plus"></i> 팀 추가
          </button>`:``}
          <button onclick="printQrBulk()" class="btn btn-outline" style="color:#685182;border-color:#685182">
            <i class="fas fa-qrcode mr-1"></i>QR 일괄 인쇄
          </button>
        </div>
      </div>

      <!-- 사용자 검색바 -->
      <div class="mb-4 relative">
        <div class="relative flex items-center gap-2">
          <div class="relative flex-1">
            <i class="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-sm pointer-events-none"></i>
            <input id="userSearchInput" type="text" placeholder="이름, 아이디, 연락처, 부서, 직위, 팀으로 검색..."
              class="form-control pl-9 pr-9 text-sm" style="border-radius:12px;border:1.5px solid #D8D0DC"
              oninput="filterUserList(this.value)">
            <button id="userSearchClear" onclick="clearUserSearch()"
              class="absolute right-3 top-1/2 -translate-y-1/2 text-gray-300 hover:text-gray-500 hidden">
              <i class="fas fa-times-circle"></i>
            </button>
          </div>
          <div id="userSearchCount" class="text-xs text-gray-400 whitespace-nowrap shrink-0" style="min-width:60px"></div>
        </div>
        <div id="userSearchNoResult" class="hidden mt-2 text-sm text-gray-400 text-center py-3 bg-gray-50 rounded-xl">
          <i class="fas fa-search mr-1"></i>검색 결과가 없습니다.
        </div>
      </div>

      <!-- 역할별 카운트 (업무 인원 4종 — sysadmin/LGU+ 제외) -->
      <div class="grid grid-cols-4 gap-2 mb-4">
        ${['worker','safety','engineer','site_rep'].map(uiRole=>{
          const info = UI_ROLE_DISPLAY[uiRole];
          const cnt = users.filter(u => dbRoleToUi(u.role, u.position, u.sub_role) === uiRole).length;
          return `<div class="card p-3 text-center" style="border-top:3px solid ${info.color}">
            <div class="text-2xl font-black" style="color:${info.color}">${cnt}</div>
            <div class="text-xs font-bold text-gray-500 mt-1"><i class="${info.icon} mr-1"></i>${info.label}</div>
          </div>`;
        }).join('')}
      </div>

      <!-- 팀별 탭 -->
      <div class="tab-bar mb-0" id="userTeamTabBar">
        <div class="tab-item active" onclick="switchUserTab('all',this)">전체 (${users.length})</div>
        ${teams.map(t=>`<div class="tab-item" onclick="switchUserTab('team-${t.id}',this)">${t.name} (${t.member_count})</div>`).join('')}
        ${noTeamUsers.length?`<div class="tab-item" onclick="switchUserTab('no-team',this)">미배정 (${noTeamUsers.length})</div>`:''}
      </div>

      <!-- 전체 탭 -->
      <div id="userTab-all" class="pt-3" style="overflow:hidden;border-radius:0 0 16px 16px;background:white;box-shadow:0 2px 8px rgba(0,0,0,.06)">
        ${buildSortableTable('userAllTable', users, '등록된 인원이 없습니다.')}
      </div>

      <!-- 팀별 탭 -->
      ${teams.map(team => buildTeamSection(team)).join('')}

      <!-- 미배정 탭 -->
      ${noTeamUsers.length?`
      <div id="userTab-no-team" class="hidden pt-3">
        <div class="mb-3 p-3 rounded-xl bg-yellow-50 border border-yellow-200 text-sm text-yellow-800">
          <i class="fas fa-exclamation-triangle mr-2"></i>아직 팀에 배정되지 않은 인원입니다.
        </div>
        <div class="card" style="padding:0;overflow:hidden">
          ${buildSortableTable('userNoTeamTable', noTeamUsers, '')}
        </div>
      </div>`:''}
    </div>`;

    // 정렬 이벤트 등록
    window._sortTrigger = (tableId, col) => {
      const map = {
        userAllTable: users, userNoTeamTable: noTeamUsers,
        ...Object.fromEntries(teams.map(t=>['userTeamTable-'+t.id, (t.members||[]).map(m=>users.find(u=>u.id===m.id)).filter(Boolean)]))
      };
      const data = map[tableId] || users;
      sortTable(tableId, col, data, (sorted) => {
        const tbody = document.querySelector(`#${tableId} tbody`);
        if (tbody) tbody.innerHTML = sorted.map(u=>renderUserRow(u)).join('');
      });
    };

    // ── 사용자 검색 함수 (클로저로 users, userTeamMap 접근) ──
    window.filterUserList = function(keyword) {
      const q = keyword.trim().toLowerCase();
      const clearBtn    = document.getElementById('userSearchClear');
      const countEl     = document.getElementById('userSearchCount');
      const noResultEl  = document.getElementById('userSearchNoResult');

      // X버튼 토글
      if (clearBtn) clearBtn.classList.toggle('hidden', !q);

      if (!q) {
        // 검색어 없으면 모든 행 표시
        document.querySelectorAll('#userAllTable tbody tr, #userNoTeamTable tbody tr, [id^="userTeamTable-"] tbody tr').forEach(tr => {
          tr.style.display = '';
        });
        if (countEl)    countEl.textContent = '';
        if (noResultEl) noResultEl.classList.add('hidden');
        return;
      }

      // 전체 사용자 데이터 기준 필터
      const matched = users.filter(u => {
        const team = userTeamMap[u.id];
        const searchStr = [
          u.name, u.username, u.phone||'', u.department||'', u.position||'',
          team?.team_name||'', getRoleDisplay(u.role, u.position, u.sub_role).label
        ].join(' ').toLowerCase();
        return searchStr.includes(q);
      });
      const matchedIds = new Set(matched.map(u => u.id));

      // 각 테이블의 tbody tr에 data-userid가 없으므로 행 순서와 users 배열 순서로 매핑
      // renderUserRow 출력의 input[value] 로 id 판별
      document.querySelectorAll('#userAllTable tbody tr, #userNoTeamTable tbody tr, [id^="userTeamTable-"] tbody tr').forEach(tr => {
        const cb = tr.querySelector('input[type="checkbox"]');
        const uid = cb ? Number(cb.value) : -1;
        tr.style.display = (uid > 0 && matchedIds.has(uid)) ? '' : 'none';
      });

      if (countEl)    countEl.textContent = `${matched.length}명`;
      if (noResultEl) noResultEl.classList.toggle('hidden', matched.length > 0);
    };

    window.clearUserSearch = function() {
      const input = document.getElementById('userSearchInput');
      if (input) { input.value = ''; input.focus(); }
      window.filterUserList('');
    };

  } catch(e) {
    container.innerHTML = `<p class="text-red-500 p-4">로드 실패: ${e.message}</p>`;
  }
}

// 작업자별 점검 이력 팝업
// ======= 불량/우수 결과별 이력 팝업 (숫자 클릭) =======
async function showWorkerResultHistory(workerId, workerName, resultType, dateStart, dateEnd) {
  // resultType: '불량' | '우수' | '전체'
  const isAll  = resultType === '전체';
  const isPoor = resultType === '불량';
  // 헤더 색상
  const hColor  = isAll ? '#685182' : isPoor ? '#D70072' : '#685182';
  const hBg     = isAll ? '#F5F0F8' : isPoor ? '#FDE8F3' : '#F5F0F8';
  const hBorder = isAll ? '#D8D0DC' : isPoor ? '#D7007244' : '#68518244';
  const hIcon   = isAll ? 'fa-list-alt' : isPoor ? 'fa-exclamation-triangle' : 'fa-star';

  // 결과별 색상 맵
  const RC = {
    '불량': { color:'#D70072', bg:'#FDE8F3', border:'#FF349E', icon:'fa-exclamation-triangle' },
    '우수': { color:'#685182', bg:'#F5F0F8', border:'#8E72A8', icon:'fa-star' },
  };
  // 위험도
  const HAZARD_LBL = { critical:'긴급', high:'높음', medium:'보통', low:'낮음' };
  const HAZARD_COL = { critical:'#D70072', high:'#D70072', medium:'#D70072', low:'#C6C6C6' };
  // 처리상태
  const INS_STS_LBL = { open:'미처리', in_progress:'처리중', closed:'완료' };
  const INS_STS_COL = { open:'#D70072', in_progress:'#685182', closed:'#685182' };
  // 작업상태
  const TASK_STS_LBL = {
    unassigned:'미배정', assigned:'배정완료', in_progress:'준비중',
    tbm_done:'TBM완료', working:'작업중', work_completed:'작업완료', completed:'완료'
  };

  const modalId = `wrHistory_${Date.now()}`;
  const modal   = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
  <div class="modal" style="max-width:580px">
    <div class="modal-header" style="background:${hBg};border-bottom:2px solid ${hBorder}">
      <div>
        <h3 class="font-bold text-base" style="color:${hColor}">
          <i class="fas ${hIcon} mr-2"></i>${workerName} — ${resultType} 점검 이력
        </h3>
        ${dateStart ? `<div class="text-xs mt-0.5" style="color:${hColor};opacity:.75">${dateStart} ~ ${dateEnd}</div>` : ''}
      </div>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body" id="${modalId}_body">
      <div class="text-center py-8 text-gray-300"><i class="fas fa-spinner fa-spin text-2xl"></i></div>
    </div>
  </div>`;
  document.body.appendChild(modal);

  try {
    // 서버에서 기간 + result_type 필터 적용 조회 (전체면 result_type 파라미터 생략)
    const qParams = {};
    if (!isAll) qParams.result_type = resultType;
    if (dateStart) qParams.start = dateStart;
    if (dateEnd)   qParams.end   = dateEnd;

    const res     = await API.get(`/inspections/worker-history/${workerId}`, { params: qParams });
    const records = res.data || [];

    const body = document.getElementById(`${modalId}_body`);
    if (!body) return;

    if (records.length === 0) {
      body.innerHTML = `<div class="text-center py-12 text-gray-400">
        <i class="fas ${hIcon} text-4xl mb-3 block opacity-20" style="color:${hColor}"></i>
        <p class="text-sm font-medium">${resultType} 점검 기록이 없습니다.</p>
        ${dateStart ? `<p class="text-xs mt-1 text-gray-300">${dateStart} ~ ${dateEnd}</p>` : ''}
      </div>`;
      return;
    }

    // 전체일 때 불량/우수 건수 집계
    const poorCnt  = records.filter(r => r.result_type === '불량').length;
    const excelCnt = records.filter(r => r.result_type === '우수').length;

    // 요약 배너
    let html = `
    <div class="flex items-center gap-3 mb-4 p-3 rounded-xl" style="background:${hBg};border:1px solid ${hBorder}">
      <span class="inline-flex items-center justify-center w-9 h-9 rounded-full text-white font-black flex-shrink-0" style="background:${hColor}">
        <i class="fas ${hIcon}"></i>
      </span>
      <div class="flex-1 min-w-0">
        <div class="font-black text-sm" style="color:${hColor}">총 ${records.length}건 ${resultType} 이력</div>
        <div class="text-xs text-gray-500 mt-0.5 flex gap-3 flex-wrap">
          <span>${workerName}</span>
          ${dateStart ? `<span>${dateStart} ~ ${dateEnd}</span>` : '<span>전체 기간</span>'}
          ${isAll ? `<span style="color:#D70072">불량 ${poorCnt}건</span><span style="color:#685182">우수 ${excelCnt}건</span>` : ''}
        </div>
      </div>
    </div>
    <div class="space-y-2">`;

    records.forEach(r => {
      const rType    = r.result_type || '우수';
      const rc       = RC[rType] || RC['우수'];
      const dateStr  = r.inspection_date_only || '-';
      const hzLbl    = HAZARD_LBL[r.hazard_level] || '';
      const hzCol    = HAZARD_COL[r.hazard_level]  || '';
      const isLbl    = INS_STS_LBL[r.ins_status]  || r.ins_status || '';
      const isCol    = INS_STS_COL[r.ins_status]   || '#C6C6C6';
      const tsLbl    = TASK_STS_LBL[r.task_status] || '';

      // 해당 기록의 점수 (불량: -10점, 우수: +5점)
      const recScore     = rType === '불량' ? -10 : 5;
      const recScoreStr  = recScore > 0 ? `+${recScore}점` : `${recScore}점`;

      html += `
      <div class="rounded-xl overflow-hidden cursor-pointer hover:shadow-md transition-all"
           style="border:1.5px solid ${rc.border}"
           onclick="this.closest('.modal-overlay').remove(); showInspectionDetail(${r.inspection_id})">

        <!-- 상단: 결과뱃지 / 날짜 / 위험도 / 점수 / 처리상태 -->
        <div class="flex items-center gap-2 px-3 py-1.5 flex-wrap" style="background:${rc.bg}">
          <span class="text-xs font-black text-white px-2 py-0.5 rounded-full" style="background:${rc.color}">
            <i class="fas ${rc.icon} mr-1"></i>${rType}
          </span>
          <span class="text-xs font-bold text-gray-600">
            <i class="fas fa-calendar-alt mr-1 opacity-40"></i>${dateStr}
          </span>
          ${hzLbl ? `<span class="text-xs font-bold text-white px-1.5 py-0.5 rounded" style="background:${hzCol}">${hzLbl}</span>` : ''}
          <span class="font-black px-2 py-0.5 rounded-lg" style="font-size:12px;color:${rc.color};background:white;border:1.5px solid ${rc.color}44;margin-left:auto">${recScoreStr}</span>
          <span class="text-xs font-bold px-1.5 py-0.5 rounded" style="color:${isCol};background:${isCol}18">${isLbl}</span>
        </div>

        <!-- 본문 -->
        <div class="px-3 py-2 bg-white">
          ${r.task_title ? `
          <div class="flex items-center gap-1.5 mb-1.5 pb-1.5" style="border-bottom:1px dashed #F5F0F8">
            <i class="fas fa-hammer text-blue-300" style="font-size:10px;flex-shrink:0"></i>
            <span class="text-xs font-bold text-blue-600">${r.task_number ? '['+r.task_number+'] ' : ''}${r.task_title}</span>
            ${tsLbl ? `<span class="text-xs text-gray-400 ml-1">(${tsLbl})</span>` : ''}
          </div>` : ''}

          <div class="flex items-start gap-1.5 mb-1">
            <i class="fas fa-map-marker-alt text-gray-300 mt-0.5 flex-shrink-0" style="font-size:10px"></i>
            <span class="text-xs text-gray-600">${r.location || '-'}</span>
          </div>

          ${r.result_reason ? `
          <div class="flex items-start gap-1.5 mb-1.5 px-2 py-1 rounded-lg" style="background:${rc.bg}">
            <i class="fas ${rc.icon} flex-shrink-0 mt-0.5" style="font-size:10px;color:${rc.color}"></i>
            <span class="text-xs font-semibold" style="color:${rc.color}">${r.result_reason}</span>
          </div>` : ''}

          ${r.findings ? `
          <div class="flex items-start gap-1.5 mb-1">
            <i class="fas fa-clipboard-list text-gray-300 mt-0.5 flex-shrink-0" style="font-size:10px"></i>
            <span class="text-xs text-gray-700">${r.findings}</span>
          </div>` : ''}

          ${r.corrective_actions ? `
          <div class="flex items-start gap-1.5 mt-1 pt-1 mb-1" style="border-top:1px dashed #F5F0F8">
            <i class="fas fa-wrench text-gray-300 mt-0.5 flex-shrink-0" style="font-size:10px"></i>
            <span class="text-xs text-gray-500">${r.corrective_actions}</span>
          </div>` : ''}

          <div class="flex items-center justify-between mt-1.5">
            <span class="text-xs text-gray-400">
              <i class="fas fa-user mr-1 opacity-40"></i>${r.inspector_name || '-'}
            </span>
            <i class="fas fa-chevron-right text-gray-200" style="font-size:10px"></i>
          </div>
        </div>
      </div>`;
    });

    html += `</div>
    <p class="text-xs text-center text-gray-300 mt-4 pb-1">
      <i class="fas fa-hand-pointer mr-1"></i>카드 클릭 시 점검 상세로 이동합니다.
    </p>`;

    body.innerHTML = html;
  } catch(e) {
    const body = document.getElementById(`${modalId}_body`);
    if (body) body.innerHTML = `<p class="text-red-500 text-sm p-4">로드 실패: ${e.message}</p>`;
  }
}

// ======= 불량 기록 작업 리스트 모달 =======
async function showWorkerPoorTasks(workerId, workerName, dateStart, dateEnd) {
  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
  <div class="modal" style="max-width:600px">
    <div class="modal-header" style="background:linear-gradient(135deg,#FDE8F3,#FDE8F3);border-bottom:2px solid #D7007233">
      <h3 class="font-bold text-lg" style="color:#D70072">
        <i class="fas fa-exclamation-triangle mr-2"></i>${workerName} — 불량 기록 작업 목록
      </h3>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body" id="poorTaskModal_body">
      <div class="text-center py-8 text-gray-400"><i class="fas fa-spinner fa-spin text-2xl"></i><p class="mt-2 text-sm">불러오는 중...</p></div>
    </div>
  </div>`;
  document.body.appendChild(modal);

  try {
    const params = {};
    if (dateStart) params.start = dateStart;
    if (dateEnd)   params.end   = dateEnd;
    const res = await API.get(`/inspections/worker-poor-tasks/${workerId}`, { params });
    const tasks = res.data || [];
    const body = document.getElementById('poorTaskModal_body');
    if (!body) return;

    if (tasks.length === 0) {
      body.innerHTML = `<div class="text-center py-10 text-gray-400">
        <i class="fas fa-check-circle text-4xl mb-3 block opacity-30" style="color:#685182"></i>
        <p class="text-sm font-medium">해당 기간 불량 기록이 없습니다.</p>
      </div>`;
      return;
    }

    const TASK_STATUS_LBL = {
      unassigned:'미배정', assigned:'배정완료', in_progress:'준비중',
      tbm_done:'TBM완료', working:'작업중', work_completed:'작업완료',
      completed:'완료', cancelled:'취소'
    };
    const TASK_STATUS_COLOR = {
      unassigned:'#C6C6C6', assigned:'#685182', in_progress:'#D70072',
      tbm_done:'#685182', working:'#685182', work_completed:'#685182',
      completed:'#685182', cancelled:'#D70072'
    };

    const totalPoor = tasks.reduce((s, t) => s + (t.poor_count || 0), 0);

    let html = `
    <!-- 요약 -->
    <div class="flex items-center gap-3 mb-4 p-3 rounded-xl" style="background:#FDE8F3;border:1px solid #D7007233">
      <span class="inline-flex items-center justify-center w-10 h-10 rounded-full text-white font-black text-lg flex-shrink-0" style="background:#D70072">
        <i class="fas fa-exclamation-triangle"></i>
      </span>
      <div>
        <div class="font-black text-sm" style="color:#D70072">총 ${totalPoor}건 불량 기록</div>
        <div class="text-xs text-gray-500 mt-0.5">${tasks.length}개 작업에서 발생${dateStart ? ` · ${dateStart} ~ ${dateEnd}` : ''}</div>
      </div>
    </div>

    <!-- 작업 목록 -->
    <div class="space-y-2">`;

    tasks.forEach(t => {
      const statusLbl   = TASK_STATUS_LBL[t.task_status]   || t.task_status || '-';
      const statusColor = TASK_STATUS_COLOR[t.task_status]  || '#C6C6C6';
      const dateStr = t.last_ins_date || t.planned_date || t.work_date || '-';
      // findings_list 첫 번째 항목
      const firstFinding = t.findings_list ? t.findings_list.split('||')[0] : '';
      const inspectors = t.inspector_names ? [...new Set(t.inspector_names.split(','))].join(', ') : '-';

      html += `
      <div class="rounded-xl p-3 cursor-pointer transition-all hover:shadow-md"
           style="background:white;border:1.5px solid #FF349E"
           onclick="this.closest('.modal-overlay').remove(); showTaskDetail(${t.task_id})">
        <div class="flex items-start justify-between gap-3">
          <div class="flex-1 min-w-0">
            <!-- 작업명 + 상태 -->
            <div class="flex items-center gap-2 flex-wrap mb-1">
              <span class="inline-flex items-center justify-center min-w-[22px] h-5 px-1.5 rounded-full text-xs font-black text-white flex-shrink-0"
                style="background:#D70072">${t.poor_count}</span>
              <span class="font-bold text-sm text-gray-900 truncate">${t.task_title || '(작업명 없음)'}</span>
              ${t.task_number ? `<span class="text-xs text-gray-400">[${t.task_number}]</span>` : ''}
            </div>
            <!-- 상태 + 날짜 -->
            <div class="flex items-center gap-2 flex-wrap">
              <span class="text-xs px-2 py-0.5 rounded-full font-bold text-white" style="background:${statusColor}">${statusLbl}</span>
              ${t.task_location ? `<span class="text-xs text-gray-400"><i class="fas fa-map-marker-alt mr-0.5"></i>${t.task_location}</span>` : ''}
              <span class="text-xs text-gray-400"><i class="fas fa-calendar mr-0.5"></i>최근 점검: ${dateStr}</span>
            </div>
            <!-- 점검 내용 -->
            ${firstFinding ? `<div class="text-xs text-gray-500 mt-1.5 line-clamp-1"><i class="fas fa-clipboard mr-1 text-gray-300"></i>${firstFinding}</div>` : ''}
            <div class="text-xs text-gray-400 mt-1"><i class="fas fa-user mr-1 text-gray-300"></i>점검자: ${inspectors}</div>
          </div>
          <div class="flex-shrink-0 text-gray-300 text-sm mt-1">
            <i class="fas fa-chevron-right"></i>
          </div>
        </div>
      </div>`;
    });

    html += `</div>
    <p class="text-xs text-center text-gray-400 mt-4">
      <i class="fas fa-hand-pointer mr-1"></i>항목 클릭 시 작업 상세 페이지로 이동합니다.
    </p>`;

    body.innerHTML = html;
  } catch(e) {
    const body = document.getElementById('poorTaskModal_body');
    if (body) body.innerHTML = `<p class="text-red-500 text-sm p-4">로드 실패: ${e.message}</p>`;
  }
}

async function showUserInspectionHistory(userId, userName) {
  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
  <div class="modal" style="max-width:560px">
    <div class="modal-header">
      <h3 class="font-bold text-lg">
        <i class="fas fa-clipboard-check mr-2" style="color:#D70072"></i>${userName} 점검 이력
      </h3>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-gray-400 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body" id="insHistModal_body">
      <div class="text-center py-8 text-gray-400"><i class="fas fa-spinner fa-spin text-2xl"></i><p class="mt-2 text-sm">불러오는 중...</p></div>
    </div>
  </div>`;
  document.body.appendChild(modal);

  try {
    const res = await API.get(`/inspections/worker-history/${userId}`);
    const records = res.data || [];
    const body = document.getElementById('insHistModal_body');
    if (!body) return;

    if (records.length === 0) {
      body.innerHTML = `<div class="text-center py-10 text-gray-400"><i class="fas fa-clipboard-check text-4xl mb-3 block opacity-30"></i><p class="text-sm">불량·우수 점검 기록이 없습니다.</p></div>`;
      return;
    }

    const poor   = records.filter(r => r.result_type === '불량');
    const excel  = records.filter(r => r.result_type === '우수');

    function makeCard(r) {
      const isPoor = r.result_type === '불량';
      const color  = isPoor ? '#D70072' : '#685182';
      const bg     = isPoor ? '#FDE8F3' : '#F5F0F8';
      const icon   = isPoor ? 'fa-exclamation-triangle' : 'fa-star';
      return `
      <div class="rounded-xl p-3 mb-2" style="background:${bg};border:1px solid ${color}33">
        <div class="flex items-start gap-3">
          <span class="inline-flex items-center justify-center w-8 h-8 rounded-full text-white flex-shrink-0 text-xs font-bold" style="background:${color}">
            <i class="fas ${icon}"></i>
          </span>
          <div class="flex-1 min-w-0">
            <div class="flex items-center gap-2 flex-wrap">
              <span class="text-xs font-bold px-2 py-0.5 rounded-full text-white" style="background:${color}">${r.result_type}</span>
              <span class="text-xs text-gray-500">${r.inspection_date_only || r.recorded_at?.slice(0,10) || '-'}</span>
              ${r.task_title ? `<span class="text-xs text-blue-600 font-medium truncate"><i class="fas fa-hammer mr-0.5"></i>${r.task_number ? '['+r.task_number+'] ':''  }${r.task_title}</span>` : ''}
            </div>
            <div class="text-xs text-gray-600 mt-1"><i class="fas fa-map-marker-alt mr-1 text-gray-400"></i>${r.location || '-'}</div>
            ${r.findings ? `<div class="text-xs text-gray-500 mt-1 line-clamp-2">${r.findings}</div>` : ''}
            <div class="text-xs text-gray-400 mt-1">점검자: ${r.inspector_name || '-'}</div>
          </div>
        </div>
      </div>`;
    }

    // 안전점수 계산: 우수×+5, 불량×-10
    const safetyScore = excel.length * 5 + poor.length * (-10);
    const scoreColor = safetyScore > 0 ? '#685182' : safetyScore === 0 ? '#D70072' : '#D70072';
    const scoreBg    = safetyScore > 0 ? '#F5F0F8'  : safetyScore === 0 ? '#FDE8F3' : '#FDE8F3';

    let html = '';
    // 요약 배지
    html += `<div class="flex gap-2 mb-4">
      <div class="flex-1 rounded-xl p-3 text-center" style="background:#FDE8F3;border:1px solid #D7007233">
        <div class="text-2xl font-black" style="color:#D70072">${poor.length}</div>
        <div class="text-xs font-bold text-gray-500 mt-1"><i class="fas fa-exclamation-triangle mr-1"></i>불량</div>
      </div>
      <div class="flex-1 rounded-xl p-3 text-center" style="background:#F5F0F8;border:1px solid #68518233">
        <div class="text-2xl font-black" style="color:#685182">${excel.length}</div>
        <div class="text-xs font-bold text-gray-500 mt-1"><i class="fas fa-star mr-1"></i>우수</div>
      </div>
      <div class="flex-1 rounded-xl p-3 text-center" style="background:#F5F0F8;border:1px solid #D8D0DC">
        <div class="text-2xl font-black text-gray-700">${records.length}</div>
        <div class="text-xs font-bold text-gray-500 mt-1"><i class="fas fa-list mr-1"></i>전체</div>
      </div>
      <div class="flex-1 rounded-xl p-3 text-center" style="background:${scoreBg};border:1px solid ${scoreColor}33">
        <div class="text-2xl font-black" style="color:${scoreColor}">${safetyScore > 0 ? '+' : ''}${safetyScore}</div>
        <div class="text-xs font-bold text-gray-500 mt-1"><i class="fas fa-shield-alt mr-1"></i>안전점수</div>
      </div>
    </div>
    <div class="text-xs text-gray-400 text-right mb-3" style="margin-top:-8px">우수×+5점 · 불량×-10점</div>`;

    if (poor.length) {
      html += `<div class="text-xs font-black text-red-600 mb-2 mt-3"><i class="fas fa-exclamation-triangle mr-1"></i>불량 기록 (${poor.length}건)</div>`;
      html += poor.map(makeCard).join('');
    }
    if (excel.length) {
      html += `<div class="text-xs font-black text-green-600 mb-2 mt-3"><i class="fas fa-star mr-1"></i>우수 기록 (${excel.length}건)</div>`;
      html += excel.map(makeCard).join('');
    }

    body.innerHTML = html;

    // 버튼 배지 업데이트 (불량 있으면 빨간 뱃지, 우수만 있으면 초록, 없으면 기본)
    const btn = document.getElementById(`insHistBtn_${userId}`);
    if (btn) {
      if (poor.length > 0) {
        btn.style.background = '#FDE8F3'; btn.style.color = '#D70072'; btn.style.borderColor = '#D70072';
        btn.title = `점검 이력 (불량 ${poor.length}건)`;
      } else if (excel.length > 0) {
        btn.style.background = '#F5F0F8'; btn.style.color = '#685182'; btn.style.borderColor = '#685182';
        btn.title = `점검 이력 (우수 ${excel.length}건)`;
      }
    }
  } catch(e) {
    const body = document.getElementById('insHistModal_body');
    if (body) body.innerHTML = `<p class="text-red-500 text-sm p-4">로드 실패: ${e.message}</p>`;
  }
}

function switchUserTab(tabKey, el) {
  document.querySelectorAll('#userTeamTabBar .tab-item').forEach(t=>t.classList.remove('active'));
  el.classList.add('active');
  document.querySelectorAll('[id^="userTab-"]').forEach(p=>p.classList.add('hidden'));
  const panel = document.getElementById(`userTab-${tabKey}`);
  if (panel) panel.classList.remove('hidden');
}

// 인원 엑셀(CSV) 다운로드
function downloadUsersCSV() {
  const headers = ['이름','아이디','연락처','역할','부서','직책','소속(회사)','팀구분'];
  const rows = _userListData.map(u => [
    u.name||'', u.username||'', u.phone||'', getRoleDisplay(u.role, u.position, u.sub_role).label||'',
    u.department||'', u.position||'', u.company||'',
  ]);
  downloadCSV(`사용자현황_${kstDateStr()}.csv`, headers, rows);
}

// QR 체크박스 전체 선택/해제 (테이블 내)
function toggleAllQrChecks(masterCb, tableId) {
  const table = document.getElementById(tableId);
  if (!table) return;
  table.querySelectorAll('.user-qr-check').forEach(cb => { cb.checked = masterCb.checked; });
  updateQrBulkCount();
}

// 선택된 QR 수 카운트 표시 (헤더 버튼 레이블 업데이트)
function updateQrBulkCount() {
  const checked = document.querySelectorAll('.user-qr-check:checked');
  const btn = document.querySelector('button[onclick="printQrBulk()"]');
  if (btn) {
    btn.innerHTML = checked.length > 0
      ? `<i class="fas fa-qrcode mr-1"></i>QR 일괄 인쇄 <span style="background:#D70072;color:white;border-radius:999px;padding:0 6px;font-size:11px;margin-left:4px">${checked.length}</span>`
      : `<i class="fas fa-qrcode mr-1"></i>QR 일괄 인쇄`;
  }
}

// 체크된 인원 QR 카드 일괄 인쇄
async function printQrBulk() {
  // QRCode 라이브러리 로드 보장
  if (!window.QRCode) {
    await new Promise(resolve => {
      const s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/qrcodejs@1.0.0/qrcode.min.js';
      s.onload = resolve;
      document.head.appendChild(s);
    });
  }

  const checked = [...document.querySelectorAll('.user-qr-check:checked')];
  if (!checked.length) {
    toast('인쇄할 인원을 체크박스로 선택하세요.', 'error');
    return;
  }

  const origin = window.location.origin;
  // 각 인원의 QR 데이터 수집
  const items = checked.map(cb => ({
    id: cb.value,
    name: cb.dataset.name || ('사용자 ' + cb.value),
    team: cb.dataset.team || '',
    position: cb.dataset.position || '',
    url: origin + '/qr/' + cb.value
  }));

  // QR 이미지를 data URL로 생성 (canvas 기반)
  async function makeQrDataUrl(url) {
    return new Promise(resolve => {
      const div = document.createElement('div');
      div.style.cssText = 'position:fixed;left:-9999px;top:-9999px;width:160px;height:160px';
      document.body.appendChild(div);
      try {
        const qr = new QRCode(div, {
          text: url, width: 150, height: 150,
          colorDark: '#4E3A63', colorLight: '#FFFFFF',
          correctLevel: QRCode.CorrectLevel.H
        });
        setTimeout(() => {
          const img = div.querySelector('img') || div.querySelector('canvas');
          const src = img ? (img.toDataURL ? img.toDataURL() : img.src) : '';
          document.body.removeChild(div);
          resolve(src);
        }, 300);
      } catch(e) {
        document.body.removeChild(div);
        resolve('');
      }
    });
  }

  toast(`QR 카드 ${items.length}장 생성 중...`, 'info');

  // QR 이미지 병렬 생성
  const qrImages = await Promise.all(items.map(item => makeQrDataUrl(item.url)));

  const win = window.open('', '_blank');
  win.document.write(`<!DOCTYPE html>
<html lang="ko"><head>
<meta charset="UTF-8">
<title>QR 안전카드 일괄 인쇄 (${items.length}명)</title>
<style>
  /* ── 기본 리셋 ── */
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: #D8D0DC; font-family: 'LG Smart KR', 'Apple SD Gothic Neo', 'Malgun Gothic', sans-serif; }

  /* ── 화면 미리보기 ── */
  .page {
    width: 210mm;
    min-height: 297mm;
    margin: 12px auto;
    background: white;
    padding: 5mm;
    box-shadow: 0 2px 12px rgba(0,0,0,0.15);
  }
  .page-title {
    text-align: center;
    font-size: 9px;
    color: #C6C6C6;
    margin-bottom: 2mm;
    letter-spacing: 0.3px;
  }

  /* ── 20칸 그리드: 4열 × 5행 ── */
  /* A4 가용폭(margin 5mm×2) = 200mm, 카드 4개 + 간격 3개(1.5mm) */
  /* 카드폭 = (200 - 3×1.5mm) / 4 = 48.9mm */
  .grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 1.5mm;
  }

  /* ── 카드 ── */
  /* A4 가용높이(margin 5mm×2) = 287mm, 카드 5행 + 간격 4개(1.5mm) + 타이틀 5mm */
  /* 카드높이 = (287 - 5 - 4×1.5mm) / 5 = 55.2mm */
  .qr-card {
    width: 100%;
    height: 55mm;
    background: white;
    border-radius: 3px;
    overflow: hidden;
    border: 1px solid #D8D0DC;
    display: flex;
    flex-direction: column;
    page-break-inside: avoid;
    break-inside: avoid;
  }

  /* 헤더 */
  .card-header {
    background: linear-gradient(135deg, #D70072, #685182);
    padding: 1.5px 5px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
  }
  .brand-logo { font-size: 6.5px; font-weight: 900; color: white; letter-spacing: -0.2px; }
  .safety-icon { font-size: 9px; }

  /* 바디: QR 최대화 + 이름 하단 배치 */
  .card-body {
    flex: 1;
    padding: 2px 3px 2px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-between;
    gap: 1px;
  }

  /* QR: 가능한 최대 크기 */
  .qr-wrap {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    width: 100%;
  }
  .qr-wrap img {
    width: 34mm;
    height: 34mm;
    display: block;
    image-rendering: pixelated;
  }

  /* 인적사항: 이름 최대, 직위/팀 70% */
  .person-info { text-align: center; width: 100%; line-height: 1.2; }
  .person-name { font-size: 11px; font-weight: 900; color: #4E3A63; letter-spacing: -0.5px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .person-sub  { font-size: 7.7px; color: #4E3A63; font-weight: 600; margin-top: 0.5px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .person-sub span.team  { color: #685182; }
  .person-sub span.pos   { color: #C6C6C6; }

  /* 푸터 */
  .brand {
    text-align: center;
    font-size: 5.5px;
    color: #C6C6C6;
    padding: 1px;
    border-top: 1px solid #D8D0DC;
    flex-shrink: 0;
    letter-spacing: 0.2px;
  }

  /* ── 인쇄 전용 ── */
  @media print {
    @page { size: A4 portrait; margin: 5mm; }
    body { background: white; }
    .page { margin: 0; padding: 0; box-shadow: none; width: 100%; min-height: unset; }
    .page-title { display: none; }
    .grid { gap: 1.5mm; }
    .page { page-break-after: always; }
    .page:last-child { page-break-after: avoid; }
    .qr-card { border: 0.5px solid #C6C6C6; }
    .print-btn { display: none; }
  }
</style>
</head><body>
${(() => {
  const PER_PAGE = 20;
  const pages = [];
  for (let p = 0; p < items.length; p += PER_PAGE) {
    const slice = items.slice(p, p + PER_PAGE);
    const pageNum = Math.floor(p / PER_PAGE) + 1;
    const totalPages = Math.ceil(items.length / PER_PAGE);
    pages.push(`
<div class="page">
  <p class="page-title">⛑ Safety NOTE — QR 안전카드 (${items.length}명) · ${pageNum}/${totalPages}페이지 · 4×5=20장</p>
  <div class="grid">${slice.map((item, si) => {
      const i = p + si;
      const subParts = [
        item.team     ? `<span class="team">👥 ${item.team}</span>`    : '',
        item.position ? `<span class="pos">${item.position}</span>`    : '',
      ].filter(Boolean).join('<span style="color:#C6C6C6"> · </span>');
      return `
    <div class="qr-card">
      <div class="card-header">
        <div class="brand-logo">⛑ Safety NOTE</div>
        <div class="safety-icon">🦺</div>
      </div>
      <div class="card-body">
        <div class="qr-wrap">
          ${qrImages[i]
            ? `<img src="${qrImages[i]}" alt="QR">`
            : `<div style="width:34mm;height:34mm;display:flex;align-items:center;justify-content:center;background:#F5F0F8;border-radius:3px;font-size:7px;color:#C6C6C6">QR 오류</div>`}
        </div>
        <div class="person-info">
          <div class="person-name">${item.name}</div>
          ${subParts ? `<div class="person-sub">${subParts}</div>` : ''}
        </div>
      </div>
      <div class="brand">Safety NOTE</div>
    </div>`;
    }).join('')}</div>
</div>`);
  }
  return pages.join('');
})()}
<div class="print-btn" style="text-align:center;margin:10px 0 20px">
  <button onclick="window.print()" style="padding:8px 24px;background:linear-gradient(135deg,#D70072,#685182);color:white;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer">🖨️ 인쇄</button>
</div>
<script>setTimeout(() => window.print(), 700);<\/script>
</body></html>`);
  win.document.close();
}

// 팀 수정 모달 (사용자현황 팀탭에서 호출)
async function showEditTeamModal(teamId, currentName, currentDesc) {
  const modal = document.createElement('div');
  modal.className = 'modal-overlay modal-sm';
  modal.innerHTML = `
  <div class="modal" style="max-width:420px">
    <div class="modal-header" style="background:linear-gradient(135deg,#685182,#D70072);border-radius:20px 20px 0 0;border-bottom:none;padding:18px 24px">
      <h3 class="font-black text-white text-base"><i class="fas fa-edit mr-2"></i>팀 정보 수정</h3>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-white opacity-70 hover:opacity-100 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">팀명 <span class="text-red-500">*</span></label>
        <input id="etName" class="form-control" value="${currentName}">
      </div>
      <div class="form-group">
        <label class="form-label">설명</label>
        <input id="etDesc" class="form-control" value="${currentDesc}">
      </div>
    </div>
    <div class="modal-footer">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button onclick="updateTeam(${teamId})" class="btn btn-primary"><i class="fas fa-save"></i> 저장</button>
    </div>
  </div>`;
  document.body.appendChild(modal);
}

async function updateTeam(teamId) {
  const name = document.getElementById('etName')?.value.trim();
  const desc = document.getElementById('etDesc')?.value.trim()||'';
  if (!name) { toast('팀명을 입력하세요.', 'error'); return; }
  try {
    await API.put(`/teams/${teamId}`, { name, description: desc });
    toast('팀 정보가 수정되었습니다.');
    document.querySelector('.modal-overlay')?.remove();
    renderUsersPage(document.getElementById('page-content'));
  } catch(e) { toast(e.response?.data?.error||'수정 실패','error'); }
}

// ─── 현장팀관리 페이지 ──────────────────────────────────────────────────────
async function renderTeamsPage(container) {
  try {
    const res = await API.get('/teams');
    const teams = res.data;

    container.innerHTML = `
    <div class="page-container">
      <!-- 헤더 -->
      <div class="flex items-center justify-between mb-5">
        <div>
          <h2 class="text-xl font-black text-gray-900" style="border-left:4px solid #685182;padding-left:10px">현장팀관리</h2>
          <p class="text-sm text-gray-400 mt-1 pl-4">팀장 배정 시 해당 팀원 전체가 작업에 자동 배정됩니다</p>
        </div>
        ${currentUser.role === 'admin' ? `<button onclick="showCreateTeamModal()" class="btn btn-success">
          <i class="fas fa-plus"></i> 팀 추가
        </button>` : ''}
      </div>

      <!-- 팀 카드 -->
      <div class="space-y-4">
        ${teams.length === 0 ? `<div class="card text-center py-12 text-gray-400">
          <i class="fas fa-people-group text-4xl mb-3 block opacity-30"></i>
          <p>등록된 팀이 없습니다.</p>
        </div>` : teams.map(team => `
        <div class="card" style="border-left:4px solid #685182">
          <div class="flex items-start justify-between flex-wrap gap-3">
            <div class="flex items-center gap-3">
              <div>
                <div class="font-black text-lg text-gray-900">${team.name}</div>
                <div class="text-sm text-gray-500">${team.description || ''}</div>
                <div class="flex items-center gap-2 mt-1">
                  <span class="badge" style="background:#EDE7F6;color:#685182;font-size:11px">
                    <i class="fas fa-users mr-1"></i>팀원 ${team.member_count}명
                  </span>
                  ${team.leader
                    ? `<span class="badge" style="background:#FDE8F3;color:#D70072;font-size:11px"><i class="fas fa-star mr-1"></i>팀장: ${team.leader.name}</span>`
                    : `<span class="badge" style="background:#EDE7F6;color:#4E3A63;font-size:11px"><i class="fas fa-exclamation-triangle mr-1"></i>팀장 미지정</span>`}
                </div>
              </div>
            </div>
            ${currentUser.role === 'admin' ? `
            <div class="flex gap-2">
              <button onclick="showTeamMembersModal(${team.id})" class="btn btn-outline btn-sm">
                <i class="fas fa-users-cog"></i> 팀원 관리
              </button>
              <button onclick="deleteTeam(${team.id}, '${team.name}')" class="btn btn-danger btn-sm">
                <i class="fas fa-trash"></i>
              </button>
            </div>` : ''}
          </div>

          <!-- 팀원 목록 -->
          <div class="mt-4 pt-4" style="border-top:1px solid #F5F0F8">
            <div class="text-xs font-bold text-gray-500 mb-2 uppercase tracking-wide">팀원 구성</div>
            <div class="flex flex-wrap gap-2">
              ${(team.members||[]).map(m => `
              <span class="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold"
                style="background:${m.is_leader ? '#FDE8F3' : '#F5F0F8'};color:${m.is_leader ? '#D70072' : '#685182'}">
                ${m.is_leader ? '<i class="fas fa-star text-xs"></i>' : '<i class="fas fa-user text-xs"></i>'}
                ${m.name}
                ${m.is_leader ? '<span class="text-xs opacity-70">(팀장)</span>' : ''}
              </span>`).join('') || '<span class="text-gray-400 text-sm">팀원 없음</span>'}
            </div>
          </div>
        </div>
        `).join('')}
      </div>
    </div>`;
  } catch(e) {
    container.innerHTML = `<p class="text-red-500 p-4">로드 실패: ${e.message}</p>`;
  }
}

// 팀 생성 모달
async function showCreateTeamModal() {
  const usersRes = await API.get('/users');
  const allUsers = usersRes.data;
  // 근로자만 팀원 후보
  const workerUsers = allUsers.filter(u => u.role === 'worker');
  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
  <div class="modal" style="max-width:540px">
    <div class="modal-header" style="background:linear-gradient(135deg,#685182,#D70072);border-radius:20px 20px 0 0;border-bottom:none;padding:18px 24px">
      <h3 class="font-black text-white text-base"><i class="fas fa-plus-circle mr-2"></i>새 팀 만들기</h3>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-white opacity-70 hover:opacity-100 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">팀명 <span class="text-red-500">*</span></label>
        <input id="ctName" class="form-control" placeholder="예: 외선2팀, 접속2팀" value="">
      </div>
      <div class="form-group">
        <label class="form-label">설명</label>
        <input id="ctDesc" class="form-control" placeholder="팀 설명 (선택)">
      </div>
      <div class="form-group">
        <label class="form-label">팀원 선택 <span class="text-xs text-gray-400">(근로자만 표시)</span></label>
        <div class="max-h-56 overflow-y-auto border border-gray-200 rounded-xl p-2 space-y-1">
          ${workerUsers.map(u => `
          <label class="custom-check p-2 hover:bg-gray-50 rounded-lg cursor-pointer flex items-center gap-2"
                 onclick="updateCtLeaderSelect()">
            <input type="checkbox" name="ctMember" value="${u.id}" class="w-4 h-4" onchange="updateCtLeaderSelect()">
            <span class="text-sm font-bold text-gray-800">${u.name}</span>
            <span class="text-xs px-1.5 py-0.5 rounded font-medium" style="background:#FDE8F3;color:#A8005A">${u.position || '근로자'}</span>
          </label>`).join('')}
          ${workerUsers.length === 0 ? `<p class="text-sm text-gray-400 p-3 text-center">등록된 근로자가 없습니다.</p>` : ''}
        </div>
      </div>
      <div class="form-group">
        <label class="form-label"><i class="fas fa-star mr-1" style="color:#D70072"></i>팀장 지정 <span class="text-xs text-gray-400">(체크된 팀원 중 선택)</span></label>
        <select id="ctLeader" class="form-control">
          <option value="">-- 팀장 선택 --</option>
        </select>
      </div>
    </div>
    <div class="modal-footer">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button onclick="createTeam()" class="btn btn-success"><i class="fas fa-check"></i> 팀 생성</button>
    </div>
  </div>`;
  document.body.appendChild(modal);
}

// 팀 생성 모달: 체크된 팀원으로 팀장 select 갱신
function updateCtLeaderSelect() {
  setTimeout(() => {
    const checkedEls = [...document.querySelectorAll('input[name="ctMember"]:checked')];
    const leaderSel  = document.getElementById('ctLeader');
    if (!leaderSel) return;
    const prevLeader = leaderSel.value;
    leaderSel.innerHTML = '<option value="">-- 팀장 선택 --</option>' +
      checkedEls.map(el => {
        const label = el.closest('label');
        const name  = label?.querySelector('.text-sm.font-bold')?.textContent?.trim() || '';
        const pos   = label?.querySelector('.text-xs.px-1\\.5')?.textContent?.trim() || '';
        const val   = el.value;
        const sel   = val === prevLeader ? 'selected' : '';
        return `<option value="${val}" ${sel}>${name}${pos ? ' · ' + pos : ''}</option>`;
      }).join('');
  }, 10);
}

async function createTeam() {
  const name = document.getElementById('ctName').value.trim();
  if (!name) { toast('팀명을 입력하세요.', 'error'); return; }
  try {
    const res = await API.post('/teams', {
      name, description: document.getElementById('ctDesc').value.trim()
    });
    const teamId = res.data.id;
    const memberIds = [...document.querySelectorAll('input[name="ctMember"]:checked')].map(el=>parseInt(el.value));
    const leaderId = parseInt(document.getElementById('ctLeader').value) || null;
    if (memberIds.length > 0 || leaderId) {
      const allIds = leaderId && !memberIds.includes(leaderId) ? [...memberIds, leaderId] : memberIds;
      await API.put(`/teams/${teamId}/members`, { user_ids: allIds, leader_id: leaderId });
    }
    toast(`${name} 팀이 생성되었습니다.`);
    document.querySelector('.modal-overlay')?.remove();
    renderTeamsPage(document.getElementById('page-content'));
  } catch(e) {
    toast(e.response?.data?.error || '생성 실패', 'error');
  }
}

// 팀원 관리 모달
async function showTeamMembersModal(teamId) {
  const [teamRes, usersRes] = await Promise.all([API.get(`/teams/${teamId}`), API.get('/users')]);
  const team = teamRes.data;
  const allUsers = usersRes.data;
  // 근로자만 필터
  const workerUsers = allUsers.filter(u => u.role === 'worker');
  const currentMemberIds = (team.members||[]).filter(m => {
    const u = allUsers.find(u => u.id === m.id);
    return u && u.role === 'worker';
  }).map(m => m.id);

  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
  <div class="modal" style="max-width:580px">
    <div class="modal-header" style="background:linear-gradient(135deg,#685182,#D70072);border-radius:20px 20px 0 0;border-bottom:none;padding:18px 24px">
      <h3 class="font-black text-white text-base"><i class="fas fa-users-cog mr-2"></i>${team.name} 팀원 관리</h3>
      <button onclick="this.closest('.modal-overlay').remove()" class="text-white opacity-70 hover:opacity-100 text-xl"><i class="fas fa-times"></i></button>
    </div>
    <div class="modal-body">
      <!-- 안내 -->
      <div class="mb-3 p-2.5 rounded-xl text-xs" style="background:#EDE7F6;color:#685182">
        <i class="fas fa-info-circle mr-1"></i>근로자만 팀원으로 선택할 수 있습니다. 체크 후 팀장을 지정하세요.
      </div>
      <!-- 팀원 선택 -->
      <div class="form-group">
        <label class="form-label">팀원 선택 <span class="text-xs text-gray-400">(근로자만 표시)</span></label>
        <div id="tmMemberList" class="max-h-64 overflow-y-auto border border-gray-200 rounded-xl p-2 space-y-1">
          ${workerUsers.map(u => `
          <label class="custom-check p-2 hover:bg-gray-50 rounded-lg cursor-pointer flex items-center gap-2"
                 onclick="updateTmLeaderSelect()">
            <input type="checkbox" name="tmMember" value="${u.id}"
                   ${currentMemberIds.includes(u.id)?'checked':''}
                   class="w-4 h-4" onchange="updateTmLeaderSelect()">
            <span class="text-sm font-bold text-gray-800">${u.name}</span>
            <span class="text-xs px-1.5 py-0.5 rounded font-medium ml-1"
                  style="background:#FDE8F3;color:#A8005A">${u.position || '근로자'}</span>
            ${u.id === team.leader?.id ? `<span class="badge text-xs ml-auto" style="background:#FDE8F3;color:#D70072"><i class="fas fa-star mr-0.5"></i>현 팀장</span>` : ''}
          </label>`).join('')}
          ${workerUsers.length === 0 ? `<p class="text-sm text-gray-400 p-3 text-center">등록된 근로자가 없습니다.</p>` : ''}
        </div>
      </div>
      <!-- 팀장 지정 (체크된 팀원 중에서 선택) -->
      <div class="form-group">
        <label class="form-label"><i class="fas fa-star mr-1" style="color:#D70072"></i>팀장 지정 <span class="text-xs text-gray-400">(위에서 체크된 팀원 중 선택)</span></label>
        <select id="tmLeader" class="form-control">
          <option value="">-- 팀장 선택 --</option>
          ${currentMemberIds.map(mid => {
            const u = workerUsers.find(u => u.id === mid);
            if (!u) return '';
            return `<option value="${u.id}" ${u.id === team.leader?.id ? 'selected' : ''}>${u.name}${u.position ? ' · ' + u.position : ''}</option>`;
          }).join('')}
        </select>
      </div>
    </div>
    <div class="modal-footer">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button onclick="saveTeamMembers(${teamId})" class="btn btn-success"><i class="fas fa-save"></i> 저장</button>
    </div>
  </div>`;
  document.body.appendChild(modal);
}

// 팀원 체크박스 변경 시 팀장 select 동적 업데이트
function updateTmLeaderSelect() {
  // 약간의 딜레이로 체크박스 상태 변경 후 실행
  setTimeout(() => {
    const checkedEls = [...document.querySelectorAll('input[name="tmMember"]:checked')];
    const leaderSel  = document.getElementById('tmLeader');
    if (!leaderSel) return;
    const prevLeader = leaderSel.value;
    leaderSel.innerHTML = '<option value="">-- 팀장 선택 --</option>' +
      checkedEls.map(el => {
        // 체크박스의 label 안에 있는 이름과 직위 읽기
        const label = el.closest('label');
        const name  = label?.querySelector('.text-sm.font-bold')?.textContent?.trim() || '';
        const pos   = label?.querySelector('.text-xs.px-1\\.5')?.textContent?.trim() || '';
        const val   = el.value;
        const sel   = val === prevLeader ? 'selected' : '';
        return `<option value="${val}" ${sel}>${name}${pos ? ' · ' + pos : ''}</option>`;
      }).join('');
  }, 10);
}

async function saveTeamMembers(teamId) {
  const memberIds = [...document.querySelectorAll('input[name="tmMember"]:checked')].map(el=>parseInt(el.value));
  const leaderId = parseInt(document.getElementById('tmLeader').value) || null;
  const allIds = leaderId && !memberIds.includes(leaderId) ? [...memberIds, leaderId] : memberIds;
  try {
    await API.put(`/teams/${teamId}/members`, { user_ids: allIds, leader_id: leaderId });
    toast('팀원 구성이 저장되었습니다.');
    document.querySelector('.modal-overlay')?.remove();
    renderTeamsPage(document.getElementById('page-content'));
  } catch(e) {
    toast(e.response?.data?.error || '저장 실패', 'error');
  }
}

function deleteTeam(teamId, teamName) {
  const m = document.createElement('div');
  m.className = 'modal-overlay modal-sm';
  m.innerHTML = `
  <div class="modal" style="max-width:360px">
    <div class="modal-header" style="background:linear-gradient(135deg,#4E3A63,#D70072);color:white">
      <div class="flex items-center gap-2">
        <i class="fas fa-people-group text-lg"></i>
        <h3 class="font-bold">팀 삭제</h3>
      </div>
      <button onclick="this.closest('.modal-overlay').remove()" style="background:none;border:none;color:white;font-size:20px;cursor:pointer;opacity:0.8">×</button>
    </div>
    <div class="modal-body">
      <div style="background:#FDE8F3;border:1.5px solid #FDE8F3;border-radius:12px;padding:14px 16px;color:#A8005A;font-size:14px;line-height:1.6">
        <i class="fas fa-exclamation-triangle mr-2 text-red-400"></i>
        <strong>"${teamName}"</strong> 팀을 삭제하시겠습니까?<br>
        <span style="font-size:12px;opacity:0.8;display:block;margin-top:4px">소속 팀원의 팀 배정이 해제됩니다.</span>
      </div>
    </div>
    <div class="modal-footer" style="display:flex;gap:8px;justify-content:flex-end">
      <button onclick="this.closest('.modal-overlay').remove()" class="btn btn-outline">취소</button>
      <button id="doDeleteTeamBtn" class="btn btn-danger font-bold"><i class="fas fa-trash mr-1"></i>팀 삭제</button>
    </div>
  </div>`;
  document.body.appendChild(m);
  m.querySelector('#doDeleteTeamBtn').onclick = async () => {
    m.remove();
    try {
      await API.delete(`/teams/${teamId}`);
      toast(`${teamName} 팀이 삭제되었습니다.`);
      renderTeamsPage(document.getElementById('page-content'));
    } catch(e) {
      toast(e.response?.data?.error || '삭제 실패', 'error');
    }
  };
}

