// ═══════════════════════════════════════════════════════════════
// 사용자 일괄 등록 (엑셀 업로드)
// ═══════════════════════════════════════════════════════════════

// 엑셀 컬럼 정의 (순서 = 템플릿 열 순서)
const BULK_USER_COLUMNS = [
  { key:'username',          label:'아이디*',         required:true,  example:'hong123' },
  { key:'password',          label:'비밀번호*',        required:true,  example:'1234' },
  { key:'name',              label:'이름*',            required:true,  example:'홍길동' },
  { key:'role_label',        label:'역할*',            required:true,  example:'근로자',       note:'근로자/안전관리자/공무/현장대리인/CEO/LGU+/시스템관리자' },
  { key:'company',           label:'소속(회사명)',     required:false, example:'(주)현대건설' },
  { key:'department',        label:'부서',             required:false, example:'토목팀' },
  { key:'position',          label:'직책',             required:false, example:'대리',         note:'사원/대리/차장/과장/부장/이사/상무/전무/대표이사 또는 역할식별자' },
  { key:'phone',             label:'연락처',           required:false, example:'010-1234-5678' },
  { key:'blood_type',        label:'혈액형',           required:false, example:'A+',           note:'A+/A-/B+/B-/O+/O-/AB+/AB-' },
  { key:'emergency_contact', label:'긴급연락처',       required:false, example:'홍아버지/부/010-9999-8888' },
];

// UI 역할 레이블 → DB role + sub_role 변환 테이블
const BULK_ROLE_MAP = {
  '근로자':     { role:'worker',     sub_role:'' },
  '안전관리자': { role:'supervisor', sub_role:'safety' },
  '공무':       { role:'supervisor', sub_role:'engineer' },
  '현장대리인': { role:'supervisor', sub_role:'site_rep' },
  'CEO':        { role:'admin',      sub_role:'ceo' },
  'LGU+':       { role:'lgu_plus',   sub_role:'' },         // [FEAT-048] 단일 역할
  '시스템관리자':{ role:'admin',     sub_role:'sysadmin' },
};

// 직위 레이블 → position 문자열 (입력값 그대로 사용, 역할 식별자 우선)
function bulkResolvePosition(roleLabel, positionVal) {
  const roleInfo = BULK_ROLE_MAP[roleLabel] || {};
  const sub = roleInfo.sub_role || '';
  const pos = (positionVal || '').trim();
  // 역할 식별자(첫 옵션) 강제 세팅 규칙 (개별 등록과 동일)
  if (sub === 'lgu_plus')  return 'LGU+';
  if (sub === 'sysadmin')  return '시스템관리자';
  if (pos) return pos;
  // position 미입력 시 역할 식별자 기본값
  if (sub === 'safety')   return '안전관리자';
  if (sub === 'engineer') return '공무';
  if (sub === 'site_rep') return '현장대리인';
  return '';
}

/* ── SheetJS 로드 대기 헬퍼 (최대 8초, 200ms 간격 폴링) ── */
function waitForXLSX(callback) {
  if (typeof XLSX !== 'undefined') { callback(); return; }
  let tries = 0;
  const maxTries = 40; // 200ms × 40 = 8초
  const tid = setInterval(() => {
    tries++;
    if (typeof XLSX !== 'undefined') {
      clearInterval(tid);
      callback();
    } else if (tries >= maxTries) {
      clearInterval(tid);
      toast('엑셀 라이브러리를 불러오지 못했습니다. 페이지를 새로고침 후 다시 시도해주세요.', 'error');
    } else if (tries === 1) {
      toast('엑셀 라이브러리 로딩 중... 잠시 기다려 주세요.', 'info');
    }
  }, 200);
}

/* ── 엑셀 템플릿 다운로드 ── */
function downloadUserBulkTemplate() {
  waitForXLSX(() => {

  const wb = XLSX.utils.book_new();

  // ① 입력 시트
  const headerRow = BULK_USER_COLUMNS.map(c => c.label);
  const exampleRow = BULK_USER_COLUMNS.map(c => c.example || '');
  const ws = XLSX.utils.aoa_to_sheet([headerRow, exampleRow]);

  // 열 너비 자동 조절
  ws['!cols'] = BULK_USER_COLUMNS.map(c => ({ wch: Math.max(c.label.length * 2.5, 14) }));

  // 헤더 행 스타일 (필수 항목 강조)
  BULK_USER_COLUMNS.forEach((col, ci) => {
    const cellRef = XLSX.utils.encode_cell({ r: 0, c: ci });
    if (!ws[cellRef]) return;
    ws[cellRef].s = {
      font:    { bold: true, color: { rgb: col.required ? 'FFFFFF' : '333333' } },
      fill:    { fgColor: { rgb: col.required ? 'D70072' : '685182' } },
      alignment: { horizontal: 'center' },
    };
  });

  XLSX.utils.book_append_sheet(wb, ws, '사용자등록');

  // ② 안내 시트
  const guideData = [
    ['[사용자 일괄 등록 안내]'],
    [''],
    ['항목',      '설명',                                     '예시'],
    ['아이디*',   '로그인에 사용할 고유 아이디 (중복 불가)',   'hong123'],
    ['비밀번호*', '초기 비밀번호',                             '1234'],
    ['이름*',     '실명',                                      '홍길동'],
    ['역할*',     '근로자 / 안전관리자 / 공무 / 현장대리인 / CEO / LGU+ / 시스템관리자 중 택1', '근로자'],
    ['소속(회사명)', '소속 회사명 (선택)',                     '(주)현대건설'],
    ['부서',      '소속 부서명 (선택)',                        '토목팀'],
    ['직책', '사원/대리/차장/과장/부장/이사/상무/전무/대표이사 (선택)', '대리'],
    ['연락처',    '숫자와 하이픈 형식 (선택)',                 '010-1234-5678'],
    ['혈액형',    'A+/A-/B+/B-/O+/O-/AB+/AB- (선택)',        'A+'],
    ['긴급연락처','이름/관계/전화번호 형식 (선택)',             '홍아버지/부/010-9999-8888'],
    [''],
    ['* 표시 항목은 필수 입력입니다.'],
    ['* 2행(예시 행)은 실제 등록 전 삭제하거나 덮어써 주세요.'],
    ['* 아이디가 중복된 행은 등록에서 제외됩니다.'],
  ];
  const wsGuide = XLSX.utils.aoa_to_sheet(guideData);
  wsGuide['!cols'] = [{ wch: 14 }, { wch: 52 }, { wch: 26 }];
  XLSX.utils.book_append_sheet(wb, wsGuide, '작성안내');

  XLSX.writeFile(wb, '사용자_일괄등록_양식.xlsx');
  toast('엑셀 양식을 다운로드했습니다.');
  }); // waitForXLSX
}

