    const BYPASS_OPTS   = ['','해당없음','우회필요','우회중'].map(v=>`<option value="${v}">${v||'우회여부'}</option>`).join('');
    const LOCATION_OPTS = ['','지하','지상','기타'].map(v=>`<option value="${v}">${v||'위치'}</option>`).join('');
    // 작업 케이블정보 전용 옵션
