function _upSwitchTab(tab) {
  const stateEl = document.getElementById('up-active-tab');
  if (stateEl) stateEl.value = tab;
  const cableSection  = document.getElementById('up-cable-section');
  const spliceSection = document.getElementById('up-splice-section');
  const cableBtn      = document.getElementById('up-tab-cable-btn');
  const spliceBtn     = document.getElementById('up-tab-splice-btn');
  if (tab === 'cable') {
    cableSection?.classList.remove('hidden');
    spliceSection?.classList.add('hidden');
    if (cableBtn)  cableBtn.className  = 'flex-1 py-2 text-center transition bg-pink-50 text-pink-700 border-r border-gray-200';
    if (spliceBtn) spliceBtn.className = 'flex-1 py-2 text-center transition text-gray-500 hover:bg-gray-50';
  } else {
    cableSection?.classList.add('hidden');
    spliceSection?.classList.remove('hidden');
    if (spliceBtn) spliceBtn.className = 'flex-1 py-2 text-center transition bg-indigo-50 text-indigo-700';
    if (cableBtn)  cableBtn.className  = 'flex-1 py-2 text-center transition text-gray-500 hover:bg-gray-50 border-r border-gray-200';
  }
}

// ── 외선 공종 추가 ──
async function _upAddCableItem() {
  const labelEl = document.getElementById('up-cable-add-label');
  const priceEl = document.getElementById('up-cable-add-price');
  const label   = (labelEl?.value || '').trim();
  const price   = Number(priceEl?.value) || 0;
  if (!label) { toast('공종명을 입력하세요.', 'error'); return; }
  // item_key: a + 6자리 순번 자동 부여 (기존 키 중 최대값 + 1)
  const tbody = document.getElementById('up-cable-tbody');
  const existingKeys = tbody
    ? [...tbody.querySelectorAll('tr[data-key]')].map(tr => tr.dataset.key).filter(k => /^a\d{6}$/.test(k))
    : [];
  const maxNum = existingKeys.reduce((m, k) => Math.max(m, parseInt(k.slice(1), 10)), 0);
  const item_key = 'a' + String(maxNum + 1).padStart(6, '0');
  try {
    await API.post('/volume-unit-prices', { item_key, item_label: label, unit_price: price });
    toast(`'${label}' 공종이 추가되었습니다.`);
    if (labelEl) labelEl.value = '';
    if (priceEl) priceEl.value = '';
    // 테이블에 즉시 행 추가 — 열 순서: 공종키|공종명|단위|단가|삭제 (FEAT-039 기준)
    const tbody = document.getElementById('up-cable-tbody');
    if (tbody) {
      const tr = document.createElement('tr');
      tr.className = 'border-b border-gray-50 hover:bg-gray-50';
      tr.dataset.key = item_key;
      tr.innerHTML = `
        <td class="px-2 py-1.5" style="width:90px;min-width:80px">
          <span class="text-xs text-gray-400 font-mono">${item_key}</span>
        </td>
        <td class="px-2 py-1.5" style="min-width:120px">
          <input type="text" maxlength="40"
            class="up-cable-label-input w-full border border-transparent rounded-lg px-2 py-1 text-sm text-gray-700 font-medium focus:outline-none focus:border-pink-300 focus:bg-pink-50 hover:border-gray-200 bg-transparent"
            data-key="${item_key}" value="${label.replace(/"/g,'&quot;')}" placeholder="공종명">
        </td>
        <td class="px-2 py-1.5 text-center" style="width:56px;min-width:48px">
          <input type="text" maxlength="10"
            class="up-cable-unit-input w-full border border-transparent rounded-lg px-1 py-1 text-sm text-center text-gray-500 focus:outline-none focus:border-pink-300 focus:bg-pink-50 hover:border-gray-200 bg-transparent"
            data-key="${item_key}" value="식" placeholder="단위">
        </td>
        <td class="px-2 py-1.5 text-right" style="width:120px;min-width:100px">
          <input type="number" min="0" step="100"
            class="up-cable-input w-full border border-gray-200 rounded-lg px-2 py-1 text-right text-sm focus:outline-none focus:border-pink-300"
            data-key="${item_key}" value="${price}">
        </td>
        <td class="px-2 py-1.5 text-center" style="width:36px">
          <button onclick="_upDeleteCableItem('${item_key}','${label}')"
            class="text-gray-300 hover:text-red-500 text-sm transition">
            <i class="fas fa-trash-alt"></i>
          </button>
        </td>`;
      tbody.appendChild(tr);
    }
  } catch(e) {
    toast('추가 실패: ' + (e.response?.data?.error || e.message), 'error');
  }
}

// ── 외선 공종 삭제 ──
async function _upDeleteCableItem(itemKey, itemLabel) {
  const ok = await showConfirmDialog(
    '공종 삭제',
    `'${itemLabel}' 공종을 삭제하시겠습니까?\n기존 집계 데이터에는 영향이 없습니다.`,
    '삭제', '취소', 'danger'
  );
  if (!ok) return;
  try {
    await API.delete(`/volume-unit-prices/${encodeURIComponent(itemKey)}`);
    toast(`'${itemLabel}' 공종이 삭제되었습니다.`);
    document.querySelector(`#up-cable-tbody tr[data-key="${itemKey}"]`)?.remove();
  } catch(e) {
    toast('삭제 실패: ' + (e.response?.data?.error || e.message), 'error');
  }
}

