async function _saveUnitPrices() {
  // 단가 input 수집
  const priceInputs = document.querySelectorAll('.up-cable-input');
  // 공종명 input 수집
  const labelInputs = document.querySelectorAll('.up-cable-label-input');
  // 단위 input 수집
  const unitInputs  = document.querySelectorAll('.up-cable-unit-input');

  // key → { unit_price, item_label, unit } 맵 구성
  const dataMap = {};
  priceInputs.forEach(el => {
    const k = el.dataset.key;
    if (!dataMap[k]) dataMap[k] = {};
    dataMap[k].unit_price = Number(el.value) || 0;
  });
  labelInputs.forEach(el => {
    const k = el.dataset.key;
    if (!dataMap[k]) dataMap[k] = {};
    const v = (el.value || '').trim();
    dataMap[k].item_label = v || undefined;  // 빈값이면 undefined → 서버에서 기존값 유지
  });
  unitInputs.forEach(el => {
    const k = el.dataset.key;
    if (!dataMap[k]) dataMap[k] = {};
    dataMap[k].unit = (el.value || '').trim() || '식';
  });

  const prices = Object.entries(dataMap).map(([item_key, v]) => ({ item_key, ...v }));
  const msgEl = document.getElementById('up-msg');
  try {
    await API.put('/volume-unit-prices', { prices });
    msgEl.className = 'text-center text-sm text-green-600 bg-green-50 rounded-lg py-2';
    msgEl.textContent = '✅ 외선 단가가 저장되었습니다.';
    msgEl.classList.remove('hidden');
    setTimeout(() => msgEl.classList.add('hidden'), 3000);
  } catch(e) {
    msgEl.className = 'text-center text-sm text-red-600 bg-red-50 rounded-lg py-2';
    msgEl.textContent = '❌ 저장 실패: ' + (e.response?.data?.error || e.message);
    msgEl.classList.remove('hidden');
  }
}

async function _saveSpliceUnitPrices() {
  // 기본단가 input: class="up-splice-input", data-key
  // 야간추가: class="up-splice-input-night", data-key
  // 가공추가: class="up-splice-input-aerial", data-key
  // 공종명:   class="up-splice-label-input", data-key
  // 단위:     class="up-splice-unit-input",  data-key
  const baseInputs   = document.querySelectorAll('.up-splice-input');
  const nightInputs  = document.querySelectorAll('.up-splice-input-night');
  const aerialInputs = document.querySelectorAll('.up-splice-input-aerial');
  const labelInputs  = document.querySelectorAll('.up-splice-label-input');
  const unitInputs   = document.querySelectorAll('.up-splice-unit-input');

  // key → { unit_price, night_price, aerial_price, item_label, unit } 맵 구성
  const priceMap = {};
  const ensureKey = (k) => { if (!priceMap[k]) priceMap[k] = { unit_price:0, night_price:0, aerial_price:0 }; };
  baseInputs.forEach(el   => { ensureKey(el.dataset.key); priceMap[el.dataset.key].unit_price   = Number(el.value) || 0; });
  nightInputs.forEach(el  => { ensureKey(el.dataset.key); priceMap[el.dataset.key].night_price  = Number(el.value) || 0; });
  aerialInputs.forEach(el => { ensureKey(el.dataset.key); priceMap[el.dataset.key].aerial_price = Number(el.value) || 0; });
  labelInputs.forEach(el  => {
    ensureKey(el.dataset.key);
    const v = (el.value || '').trim();
    if (v) priceMap[el.dataset.key].item_label = v;
  });
  unitInputs.forEach(el   => {
    ensureKey(el.dataset.key);
    priceMap[el.dataset.key].unit = (el.value || '').trim() || '개소';
  });

  const prices = Object.entries(priceMap).map(([item_key, v]) => ({ item_key, ...v }));
  const msgEl = document.getElementById('up-splice-msg');
  try {
    await API.put('/splice-unit-prices', { prices });
    msgEl.className = 'text-center text-sm text-green-600 bg-green-50 rounded-lg py-2';
    msgEl.textContent = '✅ 접속 단가가 저장되었습니다.';
    msgEl.classList.remove('hidden');
    setTimeout(() => msgEl.classList.add('hidden'), 3000);
  } catch(e) {
    msgEl.className = 'text-center text-sm text-red-600 bg-red-50 rounded-lg py-2';
    msgEl.textContent = '❌ 저장 실패: ' + (e.response?.data?.error || e.message);
    msgEl.classList.remove('hidden');
  }
}

// ── 단가 관리 — 엑셀(CSV) 다운로드 ──────────────────────────────────────────
function _upExportCsv(type) {
  // 브라우저에서 직접 API 호출하여 CSV 파일 다운로드
  const token = localStorage.getItem('token') || '';
  const url = type === 'cable'
    ? '/api/volume-unit-prices/export'
    : '/api/splice-unit-prices/export';
  // fetch + blob 방식으로 다운로드 (Authorization 헤더 포함)
  fetch(url, { headers: { 'Authorization': 'Bearer ' + token } })
    .then(res => {
      if (!res.ok) throw new Error('다운로드 실패 (' + res.status + ')');
      const disp = res.headers.get('Content-Disposition') || '';
      // 파일명 추출
      let filename = type === 'cable' ? '외선단가.csv' : '접속단가.csv';
      const matchUtf8 = disp.match(/filename\*=UTF-8''([^;]+)/i);
      const matchPlain = disp.match(/filename="?([^";]+)"?/i);
      if (matchUtf8) filename = decodeURIComponent(matchUtf8[1]);
      else if (matchPlain) filename = matchPlain[1];
      return res.blob().then(blob => ({ blob, filename }));
    })
    .then(({ blob, filename }) => {
      const a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 1000);
      toast('엑셀 파일을 다운로드했습니다.', 'success');
    })
    .catch(e => toast('다운로드 실패: ' + e.message, 'error'));
}

// ── 단가 관리 — 엑셀(CSV) 업로드 ────────────────────────────────────────────
async function _upImportCsv(input, type) {
  const file = input?.files?.[0];
  if (!file) return;
  input.value = ''; // 같은 파일 재선택 가능하게 초기화

  const ext = file.name.split('.').pop()?.toLowerCase() || '';
  if (!['csv'].includes(ext)) {
    toast('CSV 파일만 업로드 가능합니다.\n엑셀(.xlsx)은 먼저 CSV로 저장 후 업로드해 주세요.', 'error');
    return;
  }

  const label = type === 'cable' ? '외선' : '접속';
  const confirmed = await showConfirmDialog(
    `${label} 단가 일괄 업로드`,
    `"${file.name}" 파일을 업로드합니다.\n기존 단가는 공종키 기준으로 덮어씁니다.\n신규 공종키는 새로 추가됩니다.\n\n계속 진행하시겠습니까?`,
    '업로드', '취소', 'primary'
  );
  if (!confirmed) return;

  try {
    const text = await file.text();
    const url = type === 'cable'
      ? '/volume-unit-prices/import'
      : '/splice-unit-prices/import';
    const res = await API.post(url, text, {
      headers: { 'Content-Type': 'text/csv; charset=utf-8' }
    });
    const { upserted, skipped, total } = res.data;
    toast(`✅ ${label} 단가 업로드 완료\n총 ${total}행 중 ${upserted}행 적용, ${skipped}행 건너뜀`, 'success');
    // 페이지 새로고침
    setTimeout(() => renderUnitPricePage(document.getElementById('page-content')), 800);
  } catch(e) {
    toast('업로드 실패: ' + (e.response?.data?.error || e.message), 'error');
  }
}

// ── 작업 완료 물량 워크시트 UI 헬퍼 ──────────────────────────────────────────

// 작업 완료 물량 종류 선택 버튼 클릭 핸들러
function selectWorkVolType(btn, type) {
  // 모든 버튼 비활성화 스타일
  document.querySelectorAll('.work-vol-type-btn').forEach(b => {
    b.style.borderColor = '#E5E7EB';
    b.style.background = '#F9FAFB';
    b.style.color = '#6B7280';
  });
  // 선택된 버튼 활성화 스타일
  btn.style.borderColor = '#D70072';
  btn.style.background = '#FDE8F3';
  btn.style.color = '#D70072';

  // 입력 영역 표시 (splice는 별도 테이블, 나머지는 textarea)
  const inputArea    = document.getElementById('workVolInputArea');
  const spliceArea   = document.getElementById('workVolSpliceArea');
  const cableAction  = document.getElementById('workVolCableAction');
  const spliceAction = document.getElementById('workVolSpliceAction');

  // 접속 포함 모든 타입에서 textarea 입력 영역 표시
  if (inputArea)  inputArea.classList.remove('hidden');
  if (spliceArea) spliceArea.classList.add('hidden'); // spliceArea 미사용

  // 외선 선택 → 외선일보 작성 버튼, 접속 선택 → 접속일보 작성 버튼
  if (cableAction)  cableAction.classList.toggle('hidden',  type !== 'cable');
  if (spliceAction) spliceAction.classList.toggle('hidden', type !== 'splice');

  // placeholder 업데이트
  const textarea = document.getElementById('logWorkVolume');
  if (textarea) {
    const placeholders = {
      cable: '예: 단심 케이블 50m, 다심 케이블 20m',
      splice: '예: 광케이블 접속 2점, 동축 접속 1점',
      duct: '예: 관로 굴착 30m, 맨홀 설치 2개소',
      equip: '예: 지상분전함 설치 1대, 단자함 교체 2대'
    };
    textarea.placeholder = placeholders[type] || '완료 물량을 입력하세요';
  }
}

// 외선일보 작성 화면으로 이동 (작업일지 모달 닫고 이동)
// ── 접속 공종 기본 항목 정의 ────────────────────────────────────────────────
const SPLICE_DEFAULT_ITEMS = [
  { label: '함체작업',              night: true,  aerial: true,  unit: '개소' },
  { label: '중간분기',              night: true,  aerial: true,  unit: '개소' },
  { label: '선번확인',              night: true,  aerial: true,  unit: '개소' },
  { label: '광케이블 코아접속',     night: true,  aerial: true,  unit: '코어' },
  { label: '광케이블 성단',         night: true,  aerial: true,  unit: '코어' },
  { label: '광탭작업',              night: true,  aerial: true,  unit: '개소' },
  { label: '광탭 중간분기',         night: true,  aerial: true,  unit: '개소' },
  { label: '광커넥터 현장조립/취부', night: true, aerial: true,  unit: '개소' },
  { label: '광탭 결합/고정 작업',   night: true,  aerial: true,  unit: '개소' },
  { label: 'FTTH 레벨 측정시험',    night: true,  aerial: true,  unit: '코어' },
  { label: '신호수배치',            night: true,  aerial: false, unit: '건'   },
];

// 접속 공종 tbody 초기화 (처음 한 번만 기본 항목 채움)
function _spliceInitRows() {
  const tbody = document.getElementById('splice-work-tbody');
  if (!tbody || tbody.rows.length > 0) return; // 이미 행 있으면 skip
  SPLICE_DEFAULT_ITEMS.forEach(item => _spliceAppendRow(tbody, item));
}

// 행 추가 버튼 클릭
function _spliceAddRow() {
  const tbody = document.getElementById('splice-work-tbody');
  if (!tbody) return;
  _spliceAppendRow(tbody, { label: '', night: false, aerial: false, unit: '' });
}

// 실제 행 DOM 생성
function _spliceAppendRow(tbody, item) {
  const tr = document.createElement('tr');
  tr.className = 'hover:bg-purple-50';
  const isCustom = !item.label; // 사용자 추가 행 여부 (label 없으면 커스텀)
  tr.innerHTML = `
    <td class="border border-gray-200 p-0.5">
      ${isCustom
        ? `<input type="text" class="w-full border-0 bg-transparent text-xs p-1 focus:outline-none splice-label" placeholder="공종명 입력">`
        : `<span class="px-2 py-1 block text-xs text-gray-700 splice-label-text">${item.label}<input type="hidden" class="splice-label" value="${item.label}"></span>`
      }
    </td>
    <td class="border border-gray-200 px-2 py-1 text-center">
      ${item.aerial !== false
        ? `<input type="checkbox" class="splice-night w-4 h-4 accent-indigo-600" ${item.night ? '' : ''}>`
        : `<span class="text-gray-300 text-xs">—</span>`}
    </td>
    <td class="border border-gray-200 px-2 py-1 text-center">
      ${item.aerial !== false
        ? `<input type="checkbox" class="splice-aerial w-4 h-4 accent-indigo-600" ${item.aerial ? '' : ''}>`
        : `<span class="text-gray-300 text-xs">—</span>`}
    </td>
    <td class="border border-gray-200 p-0.5">
      <input type="number" step="1" min="0" class="w-full border-0 bg-transparent text-xs p-1 focus:outline-none text-right splice-qty" placeholder="0">
    </td>
    <td class="border border-gray-200 px-2 py-1 text-center text-xs text-gray-500">
      ${isCustom
        ? `<input type="text" class="w-full border-0 bg-transparent text-xs p-1 focus:outline-none text-center splice-unit" placeholder="단위">`
        : `<span class="splice-unit-text">${item.unit}</span><input type="hidden" class="splice-unit" value="${item.unit}">`
      }
    </td>
    <td class="border border-gray-200 px-1 py-1 text-center">
      ${isCustom
        ? `<button onclick="this.closest('tr').remove()" class="text-red-300 hover:text-red-500 text-xs px-1"><i class="fas fa-times"></i></button>`
        : `<span class="text-gray-200 text-xs px-1">—</span>`}
    </td>`;
  tbody.appendChild(tr);
}

function goToWorkReport(taskId) {
  if (!taskId) { toast('작업 정보를 찾을 수 없습니다.', 'error'); return; }
  // 모달 전체 닫기
  document.querySelectorAll('.modal-overlay').forEach(m => m.remove());
  // 외선일보 작성 페이지로 이동
  const content = document.getElementById('page-content');
  if (content) {
    renderWorkReportForm(content, taskId);
    // 사이드바 메뉴 활성화
    document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
    const navItem = document.querySelector('.nav-item[data-page="field-report"]');
    if (navItem) navItem.classList.add('active');
  }
}

// 접속일보 작성 화면으로 이동 (작업일지 모달 닫고 이동)
function goToSpliceReport(taskId) {
  // 모달 전체 닫기
  document.querySelectorAll('.modal-overlay').forEach(m => m.remove());
  // 접속일보 작성 페이지로 이동
  const content = document.getElementById('page-content');
  if (content) {
    renderSpliceReportForm(content, null, taskId || null);
    // 사이드바 메뉴 활성화
    document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
    const navItem = document.querySelector('.nav-item[data-page="report-write"]');
    if (navItem) navItem.classList.add('active');
  }
}

// ═══════════════════════════════════════════════════════════════
// 현장위치 지도 페이지  /site-map
// ═══════════════════════════════════════════════════════════════

let _kakaoMapInstance = null;  // 카카오맵 인스턴스 재사용

async function renderSiteMapPage(container) {
  // ── 전역 필터 초기화 (첫 진입: 오늘(KST), 탭: 위험성체크) ──
  const _today = getKSTDate(); // KST 기준 오늘
  if (window._smTab      === undefined) window._smTab      = 'risk';
  if (window._smDateFrom === undefined) window._smDateFrom = _today;  // 기본: 오늘
  if (window._smDateTo   === undefined) window._smDateTo   = _today;  // 기본: 오늘
  if (window._smUserId   === undefined) window._smUserId   = '';   // 전체 사용자
  if (window._smUserList === undefined) window._smUserList = [];   // 사용자 목록 캐시

  const _tab    = window._smTab;
  const _df     = window._smDateFrom;
  const _dt     = window._smDateTo;
  const _userId = window._smUserId;

  const dateRangeLabel = (_df === _dt && _df)
    ? _df : (_df || _dt) ? `${_df||'처음'} ~ ${_dt||'오늘'}` : '전체 기간';

  // ── 탭 정의 ──
  const TAB_DEFS = [
    { key:'risk',       label:'⚠️ 위험성체크', color:'#F59E0B', desc:'위험성평가 작성 위치' },
    { key:'tbm',        label:'🦺 TBM',       color:'#685182', desc:'TBM 완료 후 작업 개시 대기 중인 현장 위치' },
    { key:'working',    label:'🟢 진행',       color:'#10B981', desc:'작업 개시(진행중) 현장 위치' },
    { key:'completed',  label:'✅ 완료',       color:'#6B7280', desc:'작업 완료된 현장 위치' },
  ];

  // ── 사용자 목록 로드 (캐시) ──
  if (window._smUserList.length === 0) {
    try {
      const r = await API.get('/users?limit=200');
      window._smUserList = Array.isArray(r.data) ? r.data : (r.data?.users || r.data?.items || []);
    } catch(e) { window._smUserList = []; }
  }
  const userList = window._smUserList;

  // 현재 선택된 사용자 이름
  const selUser = userList.find(u => String(u.id) === String(_userId));
  const userLabel = selUser ? selUser.name : '전체 사용자';

  container.innerHTML = `
    <div id="siteMapRoot" style="display:flex;flex-direction:column;height:100%">

      <!-- 헤더 -->
      <div class="flex items-center justify-between mb-3">
        <h2 class="text-xl font-black text-gray-900" style="border-left:4px solid #685182;padding-left:10px">현장위치 지도</h2>
        <p class="text-xs text-gray-400">${dateRangeLabel}</p>
      </div>

      <!-- ① 구분 탭 (현장점검과 동일 라운드 버튼) -->
      <div class="flex gap-1 mb-3 flex-wrap">
        ${TAB_DEFS.map(tab => {
          const isActive = _tab === tab.key;
          return `<button
            onclick="window._smTab='${tab.key}';_applySiteMapFilters()"
            title="${tab.desc}"
            style="padding:6px 14px;border-radius:999px;font-size:12px;font-weight:700;
                   border:2px solid ${isActive ? tab.color : '#D8D0DC'};
                   background:${isActive ? tab.color : 'white'};
                   color:${isActive ? 'white' : tab.color};
                   cursor:pointer;transition:all .15s;white-space:nowrap">
            ${tab.label}
          </button>`;
        }).join('')}
      </div>

      <!-- ② 필터 바 (날짜 + 사용자) -->
      <div class="card p-3 mb-3" style="background:#F5F0F8;border:1px solid #D8D0DC;flex-shrink:0">
        <div class="flex flex-wrap items-center gap-2">

          <!-- 날짜 -->
          <div class="flex items-center gap-1">
            <label class="text-xs font-bold text-gray-600 whitespace-nowrap">등록일</label>
            <input type="date" id="siteMapDateFrom" value="${_df}" class="form-control text-sm" style="width:130px">
            <span class="text-gray-400 text-sm">~</span>
            <input type="date" id="siteMapDateTo"   value="${_dt}" class="form-control text-sm" style="width:130px">
          </div>
          <!-- 빠른 날짜 -->
          <div class="flex gap-1">
            <button onclick="_setSiteMapDateRange('today')" class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">오늘</button>
            <button onclick="_setSiteMapDateRange('week')"  class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">7일</button>
            <button onclick="_setSiteMapDateRange('month')" class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">30일</button>
            <button onclick="_setSiteMapDateRange('all')"   class="btn btn-outline btn-xs" style="font-size:11px;padding:2px 8px">전체</button>
          </div>

          <!-- 사용자 선택 드롭다운 -->
          <div class="flex items-center gap-1 ml-auto">
            <i class="fas fa-user text-xs" style="color:#685182"></i>
            <select id="siteMapUserId"
              onchange="window._smUserId=this.value;_applySiteMapFilters()"
              class="form-control text-sm" style="width:130px;padding:4px 6px;border-radius:8px;border:1px solid #D8D0DC">
              <option value="" ${!_userId ? 'selected' : ''}>전체 사용자</option>
              ${userList.map(u =>
                `<option value="${u.id}" ${String(u.id)===String(_userId)?'selected':''}>${u.name}${u.position?` (${u.position})`:''}</option>`
              ).join('')}
            </select>
          </div>

          <!-- 조회 버튼 -->
          <button onclick="_applySiteMapFilters()" class="btn btn-sm" style="background:#685182;color:white;border:none">
            <i class="fas fa-search mr-1"></i>조회
          </button>
        </div>
      </div>

      <!-- ③ 지도 (flex-grow: 남은 공간 모두 차지) -->
      <div id="leafletMap" style="width:100%;flex:1;min-height:300px;border-radius:12px;overflow:hidden;background:#f3f4f6;position:relative;z-index:0;"></div>

      <!-- ④ 범례 -->
      <div class="flex gap-4 mt-3 text-sm flex-wrap" id="siteMapLegend" style="flex-shrink:0">
        ${TAB_DEFS.map(t => `
          <span class="flex items-center gap-1" style="color:#6B7280">
            <span style="display:inline-block;width:10px;height:10px;background:${t.color};border-radius:50%"></span>
            ${t.label}
          </span>`).join('')}
        ${_userId ? `<span class="flex items-center gap-1 ml-2" style="color:#685182;font-weight:600">
          <i class="fas fa-user" style="font-size:10px"></i> ${userLabel}
        </span>` : ''}
      </div>

      <!-- ⑤ 위치 목록 -->
      <div id="siteMapList" class="mt-4 space-y-2" style="flex-shrink:0"></div>
    </div>
  `;

  // page-content가 남은 화면을 모두 채우도록 flex 설정
  const pageContent = document.getElementById('page-content');
  if (pageContent) {
    pageContent.style.display = 'flex';
    pageContent.style.flexDirection = 'column';
    pageContent.style.flex = '1';
    pageContent.style.height = '100%';
    pageContent.style.boxSizing = 'border-box';
  }

  await loadLeafletMap();
}

// 조회 버튼: DOM → 전역 저장 후 재렌더링
function _applySiteMapFilters() {
  window._smDateFrom = document.getElementById('siteMapDateFrom')?.value ?? window._smDateFrom ?? '';
  window._smDateTo   = document.getElementById('siteMapDateTo')?.value   ?? window._smDateTo   ?? '';
  const selEl = document.getElementById('siteMapUserId');
  if (selEl) window._smUserId = selEl.value;
  renderSiteMapPage(document.getElementById('page-content'));
}

// 빠른 날짜 선택: 전역 직접 수정 후 재렌더링
function _setSiteMapDateRange(range) {
  const today = getKSTDate(); // KST 기준 오늘
  if (range === 'today')      { window._smDateFrom = today; window._smDateTo = today; }
  else if (range === 'week')  { const d = getKSTNow(); d.setUTCDate(d.getUTCDate()-7);  window._smDateFrom = d.toISOString().split('T')[0]; window._smDateTo = today; }
  else if (range === 'month') { const d = getKSTNow(); d.setUTCDate(d.getUTCDate()-30); window._smDateFrom = d.toISOString().split('T')[0]; window._smDateTo = today; }
  else if (range === 'all')   { window._smDateFrom = ''; window._smDateTo = ''; }
  renderSiteMapPage(document.getElementById('page-content'));
}

// Leaflet 지도 로드 (OpenStreetMap 기반 — 외부 차단 없음)
async function loadLeafletMap() {
  // Leaflet CSS 동적 추가
  if (!document.getElementById('leaflet-css')) {
    const link = document.createElement('link');
    link.id = 'leaflet-css';
    link.rel = 'stylesheet';
    link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
    document.head.appendChild(link);
  }

  // Leaflet JS 동적 로드
  if (!window.L) {
    await new Promise((resolve, reject) => {
      const script = document.createElement('script');
      script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
      script.onload = resolve;
      script.onerror = reject;
      document.head.appendChild(script);
    });
  }

  const mapEl = document.getElementById('leafletMap');
  if (!mapEl) return;

  // 기존 지도 제거
  if (_kakaoMapInstance) {
    _kakaoMapInstance.remove();
    _kakaoMapInstance = null;
  }

  // 지도 생성 (한국 중심)
  const map = window.L.map('leafletMap').setView([36.5, 127.5], 7);
  window.L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '© OpenStreetMap contributors',
    maxZoom: 19
  }).addTo(map);

  _kakaoMapInstance = map;

  // ResizeObserver: 컨테이너 크기 변경 시 Leaflet 지도 자동 재조정
  if (window._siteMapResizeObserver) {
    window._siteMapResizeObserver.disconnect();
  }
  if (typeof ResizeObserver !== 'undefined') {
    window._siteMapResizeObserver = new ResizeObserver(() => {
      if (_kakaoMapInstance) {
        _kakaoMapInstance.invalidateSize();
      }
    });
    window._siteMapResizeObserver.observe(mapEl);
  }

  await loadSiteMapMarkers(map);
}

async function refreshSiteMap() {
  renderSiteMapPage(document.getElementById('page-content'));
}

async function loadSiteMapMarkers(map) {
  const L        = window.L;
  const filter   = window._smTab      || 'risk';  // 기본: 위험성체크
  const dateFrom = window._smDateFrom || '';
  const dateTo   = window._smDateTo   || '';
  const userId   = window._smUserId   || '';
  const listEl   = document.getElementById('siteMapList');
  const latLngs  = [];
  let listItems  = [];

  // 탭별 색상/아이콘 정의
  const TAB_META = {
    risk:      { color: '#F59E0B', faIcon: 'fa-exclamation-triangle', label: '⚠️ 위험성체크', emptyMsg: '위험성평가 작성 시 GPS 버튼을 눌러 위치를 기록해 주세요.' },
    tbm:       { color: '#685182', faIcon: 'fa-hard-hat',             label: '🦺 TBM (개시 대기)',    emptyMsg: 'TBM 완료 후 작업 개시 대기 중인 작업이 없거나 GPS 기록이 없습니다.' },
    working:   { color: '#10B981', faIcon: 'fa-play-circle',          label: '🟢 진행중',             emptyMsg: '작업 개시 시 GPS를 허용하면 위치가 기록됩니다. 현재 진행중 GPS 기록이 없습니다.' },
    completed: { color: '#6B7280', faIcon: 'fa-check-circle',         label: '✅ 완료',               emptyMsg: '완료된 작업의 GPS 기록이 없습니다.' },
  };
  const meta = TAB_META[filter] || TAB_META.risk;

  // 커스텀 마커 아이콘 생성
  const makeIcon = (color, label) => L.divIcon({
    html: `<div style="background:${color};color:#fff;padding:4px 8px;border-radius:20px;font-size:11px;font-weight:700;white-space:nowrap;box-shadow:0 2px 6px rgba(0,0,0,0.3);transform:translateX(-50%)">${label}</div>`,
    className: '',
    iconAnchor: [0, 0]
  });

  // 로딩 표시
  if (listEl) listEl.innerHTML = `<div class="text-center text-gray-400 py-4 text-sm"><i class="fas fa-spinner fa-spin mr-2"></i>위치 데이터 로드 중...</div>`;

  // 쿼리스트링 생성 헬퍼 (날짜 + 사용자 포함)
  const dateParams = () => {
    const p = new URLSearchParams();
    if (dateFrom) p.set('date_from', dateFrom);
    if (dateTo)   p.set('date_to',   dateTo);
    if (userId)   p.set('user_id',   userId);
    p.set('limit', '500');
    return `?${p.toString()}`;
  };

  try {

    // ── ① 위험성체크 탭 ─────────────────────────────────────────
    if (filter === 'risk') {
      const res = await API.get(`/risk${dateParams()}`);
      const list = Array.isArray(res.data) ? res.data : (res.data?.items || res.data?.risks || []);
      for (const ra of list) {
        // tasks JOIN으로 받은 GPS 사용 (risk_assessments 테이블엔 GPS 없음)
        if (!ra.gps_lat || !ra.gps_lon) continue;
        const lat = parseFloat(ra.gps_lat);
        const lon = parseFloat(ra.gps_lon);
        if (isNaN(lat) || isNaN(lon)) continue;

        const displayDate = _toKSTDateTime(ra.created_at || '');
        const name = ra.task_title || ra.work_type_name || '위험성평가';
        const addr = ra.gps_address || ra.confirmed_address || ra.task_location || `${lat.toFixed(5)}, ${lon.toFixed(5)}`;

        const marker = L.marker([lat, lon], { icon: makeIcon(meta.color, '⚠️ 위험성') }).addTo(map);
        marker.bindPopup(`
          <div style="min-width:200px;font-size:13px;">
            <div style="font-weight:700;color:${meta.color};margin-bottom:4px">⚠️ 위험성체크</div>
            <div style="font-weight:600">${name}</div>
            <div style="color:#6B7280;font-size:11px;margin-top:2px">
              <i class="fas fa-user mr-1"></i>${ra.assessor_name || '-'}
            </div>
            <div style="color:#6B7280;font-size:11px;margin-top:2px">
              <i class="fas fa-tag mr-1"></i>${ra.assessment_type || '-'}
            </div>
            <div style="color:#6B7280;font-size:11px;margin-top:2px">
              <i class="fas fa-calendar-alt mr-1"></i>${displayDate || '-'}
            </div>
            <div style="color:#6B7280;font-size:11px;margin-top:2px">
              <i class="fas fa-map-marker-alt mr-1"></i>${addr}
            </div>
          </div>`);

        latLngs.push([lat, lon]);
        listItems.push({ color: meta.color, icon: meta.faIcon, date: displayDate, name,
          author: ra.assessor_name || '', address: addr, lat, lon });
      }
    }

    // ── ② TBM 탭 ─────────────────────────────────────────────────
    // task_status = 'tbm_done' (TBM 완료, 작업 개시 전) 인 것만 표시
    // 작업 개시(working) 이후 건은 진행 탭으로 이동됨
    if (filter === 'tbm') {
      const res = await API.get(`/tbm${dateParams()}`);
      const list = Array.isArray(res.data) ? res.data : (res.data?.items || res.data?.tbms || []);
      for (const tbm of list) {
        // task_status가 tbm_done 인 것만 (working·완료 상태는 각 탭에서 표시)
        if (tbm.task_status && tbm.task_status !== 'tbm_done') continue;
        if (!tbm.gps_lat || !tbm.gps_lon) continue;
        const lat = parseFloat(tbm.gps_lat);
        const lon = parseFloat(tbm.gps_lon);
        if (isNaN(lat) || isNaN(lon)) continue;

        const displayDate = _toKSTDateTime(tbm.tbm_date || tbm.work_date || tbm.created_at || '');
        const name = tbm.task_title || tbm.work_name || tbm.construction_name || 'TBM';
        const addr = tbm.gps_address || `${lat.toFixed(5)}, ${lon.toFixed(5)}`;

        const marker = L.marker([lat, lon], { icon: makeIcon(meta.color, '🦺 TBM') }).addTo(map);
        marker.bindPopup(`
          <div style="min-width:200px;font-size:13px;">
            <div style="font-weight:700;color:${meta.color};margin-bottom:4px">🦺 TBM 완료 (개시 대기)</div>
            <div style="font-weight:600">${name}</div>
            <div style="color:#6B7280;font-size:11px;margin-top:2px">
              <i class="fas fa-user mr-1"></i>${tbm.conductor_name || '-'}
            </div>
            <div style="color:#6B7280;font-size:11px;margin-top:2px">
              <i class="fas fa-calendar-alt mr-1"></i>${displayDate || '-'}
            </div>
            <div style="color:#6B7280;font-size:11px;margin-top:2px">
              <i class="fas fa-map-marker-alt mr-1"></i>${addr}
            </div>
          </div>`);

        latLngs.push([lat, lon]);
        listItems.push({ color: meta.color, icon: meta.faIcon, date: displayDate, name,
          author: tbm.conductor_name || '', address: addr, lat, lon });
      }
    }

    // ── ③ 진행 탭 (status = 'working') ──────────────────────────
    // [FEAT-011] /api/tasks?status=working 기반으로 변경
    // 이유: TBM 없이 작업개시된 경우 /api/tbm에 데이터 자체가 없어 마커 미표시
    // GPS 우선순위: tbm_records.gps → work_logs.gps → 좌표 없음(목록만)
    if (filter === 'working') {
      // ① tasks API로 working 상태 작업 목록 확보 (날짜 파라미터 변환)
      const tp = new URLSearchParams();
      if (dateFrom) tp.set('start_date', dateFrom);
      if (dateTo)   tp.set('end_date',   dateTo);
      if (userId)   tp.set('worker_id',  userId);
      tp.set('limit', '500');
      const taskRes = await API.get(`/tasks?status=working&${tp.toString()}`);
      const _rawTaskListW = Array.isArray(taskRes.data) ? taskRes.data
        : (taskRes.data?.tasks || taskRes.data?.items || []);
      // [BUG-079] LGU+ 클라이언트 필터: is_auto_request_no=0 건만 표시
      var _smMyUiRoleW = dbRoleToUi(currentUser.role, currentUser.position, currentUser.sub_role);
      var _smIsLguW = (_smMyUiRoleW === 'lgu_plus' || currentUser.role === 'lgu_plus' || currentUser.role === 'lgu'); // [FEAT-048]
      const taskList = _smIsLguW
        ? _rawTaskListW.filter(function(t) { return t.is_auto_request_no === 0; })
        : _rawTaskListW;

      if (taskList.length === 0) {
        // 데이터 없음 — 빈 목록으로 종료
      } else {
        const taskIds = taskList.map(t => t.id).filter(Boolean);

        // ② TBM GPS 캐시: { task_id → { lat, lon, gps_address, tbm_date, conductor_name } }
        const tbmGpsCache = {};
        try {
          const tbmRes = await API.get(`/tbm?limit=500`);
          const tbmList = Array.isArray(tbmRes.data) ? tbmRes.data : (tbmRes.data?.items || []);
          for (const tbm of tbmList) {
            if (!tbm.task_id || !tbm.gps_lat || !tbm.gps_lon) continue;
            if (tbmGpsCache[tbm.task_id]) continue; // 최신 1건만 (DESC 정렬 신뢰)
            tbmGpsCache[tbm.task_id] = {
              lat: parseFloat(tbm.gps_lat),
              lon: parseFloat(tbm.gps_lon),
              addr: tbm.gps_address || '',
              date: tbm.tbm_date || tbm.created_at || '',
              conductor: tbm.conductor_name || ''
            };
          }
        } catch(_) {}

        // ③ work_logs GPS 캐시: TBM GPS 없는 task_id만 조회 (병렬)
        const noTbmGpsIds = taskIds.filter(tid => !tbmGpsCache[tid]);
        const wlGpsCache = {};
        await Promise.all(noTbmGpsIds.map(async (tid) => {
          try {
            const wlRes = await API.get(`/worklogs?task_id=${tid}`);
            const wlList = Array.isArray(wlRes.data) ? wlRes.data : (wlRes.data?.items || []);
            const found = wlList.find(wl => wl.gps_lat && wl.gps_lon);
            if (found) wlGpsCache[tid] = {
              lat: parseFloat(found.gps_lat),
              lon: parseFloat(found.gps_lon),
              date: found.gps_recorded_at || found.log_date || ''
            };
          } catch(_) {}
        }));

        // ④ 마커 생성
        for (const task of taskList) {
          let lat = null, lon = null, gpsSource = '', addr = '', displayDate = '';

          const tbmG = tbmGpsCache[task.id];
          const wlG  = wlGpsCache[task.id];

          // 상태변경 시각 fallback (GPS 날짜 없을 때 또는 GPS 자체 없을 때)
          const statusTime = task.work_started_at || task.updated_at || '';

          if (tbmG) {
            lat = tbmG.lat; lon = tbmG.lon;
            addr = tbmG.addr || `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
            displayDate = _toKSTDateTime(tbmG.date || statusTime);
            gpsSource = 'tbm';
          } else if (wlG) {
            lat = wlG.lat; lon = wlG.lon;
            addr = `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
            displayDate = _toKSTDateTime(wlG.date || statusTime);
            gpsSource = 'worklog';
          } else {
            // GPS 기록 없음 — 마커는 skip하지만 displayDate는 상태변경 시각으로 설정
            displayDate = _toKSTDateTime(statusTime);
          }

          if (!lat || !lon || isNaN(lat) || isNaN(lon)) continue;

          const name = task.title || '작업';
          const gpsLabel = gpsSource === 'worklog' ? '🟢 진행(일지GPS)' : '🟢 진행';
          const conductor = tbmG?.conductor || task.supervisor_name || '';

          const marker = L.marker([lat, lon], { icon: makeIcon(meta.color, gpsLabel) }).addTo(map);
          marker.bindPopup(`
            <div style="min-width:200px;font-size:13px;">
              <div style="font-weight:700;color:${meta.color};margin-bottom:4px">🟢 작업 진행중</div>
              <div style="font-weight:600">${name}</div>
              ${task.task_number ? `<div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-hashtag mr-1"></i>${task.task_number}
              </div>` : ''}
              ${conductor ? `<div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-user-hard-hat mr-1"></i>${conductor}
              </div>` : ''}
              <div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-calendar-alt mr-1"></i>${displayDate || '-'}
              </div>
              <div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-map-marker-alt mr-1"></i>${addr}
              </div>
              ${gpsSource === 'worklog' ? `<div style="color:#10B981;font-size:10px;margin-top:3px">
                <i class="fas fa-info-circle mr-1"></i>작업일지 GPS 기준
              </div>` : ''}
            </div>`);

          latLngs.push([lat, lon]);
          listItems.push({ color: meta.color, icon: meta.faIcon, date: displayDate, name,
            author: conductor, address: addr, lat, lon, taskId: task.id });
        }
      }
    }

    // ── ④ 완료 탭 (status = 'work_completed' | 'completed') ────────
    // [FEAT-011] /api/tasks?status=work_completed,completed 기반으로 변경
    // GPS 우선순위: tbm_records.gps → work_logs.gps → 좌표 없음(목록만)
    if (filter === 'completed') {
      // ① tasks API로 완료 작업 목록 확보
      const tp = new URLSearchParams();
      tp.set('status', 'work_completed,completed');
      if (dateFrom) tp.set('start_date', dateFrom);
      if (dateTo)   tp.set('end_date',   dateTo);
      if (userId)   tp.set('worker_id',  userId);
      tp.set('limit', '500');
      const taskRes = await API.get(`/tasks?${tp.toString()}`);
      const _rawTaskListC = Array.isArray(taskRes.data) ? taskRes.data
        : (taskRes.data?.tasks || taskRes.data?.items || []);
      // [BUG-079] LGU+ 클라이언트 필터: is_auto_request_no=0 건만 표시
      var _smMyUiRoleC = dbRoleToUi(currentUser.role, currentUser.position, currentUser.sub_role);
      var _smIsLguC = (_smMyUiRoleC === 'lgu_plus' || currentUser.role === 'lgu_plus' || currentUser.role === 'lgu'); // [FEAT-048]
      const taskList = _smIsLguC
        ? _rawTaskListC.filter(function(t) { return t.is_auto_request_no === 0; })
        : _rawTaskListC;

      if (taskList.length > 0) {
        const taskIds = taskList.map(t => t.id).filter(Boolean);

        // ② TBM GPS 캐시
        const tbmGpsCache = {};
        try {
          const tbmRes = await API.get(`/tbm?limit=500`);
          const tbmList = Array.isArray(tbmRes.data) ? tbmRes.data : (tbmRes.data?.items || []);
          for (const tbm of tbmList) {
            if (!tbm.task_id || !tbm.gps_lat || !tbm.gps_lon) continue;
            if (tbmGpsCache[tbm.task_id]) continue;
            tbmGpsCache[tbm.task_id] = {
              lat: parseFloat(tbm.gps_lat),
              lon: parseFloat(tbm.gps_lon),
              addr: tbm.gps_address || '',
              date: tbm.tbm_date || tbm.created_at || '',
              conductor: tbm.conductor_name || ''
            };
          }
        } catch(_) {}

        // ③ work_logs GPS 캐시: TBM GPS 없는 task_id만 조회
        const noTbmGpsIds = taskIds.filter(tid => !tbmGpsCache[tid]);
        const wlGpsCache = {};
        await Promise.all(noTbmGpsIds.map(async (tid) => {
          try {
            const wlRes = await API.get(`/worklogs?task_id=${tid}`);
            const wlList = Array.isArray(wlRes.data) ? wlRes.data : (wlRes.data?.items || []);
            const found = wlList.find(wl => wl.gps_lat && wl.gps_lon);
            if (found) wlGpsCache[tid] = {
              lat: parseFloat(found.gps_lat),
              lon: parseFloat(found.gps_lon),
              date: found.gps_recorded_at || found.log_date || ''
            };
          } catch(_) {}
        }));

        // ④ 마커 생성
        for (const task of taskList) {
          let lat = null, lon = null, gpsSource = '', addr = '', displayDate = '';

          const tbmG = tbmGpsCache[task.id];
          const wlG  = wlGpsCache[task.id];

          // 상태변경 시각 fallback (GPS 날짜 없을 때 또는 GPS 자체 없을 때)
          const statusTime = task.work_completed_at || task.updated_at || '';

          if (tbmG) {
            lat = tbmG.lat; lon = tbmG.lon;
            addr = tbmG.addr || `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
            displayDate = _toKSTDateTime(tbmG.date || statusTime);
            gpsSource = 'tbm';
          } else if (wlG) {
            lat = wlG.lat; lon = wlG.lon;
            addr = `${lat.toFixed(5)}, ${lon.toFixed(5)}`;
            displayDate = _toKSTDateTime(wlG.date || statusTime);
            gpsSource = 'worklog';
          } else {
            // GPS 기록 없음 — 마커는 skip하지만 displayDate는 상태변경 시각으로 설정
            displayDate = _toKSTDateTime(statusTime);
          }

          if (!lat || !lon || isNaN(lat) || isNaN(lon)) continue;

          const name = task.title || '작업';
          const doneLabel = task.status === 'completed' ? '✅ 일지완료' : '✅ 작업완료';
          const conductor = tbmG?.conductor || task.supervisor_name || '';

          const marker = L.marker([lat, lon], { icon: makeIcon(meta.color, doneLabel) }).addTo(map);
          marker.bindPopup(`
            <div style="min-width:200px;font-size:13px;">
              <div style="font-weight:700;color:${meta.color};margin-bottom:4px">${doneLabel}</div>
              <div style="font-weight:600">${name}</div>
              ${task.task_number ? `<div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-hashtag mr-1"></i>${task.task_number}
              </div>` : ''}
              ${conductor ? `<div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-user-hard-hat mr-1"></i>${conductor}
              </div>` : ''}
              <div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-calendar-alt mr-1"></i>${displayDate || '-'}
              </div>
              <div style="color:#6B7280;font-size:11px;margin-top:2px">
                <i class="fas fa-map-marker-alt mr-1"></i>${addr}
              </div>
              ${gpsSource === 'worklog' ? `<div style="color:#6B7280;font-size:10px;margin-top:3px">
                <i class="fas fa-info-circle mr-1"></i>작업일지 GPS 기준
              </div>` : ''}
            </div>`);

          latLngs.push([lat, lon]);
          listItems.push({ color: meta.color, icon: meta.faIcon, date: displayDate, name,
            author: conductor, address: addr, lat, lon, taskId: task.id });
        }
      }
    }

    // 마커 있으면 지도 범위 자동 조정
    if (latLngs.length > 0) {
      map.fitBounds(latLngs, { padding: [40, 40] });
    }

    // 날짜 범위 표시 레이블
    const dateRangeLabel = (dateFrom || dateTo)
      ? `${dateFrom || '처음'} ~ ${dateTo || '오늘'}`
      : '전체 기간';

    // 목록 렌더링
    if (listEl) {
      if (listItems.length === 0) {
        listEl.innerHTML = `<div class="text-center text-gray-400 py-6">
          <i class="fas fa-map-pin text-2xl mb-2 block opacity-30"></i>
          <div class="text-sm font-medium text-gray-500">GPS 기록이 없습니다</div>
          <div class="text-xs text-gray-400 mt-1">조회 기간: ${dateRangeLabel}</div>
          <div class="text-xs text-gray-400 mt-1">${meta.emptyMsg}</div>
        </div>`;
      } else {
        // 날짜 최신순 정렬
        listItems.sort((a, b) => b.date.localeCompare(a.date));
        listEl.innerHTML = `
          <div class="flex items-center justify-between mb-2 px-1">
            <div class="text-sm font-bold text-gray-600">
              <i class="fas fa-map-pin mr-1" style="color:${meta.color}"></i>${meta.label} ${listItems.length}건
            </div>
            <div class="text-xs text-gray-400">${dateRangeLabel}</div>
          </div>
          ${listItems.map(item => `
            <div class="flex items-center gap-3 p-3 bg-white rounded-xl border border-gray-100 hover:bg-gray-50 transition-colors">
              <!-- 아이콘 (클릭 → 지도 이동) -->
              <div style="width:36px;height:36px;background:${item.color};border-radius:50%;display:flex;align-items:center;justify-content:center;flex-shrink:0;cursor:pointer"
                onclick="_moveSiteMapTo(${item.lat}, ${item.lon})" title="지도에서 위치 보기">
                <i class="fas ${item.icon} text-white text-xs"></i>
              </div>
              <!-- 내용 (클릭 → 지도 이동) -->
              <div class="flex-1 min-w-0 cursor-pointer" onclick="_moveSiteMapTo(${item.lat}, ${item.lon})">
                <div class="font-semibold text-gray-800 text-sm truncate">${item.name}</div>
                ${item.author ? `<div class="text-xs font-medium truncate" style="color:${item.color}">
                  <i class="fas fa-user mr-1"></i>${item.author}
                </div>` : ''}
                <div class="text-xs text-gray-400 truncate mt-0.5">
                  <i class="fas fa-calendar-alt mr-1"></i>${item.date || '-'}
                  &nbsp;·&nbsp;<i class="fas fa-map-marker-alt mr-1"></i>${item.address}
                </div>
              </div>
              <!-- 작업 상세 이동 버튼 (taskId 있을 때만) -->
              ${item.taskId ? `
              <button onclick="event.stopPropagation();showTaskDetail(${item.taskId})"
                title="작업 상세 보기"
                style="flex-shrink:0;padding:5px 9px;border-radius:8px;border:1.5px solid #D8D0DC;background:#fff;color:#685182;font-size:11px;font-weight:600;cursor:pointer;white-space:nowrap">
                <i class="fas fa-file-alt mr-1"></i>상세
              </button>` : `<i class="fas fa-chevron-right text-gray-300 flex-shrink-0"></i>`}
            </div>
          `).join('')}`;
      }
    }

  } catch(e) {
    console.error('[SiteMap]', e);
    if (listEl) listEl.innerHTML = `<div class="text-center text-red-400 py-4 text-sm"><i class="fas fa-exclamation-circle mr-1"></i>데이터 로드 실패: ${e.message}</div>`;
  }
}

// 지도 특정 위치로 이동
function _moveSiteMapTo(lat, lon) {
  if (!_kakaoMapInstance) return;
  _kakaoMapInstance.setView([lat, lon], 16);
}
